-- Poems batch 290
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ea9f0ac4-ecf8-456a-a98c-c2ff9b9b154d','和白雲庵七首 宴坐臺','黄庶','宋','宋诗','song-poetry','','[]','老僧坐見萬物空，往往終日居此臺。',32,'全唐诗/poet.song.26000.json','["老僧坐見萬物空，往往終日居此臺。", "破衣兀坐若枯木，山鳥不怕行莓苔。"]'),
('c9d6bc28-003e-4be4-af16-d76c1f6d9bed','和白雲庵七首 醒石','黄庶','宋','宋诗','song-poetry','','[]','老僧拂拭待遊者，雲骨一片莓苔青。',32,'全唐诗/poet.song.26000.json','["老僧拂拭待遊者，雲骨一片莓苔青。", "塵埃萬事心若醉，到此不覺令人醒。"]'),
('a886227f-5428-4fb0-89a6-56d9e019939c','和白雲庵七首 磬石','黄庶','宋','宋诗','song-poetry','','[]','古樂破散鄭衛起，走入萬物不可名。',32,'全唐诗/poet.song.26000.json','["古樂破散鄭衛起，走入萬物不可名。", "山中惆悵莫能到，疑是舜時韶一聲。"]'),
('22eac3cc-93ae-4031-8a07-8c571aae422c','和白雲庵七首 明月臺','黄庶','宋','宋诗','song-poetry','','[]','老僧山中嫌月窄，夜夜獨上高高臺。',32,'全唐诗/poet.song.26000.json','["老僧山中嫌月窄，夜夜獨上高高臺。", "四邊不肯著閑樹，故要滿坐清光來。"]'),
('07f833e4-4d2f-40c3-a661-4bfd3fe60d27','和白雲庵七首 白石澗','黄庶','宋','宋诗','song-poetry','','[]','林間旋疊石爲路，日日自汲澗底泉。',32,'全唐诗/poet.song.26000.json','["林間旋疊石爲路，日日自汲澗底泉。", "老僧意趣似童子，洗手濯足聽潺湲。"]'),
('1a7f2f5d-5ee0-4b0a-8291-81184cab574a','登扶風王宗元山亭','黄庶','宋','宋诗','song-poetry','','[]','雲收南山頭，太白青崔嵬。',120,'全唐诗/poet.song.26000.json','["雲收南山頭，太白青崔嵬。", "我有泉石夢，坐對懷抱開。", "小池數斛水，涉鳥來毰毸。", "遺翎與行迹，縱橫在蒼苔。", "憶得釣磯上，到家如一迴。", "蔬畦參差綠，採掇助酒杯。", "痛飲不能去，遶竹猶徘徊。", "主人林巖癖，笑傲蒼烟堆。", "心憂百里病，良田正黄埃。", "欲知主人喜，雨抱山脚來。"]'),
('7a58cdf2-0f85-4f35-9304-cda5786189bd','賦得退之畫像','黄庶','宋','宋诗','song-poetry','','[]','功名已寫後世耳，身入人間圖畫看。',32,'全唐诗/poet.song.26000.json','["功名已寫後世耳，身入人間圖畫看。", "嘆息浮圖滿天下，猶疑怒髪尚衝冠。"]'),
('ee1490e3-0297-457e-97b3-a8466b83872d','游石甕寺','黄庶','宋','宋诗','song-poetry','','[]','飛泉自有迎客意，聲到山前入人耳。',160,'全唐诗/poet.song.26000.json','["飛泉自有迎客意，聲到山前入人耳。", "泉聲引行不知疲，石路磽确折屐齒。", "長安睫滿車馬塵，林巖夜夜來夢寐。", "雲烟郊原鋪古圖，心眼開快明如洗。", "渭流屈曲成大篆，書破野色爲綠紙。", "丘墟沉吟古興廢，秋風正入紅樹起。", "折碑斷垣卧荆棘，意思紛亂不可理。", "窮幽更下蒼崖根，把酒坐聽潺湲醉。", "山花似欲勸苦飲，時散清香入人鼻。", "奔走恨不身長遊，喜寫姓名藏薜荔。"]'),
('2288f09e-6c71-4383-8c7d-993a1f8745c8','喜雪','黄庶','宋','宋诗','song-poetry','','[]','長安雪一尺，朝扉失南山。',96,'全唐诗/poet.song.26000.json','["長安雪一尺，朝扉失南山。", "坐喜疾疫消，敢避衣褐單。", "關中西征後，所向饘粥慳。", "去年新錢敝，千里成彫殘。", "漫漫豐穰候，風俗開客顔。", "秦人飽稼穡，共望倉廩寬。", "幕府俸薄少，藜藿日滿盤。", "明年麥定好，慰喜聊加餐。"]'),
('017d5fa8-2297-4642-bbc6-91b13ee06892','次韵和松徑','黄庶','宋','宋诗','song-poetry','','[]','行人旱亢日，共蔭蒼烟姿。',48,'全唐诗/poet.song.26000.json','["行人旱亢日，共蔭蒼烟姿。", "豈識雪霜心，但輕螻蟻皮。", "中爲棟梁用，莫嘆斧斤遲。", "樗柳盡犧象，後凋終不衰。"]'),
('4228352a-5772-4cb2-a4c4-d40f05a08e37','登大雲頂','黄庶','宋','宋诗','song-poetry','','[]','區區霸迹欲知小，試絕大雲孤頂看。',32,'全唐诗/poet.song.26000.json','["區區霸迹欲知小，試絕大雲孤頂看。", "老僧指我日上處，鏡面瀉出黄金盤。"]'),
('cd99ac19-cba9-489d-ab99-1a5547085c7d','送黄景微西遊','黄庶','宋','宋诗','song-poetry','','[]','先生古肝脾，久恨不得識。',144,'全唐诗/poet.song.26000.json','["先生古肝脾，久恨不得識。", "唯聞公卿家，要作門下客。", "千載卞和淚，爭磨薦書墨。", "姓名落四海，履雜車馬迹。", "塵埃十年衣，幾度改顔色。", "紛紛九衢中，拭眼見珪璧。", "敝褐埋衆人，胸肺無丈尺。", "從來饑渴心，既見轉不釋。", "斗酒聽語論，今古吐白黑。", "秋入汴柳枝，買馬欲西適。", "虜方豺狼驕，似漢子弟國。", "予知弱諸侯，必得主父策。"]'),
('0581e574-99e6-4173-a5e0-3aae42d2d980','謝劉簿李尉見訪','黄庶','宋','宋诗','song-poetry','','[]','詩書卧蓬蓽，柴門晝方開。',96,'全唐诗/poet.song.26000.json','["詩書卧蓬蓽，柴門晝方開。", "邑官劉與李，馬蹄破蒼苔。", "林居厭蛙黽，喜振敝席埃。", "見此六翮姿，茅荆共徘徊。", "我欲駐車轍，蔬果傾舊醅。", "山花恨未饒，無以助酒杯。", "今古飽夜話，痛飲勝百迴。", "春風旌旆滿，匏瓜去難陪。"]'),
('2d691296-b39e-49a6-b414-c7b8c1fb1f1a','送郭評事節判磨勘','黄庶','宋','宋诗','song-poetry','','[]','塵埃衣襟改顔色，獨洗青衫三十年。',96,'全唐诗/poet.song.26000.json','["塵埃衣襟改顔色，獨洗青衫三十年。", "足迹不入奔走途，來往銓戶鞋履穿。", "一時同上青雲人，往往裨補造化權。", "朝梳滿手見白髪，嘆息不置齒牙間。", "只言歸田有幾畝，種秫欲釀山中泉。", "腰邊即見佩銅墨，我喜百里瘡痍痊。"]'),
('4813e34a-5b0f-494a-ae3d-348617455b23','登見山樓','黄庶','宋','宋诗','song-poetry','','[]','太守終南爲客主，出入厭倦馬與車。',160,'全唐诗/poet.song.26000.json','["太守終南爲客主，出入厭倦馬與車。", "與山朝夕欲還往，作樓近在室一隅。", "主人去久山寂寞，正值青帝催焦枯。", "我拘簿書甚杻械，擺脫步上提酒壺。", "郊原猶未見春色，似據水墨長安圖。", "也知好景天更惜，高峰常是雲模糊。", "安得風伯持大篲，掃灑百里如屏鋪。", "顯昧萬狀古詩國，收拾可禿千毫書。", "我來願作風雅戶，醉倒坐待明月扶。", "去家若有巖下夢，免復夜夜尋歸途。"]'),
('9a5df3e3-a2c6-46f4-9652-54d98dbebf1b','和題竹軒','黄庶','宋','宋诗','song-poetry','','[]','小軒移得清風枝，知君公退來忘機。',32,'全唐诗/poet.song.26000.json','["小軒移得清風枝，知君公退來忘機。", "山禽自識主人慣，客到有時驚不飛。"]'),
('a20d9e05-ecd0-4dbb-accd-ee87bd708129','下棋','黄庶','宋','宋诗','song-poetry','','[]','古人欲寫得喪形，萬事畫在方罫內。',32,'全唐诗/poet.song.26000.json','["古人欲寫得喪形，萬事畫在方罫內。", "黑白勝負無已時，目送孤鴻出雲外。"]'),
('c089349c-d745-40ac-8deb-66642974b39a','暑軒夜坐','黄庶','宋','宋诗','song-poetry','','[]','夜氣入庭樹，小軒坐前檐。',48,'全唐诗/poet.song.26000.json','["夜氣入庭樹，小軒坐前檐。", "清風動巨箑，浮雲捲重簾。", "月遲待交舊，蚊噪憎諛讒。", "輕凉若可買，金願量谷巖。"]'),
('cecd503f-7d23-42f6-bd1d-bd976be94ee0','聞蛙','黄庶','宋','宋诗','song-poetry','','[]','佞舌兒女柔，異教蜩螗喧。',24,'全唐诗/poet.song.26000.json','["佞舌兒女柔，異教蜩螗喧。", "豈能聽蛙黽，靜枕詩書眠。"]'),
('25cfdb2a-30b0-4cd0-afa2-d87ae719afb1','憶竹亭','黄庶','宋','宋诗','song-poetry','','[]','蓬萊楚山底，傍舍竹四圍。',216,'全唐诗/poet.song.26000.json','["蓬萊楚山底，傍舍竹四圍。", "狂鞭入門戶，亂笋爭牆籬。", "與竹事還往，相對一束書。", "壯長走世路，駑駘强鞭笞。", "塵埃客灞滻，遠夢夜夜歸。", "小亭久不理，漏棟生白芝。", "偶放簿書筆，杖屨改舊詩。", "呼童誅蒿萊，掃灑莓苔基。", "誰庭無花卉，憎有兒女姿。", "獨移蒼烟本，慰我千里思。", "坐生山林趣，亭園有光輝。", "免使清風來，留在桃李枝。", "月明遶竹步，撚挽頤頷髭。", "相向若知己，動摇影參差。", "人間欠藥石，稚乳驕羌夷。", "青杉汙汙垢，寸尺莫可裨。", "忍作倉廩盜，寧老詩書饑。", "養笋爲釣竿，早晚耕蒿藜。"]'),
('502bbfab-ffa4-41e5-b1c5-1a118926081b','和百塔寺四首 四開亭','黄庶','宋','宋诗','song-poetry','','[]','亭前流水醒客耳，亭上白雲開客顔。',32,'全唐诗/poet.song.26000.json','["亭前流水醒客耳，亭上白雲開客顔。", "老僧有意厚來往，四面更令看好山。"]'),
('018b198d-71b6-401a-89f5-8c31790f74c3','和百塔寺四首 聽泉近詔天下收古樂器','黄庶','宋','宋诗','song-poetry','','[]','五音入耳大聲散，情性破碎不可完。',32,'全唐诗/poet.song.26000.json','["五音入耳大聲散，情性破碎不可完。", "而今虞舜欲儀鳳，願獻泉譜爲韶源。"]'),
('5136a34a-d429-4eb2-ba71-6441b13ae70a','和百塔寺四首 芳亭','黄庶','宋','宋诗','song-poetry','','[]','峨峨佛屋瘦四海，志士嘆息傷容顔。',32,'全唐诗/poet.song.26000.json','["峨峨佛屋瘦四海，志士嘆息傷容顔。", "高僧淳拙有深意，獨自結茅山水間。"]'),
('8f45f082-1ff0-480a-a748-0287686d65a8','和百塔寺四首 水閣','黄庶','宋','宋诗','song-poetry','','[]','山僧聽泉心不足，鑿池汲引爲蟾泓。',32,'全唐诗/poet.song.26000.json','["山僧聽泉心不足，鑿池汲引爲蟾泓。", "自言猶欲洗俗耳，夜靜爲聞蛙黽聲。"]'),
('3a514400-f324-473b-bfaa-78dcb09e22d8','和暑雨偶書','黄庶','宋','宋诗','song-poetry','','[]','暑如煎烹欲狂走，猛雨似洗沉痾瘳。',64,'全唐诗/poet.song.26000.json','["暑如煎烹欲狂走，猛雨似洗沉痾瘳。", "寧知詩書一枕夢，便作桃李三春遊。", "蛙蜩叫噪若交舊，蚊蠅癡鈍如仇讎。", "今君病起正高卧，莊蝶處處宜相求。"]'),
('fdf02221-9ee1-43b7-95d3-8f9f95d7e2f3','漁家長安前詩','黄庶','宋','宋诗','song-poetry','','[]','插屋數竿網，穿籬幾尺船。',24,'全唐诗/poet.song.26000.json','["插屋數竿網，穿籬幾尺船。", "水鄉菱芡足，不著免租錢。"]'),
('7e296c2d-b2af-4a5e-9af9-34830c5ece27','宿趙屯','黄庶','宋','宋诗','song-poetry','','[]','蘆花一股水，弭楫日已暮。',72,'全唐诗/poet.song.26000.json','["蘆花一股水，弭楫日已暮。", "山間聞鷄犬，無人見烟樹。", "行逐羊豕迹，始識入市路。", "菱芡與魚蟹，居人足來去。", "漁家無鄉縣，滿船載稚乳。", "鞭笞公私急，醉眠聽秋雨。"]'),
('fc1458cc-fd67-4807-a4e2-8d3e81ec9d16','宿采石','黄庶','宋','宋诗','song-poetry','','[]','秋風宿兼葭，花落若霜雪。',120,'全唐诗/poet.song.26000.json','["秋風宿兼葭，花落若霜雪。", "江山古興廢，荆棘壘出沒。", "水收鳬雁聲，夜靜寒籟發。", "漁舟自來去，笑語載明月。", "詩形動筆墨，恨乏風雅骨。", "謫仙爲黄土，冢平名突兀。", "句編天下口，千載字不滅。", "人間比興復，泉底魂魄悅。", "坐誦姑熟語，酌酒當棗栗。", "醉夢若可見，好句當須乞。"]'),
('2b0680dd-a858-424b-ad03-26026ca55394','擬歐陽舍人古篆','黄庶','宋','宋诗','song-poetry','','[]','隸書滿紙籀文廢，字法破碎失本根。',208,'全唐诗/poet.song.26000.json','["隸書滿紙籀文廢，字法破碎失本根。", "中間陽冰入篆室，下筆日與丞相親。", "點畫各得萬物體，科蚪筋骨千載新。", "泉銘學語童子知，大曆幾字名忽振。", "足知古人自負恃，碑峴巨石垂千春。", "篆字堆積天下宇，晚得紙本如希珍。", "鋪舒牆壁動人眼，直木曲鐵若可捫。", "人爲黄土久寂寞，略不訛缺纔鱗皴。", "我疑山鬼恐漫滅，往往鎸鑿施斧斤。", "公來醉吟江山國，得之愛嘆何殷勤。", "刻詞猶恨紀不足，句句與古風雅鄰。", "一旦紙貴文字市，粥詩賈篆聲云云。", "蘇梅鸞鳳相上下，鄙語燕雀何能群。"]'),
('1a254ae0-e74a-48be-8a73-8760b18750ce','大孤山','黄庶','宋','宋诗','song-poetry','','[]','彭蠡百里南國襟，萬頃蒼烟插孤岑。',160,'全唐诗/poet.song.26000.json','["彭蠡百里南國襟，萬頃蒼烟插孤岑。", "不知天星何時落，春秋不書不可尋。", "石怪木老鬼所附，茲乃與水同浮沉。", "鳴鴟大藤樹下廟，祭血不乾年世深。", "軸艫千里不敢越，割牲釃酒來獻斟。", "我行不忍隨人後，許國肝膽神所歆。", "落帆夜宿白鳥岸，睥睨百遶寒藤陰。", "銀山大浪獨夫險，比干一片崔嵬心。", "宦遊遠去父母國，心病若有山水淫。", "江南畫工今誰在，拂拭東絹傾千金。"]'),
('473e49d9-8c6a-4549-b963-6bead1b8b820','汴河','黄庶','宋','宋诗','song-poetry','','[]','汴都峨峨在平地，宋恃其德爲金湯。',144,'全唐诗/poet.song.26000.json','["汴都峨峨在平地，宋恃其德爲金湯。", "先帝始初有深意，不使子孫生怠荒。", "萬艘北來食京師，汴水遂作東南吭。", "甲兵百萬以爲命，千里天下之腑腸。", "人心愛惜此流水，不啻布帛與稻粱。", "漢唐關中數百年，木牛可以腐太倉。", "舟楫利今百於古，奈何益見府庫瘡。", "天心正欲醫造化，人間豈無針石良。", "窟穴但去錢穀蠹，此水何必求桑羊。"]'),
('e62e1a54-89af-4f4b-a2f2-861c5eb3e8f9','樊侯廟','黄庶','宋','宋诗','song-poetry','','[]','陰森樊侯廟，古木澧水傍。',120,'全唐诗/poet.song.26000.json','["陰森樊侯廟，古木澧水傍。", "茲民畏如生，奔走豕與羊。", "家家奉侯諱，若在父母堂。", "我來憩行役，再拜奠公觴。", "緬思英豪姿，名與此水長。", "風偃衆樹枝，擬若怒鬣張。", "陰官有兵師，想在賁育行。", "今茲戎虜驕，內爲府庫瘡。", "安得七尺軀，長戟再激昂。", "橫行匈奴中，庶以康肺腸。"]'),
('755fd064-680c-4611-9197-14099c71a901','游石池潭','黄庶','宋','宋诗','song-poetry','','[]','吾家溪潭動百尺，坐見游魚可倒指。',256,'全唐诗/poet.song.26000.json','["吾家溪潭動百尺，坐見游魚可倒指。", "月明無風水不動，鈎絲鑒中出朱鯉。", "乘閒具酒席草岸，呼網一舉常百尾。", "鱠霜炙玉眠鴟夷，樹挂落日醉不起。", "幾年手板負青山，趁魚舷聲不入耳。", "凉秋九月役吏事，瘦馬奔走黄葉裏。", "有酒不得好景飲，訪古或問芻牧子。", "指我石池十里近，蒼苔畏崖碧無底。", "楚王北遊嘆寂寞，創奇造幽有遺址。", "我來徘徊知是否，廢興盡可付流水。", "彷彿故溪在吾目，濯手漱齒有餘思。", "開樽喜與風景遇，蘆花入杯勸人醉。", "漁翁有意助酒卮，青竹盡日垂空餌。", "我疑溪靈靳異景，不遣紅鱗滿人意。", "人生天地未歸客，計較貴賤羞犬彘。", "當須醉倒載月歸，不信鄉夢留不止。"]'),
('861ab90d-c072-4a65-a7dd-4ddf76a2cf40','食鱠','黄庶','宋','宋诗','song-poetry','','[]','秋風蓴魚肥，兔罝饞涎落。',120,'全唐诗/poet.song.26000.json','["秋風蓴魚肥，兔罝饞涎落。", "溪友入晝夢，但苦青衫縛。", "落日渡河水，食指相悟覺。", "宿夕治鱠具，共作泛舟約。", "網罟遮青答，老鱒薦絲臛。", "玉軟飽下筯，坐視肴果惡。", "酒薄如疲兵，對此得衛霍。", "迴首食五鼎，適意均一樂。", "人間軍須後，甑釜有藜藿。", "甘鮮豈敢事，聊此慰寂寞。"]'),
('87b1217b-2ad6-4fb0-b531-dc5666e3089a','家僮來持雙井芽數數飲之輒成詩以示同舍','黄庶','宋','宋诗','song-poetry','','[]','我疑醇醲千古味，寂寞散在山茶枝。',192,'全唐诗/poet.song.26000.json','["我疑醇醲千古味，寂寞散在山茶枝。", "雙井名入天下耳，建溪春色無光輝。", "吾鄉茶友若敵國，糞土尺璧珍刀圭。", "嗟予奔走車馬迹，塵埃荆棘生喉頤。", "煮雲爲腴不可見，青泉綠樹應相嗤。", "長鬚前日千里至，百芽包裹林巖姿。", "開緘春風若滿手，喜氣收拾人恐知。", "江南陽和夜欲試，小齋獨與清風期。", "石鼎泉甘火齊得，混沌不死元氣肥。", "詩書坐對爲客主，一啜已見沆瀣醨。", "通宵安穩睡物外，家夢欲遣不肯歸。", "不信試來與君飲，洗出正性還肝脾。"]'),
('b34a2864-9fe1-4934-8e75-74ac3e145f51','靈井','黄庶','宋','宋诗','song-poetry','','[]','何年清泉眼，幾斛涵蒼苔。',120,'全唐诗/poet.song.26000.json','["何年清泉眼，幾斛涵蒼苔。", "甕盎日夜至，長滿莫可涯。", "天旱不知竭，衆流起黄埃。", "淘綆乾未定，能使沴氣開。", "廟祠失根柢，故老奠酒杯。", "蠶民咒棗栗，千斤意徘徊。", "兒童慣冷暖，預知春秋來。", "臨之鑒鬚眉，方鑒無煤炲。", "窟穴若喉吭，我疑吐雲雷。", "何當鞭蜃螭，與國驅旱災。"]'),
('8d7c0498-3e81-4944-820e-cbe1affb8677','過建成侯廟','黄庶','宋','宋诗','song-poetry','','[]','鳴鴟古木末，饑鳥啄腐柯。',96,'全唐诗/poet.song.26000.json','["鳴鴟古木末，饑鳥啄腐柯。", "下有黄侯宮，清風在藤蘿。", "公昔爲刺史，俗若閨門和。", "德銘潁人心，千載不可磨。", "至今奉如生，慢侮莫敢過。", "破祠望道路，丹檐獨峨峨。", "春秋賽豚肩，里巫日婆娑。", "牛童不知此，來往夕陽歌。"]'),
('c3d9d5bc-e9a2-4db5-8351-c2e886f279e0','過許由冢','黄庶','宋','宋诗','song-poetry','','[]','稷契寧渴死，不飲箕潁泉。',120,'全唐诗/poet.song.26000.json','["稷契寧渴死，不飲箕潁泉。", "先生獨洗耳，不聽天子言。", "清風飽進退，千載何悠然。", "孤墳沒荆棘，高名爭青山。", "嗟我迍邅身，一命行十年。", "味薄無辛鹹，璞頑廢雕鎸。", "朝行箕山麓，暮挹潁水源。", "竹帛何處所，搔首熊魚間。", "白雲要閑友，尚苦兒女牽。", "丈夫合勇决，顧計羞面顔。"]'),
('efff62db-0915-43e4-9a7a-2d8e472480c7','洛陽道中','黄庶','宋','宋诗','song-poetry','','[]','秋風滿巾衣，洛水行飲馬。',48,'全唐诗/poet.song.26000.json','["秋風滿巾衣，洛水行飲馬。", "山川氣象老，身若在古畫。", "嵩雲知客心，峰色如掃灑。", "荒草遍丘墟，沉吟動舒瀉。"]'),
('4d63b655-58e9-4c41-8c19-b3606e454f02','過少姨廟','黄庶','宋','宋诗','song-poetry','','[]','陰森老柏少姨廟，爐烟蓬勃疑行雲。',32,'全唐诗/poet.song.26000.json','["陰森老柏少姨廟，爐烟蓬勃疑行雲。", "祭盤狼籍山鳥飽，巫祝生涯來往人。"]'),
('f0f2fa6d-dc7a-465a-b0ee-74cc5daf2eab','竹軒','黄庶','宋','宋诗','song-poetry','','[]','小軒與竹事還往，庭下寂寂無客塵。',32,'全唐诗/poet.song.26000.json','["小軒與竹事還往，庭下寂寂無客塵。", "開書讀對聖賢語，一畝清風爲主人。"]'),
('c8274702-d378-4d3b-bf09-36b188eb942a','賦聞角','黄庶','宋','宋诗','song-poetry','','[]','角本金鼓儔，獨主昏曉色。',72,'全唐诗/poet.song.26000.json','["角本金鼓儔，獨主昏曉色。", "日收雲氣黄，月斜霜露白。", "征夫朝夕聞，淚落甲鎧黑。", "時平腐橐鞬，白首眼不識。", "嚴城重啟閉，不廢角人職。", "老農鼓腹聽，安識天子德。"]'),
('e269f3aa-5970-475b-8a2c-81a082f0306d','賦小桐','黄庶','宋','宋诗','song-poetry','','[]','小桐纔幾尺，氣壓百歲樗。',72,'全唐诗/poet.song.26000.json','["小桐纔幾尺，氣壓百歲樗。", "雨露意未飽，風月韵已孤。", "鳳凰肯寂寞，燕雀空踟躕。", "天地有和氣，想爲桐之腴。", "我願刳作琴，獻上九重居。", "坐使薰風還，雖死骨不枯。"]'),
('f95dcdfa-1db6-4958-8cec-fd194a1ac2e4','賦轆轤','黄庶','宋','宋诗','song-poetry','','[]','火雲旱風苗欲死，曲木直綆寒泉深。',32,'全唐诗/poet.song.26000.json','["火雲旱風苗欲死，曲木直綆寒泉深。", "耕夫淚濕原上土，老圃顧盼輕黄金。"]'),
('d65df52d-8d26-4b2e-8099-d1107d96286d','賦古佛','黄庶','宋','宋诗','song-poetry','','[]','樹老枝半死，碑斷壁底眠。',132,'全唐诗/poet.song.26000.json','["樹老枝半死，碑斷壁底眠。", "古屋顔色改，有佛獨巋然。", "蒼首上雨足，壞臂蔓草纏。", "野老每再拜，往往報豐年。", "孔祠照四方，制度丹雘妍。", "朝夕過其下，孰肯爲恭虔。", "土木茲僅分，吾民信益堅。", "佛法入人心，誰與斸其根。", "蒼蒼不可問，用意或者偏。", "木蠹罪豈大，付與啄木權。", "胡不啄佛徒，使蠹民之天。"]'),
('9918c55a-835d-4aeb-b028-af63e849fc49','賦古碑','黄庶','宋','宋诗','song-poetry','','[]','古寺得斷碣，偃卧敗壁陰。',96,'全唐诗/poet.song.26000.json','["古寺得斷碣，偃卧敗壁陰。", "莓苔入破字，欲讀不易尋。", "姓字駁難辨，展轉風雨侵。", "塵穴夏蛙宿，草盛秋蟲吟。", "田夫煅可礪，老婦寒可砧。", "伊非浮圖家，歲月徒駸駸。", "予聞岐陽鼓，篆法抵萬金。", "存者十止九，太息涕泗霪。"]'),
('6897b47a-3026-4b79-8d76-f3128ed107ff','次韵和中伏坐夜','黄庶','宋','宋诗','song-poetry','','[]','萬兵昏雨過，暑斗插雲傾。',120,'全唐诗/poet.song.26000.json','["萬兵昏雨過，暑斗插雲傾。", "老佞溪蛙靜，真交海月生。", "遊氛褰幕帟，遠籟起莖英。", "清洗塵埃慮，幽通造化情。", "酸鹹時味薄，寂寞古途亨。", "去象筌真意，無形寫天聲。", "詩疑窺杜子，文欲造盤庚。", "身在清風國，神游白玉城。", "希夷乘浩氣，沆瀣飲元精。", "坐久忘昏寐，迴頭有啟明。"]'),
('b227e6e3-5f27-4cea-8e2d-6b66aaef9b58','灸贅疣','黄庶','宋','宋诗','song-poetry','','[]','贅疣在予手，累久至三四。',192,'全唐诗/poet.song.26000.json','["贅疣在予手，累久至三四。", "初視君外物，於意不能置。", "居閑或灸灼，已沒出復繼。", "贅出與贅沒，曾莫生死異。", "天地贅一氣，萬物贅天地。", "贅復贅於人，小大而已矣。", "人之於爲贅，作爲有大盩。", "至理本無事，破真以爲僞。", "善惡亂大性，賞罰亂大治。", "宮徵亂大聲，青黄亂大賁。", "寸尺亂大刑，酸鹹亂大味。", "大樸如瘡疽，空虛無完理。", "天地不爾仇，爾獨贅之計。", "耻指不若人，孟子其有謂。", "志小略其大，殆非達者意。", "棄火復投艾，兩忘吾贅贅。"]'),
('745e0b8e-5c73-4e1c-82e3-1287f6d986ab','賦八月竹','黄庶','宋','宋诗','song-poetry','','[]','我養一軒竹，秋來成綠陰。',48,'全唐诗/poet.song.26000.json','["我養一軒竹，秋來成綠陰。", "萬物有衰意，獨懷霜雪心。", "西風嵇叔醉，明月白公吟。", "迴首看桃李，何嘗費百金。"]'),
('849b9655-7962-4dc9-9739-4060c4576628','遊雲門山','黄庶','宋','宋诗','song-poetry','','[]','南山州之屏，四時改顔色。',144,'全唐诗/poet.song.26000.json','["南山州之屏，四時改顔色。", "日夕太守宴，供帳減繒帛。", "更求秉燭飲，圖寫在四壁。", "烟雲時藏埋，景好疑愛惜。", "我官府中塵，喜與山相識。", "泉石未還往，愧負苦逋責。", "秋風復杖屨，持酒窮勝僻。", "莓苔轉蒼崖，郡國在几席。", "廢興賦飛鳥，牛羊自朝夕。", "風物摹大句，才薄徒噤嘿。", "唯作酩酊歸，山月吐半璧。", "沉吟又慰喜，三友添飲客。"]'),
('0847e69c-a4e2-4f0b-9a4e-881a910e536d','携家遊倭松','黄庶','宋','宋诗','song-poetry','','[]','倭松名載四海耳，百怪老筆不可傳。',32,'全唐诗/poet.song.26000.json','["倭松名載四海耳，百怪老筆不可傳。", "左妻右兒醉樹下，安得白首巢其巔。"]'),
('57641c7e-bace-4279-a4f9-910c1b5f5a8e','庭樹聯句枝字爲韵','黄庶','宋','宋诗','song-poetry','','[]','婆娑庭中樹，老大千年枝。',288,'全唐诗/poet.song.26000.json','["婆娑庭中樹，老大千年枝。", "百弓蔽赫日，四座生凉颸。", "影怪疑龍蛇，聲和認塤篪。", "未被斧斤賞，敢辭塵埃欺。", "輪囷壯士嘆，冷淡童子嗤。", "盤根得地固，挺材本天資。", "枌榆謾百尺，杞柳徒一圍。", "節堅費刻畫，莫訝繩墨遲。", "枝狂躍蛟虬，癭怪蹲熊羆。", "有時相摩擊，往往霹靂飛。", "篩月碎玉散，障日翠幄垂。", "腹空懶龍卧，實少饑禽悲。", "敗葉童僕憎，清陰兒女嬉。", "堂萱小人態，階藥老婢姿。", "春禽似竽笙，夏蜩若羹糜。", "提孩不出戶，知時如耆龜。", "得成孤高狀，敢忘毫末時。", "身遭藤蘿蔽，心與松柏期。", "晨烟拂杪起，落日侵梢齊。", "老蠹病其中，啄木爲良醫。", "公輸不在世，志士空嗟咨。", "止知楩柟高，苦厭樗櫟卑。", "大屋必欲構，老匠寧終遺。", "棟梁如採收，散材安足知。"]'),
('07b4d071-01d4-4dec-aa5d-45168b8fd70d','斑石枕聯句','黄庶','宋','宋诗','song-poetry','','[]','斸得西山骨，磨礱露斑駁。',288,'全唐诗/poet.song.26000.json','["斸得西山骨，磨礱露斑駁。", "凝結一何怪，形模萬難學。", "直疑彩雲根，又訝紫珉璞。", "中瘦皺蛟腹，外文灼龜殻。", "冷剖清泉肝，𥡥搘老鰲脚。", "堅方君子性，清純聖人樸。", "有氣當補天，無瑕應並瑴。", "定漬盤古苔，想漏神農藥。", "堪作夢寐寶，尤是炎蒸託。", "眠月病頭愈，橫風酲肺濯。", "珊瑚侈可唾，陶甄脆堪撲。", "夜深魘鬼驚，晝冷詩魔愕。", "首愜無俗夢，心清去煩惡。", "蘄簟方敢友，蜀筇良可攫。", "何必檄愈風，何必文驅瘧。", "質任兒女嗤，頑宜僮僕謔。", "枕流固迂誕，籍糟徒落魄。", "潤生審將雨，輝發疑有玨。", "髑髏莊生狂，虎魄宋武薄。", "欲鑱中郎銘，文章體猶弱。", "欲秘淮南書，神仙志非樂。", "我疑混沌礦，誰與礱竅鑿。", "可作甘寢輿，華胥詣冥寞。", "子道足施爲，我拙困嬰縛。"]'),
('1134f8a1-759c-4aa5-944c-ca12a53a9882','送蘇田司理','黄庶','宋','宋诗','song-poetry','','[]','秦人勇鬥暴，獄訟號難理。',96,'全唐诗/poet.song.26000.json','["秦人勇鬥暴，獄訟號難理。", "錙銖較罪法，闕責莫可避。", "蘇生决曹掾，以明縛奸吏。", "我見獄戶囚，出入有平氣。", "章章三年課，已在山公啟。", "六月暑濕衣，出汗若炊燹。", "俸微迫朝夕，衝熱事行李。", "一身不能賙，送子腸腑沸。"]'),
('c3ba1bdb-9a92-4632-be19-c4c8c12816eb','送李室長慶州寧覲','黄庶','宋','宋诗','song-poetry','','[]','我愛孟堅文學飽，持筆去作將軍客。',288,'全唐诗/poet.song.26000.json','["我愛孟堅文學飽，持筆去作將軍客。", "鋪張大漢征北功，手携直上燕然刻。", "千載事挂單于眼，至今猶若擒白黑。", "幾年羌夷瘡一方，窟穴未掃壯士瘠。", "我生南方長詩書，愛國區區肺如炙。", "欲於塞外勒姓名，往往夜夢賀蘭石。", "一來長安事刀筆，駑駘不展芻粟力。", "峨峨李公邦之梓，聲載百郡理霹靂。", "今年權佩慶州印，上馬威至吞秋色。", "羌夷奔走若奴婢，剺面童子嗔可摑。", "白頭慶民能記數，前時太守有陰德。", "試求園中手栽樹，邊人應作甘棠惜。", "老幼事公如父兄，妥帖不敢相干極。", "子來別我省塞上，霜風漸著邊樹赤。", "塵埃恨絆不得往，安得鑽肩生羽翼。", "子今才華筆端富，山川去入風雅國。", "黄雲白草牛羊肥，區落鷄犬晴歷歷。", "將詩寫作聚米圖，歸來爲我一指畫。"]'),
('b9a94a95-c5a6-442f-bbc7-17c022e5f5f6','和柳子玉官舍十首 心適堂','黄庶','宋','宋诗','song-poetry','','[]','一屏一榻無俗塵，左置枯琴右開易。',32,'全唐诗/poet.song.26000.json','["一屏一榻無俗塵，左置枯琴右開易。", "重門不閉誰往還，明月清風是相識。"]'),
('20547e02-1e83-4304-8e9f-b2c9ac05f862','和柳子玉官舍十首 思山齋','黄庶','宋','宋诗','song-poetry','','[]','吳兒心著吳山深，終南滿目不自慰。',32,'全唐诗/poet.song.26000.json','["吳兒心著吳山深，終南滿目不自慰。", "有時蟬蛻書几邊，夢到五湖千里外。"]'),
('795def6a-ddd5-406b-9213-b72b62211e70','和柳子玉官舍十首 小池','黄庶','宋','宋诗','song-poetry','','[]','清泉數斛關幽事，坐見鏡中魚往來。',32,'全唐诗/poet.song.26000.json','["清泉數斛關幽事，坐見鏡中魚往來。", "浮萍蝕盡秋月面，霜爲一磨如匣開。"]'),
('5c47a3bd-974b-4a66-b061-e594e365c858','和柳子玉官舍十首 新泉','黄庶','宋','宋诗','song-poetry','','[]','牆根新冽寒泉眼，風廊一股來泠泠。',32,'全唐诗/poet.song.26000.json','["牆根新冽寒泉眼，風廊一股來泠泠。", "燈花夜半知我喜，恰是舊山穿石聲。"]'),
('12ef4b1c-e2ce-489a-b854-252cf4aba329','和柳子玉官舍十首 竹塢','黄庶','宋','宋诗','song-poetry','','[]','笋隨人意疏處生，清風如歸自來去。',32,'全唐诗/poet.song.26000.json','["笋隨人意疏處生，清風如歸自來去。", "雖然不與俗子期，陰過鄰家亦銷暑。"]'),
('18637b5e-2aa5-4c03-846b-d7ef6f6200f9','和柳子玉官舍十首 土榻','黄庶','宋','宋诗','song-poetry','','[]','床前一尺二尺泉，床後三枝五枝樹。',32,'全唐诗/poet.song.26000.json','["床前一尺二尺泉，床後三枝五枝樹。", "眠閑圖似在家山，夢魂不使東南去。"]'),
('94d313d9-2b17-495b-9fc0-519c6cea0ef8','和柳子玉官舍十首 怪石','黄庶','宋','宋诗','song-poetry','','[]','山阿有人著薜荔，廷下縛虎眠莓苔。',32,'全唐诗/poet.song.26000.json','["山阿有人著薜荔，廷下縛虎眠莓苔。", "手磨心語知許事，曾見漢唐池館來。"]'),
('e30a699a-20ea-4cf0-85a8-faadbf82342f','和柳子玉官舍十首 怪石','黄庶','宋','宋诗','song-poetry','','[]','山嵬水怪着薜荔，天禄辟邪眠莓苔。',32,'全唐诗/poet.song.26000.json','["山嵬水怪着薜荔，天禄辟邪眠莓苔。", "鈎簾坐對心語口，曾見漢唐池館來。"]'),
('b6f8644e-569d-4f9a-9e04-acad25deed32','和柳子玉官舍十首 茴香','黄庶','宋','宋诗','song-poetry','','[]','鄰家爭插紅紫歸，詩人獨行嗅芳草。',32,'全唐诗/poet.song.26000.json','["鄰家爭插紅紫歸，詩人獨行嗅芳草。", "叢邊幽蠹更不凡，蝴蝶紛紛逐花老。"]'),
('69a31a68-cfb8-45be-b5e0-8fe847a740fc','和柳子玉官舍十首 蜜蜂','黄庶','宋','宋诗','song-poetry','','[]','秋成想見香租入，菊露楓膠蜜幾脾。',32,'全唐诗/poet.song.26000.json','["秋成想見香租入，菊露楓膠蜜幾脾。", "日日山僮掃紅葉，蜂衙知是主人歸。"]'),
('a08e6130-f899-425e-b306-0d3a2e910db0','和柳子玉官舍十首 芭蕉','黄庶','宋','宋诗','song-poetry','','[]','有底春風能好事，解將刀尺翦青天。',32,'全唐诗/poet.song.26000.json','["有底春風能好事，解將刀尺翦青天。", "知君新得草書法，旋卷碧雲供小牋。"]'),
('c3e09680-d708-488e-a25d-1125a2efff05','送楊侍讀自長安之蜀','黄庶','宋','宋诗','song-poetry','','[]','西征七年四方病，關中所向尤瘡痍。',256,'全唐诗/poet.song.26000.json','["西征七年四方病，關中所向尤瘡痍。", "欲令福星及憔悴，千里特輟廊廟姿。", "公如手持天子德，家至戶到人人施。", "秦俗鬥暴號難理，列郡京兆猶鼎糜。", "公來寬假訟訴少，杻械顛倒生菌芝。", "神疑公惠入人淺，六月巖谷囚雨師。", "雩壇滴酒土未乾，霶霈已洗旌旗歸。", "老農笑呼刺史雨，菽粟茂好公所携。", "幾年軍須俗枯槁，老幼不足蒿與藜。", "薄田今亦夏秋稔，竇窖飽滿鷄豬肥。", "公之去思甚明白，衆口已寫德政辭。", "鎸鑱不要路傍石，人心自是長安碑。", "今年夷馬飲瀘水，苴土新佩黄金龜。", "相如才高去諭蜀，弩矢故事重光輝。", "雍人欲把寇恂借，益部已嘆廉公遲。", "傅巖今屬九折外，帝夢即往西南涯。"]'),
('6776e944-f999-4385-ba72-8741dbe4296e','答王甫判官示遊興慶池之作','黄庶','宋','宋诗','song-poetry','','[]','東池十里近，遭匝風物飽。',147,'全唐诗/poet.song.26000.json','["東池十里近，遭匝風物飽。", "南山若戶屏，登臨四時好。", "我初來長安，脚擬朝夕到。", "纏綿簿書間，拘窘若囚盜。", "一歲無幾至，荏苒成吏考。", "夜夜千頃月，只供釣魚老。", "平生林泉心，探奇欲傾倒。", "咫尺迺尚爾，滿意寧可保。", "君官苦近市，危坐若林槁。", "偷閑呶呶中，躍馬志{高交}暴。", "登覽足意思，滿腹若瑰寶。", "歸來成新詩，使我愧懷抱。"]'),
('e1455281-88ab-4fc1-b58c-ad2b5e82a9b0','依韵和酬雷太簡見貽之什','黄庶','宋','宋诗','song-poetry','','[]','生長詩與書，不信世道難。',144,'全唐诗/poet.song.26000.json','["生長詩與書，不信世道難。", "出處愧古人，章句得一官。", "舌强不肯柔，開口誰欣歡。", "十年走塵土，蹭蹬苦地寒。", "紆朱非良貴，寧較厚與單。", "古心自突兀，胸中鬰萬端。", "昔常玩於水，今乃知其瀾。", "身世心已灰，人事鼻可酸。", "病卧得君詩，喜試昏膜看。", "意遠辭淡泊，稠重欲相寬。", "以言藥我病，吳鱸佐秦餐。", "大句牽勉酬，韵高語難安。"]'),
('c47e621a-603d-4c12-b276-ecb52a778bf0','謝崔象之示詩稿','黄庶','宋','宋诗','song-poetry','','[]','古樂治情性，故使風俗完。',264,'全唐诗/poet.song.26000.json','["古樂治情性，故使風俗完。", "鄭衛入人耳，雅正聲日殫。", "教化走薄惡，靡靡如轉丸。", "全音不可見，來往寂寞間。", "我疑至和意，獨落詩人肝。", "或以鳴道德，或以傷憂患。", "存者三百篇，興寄青與丹。", "至今如清風，留在喬木端。", "敦厚久衰落，坐見王澤乾。", "後世其得者，或謁道之門。", "失者抱大羹，競下鹹與酸。", "最晚李杜出，遂將風雅壇。", "內以康心脾，睥睨萬物根。", "予早酷愛慕，强把屈瓠鑽。", "當食對藜藿，誦之若熊蹯。", "崔子我同好，韵宇嗟璞渾。", "其詩長於適，意趣猶捭豚。", "巨軸逾百篇，抵我輕璵璠。", "得之忘睡眠，夜拭瞳膜昏。", "若遊金貂市，時見太古冠。", "淡泊路久茀，共約鋤榛菅。", "當結明月期，與君酌醇源。"]'),
('78fcdb76-db21-42e9-9a92-3598e10799ff','次韵和真長幕中偶書','黄庶','宋','宋诗','song-poetry','','[]','人情歲時登，鄉縣自無訟。',120,'全唐诗/poet.song.26000.json','["人情歲時登，鄉縣自無訟。", "公庭破莓苔，日苦黥徒送。", "幕府隠詩書，黄堂卧梁棟。", "幾字署紙尾，朝夕寧倥傯。", "塵土安止足，性情適吟諷。", "收心觀無始，靜卧憫群動。", "勞生懵出處，欲把清風鞚。", "青山自無價，夜夜有歸夢。", "但知陶潛卑，寧識賈生慟。", "夜雨誦君詩，一杯齊費用。"]'),
('d5ddc2eb-6f55-49f7-a003-69a1d223ac38','次韵和酬真長對雪之作','黄庶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖主人久未至，雪雲我爲開吟天。',288,'全唐诗/poet.song.26000.json','["西湖主人久未至，雪雲我爲開吟天。", "偷閑把酒羅膾鯉，魚凍難趁煩鳴舷。", "旋求野果向山市，僮僕覓路占平川。", "恍然白玉爲飲國，寒威醉思相翩翾。", "顧盼萬景來筆端，濡染欲寫毫已堅。", "初疑萬國會盟散，斷珪破璧盈枯田。", "禽巢一一鶴上下，冰殿掃灑迎群仙。", "又疑水官愛雪柳，故把衆庶爲飛綿。", "我思江淮有流民，往往匍匐僵道邊。", "朱門意氣與寒競，上馬酒面紅欲燃。", "天將景與富貴買，不知一費幾萬錢。", "詩家把筆爭造化，對此自恨才慳偏。", "徘徊嗅嚼醉還醒，來往但見鞋履穿。", "歸來庭樹玉花落，稚子狂走皆華顛。", "擁爐搔首有餘意，喜與麰麥爲豐年。", "夜闌更欲和月看，坐久諷誦瓊瑶篇。", "調高白雪古難和，思短强被詩魔牽。", "卒章我欲涕淚下，連茹固已知君賢。"]'),
('622837a6-0112-4b36-be9d-ebd4deb22b9f','喜雨上文相公','黄庶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','火神侵官弄胸臆，青帝欲滿勾芒慵。',224,'全唐诗/poet.song.26000.json','["火神侵官弄胸臆，青帝欲滿勾芒慵。", "驕陽暴苗不得秀，風俗相顧無顔容。", "我公裨補造化手，乞許暫息平奸驄。", "西湖景好天子借，訟簡朝夕臨青銅。", "忽窺庭民有旱色，輟寢廢飯忘巾筇。", "訪求雩法得古本，若可舒卷陰陽功。", "除壇規土鍤未動，精意已與神耳通。", "雷官風師不敢息，先時奔走鞭群龍。", "稚苗霶霈飽哺乳，一夕換得千里豐。", "老幼歡呼相公雨，喜氣醖釀爲和風。", "一封朝緘萬室意，慰減焦思寬九重。", "選牲祀龍益傾倒，大宅不滿猶忡忡。", "樸愚幕吏解公意，期雨霑足環海中。", "不以一郡喜爲喜，喜憂天下公之公。"]'),
('0024db83-ba3b-457f-aaba-9389f2ccb466','次韵和象之夏夜作','黄庶','宋','宋诗','song-poetry','','[]','大暑暴虐如惡酒，意思頹困不可醒。',176,'全唐诗/poet.song.26000.json','["大暑暴虐如惡酒，意思頹困不可醒。", "日官我疑借炎熱，昊輪出火星熒熒。", "霈然一雨翳晚景，庭樹洗出蜩螗聲。", "微雲掃灑供夜坐，造化似解通人情。", "清風明月作三友，趣君可買輕連城。", "恍然身在沖泊域，目空萬狀遺骸形。", "此特象之入詩國，句句鍛鍊爐鎚精。", "窮微心到混沌側，高處意氣捫日星。", "詰朝携詩示我讀，饑腸饞口逢珍烹。", "義幽語險索究解，如手捕虎不敢停。", "歸來牽勉拾餘思，魚目愧傍蟾蜍明。"]'),
('51a62cd5-4db3-4d50-a668-8301387df04a','和象之雨後望少室山白雲','黄庶','宋','宋诗','song-poetry','','[]','塵埃奔趨插手板，十年已賣山中閑。',192,'全唐诗/poet.song.26000.json','["塵埃奔趨插手板，十年已賣山中閑。", "相逢少室若交舊，白雲與我開容顔。", "風驅烟氣去敝幕，天覆碧玉無瑕瘢。", "我疑岳神宴天上，掃灑伊洛爲圖看。", "又疑山鬼有寒稅，纊絮萬疊輸陰官。", "色如可餐無厭飽，頗梨爲甑炊琅玕。", "去去還觀不能已，一里迴首百據鞍。", "長安許生以畫名，閑暇拂拭新素紈。", "能求山高水深趣，常恐造化在筆端。", "每觀雲泉得意處，擬寫男女家其間。", "今對異景慚首鼠，愚若犬彘編槽欄。", "君詩託我有深意，明月一杯心往還。"]'),
('636e81d9-ae50-4037-872e-1e186f812ac8','席上賦別南宮希元','黄庶','宋','宋诗','song-poetry','','[]','十年瞇車塵，思歸入夢寐。',120,'全唐诗/poet.song.26000.json','["十年瞇車塵，思歸入夢寐。", "晨興見家山，兩目如去翳。", "故人又過我，相對有餘意。", "當樽話舊游，强笑復吁欷。", "君名在鄉書，捧檄不肯愧。", "高堂去白髪，有淚落鞭轡。", "里人獻吉夢，四壁衆所義。", "我喜先子言，在耳若龜筮。", "人生老聚散，酒薄滿莫避。", "相見意最長，强飲不能醉。"]'),
('ef85c27d-967e-461f-a2c5-3c5a9fa8a4c2','次韵和劉卿材見寄之什','黄庶','宋','宋诗','song-poetry','','[]','風波一相失，倒指歲月耗。',276,'全唐诗/poet.song.26000.json','["風波一相失，倒指歲月耗。", "交情見千里，文字每教告。", "胸中飽耘鋤，勉我穫以道。", "踟躕竹帛間，相期古人到。", "十年走塵土，心不勇於躁。", "迺知鎸磨益，不必硯席好。", "君屈百里官，卓趨而魯蹈。", "不使鞭朴教，人情自傾倒。", "訟稀禾黍登，醺若飲醇醪。", "使者席未暖，姓名達珪瑁。", "麒麟踴躍起，志遠無近報。", "糞土齪齪者，錙銖較稱號。", "青冥脚可插，泥途迹將掃。", "寧知西山民，歸車恐君膏。", "我行省版輿，假途期問勞。", "理聲如壁鄰，嘆息不可造。", "遥知詩書宰，優游漆園傲。", "極目西飛雲，徒使瞳子眊。", "敢期枉佳作，綢繆肺襟奧。", "大句驅老意，木古風雨暴。", "驚味無厭已，敗者豆籩犒。", "我輒牽勉和，徒手大阿冒。", "酌酒持君詩，吟哦舌根燥。"]'),
('65e81aa5-bf95-4242-87d9-6ab83028452d','和西湖雪中泛舟之作','黄庶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冬旱種不入，潁人無顔色。',144,'全唐诗/poet.song.26000.json','["冬旱種不入，潁人無顔色。", "上輟霖雨姿，福此千里窄。", "公來視民憂，身若抱病癖。", "霖雨變飛雪，萬室如藥石。", "幕府環鄒枚，共喜妖沴釋。", "欲有瓊樹春，選地得勝僻。", "刺舟敲湖冰，坐泛白玉國。", "持酒與寒競，醉倒無顧惜。", "餘霙入杯斝，似解勸飲客。", "而我坐席末，斗筲寬一石。", "景值風雅匠，萬狀困刀尺。", "鳴鳳相上下，獨愧如螻蟈。"]'),
('c70481be-2fab-4cc6-920e-6ed5ab917b82','送同年張明遠之興州掾','黄庶','宋','宋诗','song-poetry','','[]','赤髭苦顔貌，我怪意氣揚。',96,'全唐诗/poet.song.26000.json','["赤髭苦顔貌，我怪意氣揚。", "人曰黜文登，茲事可降霜。", "歸來卧詩書，藜藿甘肉粱。", "迺知吾同升，喜此剛肺腸。", "甘脆迫朝夕，拂衣莫安遑。", "興山在何處，蜀道難且長。", "妻孥客蓬蓽，板輿獨彷徨。", "朱門腐鼎俎，天理何茫茫。"]'),
('cc782dd5-9d74-4097-adbf-fdfa9f4ba7f0','皇祐五年三月乙巳齊大風海水暴上壽光千乘兩縣民數百家被其災而死者幾半丞相平陽公以同年李君子儀往賑之以詩見寄因而和酬','黄庶','宋','宋诗','song-poetry','','[]','鹽民沒利家海隅，奔走末業田園蕪。',144,'全唐诗/poet.song.26000.json','["鹽民沒利家海隅，奔走末業田園蕪。", "天意似遣陽侯驅，卷水沃殺煎海爐。", "怒濤百尺不及逋，老幼十五其爲魚。", "耕夫蠶婦來躊躇，百金不易箔與鋤。", "我公偃息哀其愚，埋掩尸骼賙惸孤。", "吾黨子儀馳赤駒，口賫公惠人人噓。", "日走百里嫌昳晡，不飲不食顔色癯。", "去時萬樹如束枯，回首綠暗紅紫疏。", "寄詩百言舉其粗，我愧安飽心如苴。"]'),
('acf2f842-41ee-4fa7-9b1a-011ab0660a26','元伯示清水泊之什因和酬','黄庶','宋','宋诗','song-poetry','','[]','十年不踏故溪上，有時夢去千里遊。',128,'全唐诗/poet.song.26000.json','["十年不踏故溪上，有時夢去千里遊。", "每思魚行鑒中見，青衫手板如仇讎。", "秋風鱸肥美無價，莫怪張翰不可留。", "前日誦君清水吟，胸中突起百尺愁。", "兒牽女嬰走塵土，百年一半如棄投。", "清風明月無界畔，白首願作山中侯。", "君詩寫出漁者意，老景一片在目眸。", "清泉釣舟未入手，聊可觀誦忘吾憂。"]'),
('03d08872-5a67-40c6-b47b-c3d008481145','次韵和酬隠直憶花見寄之作','黄庶','宋','宋诗','song-poetry','','[]','春工不揀勢厚薄，染成庭內花梢紅。',160,'全唐诗/poet.song.26000.json','["春工不揀勢厚薄，染成庭內花梢紅。", "反拘簿書似機械，不得醉倒眠綠叢。", "君時馬首正南走，假有樽酒何由同。", "馨香蜂蝶似相讓，顔色開落輸東風。", "公餘徘徊獨遶樹，空有嘆恨不可窮。", "君雖不見紅紫落，亦有惆悵環胸中。", "作詩寄我憶花意，句老與古爭彊雄。", "其間摸寫景如畫，爛熳一片春顔容。", "乃知詩家有刀尺，裁翦自奪陰陽功。", "誦詩酌酒無厭已，韵險强續慚非工。"]'),
('6f68b81b-9677-4dc4-8b00-61f59255a526','送劉孟卿遊天台雁蕩二山','黄庶','宋','宋诗','song-poetry','','[]','治源先生高七十，山水病僻不可瘳。',166,'全唐诗/poet.song.26000.json','["治源先生高七十，山水病僻不可瘳。", "竈無炊烟不顧計，窮幽極怪如仇讎。", "有時清風明月對好景，霹靂拔却大樹不迴頭。", "四方泉石朝入耳，杖屨百里夕已投。", "大笑箕山不敢出，走避軒冕豈自由。", "天台雁蕩潑上心，暑焦毛髪不肯留。", "縈紆長淮下平席，倒指計日觀怒濤。", "君詩功刻造化骨，吳越氣象當先愁。", "古今吟力未到處，好句願備幽人收。", "此行詩是圖畫畫山筆，歸日借我目一遊。"]'),
('cd17c6cf-153e-4662-bc01-fc908ec6d9e3','次韵和元伯南樓避暑遇雨之作','黄庶','宋','宋诗','song-poetry','','[]','城頭歸烏喘搨翼，夕陽欄干手可炙。',64,'全唐诗/poet.song.26000.json','["城頭歸烏喘搨翼，夕陽欄干手可炙。", "長虹如篆報雨來，雲脚插下千里赤。", "南山端正太古屏，飛廉掃雲爲撥墨。", "安得老筆描寫住，白頭許生死堪憶。"]'),
('2eadbb5f-edae-49f2-b92f-594b2a678043','次韵和子儀聞蟬','黄庶','宋','宋诗','song-poetry','','[]','落日挂樹間，長我庭下陰。',84,'全唐诗/poet.song.26000.json','["落日挂樹間，長我庭下陰。", "園林動秋意，高蟬忽微吟。", "清風轉餘聲，杳若下遠岑。", "微物感時節，鏗鍧吐商金。", "古樂久破碎，茲蟲抱全音。", "荒忽尚偃蹇，激起壯士心。", "願爲秋蟬操，被之朱絲琴。"]'),
('3e997e72-57c3-4b65-8d72-01fdc26c5960','和子儀巡捕蝗','黄庶','宋','宋诗','song-poetry','','[]','天子輟霖雨，茲來澤東民。',120,'全唐诗/poet.song.26000.json','["天子輟霖雨，茲來澤東民。", "威聲先公至，暴攘客四鄰。", "下車坐無事，懲勸裨秋春。", "物價以日減，囷倉飽新陳。", "俗愚其何知，蝗來遏公仁。", "所至不爲災，群飛亂烟雲。", "公慮種吾土，且爲沴氣根。", "計丁立捕法，官行勞其勤。", "老幼千里眉，朝蹙夕已伸。", "我知公之德，由此碑齊人。"]'),
('4c468ad6-c086-40ec-8875-6a9585b040ea','求郭侍禁水墨樹石','黄庶','宋','宋诗','song-poetry','','[]','塵埃典却林泉閑，家夢夜夜歸雲端。',32,'全唐诗/poet.song.26000.json','["塵埃典却林泉閑，家夢夜夜歸雲端。", "知君弄筆欺造化，乞我幾株松石看。"]'),
('a890665c-c859-4138-a7f2-6728cc9eb29f','送元伯西歸','黄庶','宋','宋诗','song-poetry','','[]','飲者爲量無大小，要於醉焉而已矣。',192,'全唐诗/poet.song.26000.json','["飲者爲量無大小，要於醉焉而已矣。", "乃知一飲一石徒，醉鄉欲到無幾爾。", "我幸俸薄飲不多，酩酊造次有餘味。", "有時酒伯投客轄，斗筲往往衆所鄙。", "近得元伯東海濱，飲少好吟性相似。", "山青月白得意時，相對觴詠不能已。", "直到千古醉者心，名利莫可污其埃。", "乘興弄筆窺造化，混沌竅鑿可倒指。", "須臾椽杵成巨軸，更唱迭和若宮徵。", "今公官滿捨我去，獨有姓名碑百里。", "踟躕預恐春風來，青草坐見飲地起。", "詩須數寄續百篇，無使塵埃昏紙尾。"]'),
('1ec6d9fc-bbbd-4c73-9ef6-8ed55a624b07','讀君謨黼扆箴','黄庶','宋','宋诗','song-poetry','','[]','常讀賈誼書，愛其極理亂。',144,'全唐诗/poet.song.26000.json','["常讀賈誼書，愛其極理亂。", "言入筆未乾，絳灌舌如鑽。", "文帝不肯爲，萬世爲扼腕。", "漢道竟齷齪，席莫一日暖。", "今讀君謨箴，句句到伊旦。", "窺國見肺肝，欲取以手浣。", "何啻可痛哭，一一中世患。", "設施有隆理，如肉以丳貫。", "可作天下藥，其應疾和緩。", "非獨起國痿，虜頸坐可絆。", "聖賢方相逢，辨別絳與灌。", "萬不使斯言，以爲後世恨。"]'),
('1fc2833e-572e-4c47-b4e8-c9bd94e4285f','過朱亥墓','黄庶','宋','宋诗','song-poetry','','[]','枯林寒草墓丘墟，等是當年一丈夫。',32,'全唐诗/poet.song.26000.json','["枯林寒草墓丘墟，等是當年一丈夫。", "地下若知應笑死，衣冠今日有屠沽。"]'),
('65723ab7-12cd-44f7-8d74-15c3a3789147','冬望','曾鞏','宋','宋诗','song-poetry','','[]','霜餘荆吳倚天山，鐵色萬仞光鋩開。',256,'全唐诗/poet.song.26000.json','["霜餘荆吳倚天山，鐵色萬仞光鋩開。", "麻姑最秀插東極，一峰挺立高嵬嵬。", "我生智出豪俊下，遠迹久此安蒿萊。", "譬如驊騮踏天路，六轡豈議收駑駘。", "巔崖初冬未冰雪，蘚花入履思莫裁。", "長松夾樹蓋十里，蒼顔毅氣不可迴。", "浮雲柳絮誰汝礙，欲往自尼誠愚哉。", "南窗聖賢有遺文，滿簡字字傾琪瑰。", "旁搜遠探得戶牖，入見奧阼何雄魁。", "日令我意失枯槁，水之灌養源源來。", "千年大說沒荒冗，義路寸土誰能培。", "嗟予計真不自料，欲挽白日之西頹。", "嘗聞古者禹稱智，過門不暇慈其孩。", "况今尪人冒壯任，力蹶豈更餘纖埃。", "龍潭瀑布入胸臆，嘆息但謝宗與雷。", "著書豈即遽有補，天下自古無能才。"]'),
('bcbfb971-ba2d-49f8-ad24-4d77a76891ba','一鶚','曾鞏','宋','宋诗','song-poetry','','[]','北風萬里開蓬蒿，山水洶洶鳴波濤。',160,'全唐诗/poet.song.26000.json','["北風萬里開蓬蒿，山水洶洶鳴波濤。", "嘗聞一鶚今始見，眼駛骨緊精神豪。", "天昏雪密飛轉疾，暮略東海朝臨洮。", "社中神狐倏閃內，腦尾分磔垂弓櫜。", "巧兔獰鷄失草木，勇鷙一下崩其毛。", "窟穴呦呦哭九子，帳前活送雙青猱。", "啁啾燕雀誰爾數，駭散亦自亡其曹。", "勢疑空山竭九澤，殺氣已應太白高。", "歸來礧嵬載俎豆，快飲百甕行春醪。", "酒酣始聞壯士嘆，丈夫試用何時遭。"]'),
('1daacd4d-d1a4-4159-9d17-1a7f13fe4c1f','宿尊勝院','曾鞏','宋','宋诗','song-poetry','','[]','朝寒陟山砠，宵雨集僧堂。',96,'全唐诗/poet.song.26000.json','["朝寒陟山砠，宵雨集僧堂。", "蔽衣蓋苦短，客卧夢不長。", "鳴風木間起，枯槁吹欲僵。", "向來雪雲端，葉下百仞隍。", "起攀蒼崖望，正受萬慮戕。", "歲運忽當爾，我顔安得芳。", "傳聞羨門仙，飛身憩蒼蒼。", "誰能乞其靈，相與超八方。"]'),
('1a9d8089-5cd7-4a87-aafd-1207845d219c','苦雨','曾鞏','宋','宋诗','song-poetry','','[]','霧圍南山鬰冥冥，狹谷荒風驅水聲。',64,'全唐诗/poet.song.26000.json','["霧圍南山鬰冥冥，狹谷荒風驅水聲。", "祇疑日失黄道去，又見雨含滄海生。", "如催病骨夜寒入，似送客心衰思驚。", "揚州青銅不在照，應有白鬚添數莖。"]'),
('de42a9d4-6be5-4942-a00e-beda4363a5f6','里社','曾鞏','宋','宋诗','song-poetry','','[]','郊天社地君所重，翦秸刲匏微得供。',112,'全唐诗/poet.song.26000.json','["郊天社地君所重，翦秸刲匏微得供。", "秦皇漢帝陋古初，桀畤殊壇傾力奉。", "年年屬車九重出，羽衛千人萬人從。", "黄金日搜盡崖窟，飛檣走箠華夷動。", "馬蹄路南村有社，里老邀神迎且送。", "荒林破屋風雨入，野鼠山狐狼藉共。", "何言茅箸古瓦甌，稻飯豚蹄人得用。"]'),
('e4ca5a05-d5f1-4871-b646-f2ad7cd588ca','南源莊','曾鞏','宋','宋诗','song-poetry','','[]','床上不廢看青山，門前便踏南澗路。',296,'全唐诗/poet.song.26000.json','["床上不廢看青山，門前便踏南澗路。", "繞牆頓失車馬喧，岸幘日得滄洲趣。", "嘗嗟秋蓬轉，未有茅屋據。", "對此耳目新，始覺精爽聚。", "滄溟未可泛舟入，雁蕩誰能胝足去。", "醫閭在夷蠻，羅浮苦煙霧。", "子真自愛谷口家，孔丘老亦洙泗住。", "吾能放意遊八極，此興久與前賢附。", "悄然怪我思慮深，已欲摧倒聞猿樹。", "眼前了了破青坂，屈椽小棟隨時具。", "野柔川深春事來，筍鞋瞑戛青雲步。", "秫田試犢耕早風，茗圃分籃摘宵露。", "竹林掃月散絺葛，雪艇搜溪出魴鱮。", "帽塵便可臨水濯，里鬥何妨閉門拒。", "介推母厭俗，久思顛崖住不顧。", "梁鴻妻亦高，能快穿衣與藜茹。", "成家儻已嫁諸妹，有立不憂吾弟孺。", "攘攘天地間，萬類殊好惡。", "歡合無一非，睽窮有百牾。", "吾獨安能逐毛髪，飲泉食力從所慕。"]'),
('0103ed58-fbf5-436c-b28e-375cd4016e58','論交','曾鞏','宋','宋诗','song-poetry','','[]','德操龐公林下時，入門豈復知客主。',64,'全唐诗/poet.song.26000.json','["德操龐公林下時，入門豈復知客主。", "夷吾鮑叔貧賤間，分財亦不辭多取。", "相傾頓使形迹空，素定已各肝膽許。", "世間未信亦論交，得失秋毫有乖忤。"]'),
('11741dce-6828-4ce5-8641-d4fc8380494f','南軒','曾鞏','宋','宋诗','song-poetry','','[]','木端青崖軒，慘淡寒日暮。',72,'全唐诗/poet.song.26000.json','["木端青崖軒，慘淡寒日暮。", "鳴鳩已安巢，飛鵲尚求樹。", "物情限與奪，茲理奚以據。", "諒知巧者勞，豈得違所賦。", "久無胸中憂，頗識書上趣。", "聖賢雖山丘，相望心或庶。"]'),
('4be8cde1-3f62-4943-9884-e5bf7fd90a10','兵間','曾鞏','宋','宋诗','song-poetry','','[]','大義缺絕久未圖，小人輕險何不至。',64,'全唐诗/poet.song.26000.json','["大義缺絕久未圖，小人輕險何不至。", "世上固自有百爲，兵間乃獨求一試。", "趙括敢將亦已危，李平請守那復議。", "吁嗟忍易萬人生，冀幸將徼一身利。"]'),
('279396a2-b448-4c44-af7e-35c1253838f2','種園','曾鞏','宋','宋诗','song-poetry','','[]','於陵爲人灌園蔬，我今園地不自種。',64,'全唐诗/poet.song.26000.json','["於陵爲人灌園蔬，我今園地不自種。", "惰慵苟恃鄉井助，緩急孰與朋友共。", "支離有疾上雖恕，陳平不事家焉用。", "著書儻得一言利，長者或許酬內訟。"]'),
('d1d54f3a-d941-45a3-a7ef-2561e931fe6f','嘆嗟','曾鞏','宋','宋诗','song-poetry','','[]','夜嘆不爲絺綌單，晝嗟不爲薇蕨少。',64,'全唐诗/poet.song.26000.json','["夜嘆不爲絺綌單，晝嗟不爲薇蕨少。", "天弓不肯射胡星，欃槍久已躔朱鳥。", "徐揚復憂羽蟲孽，襄漢正病昭回杳。", "力能懷畏未足憂，憂在北極群陰繞。"]'),
('b8642668-ba23-4418-b67b-58195dca0f9b','寄孫之翰','曾鞏','宋','宋诗','song-poetry','','[]','孫侯腹載天下書，崔嵬豈啻重百車。',240,'全唐诗/poet.song.26000.json','["孫侯腹載天下書，崔嵬豈啻重百車。", "伏羲以來可悉數，孰若自作何有餘。", "更能議論恣傾倒，萬里一瀉崑崙渠。", "誰爲胸中斡太極，元氣浩浩隨卷舒。", "昔來諫官對天子，何穢不欲親芟鋤。", "不容乃獨見磊落，出走並海飄長裾。", "孫侯風節何所似，雪洗八荒看太虛。", "親如國忠眼不顧，舊若張禹手所除。", "歸來已絕褒貶筆，進用祇調敖倉儲。", "合持詩書白虎論，更護日月金華居。", "萬世根深固社稷，百年舊叟休田閭。", "素識孤生愛茅屋，久將老母求山砠。", "秋歸願事九江耯，夜出未倦安豐漁。", "孔明苟欲性命遂，孟子豈病王公疏。", "塵埃未得見此樂，太息一付西江魚。"]'),
('d88772ab-c728-460c-b625-cc1b5777e824','豪傑','曾鞏','宋','宋诗','song-poetry','','[]','老哺薇蕨西山翁，樂傾瓢水陋巷士。',64,'全唐诗/poet.song.26000.json','["老哺薇蕨西山翁，樂傾瓢水陋巷士。", "不顧無復問周公，可歸乃獨知孔子。", "自期動即重丘山，所去何啻輕糠秕。", "取合悠悠富貴兒，豈知豪傑心之耻。"]'),
('fac86caf-4ee5-4f6b-8204-18df61e9d9c8','侯荆','曾鞏','宋','宋诗','song-poetry','','[]','侯嬴夷門白髪翁，荆軻易水奇節士。',64,'全唐诗/poet.song.26000.json','["侯嬴夷門白髪翁，荆軻易水奇節士。", "偶邀禮數車上足，暫飽腥羶館中侈。", "師迴拔劍不顧生，酒酣拂衣亦送死。", "磊落高賢勿笑今，豢養傾人久如此。"]'),
('5e1e98bf-57e8-40e4-94c5-625d64c48ec4','黄金','曾鞏','宋','宋诗','song-poetry','','[]','陳侯坐收百戰楚，呂氏行取萬乘秦。',64,'全唐诗/poet.song.26000.json','["陳侯坐收百戰楚，呂氏行取萬乘秦。", "田生立顧開兩國，陸公微辭交二臣。", "道旁白日忽再出，囊中黄金如有神。", "何須首陽二夫子，不是九鼎輸西鄰。"]'),
('fd0feac3-7943-431d-bdd3-910715a1ddee','揚顔','曾鞏','宋','宋诗','song-poetry','','[]','揚雄纂言準仲尼，顔氏爲身慕虞舜。',64,'全唐诗/poet.song.26000.json','["揚雄纂言準仲尼，顔氏爲身慕虞舜。", "千里常憂及門止，爲山更欲一簣進。", "小人君子在所蹈，烈士貪夫不同徇。", "安得蠢蠢尚自恕，百年過眼猶一瞬。"]'),
('02236991-25d6-4072-8de7-94782dd190a6','橙子','曾鞏','宋','宋诗','song-poetry','','[]','家林香橙有兩樹，根纏鐵鈕凌坡陀。',96,'全唐诗/poet.song.26000.json','["家林香橙有兩樹，根纏鐵鈕凌坡陀。", "鮮明百數見秋實，錯綴衆葉傾霜柯。", "翠羽流蘇出天仗，黄金戲毬相蕩摩。", "入苞豈數橘柚賤，芼鼎始足鹽梅和。", "江湖苦遭俗眼慢，禁籞尚覺凡木多。", "誰能出口獻天子，一致大樹凌滄波。"]'),
('0ab1886e-0a27-4e26-91e4-4f97fcc5d0c1','山檻小飲','曾鞏','宋','宋诗','song-poetry','','[]','變秋長雲豪，灑雨北風壯。',72,'全唐诗/poet.song.26000.json','["變秋長雲豪，灑雨北風壯。", "餘熇尚爭威，積晦頗異狀。", "山回攢楓顛，屋立懸狖上。", "飲檻聚石爲，歌筵注溪當。", "歡言久喧嘩，罷興一怊悵。", "旅人正飄颻，豈得諧放蕩。"]'),
('1f1704db-0e34-473e-b4af-911a9c7ba86b','胡使','曾鞏','宋','宋诗','song-poetry','','[]','南粟鱗鱗多送北，北兵林林長備胡。',96,'全唐诗/poet.song.26000.json','["南粟鱗鱗多送北，北兵林林長備胡。", "胡使一來大梁下，塞頭彎弓士如無。", "折衝素恃將與相，大策合副艱難須。", "還來里閭索窮下，斗食尺衣皆北輸。", "中原相觀嘆失色，胡騎日肥妖氣粗。", "九州四海盡帝有，何不用胡藩北隅。"]'),
('b518bf8b-2e64-4aa7-9e4a-79958c02ed5d','上翁嶺','曾鞏','宋','宋诗','song-poetry','','[]','放車秋厓望，所得過舊聞。',96,'全唐诗/poet.song.26000.json','["放車秋厓望，所得過舊聞。", "初疑古軸畫，山水秋毫分。", "時見厓下雨，多從衣上雲。", "濯足行尚側，心憂踏天文。", "八荒正摇落，獨餘草木薰。", "但覺耳目勝，未知筋力勤。", "顛毛已種種，世患方紛紛。", "何當嘯吟此，日與樵蘇群。"]'),
('e26d48a6-84f2-4cee-969b-5f3b4b5b77ce','雜詩四首  其一','曾鞏','宋','宋诗','song-poetry','','[]','張陳貧時交，干戈忽相逐。',48,'全唐诗/poet.song.26000.json','["張陳貧時交，干戈忽相逐。", "范蔡憎嫌人，卒自歸鼎軸。", "害奪怨爲欣，利驅愛成戮。", "世間不可料，人事常反覆。"]'),
('139826c3-54de-468e-8116-527a48c686c9','雜詩四首  其二','曾鞏','宋','宋诗','song-poetry','','[]','日磾斷內討，坐享七世榮。',48,'全唐诗/poet.song.26000.json','["日磾斷內討，坐享七世榮。", "霍光徇所愛，兩忘家與名。", "卓闊俱抗志，纖微獨紆情。", "得失萬世視，長令壯夫驚。"]'),
('f27e305c-2580-4662-add2-ea615308d706','雜詩四首  其三','曾鞏','宋','宋诗','song-poetry','','[]','皇皇謁荆人，伈伈遵陽虎。',48,'全唐诗/poet.song.26000.json','["皇皇謁荆人，伈伈遵陽虎。", "及覺一禮亡，翩然遂違魯。", "全身有遜接，直道無苟處。", "故稱聖如龍，屈伸茲可睹。"]'),
('ca197bea-0346-4655-bbee-d2d384dc7e08','雜詩四首  其四','曾鞏','宋','宋诗','song-poetry','','[]','揮袂謝幽側，騰身集崔嵬。',48,'全唐诗/poet.song.26000.json','["揮袂謝幽側，騰身集崔嵬。", "心胎太極氣，手揚斗間魁。", "荒荆忽成桂，蟄鱗冬有雷。", "君看九州寶，自入朱門來。"]'),
('4dd05201-9c33-4015-84b0-965cf008c1d1','欲求天下友','曾鞏','宋','宋诗','song-poetry','','[]','欲求天下友，試爲滄海行。',72,'全唐诗/poet.song.26000.json','["欲求天下友，試爲滄海行。", "風來冥冥內，擺觸怪浪生。", "突兀萬里怒，勢疑九州傾。", "鯨鵬不自保，況此一舟輕。", "我徒幸來即，可留石根耕。", "日將書上客，共須天地清。"]'),
('d550c9fa-16ba-4113-93da-b1e723503251','冬暮感懷','曾鞏','宋','宋诗','song-poetry','','[]','荒山未有雪，野水不見冰。',180,'全唐诗/poet.song.26000.json','["荒山未有雪，野水不見冰。", "一臘今已半，浮陽壯猶矜。", "奈至一歲除，未有嚴氣升。", "坐思崆峒間，負雪山千層。", "雖受栗冽僵，愈此穢濁蒸。", "感激崑崙祇，一氣吹丘陵。", "炎埃滅無遺，古色萬里興。", "我病一洗濯，懷抱失所憎。", "因思大羽獵，屬車上崚嶒。", "六軍騎皆駿，爭先雪中登。", "天時傾人意，踴躍士氣增。", "大義雖不殺，四方懾兵稜。", "今此效安在，東南塞猶乘。", "將帥色凋槁，蚍蜉勢趫騰。", "慘錯天運內，止戈信誰能。"]'),
('d222a83b-c296-420a-87b6-e38001e97822','寄舍弟','曾鞏','宋','宋诗','song-poetry','','[]','新霖洗窮臘，東南始知寒。',144,'全唐诗/poet.song.26000.json','["新霖洗窮臘，東南始知寒。", "驚我千里意，覺汝征途難。", "空江挂風席，扁舟與誰安。", "羈旅費亦久，橐衣豈無單。", "念汝西北去，壯心始桓桓。", "竟逢有司惑，斥走懷琅玕。", "士固有大意，秋毫豈能干。", "所憂道里困，久無一樽歡。", "我意生惻惻，爲之却朝餐。", "人生飄零內，何處懷抱寬。", "已期採芝樂，握手青霞端。", "無令及門喜，淹留雪霜殘。"]'),
('94b255e8-50e1-4402-98fa-25415a5058a9','至荷湖二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','鐵色對我馬，林林路南山。',72,'全唐诗/poet.song.26000.json','["鐵色對我馬，林林路南山。", "草根已變綠，冰雪尚滿顔。", "解鑣蒼烟脚，我棲就柴關。", "乖時遭飄躓，豈免生事艱。", "夙意待周孔，此士豈可還。", "濁醪且斟酌，收心一瓶間。"]'),
('61871015-e1fa-4c91-b6ce-202254f4807d','至荷湖二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','悲風我眼澀，酸狖我耳愁。',72,'全唐诗/poet.song.26000.json','["悲風我眼澀，酸狖我耳愁。", "我顛水沒馬，我起雪滿裘。", "百里不逢人，豈有烟火投。", "却倚青壁望，白霧滿九州。", "蒼蒼運乃爾，何地放我憂。", "夜卧夢成魘，猶疑拔山湫。"]'),
('1236118c-a030-4684-a1f9-a651fbdf9775','送徐竑著作知康州','曾鞏','宋','宋诗','song-poetry','','[]','溪蠻昔負命，殺氣凌南州。',192,'全唐诗/poet.song.26000.json','["溪蠻昔負命，殺氣凌南州。", "城郭漲烟火，堂皇嘯蜉蝣。", "被髪盡冠巾，吾人反縲囚。", "行剽至杪忽，歸載越山丘。", "驅攘事雖定，收合信瘡疣。", "不有異澤霑，何令餘患瘳。", "寒風在林鳴，君馬不能留。", "初佩太守章，慨然任人憂。", "問俗灰燼餘，咄唶令心謀。", "士材爲世用，因難乃知尤。", "煩苛一蕩滌，幽遠遍懷柔。", "四封鳴鷄犬，五穀被原疇。", "里閭多娛宴，歌鼓震溟陬。", "明義每所希，古人不難侔。", "日月有常運，志士無安輈。", "山川自茲始，努力千里遊。"]'),
('5a182f7a-14ee-4fd7-834e-4181e95fd628','咏雪','曾鞏','宋','宋诗','song-poetry','','[]','北風蕭蕭鳴且歇，短日悠悠生復滅。',224,'全唐诗/poet.song.26000.json','["北風蕭蕭鳴且歇，短日悠悠生復滅。", "朝含滄海滿天雲，暮斷行人千里雪。", "初通壑谷氣先冷，漸蔽郊原路疑絕。", "併包華夷德豈薄，改造乾坤事尤譎。", "驅除已與塵滓隔，濯溉終令枯槁悅。", "相持始信竹柏勁，易敗可嗟萑葦折。", "垂條巧綴如自愛，眢井隨形呀且缺。", "飛檐䡾䡾駕長浪，巨壁林林倚精鐵。", "弊衣或有骭猶凍，荒宴誰能耳偏熱。", "壯夫撫劍生銳氣，志士扃門養高節。", "已開襟胸絕煩憒，更足溝塍慰空竭。", "雖無酒醴發嘲笑，亦有詩謠恣搜抉。", "新陽彷彿送鑱鑿，舊徑參差分曲折。", "留當屐齒印崖石，徙倚長松看寥泬。"]'),
('48903133-c53f-4774-b40c-0458c01c44e9','寫懷二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','群生各有趣，營慮自纏結。',96,'全唐诗/poet.song.26000.json','["群生各有趣，營慮自纏結。", "名網智已羅，利械愚所紲。", "古今遞主客，真贋兩興滅。", "洗然大人意，杳與能者別。", "不必條蔓榮，中自老根節。", "曾非故饒培，獨得較霜雪。", "蛟龍無安舟，虎兕有危轍。", "將能此人追，得匪合明哲。"]'),
('34765c4b-8d9d-4697-964c-fd167b093d8e','寫懷二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','荒城絕所之，歲暮浩多思。',108,'全唐诗/poet.song.26000.json','["荒城絕所之，歲暮浩多思。", "病眼對湖山，孤吟寄天地。", "用心長者間，已與兒女異。", "况排千年非，獨抱六經意。", "終非常情度，豈補當世治。", "幽懷但自信，盛事皆空議。", "氣昏繁霜多，節老寒日駛。", "局促去朋友，咄唶牽夢寐。", "將論道精粗，豈必在文字。"]'),
('6df49a67-738e-4f8e-beb6-e06f8a953d5c','茅亭閑坐','曾鞏','宋','宋诗','song-poetry','','[]','荆門常晝掩，不必雲山深。',144,'全唐诗/poet.song.26000.json','["荆門常晝掩，不必雲山深。", "豈敢尚孤絕，自能收寸心。", "草萌被遠徑，鳥語變喬林。", "散帙味新趣，鳴絃嘆餘音。", "脫粟幸可飽，一瓢方獨斟。", "顔從緬雖卓，非此誰爲尋。", "盛服纏紫艾，重印鑄黄金。", "信使憂惴息，詎無勤苦侵。", "埃塵緇冠蓋，霜露泫衣衿。", "脅肩已自昔，俯首微獨吟。", "豈惟智所拙，曾是力難任。", "爲樂聊在此，焉知玉山岑。"]'),
('41fe3172-e10c-462f-bd0e-5f9d361a7897','靖安縣幽谷亭','曾鞏','宋','宋诗','song-poetry','','[]','橫江捨輕楫，對面見青山。',252,'全唐诗/poet.song.26000.json','["橫江捨輕楫，對面見青山。", "行盡車馬塵，豁見水石寰。", "地氣方以潔，崖聲落潺潺。", "雖爲千家縣，正在清華間。", "風煙凜人心，世慮自可刪。", "况無訟訴囂，得有觴咏閑。", "常疑此中吏，白首豈思還。", "人情貴公卿，燁燁就玉班。", "光華雖一時，憂悸或滿顔。", "鷄鳴已爭馳，驊騮振鑣鐶。", "豈如此中吏，日高未開關。", "一不謹所守，名聲別妖奸。", "豈如此中吏，一官老無瘝。", "愔愔謀謨消，汩汩氣象孱。", "豈如此中吏，明心懾强頑。", "况云此中居，一亭衆峰環。", "崖聲夢猶聞，谷秀坐可攀。", "倚天巉巖姿，青蒼雲斒斕。", "對之精神恬，可謝世網艱。", "人生慕虛榮，斂收意常慳。", "誠思此憂愉，自應喜榛菅。"]'),
('b0437fcf-ae7e-4add-8551-4257b1e0e277','青雲亭閑望','曾鞏','宋','宋诗','song-poetry','','[]','一登此亭高，敻脫藩廡擁。',192,'全唐诗/poet.song.26000.json','["一登此亭高，敻脫藩廡擁。", "開顔廣軒闢，吹面驚飆動。", "城回石崖抱，山亂寒潮湧。", "谷草晚更芳，沙泉細猶洶。", "崢嶸四封壯，縹緲佳氣捧。", "連天廣衢走，拂日長簷聳。", "區區射聲利，浩浩奔蹄踵。", "趨營衆所便，冒涉吾久恐。", "緬想山水宅，環觀松檜拱。", "屬耳天籟樂，脫身人事冗。", "幽閑味雖薄，放蕩愚所勇。", "窮凶勢猶競，殺伐聲更詾。", "揚揚斂臣貴，燁燁兵官寵。", "諒知草茅微，無補社稷重。", "牧放手幽鞭，耕鋤躬瘦隴。", "尚或此心諧，豈云吾道壅。"]'),
('8e32a0f3-b200-4643-b7ff-97005f8dd17c','寄子進弟','曾鞏','宋','宋诗','song-poetry','','[]','憶子去家日，南風始吹衣。',168,'全唐诗/poet.song.26000.json','["憶子去家日，南風始吹衣。", "今來日未幾，蠅蚊已群飛。", "思子兼晝夜，何啻如渴饑。", "喜聞遠客至，手自排荆扉。", "客送書一紙，翰墨子所揮。", "上言山居惡，夢寐接庭闈。", "次言服畎畝，禾黍膴已肥。", "其餘業文字，頗測幽與微。", "題詩在紙尾，語老意不非。", "我喜何所似，大似客得歸。", "我與子事親，未飽藿與薇。", "常苦去左右，辛勤治鞍鞿。", "子行何時反，我眼日已晞。", "應須畢秋刈，相見慰依依。"]'),
('1a87577a-0df8-4b5e-bdb7-29f919d198f9','喜寒','曾鞏','宋','宋诗','song-poetry','','[]','純陽四時行，無復氣節勁。',240,'全唐诗/poet.song.26000.json','["純陽四時行，無復氣節勁。", "日火相吐吞，乾離力還併。", "玄冥失所安，恇怯擅操柄。", "我行東南野，憒憒若酣醟。", "喜逢青林長，葉蔓可韜映。", "正嗟天之高，玉色萬里凈。", "忽驚西山雲，毫末生一鏡。", "須臾油然合，點滴飛雨迸。", "颼颼漸相扶，霶霈一何盛。", "積陰類潜師，形勢久已偵。", "乘時出幽墟，奮發精爽競。", "亙天逐炎官，顓面修火令。", "威加乾坤從，冽冽氣貌正。", "人無焦煩憂，冰釋天下病。", "豈須雪包林，已壓朱鳥橫。", "南方天精兵，瘴濕災可屏。", "爭難奪刀殳，發巧搜壍阱。", "收功當在今，殺伐順天正。", "况云麰麥祥，已覺閭里慶。", "高歌叩吾轅，上頌天子聖。"]'),
('069f91a0-3b7d-4c5d-826a-323432f9af38','咏史二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','京室天下歸，飛甍無餘地。',48,'全唐诗/poet.song.26000.json','["京室天下歸，飛甍無餘地。", "國士憂社稷，塗人養聲利。", "貴賤競一時，峨冠各鱗次。", "子龍獨幽遠，聘召漠無意。"]'),
('454a1e75-21ba-470a-9872-86f049a97227','咏史二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','子雲無由歸，俯首天祿閣。',48,'全唐诗/poet.song.26000.json','["子雲無由歸，俯首天祿閣。", "君平獨西南，抗顔觀寥廓。", "無猜到沉冥，有故驚寂寞。", "用心豈必殊，拘肆事終各。"]'),
('0fb23a40-c07b-4646-bc65-389bf09e2ae4','江湖','曾鞏','宋','宋诗','song-poetry','','[]','江湖俗畏遠，幽好自相宜。',48,'全唐诗/poet.song.26000.json','["江湖俗畏遠，幽好自相宜。", "淪迹異驚衆，辭囂如避時。", "優遊可以學，薇蕨易爲私。", "胡然棄回櫂，霜雪有驅馳。"]'),
('e4ec62f1-ec7b-4c34-a255-55d787715038','將之浙江延祖子山師柔會別飲散獨宿空亭遂書懷別','曾鞏','宋','宋诗','song-poetry','','[]','蜀客向何處，欲觀浙江潮。',120,'全唐诗/poet.song.26000.json','["蜀客向何處，欲觀浙江潮。", "艤舟吳門柵，况會故人招。", "置酒吳亭上，無人吹紫簫。", "浩觀萬物變，颯爾生凉飆。", "遂恐時節晚，芳蘭從此凋。", "功名竟安在，富貴空寥寥。", "鴻鵠舉千里，鸞鳳翔九霄。", "胡爲蓬蒿下，日夜悲鷦鷯。", "車馬夕已還，行人亦飄颻。", "浩然滄海志，寂寞守空宵。"]'),
('59990990-2ada-4001-ab5b-95d826dc22be','咏雪','曾鞏','宋','宋诗','song-poetry','','[]','嚴嚴層冰塞川澤，洶洶北風鳴木石。',224,'全唐诗/poet.song.26000.json','["嚴嚴層冰塞川澤，洶洶北風鳴木石。", "黄雲半夜滿千里，大雪平明深一尺。", "兩儀混合去纖間，萬類韜藏絕塵迹。", "蛟龍岌起抱巒岡，江海橫奔控阡陌。", "野林縹緲苦難狀，庭樹鮮妍疑可摘。", "開門更覺山市靜，散帙偏宜紙窗白。", "精光蕩射遍巖谷，氣象崢嶸見松柏。", "少年登望就臺觀，壯士衡凌向砂磧。", "饑鼯嗥卧伏牙爪，獵隼飛挐矜羽翮。", "茅簷客聚滿幽缶，桑徑人行沒雙屐。", "高堂暖熱厭羅綺，環堵蕭條尚絺綌。", "何當仰見白日照，坐看先從沙際釋。", "漸涵溝畎兆豐富，洗濯閭閻消瘴疫。", "便乘東北生氣起，自駕疲牛理墝塉。"]'),
('1c798fc1-2b70-40cd-8cbc-5fe2d9452097','答裴煜二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','拙者羞强合，因成杜門居。',96,'全唐诗/poet.song.26000.json','["拙者羞强合，因成杜門居。", "豈知公相尊，一室若有餘。", "愛子富文行，顧爲己不如。", "所以子之黨，頓見我僕車。", "歡誠激孤緒，合若水縱魚。", "新詩八十言，筆端産璠璵。", "屑屑委地蓬，清風爲吹噓。", "相期在規誨，庶以輔頑疏。"]'),
('e91593bb-7c11-482b-b801-1455cc7f87a6','答裴煜二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','寥寥今非古，感激事真妄。',144,'全唐诗/poet.song.26000.json','["寥寥今非古，感激事真妄。", "曾誰省孤心，祇以弭群謗。", "參差勢已甚，决起意猶强。", "親朋爲憂危，議語數鎸蕩。", "久之等聾眊，兀矣坐閭巷。", "長嗟貧累心，更苦病摧壯。", "微誠豈天與，今晨子來貺。", "顧慚小人愚，未出衆夫上。", "狂言屈子吟，浩歌仍子倡。", "相歡匪貌濟，所得實心尚。", "時節雖已晏，梅柳幸欲放。", "過從勿厭倦，相遲非欎盎。"]'),
('ed6fa5c4-b462-45ed-ac7a-a8af88015309','寄王介卿','曾鞏','宋','宋诗','song-poetry','','[]','憶昨走京塵，衡門始相識。',288,'全唐诗/poet.song.26000.json','["憶昨走京塵，衡門始相識。", "疏簾挂秋日，客庖留共食。", "紛紛說古今，洞不置藩域。", "有司甄棟榦，度量棄樗櫟。", "振轡行尚早，分首學堧北。", "初冬憩海昏，夜坐探書策。", "始得讀君文，大匠謝刀尺。", "周孔日已遠，遺經竄牆壁。", "倡佯百怪起，冠裾稔回慝。", "君材信魁崛，議論恣排闢。", "如川流渾渾，東海爲委積。", "如躋極高望，萬物著春色。", "寥寥孟韓后，斯文大難得。", "嗟予見之晚，反覆不能釋。", "胡然藴環堵，不救謀者惑。", "明朝渡江還，念念非可抑。", "如酲冒炎暑，每進意愈塞。", "維時南風薰，木葉晃繁碧。", "頹雲走石瀨，逆坂上文艗。", "欣聞被檄來，窮閻駐鑣軾。", "促榻叩其言，咸池播純繹。", "行身抗淵損，及物窺龍稷。", "綢繆指疵病，攻砭甚針石。", "淺沚有停沙，亦可洗珠璧。"]'),
('93894a55-f4bc-4198-bfed-7bbdf5a9101d','上人','曾鞏','宋','宋诗','song-poetry','','[]','金節橫光馬珂鬧，瑞鶻宮袍腰玉繞。',112,'全唐诗/poet.song.26000.json','["金節橫光馬珂鬧，瑞鶻宮袍腰玉繞。", "烟沙轣轆高軒過，路上千人瞻羽纛。", "瑶魁精彩浮蒼龍，江城四面生春風。", "城中壞屋書籤碧，有客苦吟連旦夕。", "麻衣塵暗抱書泣，歲暮黄粱不供食。", "白日曈曨望龍坂，坐上一言寒可暖。", "西入天關灑霖雨，須惜窮鱗在泥土。"]'),
('7fed3fc2-2fd5-41b7-a56a-9d99664f9371','初夏有感','曾鞏','宋','宋诗','song-poetry','','[]','我從得病卧閭巷，三見夏物爭滋榮。',272,'全唐诗/poet.song.26000.json','["我從得病卧閭巷，三見夏物爭滋榮。", "紅英紫萼逐風盡，高榦密葉還陰成。", "山亭水館處處好，朱碧萬實相駢擎。", "林烏梁燕各生子，翅羽已足爭飛騰。", "雉鷄五色繡新翮，鷕鷕慕匹相隨鳴。", "穴蜂露蝶亦有類，欻往復聚何翾輕。", "箔蠶滿室事方盛，繭綴下上如連星。", "麥芒秧穎錯雜出，高壠大澤填黄青。", "物從草木及蟲鳥，無一不自盈其情。", "嗟我獨病不如彼，胸氣卧立常怦怦。", "筋酸骨楚頭目眩，强食豈得肌膚盈。", "我身今雖落衆後，我志素欲希軻卿。", "十年萬事常坎壈，奔走未足供藜羹。", "愁勤未老鬢先白，多學只自爲身兵。", "自然感疾憊形體，後日雖復應伶俜。", "非同世俗顧顔色，所慕少壯成功名。", "但令命在尚可勉，屑細詎足傷吾平。"]'),
('6f820dcf-5074-4e4b-b82c-01f91683a4db','送人移知賀州','曾鞏','宋','宋诗','song-poetry','','[]','溪石膠船秋瀨微，南山巉空勢峨巍。',160,'全唐诗/poet.song.26000.json','["溪石膠船秋瀨微，南山巉空勢峨巍。", "風露氣嚴花草腓，天色漻漻初雁飛。", "君子往守東南圻，旟旝綵錯如翔翬。", "象茜照地榮笏衣，先後隸從何頎頎。", "初君治縣參德威，吾人涵濡樂以肥。", "念今奪去失所依，出者遮行居者希。", "我思群公坐天圍，心與星斗爭光輝。", "薦賢絀否言無違，迅若發石乘高機。", "何此茂器時所稀，噤無一語爲發揮。", "敢作此什傳王畿，旦暮璽書來敕歸。"]'),
('d3abeaee-e61e-4369-8df1-bc7fd1d0cad6','之南豐道上寄介甫','曾鞏','宋','宋诗','song-poetry','','[]','應逮冒煩暑，驅馳山水間。',210,'全唐诗/poet.song.26000.json','["應逮冒煩暑，驅馳山水間。", "泥泉沃渴肺，沙風吹汗顔。", "疲驂喘沫白，殆僕負肩殷。", "仰嗟旱雲高，俯愛芳陂潺。", "空郵降塵榻，凈館排霞關。", "城隍壯形勢，岡谷來回環。", "紅芰姹相照，翠樹鬰可攀。", "野苗雜青黄，雨露施尚慳。", "巫覡謁群望，簫鼓鳴空山。", "憂農非吾職，望歲竊所嘆。", "憩當午日烈，行瞻月初彎。", "星斗弄光彩，羅絡竈火斑。", "跋履雖云倦，桑梓得暫還。", "林僧授館舍，田客攀鞍鐶。", "吾心本皎皎，彼詬徒{口顔}{口顔}。", "方投定鑑照，即使征馬班。", "相期木蘭楫，蕩漾窮川灣。"]'),
('887ce826-c455-43f8-adda-ab67b1aa277d','謝章伯益惠硯','曾鞏','宋','宋诗','song-poetry','','[]','人生對門東西陌，口耳一間心誰傳。',240,'全唐诗/poet.song.26000.json','["人生對門東西陌，口耳一間心誰傳。", "况乃天地相去遠，一在南海一在燕。", "古今萬世復萬世，彼亦居下此在前。", "是非得失錯且繁，以情相話何由緣。", "造化豈不大且淵，到此縮縮智且慳。", "聖人智出造化先，始獨俯仰模坤乾。", "一人詰曲意百千，以文寫意意乃宣。", "簡書軸載道相聯，馳夷走貊通百蠻。", "羲皇向今谷屢遷，言語應接旦暮間。", "聖人不死術以此，又與其類殊蚑蠕。", "外之君臣內父子，仁義禮樂定筆端。", "硯與筆墨乃舟船，論功次第誰能攀。", "伯益于文敏且顓，字向紙上生戈鋋。", "與硯出入宜不捐，胡乃贄我璧棄泉。", "作詩知硯功小大，報不充賜心焦然。"]'),
('993dbb8c-822b-48a7-b021-6ebbe5ab775b','送劉醫博','曾鞏','宋','宋诗','song-poetry','','[]','小人久病如愁感，每嘆地僻無良醫。',256,'全唐诗/poet.song.26000.json','["小人久病如愁感，每嘆地僻無良醫。", "窮居索寞俗事少，坐對荏苒風光移。", "深冬山城萬木落，陰氣蕩射生寒颸。", "東方吐日光入戶，素壁閃閃含清輝。", "臨汀劉君落落者，六伎絕偉如天資。", "潜心密與造化會，布指敻有精靈隨。", "馬蹄所至病魔屈，我於此時欣得之。", "一來握手與我話，委曲衰王肺與脾。", "囊中珍丸撮星斗，俾我嚼咀心顔怡。", "灑然沉疴一日解，始免未老爲枯骸。", "越人湔腸術已緩，仲景納餠術可卑。", "劉君與我德至大，拱璧巨鼎非酬裨。", "我嗟劉君乃士類，進退婉婉無瑕疵。", "况又新承太守薦，羈鞅日背東門馳。", "禁林侍從務周慎，君挾所有直相宜。", "貴人四難真可患，去去足以爲時規。"]'),
('50e043e7-b73d-4b61-8bee-5df2dc592152','送陳商學士','曾鞏','宋','宋诗','song-poetry','','[]','柳黄半出年將破，溪溜浸苔强萬個。',144,'全唐诗/poet.song.26000.json','["柳黄半出年將破，溪溜浸苔强萬個。", "溪頭蒲葦各萌芽，山梅最繁花已墮。", "物色撩人思易狂，况躋別館情何那。", "城東日晚公將去，纛影未離愁四座。", "公於萬事不雕鎸，心意恢恢無坎坷。", "來從奎壁光鋩下，笑倚樽筵成郡課。", "嗟予齪齪才性下，棄置合守丘樊餓。", "公持姓名動人主，祓飾寧嫌筆端挫。", "從今清夜思江路，夢送公船先北過。"]'),
('fad6944b-ac9b-4262-8948-a702b75ebe14','送錢生','曾鞏','宋','宋诗','song-poetry','','[]','天下學校廢，師生無所依。',72,'全唐诗/poet.song.26000.json','["天下學校廢，師生無所依。", "子來滿橐書，璨璨璧與璣。", "一字未得讀，叩門忽言歸。", "憐子甚有志，事時與子違。", "吾無一畝宮，留子爲發揮。", "去矣善自立，毋使嗣音稀。"]'),
('7088f81d-2a1d-4163-9e6b-1dfc222bbdfa','雪咏','曾鞏','宋','宋诗','song-poetry','','[]','雪花好潔白，不待咏說知。',288,'全唐诗/poet.song.26000.json','["雪花好潔白，不待咏說知。", "區區取相似，今古同一辭。", "薛能比衆作，小去筆墨畦。", "誰能出千載，爲雪立傳碑。", "四座且勿歌，聽我白雪詩。", "天地於降雪，其功大艱難。", "去年暖風日，冬在春已還。", "山屏盡深碧，危溜聲亦潺。", "草萌各已動，梅花開最繁。", "爐火殆可謝，衣絮誰復言。", "推排臘已過，一變天更寒。", "飄風動木石，激射難出關。", "深房擁高燎，領肘曾不溫。", "仰視雲壓疊，垂欲藉屋山。", "元氣不復呵，飛鳥折羽翰。", "誰排河漢流，欲墮莽蒼間。", "道爲黑風遮，凝凍無住著。", "紛紛成片縷，六出非刻削。", "初時漏餘滴，雜雨猶可惡。", "迤邐縱飛灑，態狀不可名。", "或稀若有待，或密似相縈。", "或弱久宛轉，或狂自軒騰。", "群來信汗漫，孤飄亦零丁。", "屋角初漸斑，瓦溝忽皆平。"]'),
('5facf0a9-af74-456a-9c5d-7e7a63e9ebc1','送僧晚容','曾鞏','宋','宋诗','song-poetry','','[]','飛光無停芳歲闌，群陽不行寒氣動。',96,'全唐诗/poet.song.26000.json','["飛光無停芳歲闌，群陽不行寒氣動。", "疏篁有韵窗含雪，重幕無溫筆棲凍。", "蕭條山草葉始枯，綽約江梅蕊先弄。", "無人爲我取酒斟，有客來前乞詩送。", "多情爲客不能已，捲紙連書筆鋒縱。", "七言百字拙且卑，俗眼方憎汝休重。"]'),
('2dcf255b-196a-416c-9038-081fbecd6f00','送叔延判官','曾鞏','宋','宋诗','song-poetry','','[]','北風吹空雪花冷，平鋪雲濤冒峰頂。',144,'全唐诗/poet.song.26000.json','["北風吹空雪花冷，平鋪雲濤冒峰頂。", "江長水闊飛鳥絕，沙樹參差動波影。", "君子從戎碧油下，綠髮青瞳笏袍整。", "大馬高車府中罷，一船沿流背丁丙。", "魴魚勝銀尊酒美，物色當前若圖屏。", "危帆健櫓醉中去，千里奔過猶一頃。", "明年隨春到京國，紅紫燒空折桃杏。", "獻書又謁蓬萊宮，新斸豪曹試鋒穎。", "况遇朝廷方急材，驥騄騤騤足當騁。"]'),
('34fd10ca-4ecd-4d1e-9064-cfe470d2c309','山茶花','曾鞏','宋','宋诗','song-poetry','','[]','山茶花開春未歸，春歸正值花盛時。',128,'全唐诗/poet.song.26000.json','["山茶花開春未歸，春歸正值花盛時。", "蒼然老樹昔誰種，照耀萬朵紅相圍。", "蜂藏鳥伏不得見，東風用力先噓吹。", "追思前者葉蓋地，萬木慘慘攢空枝。", "寒梅數綻少顔色，霰雪滿眼常相迷。", "豈如此花開此日，絳艷獨出凌朝曦。", "爲憐勁意似松柏，欲搴更惜長依依。", "山榴淺薄豈足比，五月霧雨空芳霏。"]'),
('c186c352-b503-49cf-9299-c23f2d39e0c5','丁亥三月十五日','曾鞏','宋','宋诗','song-poetry','','[]','茫茫月色如溪沙，萬里不有纖雲遮。',112,'全唐诗/poet.song.26000.json','["茫茫月色如溪沙，萬里不有纖雲遮。", "今年寒氣爭春來，雪大如掌隨驚雷。", "臨川城中三月雨，城東大丘汩爲渚。", "天地慘慘無開時，常恐蟄死和與羲。", "此時謂月水中沒，溺入蛙腸那復出。", "豈知今夜月光圓，照徹萬物無遺偏。", "人間有人司重輕，安得知汝有時明。"]'),
('25fbc15b-3ccc-4821-a6f3-8015d3f2bd80','舍弟南源刈稻','曾鞏','宋','宋诗','song-poetry','','[]','買田南山下，禾黍忽已秋。',216,'全唐诗/poet.song.26000.json','["買田南山下，禾黍忽已秋。", "糟床待此注，豈止衣食謀。", "窮陰迫霜霰，不可遲揫收。", "吾黨二三子，晨行已寒裘。", "久苦城中囂，至山諒優遊。", "況已除險穢，新堂置岩幽。", "窗軒衆峰出，階墀水淙流。", "良材未成種，草樹亦已稠。", "寒花開照耀，谷鳥樂啾啁。", "心與珍境接，佳興固已遒。", "而況饋朝夕，甘美日可搜。", "黄鷄肥落俎，清酤湛盈甌。", "時鮮鱠冰鯽，餘滋拆丹榴。", "此味何以侑，文辭頗賡酬。", "晝務誡遺滯，夜工督舂揄。", "因觀稼穡勞，始覺奉養優。", "此樂詎非幸，人生復何求。", "送子固自起，往意不可留。"]'),
('ea4aefe3-b0da-4377-964a-ca9c1924f4cd','奉和滁州九咏九首 琅琊泉石篆','曾鞏','宋','宋诗','song-poetry','','[]','陽冰絕藝天下稱，琅琊石篆新有名。',224,'全唐诗/poet.song.26000.json','["陽冰絕藝天下稱，琅琊石篆新有名。", "初留泉涯俗誰顧，一日貴重繇先生。", "古今書法不可數，猶有字本存於經。", "我於八體未曾學，雖得此字寧能評。", "高文老筆又所愛，欲敘仿佛辭非精。", "筆端應驅鬼神聚，筆妙敻與陰陽爭。", "刻雕萬象出冥昧，不見刀斧曾經營。", "奇形挺若聳崖巘，險勢直恐生風霆。", "雨來莽蒼龍蛟起，秋入寥泬星斗明。", "先生七言載其側，爲地自與丘山平。", "先生抱材置荒郡，有若此字存岩扃。", "當還先生坐廊廟，悉引萬事歸繩衡。", "遂收此字入秘府，不使日灼莓苔縈。", "高材重寶不失一，唐舜湯禹寧非朋。"]'),
('a875db93-8a16-40b5-a62f-ef8dcb31e975','奉和滁州九咏九首 遊琅琊山','曾鞏','宋','宋诗','song-poetry','','[]','飛光洗積雪，南山露崔嵬。',144,'全唐诗/poet.song.26000.json','["飛光洗積雪，南山露崔嵬。", "長淮水未綠，深塢花已開。", "遠聞山中泉，隠若冰谷摧。", "初誰愛蒼翠，排空結樓臺。", "䡾䡾架梁棟，輝輝刻瓊瑰。", "先生鸞鳳姿，未免燕雀猜。", "飛鳴失其所，徘徊此山隈。", "萬事於人身，九州一浮埃。", "所要挾道德，不愧丘與回。", "先生逐二子，誰能計垠崖。", "所懷雖未寫，所適在歡咍。", "爲語幕下士，殷勤羞甕醅。"]'),
('929228ee-4d13-43d4-8bdd-7d6730ed076d','奉和滁州九咏九首 歸雲洞','曾鞏','宋','宋诗','song-poetry','','[]','洞遠人言接滄海，洞幽晴始見莓苔。',32,'全唐诗/poet.song.26000.json','["洞遠人言接滄海，洞幽晴始見莓苔。", "天下顒顒望霖雨，豈知雲入此中來。"]'),
('ee0b6ee1-8253-413b-8684-78ad036d6a1e','奉和滁州九咏九首 琅琊溪','曾鞏','宋','宋诗','song-poetry','','[]','野草山花夾亂流，橋邊旌旆影悠悠。',32,'全唐诗/poet.song.26000.json','["野草山花夾亂流，橋邊旌旆影悠悠。", "即應要地無人見，可忍開時不出遊。"]'),
('393c8387-2e4b-4b97-99d6-de8eb7b31a1b','奉和滁州九咏九首 班春亭','曾鞏','宋','宋诗','song-poetry','','[]','山亭嘗自絕浮埃，山路輝光五馬來。',32,'全唐诗/poet.song.26000.json','["山亭嘗自絕浮埃，山路輝光五馬來。", "春滿人間不知主，誰言鑪冶此中開。"]'),
('f4c588f3-3c7f-4ecf-9b54-4ac20b881669','奉和滁州九咏九首 庶子泉','曾鞏','宋','宋诗','song-poetry','','[]','琅琊石泉清照人，裏無泥沙表無塵。',32,'全唐诗/poet.song.26000.json','["琅琊石泉清照人，裏無泥沙表無塵。", "風翻日炙夏潦盡，古練一匹常奫淪。"]'),
('ed3fdf76-d667-413f-a02f-748ce003e738','奉和滁州九咏九首 石屏路','曾鞏','宋','宋诗','song-poetry','','[]','石屏不見刀斧痕，石下初誰得行徑。',32,'全唐诗/poet.song.26000.json','["石屏不見刀斧痕，石下初誰得行徑。", "千騎來時停管弦，月明更覺山中靜。"]'),
('010fac73-55a3-4486-94f7-4233cded0738','奉和滁州九咏九首 慧覺方丈','曾鞏','宋','宋诗','song-poetry','','[]','七言老意蒼松蟠，百金古字青霞鎸。',32,'全唐诗/poet.song.26000.json','["七言老意蒼松蟠，百金古字青霞鎸。", "儒林孟子先生是，墨者夷之後代傳。"]'),
('7f492a36-f673-42d5-a334-d2bafce210ba','奉和滁州九咏九首 幽谷晚飲','曾鞏','宋','宋诗','song-poetry','','[]','先生卓難攀，材真帝王佐。',240,'全唐诗/poet.song.26000.json','["先生卓難攀，材真帝王佐。", "皎皎衆所病，蜿蜿龍方卧。", "卷彼天下惠，赴此一郡課。", "幕府既多暇，山水乃屢過。", "旌旗拂蒙密，車馬經坎坷。", "愛此谷中泉，聲響遠已播。", "槎橫勢逾急，雨點綠新破。", "旁生竹相圍，竦竦碧千箇。", "遥源窅難窺，盤石坦如磋。", "遊鱗戢可數，飛鳥嚶相和。", "援琴薰風後，結宇寒岩左。", "觥筵已得月，金紈尚圍坐。", "心如合逍遥，語不綴招些。", "一時聳傳觀，千載激柔懦。", "甘棠詩之懷，峴首淚嘗墮。", "況此盛德下，襦袴人所荷。", "不假碑刻垂，棟牖敢隳挫。", "當今甲兵後，天地合轗軻。", "先生席上珍，豈忍溝中餓。", "毋徐黑轓召，當馳四方賀。"]'),
('2eebb88e-b04c-4172-b8d5-85a98f80a500','遊麻姑山','曾鞏','宋','宋诗','song-poetry','','[]','軍南古原行數里，忽見峻嶺橫千尋。',384,'全唐诗/poet.song.26000.json','["軍南古原行數里，忽見峻嶺橫千尋。", "誰開一徑破蒼翠，對植松柏何森森。", "危根自迸古崖出，老色不畏莓苔侵。", "修竹整整儼朝士，下蔭石齒明如金。", "遂登半嶺望城郭，但見積靄縈江潯。", "岡陵稍轉露樓閣，沙莽忽盡橫園林。", "秋光已逼花草歇，寒氣况乘岩谷深。", "我馳輕輿豈知倦，倏忽遂覺窮嶔崟。", "龍門誰來此中鑿，玉簡不記何年沉。", "泉聲可聽真衆籟，泉意欲寫無瑶琴。", "斗迴地勢平如削，䆉稏百頃黄差參。", "橫開三門兩出路，却立兩殿當崖陰。", "深廊千步抵岩腹，桀木萬本摩天心。", "碑文磊嵬氣不俗，筆畫縹緲工非今。", "世傳仙人家此地，天風泠泠吹我襟。", "今人豈解不老術，可怪綠髮常盈簪。", "根源分明我能說，一室傾里輸琅琳。", "相高既不擁耒耜，方壯又不持戈鐔。", "我丁轗軻豈暇議，直喜虛曠開煩襟。", "清謠出口若先構，白酒到手無停斟。", "山人執袂與我語，留我饋我山中禽。", "玲瓏當窗急雨灑，窈窕隔溪孤笛吟。", "未昏已移就明燭，病骨夜宿添重衾。", "神醒氣王目無睡，到曉獨愛流泉音。"]'),
('0455596a-bda5-4972-8628-1e8794ffd8b6','桃花源','曾鞏','宋','宋诗','song-poetry','','[]','來時秋不見桃花，空樹寒泉瀉石涯。',32,'全唐诗/poet.song.26000.json','["來時秋不見桃花，空樹寒泉瀉石涯。", "爭得時人見鸞鳳，不教身去憶烟霞。"]'),
('9b4e4e29-52b7-4c11-85d1-5f8366f88e4b','丹霞洞','曾鞏','宋','宋诗','song-poetry','','[]','麻姑石壇起雲霧，常意已極高峰顛。',176,'全唐诗/poet.song.26000.json','["麻姑石壇起雲霧，常意已極高峰顛。", "豈知造化有神處，別聳翠嶺參青天。", "長松桀柏枝嵬砢，中畫一道如流泉。", "林風颼飀滿丘壑，山鳥嘲哳凌飛烟。", "山腰古亭豁可望，下見秋色清無邊。", "忽驚陰崖勢回合，中抱幽谷何平圓。", "初誰鑿險構樓觀，更使遶舍開芝田。", "令人到此毛骨醒，欲構老筆丹青傳。", "羌夷干戈今未解，天地瘡痏誰能痊。", "大厦棟梁置沙莽，肯復顧眄桷與椽。", "吾徒於時直何用，欲住未得心茫然。"]'),
('11dcc801-5e61-4199-a057-6c4db3bf9f55','半山亭','曾鞏','宋','宋诗','song-poetry','','[]','樹杪蒼崖路屈盤，半崖亭榭午猶寒。',32,'全唐诗/poet.song.26000.json','["樹杪蒼崖路屈盤，半崖亭榭午猶寒。", "平時舉眼看山處，到此憑欄直下看。"]'),
('87a2518f-1e68-45f7-b613-fc1e05bd0381','顔碑','曾鞏','宋','宋诗','song-poetry','','[]','碑文老勢信可愛，碑意少缺誰能鎸。',32,'全唐诗/poet.song.26000.json','["碑文老勢信可愛，碑意少缺誰能鎸。", "已推心膽破奸宄，安用筆墨傳神仙。"]'),
('5a46402b-3ad3-43f6-87fd-e4dc429de8bb','碧蓮池','曾鞏','宋','宋诗','song-poetry','','[]','神仙恍惚不可明，空有池蓮變紅碧。',32,'全唐诗/poet.song.26000.json','["神仙恍惚不可明，空有池蓮變紅碧。", "清香冷落秋風前，似被麻姑妒顔色。"]'),
('497b5f31-1346-4d51-91ee-43df3201286b','流杯池','曾鞏','宋','宋诗','song-poetry','','[]','行盡壇前石崖路，忽見一曲清泠泉。',32,'全唐诗/poet.song.26000.json','["行盡壇前石崖路，忽見一曲清泠泉。", "酒行到我不辭醉，安用了了分愚賢。"]'),
('00bacd92-b3f7-4809-ade5-2d15b56a6652','七星杉','曾鞏','宋','宋诗','song-poetry','','[]','古杉蒼蒼橫斗文，其幹十圍陰蔽野。',32,'全唐诗/poet.song.26000.json','["古杉蒼蒼橫斗文，其幹十圍陰蔽野。", "應到夜深山月來，林色天光迷上下。"]'),
('4c0a7481-c887-4585-95c5-59507f5943a8','瀑布泉','曾鞏','宋','宋诗','song-poetry','','[]','飛泉一支天上來，寒影沉沉瀉龍穴。',32,'全唐诗/poet.song.26000.json','["飛泉一支天上來，寒影沉沉瀉龍穴。", "山靈欲以怪動人，山路先冬積霜雪。"]'),
('29cf989c-c13a-4ecb-a530-98e15dc71771','秋懷','曾鞏','宋','宋诗','song-poetry','','[]','天地四時誰主張，縱使群陰入風日。',176,'全唐诗/poet.song.26000.json','["天地四時誰主張，縱使群陰入風日。", "日光在天已蒼凉，風氣吹人更憀慄。", "樹木慘慘顔色衰，燕雀啾啾群侶失。", "我有愁輪行我腸，顛倒回環不能律。", "我本孜孜學詩書，詩書與今豈同術。", "智慮過人祇自讎，聞見於時未裨一。", "片心皎皎事乖背，衆醉冥冥勢陵突。", "出門榛棘不可行，終歲蒿藜尚誰恤。", "遠夢頻迷憶故人，客被初寒卧沉疾。", "將相公侯雖不爲，消長窮通豈須詰。", "聖賢穰穰力可攀，安能俯心爲苟屈。"]'),
('abcc8ada-ab1b-49fc-96c6-b31ee0184573','送歐陽員外歸覲滁州舍人','曾鞏','宋','宋诗','song-poetry','','[]','病卧不出門，非關避塵土。',132,'全唐诗/poet.song.26000.json','["病卧不出門，非關避塵土。", "深秋影雖清，孤懷共誰語。", "辱子問吾廬，輝如就賓廡。", "足音固可喜，況久捉松麈。", "子生何其祥，家庭坐軻愈。", "顧我齒諸生，漸磨苦頑魯。", "有如仰天潢，勢豈識津渚。", "又若馬牛然，安能望熊虎。", "空摇在門心，常若風中羽。", "羨子筋骨輕，歸飛得其所。", "從今夢無南，隨子渡江櫓。"]'),
('01391758-1914-4b38-84f8-e377705fd3e4','一晝千萬思','曾鞏','宋','宋诗','song-poetry','','[]','一晝千萬思，一夜千萬愁。',96,'全唐诗/poet.song.26000.json','["一晝千萬思，一夜千萬愁。", "晝思復夜愁，晝夜千萬秋。", "故人遠爲縣，海邊勾踐州。", "故人道何如，不間孔與周。", "我如道邊塵，安能望嵩丘。", "又若澗與溪，敢比滄海流。", "景山與學海，汲汲强自謀。", "愁思雖爾勤，故人得知不。"]'),
('25c9d3a0-e422-411a-9f5c-3c50af325492','送鄭秀才','曾鞏','宋','宋诗','song-poetry','','[]','鄭生雙瞳光欲溢，我意海月藏其中。',96,'全唐诗/poet.song.26000.json','["鄭生雙瞳光欲溢，我意海月藏其中。", "齒清髮紺心獨老，秋崖直聳千年松。", "來趨學宮業文字，進退佩玉何玲瓏。", "一朝束書別我去，馬蹄脫若風中蓬。", "當今文人密如櫛，子勿浪漫西與東。", "處身不可不擇處，一跳萬里無還蹤。"]'),
('23edc32b-3929-4666-8f60-92b907d65274','答所勸灸','曾鞏','宋','宋诗','song-poetry','','[]','灸灼君所勸，感君書上辭。',48,'全唐诗/poet.song.26000.json','["灸灼君所勸，感君書上辭。", "勿難火艾痛，要使功名垂。", "我道世所背，君知餘有誰。", "筋骸倘且健，學行肯教隳。"]'),
('102dc107-5b5b-43cd-8638-64ccfce5037e','菊花','曾鞏','宋','宋诗','song-poetry','','[]','菊花秋開只一種，意遠不隨桃與梅。',96,'全唐诗/poet.song.26000.json','["菊花秋開只一種，意遠不隨桃與梅。", "遊人有幾愛孤淡，零落野水空岩隈。", "層層露萼間枝葉，金靨萬個圍蒼苔。", "直從陶令酷愛尚，始有我見心眼開。", "爲憐清香與正色，欲搴更惜常徘徊。", "當携玉軫就花醉，一飲不辭三百杯。"]'),
('e8e8e40d-e3fb-4f0b-ab3c-b744e51e1d9e','答石秀才月下','曾鞏','宋','宋诗','song-poetry','','[]','今宵月色明千里，秋水與天無表裏。',112,'全唐诗/poet.song.26000.json','["今宵月色明千里，秋水與天無表裏。", "樹木矯矯蛟龍蟠，屋瓦鱗鱗雪霜洗。", "林下病人毛骨醒，目愛清光不知已。", "秋風自作竽籟聲，更送城笳夜深起。", "客衾初寒睡未能，忽得子詩哦以喜。", "子求我和何勤劬，我知枯疏少知己。", "子真愛我常存心，安用蕪辭煩筆紙。"]'),
('5f4664f4-c65c-4715-a094-1b7a01b94f08','冬曉書懷','曾鞏','宋','宋诗','song-poetry','','[]','群鷄啁哳天始明，東方吐日霜尚冰。',128,'全唐诗/poet.song.26000.json','["群鷄啁哳天始明，東方吐日霜尚冰。", "長簾高褰掃落葉，短杌背立吹殘燈。", "昔時氣銳過奔浪，今日病減真無蠅。", "南箕翻翻世所效，白璧皎皎誰非憎。", "屠龍破産習已妄，畫蛇著足棄未能。", "不容當時孔何病，更譽衆列顔非朋。", "坐知天下書最樂，心縱塵土酒可憑。", "莫過二事賢且聖，胡不學外常騰騰。"]'),
('a37b866a-ff1e-4d79-9827-c0480ae04b2c','代書寄趙宏','曾鞏','宋','宋诗','song-poetry','','[]','憶承昨歲致書召，遂入江城同一笑。',384,'全唐诗/poet.song.26000.json','["憶承昨歲致書召，遂入江城同一笑。", "羸奴小馬君所借，出犯朝寒鞅頻掉。", "從來萬事固已拙，況乃病敦顔不少。", "去隨衆後已自枉，更苦世情非可料。", "一心耿耿浪誠直，百口幡幡競訶誚。", "獨君踴躍於我顧，譬於真玉火空燒。", "別來未幾歲云換，楊柳得春還窈窕。", "東溪最好水已淥，桃李萬株紅白照。", "當時病卧不能出，日倚東風想同調。", "逡巡紅白委地休，新葉可書陰可釣。", "君持使傳入南師，忽領貔貅過蓬藋。", "僧堂取酒就君飲，不覺乘歡盞頻釂。", "屋西明月過簾白，簾角有時飛熠燿。", "明聞鉦鼓催軍發，共上高樓看旗旐。", "日高行忽又別君，從此閉門誰可嘯。", "秋風已盡始得書，喜聽車輪返窮徼。", "身欲追隨病未能，目斷珊瑚遮海嶠。", "是時肺氣壯更惡，日以沉冥憂不療。", "豈其艱苦天所憫，晚節幸值巫彭妙。", "放心已保性命在，握手猶驚骨骸峭。", "今年霜霰雖未重，室冷尚無薪可燎。", "一畝酸寒豈易言，局促不殊魚在罩。", "勞君書札數問訊，深愧薄材無象肖。", "君心卓犖衆未識，安得辨口聞廊廟。"]'),
('12c7fe98-71f2-4b2c-b768-c1b2f8d31efd','東津歸催吳秀才寄酒','曾鞏','宋','宋诗','song-poetry','','[]','荒城懶出門常掩，春氣欲歸寒不斂。',192,'全唐诗/poet.song.26000.json','["荒城懶出門常掩，春氣欲歸寒不斂。", "東鄰咫尺猶不到，況乃傍溪潭石險。", "風光得暖才幾日，不覺溪山碧於染。", "欣然與客到溪岸，衣幘不避塵泥點。", "谷花洲草各萌芽，高下迸生如刻剡。", "梅花開早今已滿，若洗新妝競妖臉。", "柳條前日尚憔悴，時節與催還荏苒。", "沙禽翅羽亦已好，爭趁午暄浮翠瀲。", "從今物物已可愛，有酒便醉情何慊。", "君厨山杏舊所識，速致百壺須灧灧。", "心知萬事難刻畫，惟有醉眠知不忝。", "預愁酩酊苦大熱，已令灑屋鋪風簟。"]'),
('5a41fce3-907a-4e7e-9a26-6a8983a2baf3','送吳秀才','曾鞏','宋','宋诗','song-poetry','','[]','一年過臘已十日，餘日到春能有幾。',160,'全唐诗/poet.song.26000.json','["一年過臘已十日，餘日到春能有幾。", "春來遠近不可問，冷碧先歸在流水。", "梅花向今獨已繁，玉艷都占春風間。", "草萌出土亦過寸，衆芳次第掛清寒。", "虛堂盡日對風影，我獨此守青琅玕。", "故人遠來未一醉，車鞅欲去今誰攀。", "憐君滿腹富文彩，倦尾赤色無波瀾。", "連年禮部試多士，白羽捨置操榛菅。", "君今忽忽負壯節，我亦春色羞衰顔。", "况逢離別可奈何，憶人日老情日多。"]'),
('d5d24624-3088-42e8-b039-27e629f4dfbe','和章友直城東春日','曾鞏','宋','宋诗','song-poetry','','[]','東流抱孤城，雨洗見春色。',120,'全唐诗/poet.song.26000.json','["東流抱孤城，雨洗見春色。", "風吹百草根，道路千里碧。", "莫盡溪漫漫，波瀾散無迹。", "遥林缺見山，冉冉蒼藹積。", "沙禽有遺蹤，文字不可識。", "青松對桃李，桃紅李花白。", "紅白勢方競，青青守岩側。", "君意無不諧，研談欲俱得。", "賦詩多所陳，炳若觀龜坼。", "城東不待到，衆物已歷歷。"]'),
('9908ba7a-c2e9-41fc-8299-8a378dfb24c5','簡如晦伯益','曾鞏','宋','宋诗','song-poetry','','[]','一年孟春月已晦，思去去臘如須臾。',96,'全唐诗/poet.song.26000.json','["一年孟春月已晦，思去去臘如須臾。", "春事競在二月間，急景豈與正月殊。", "今看桃李花未出，不知花開能幾日。", "日尋桃李不暫停，恐未十回花已失。", "筋骸縱病心尚壯，酒醴雖無鄰可乞。", "城東欲與君試行，莫嫌冷落逐書生。"]'),
('8f2db4b1-bce8-4702-bbb1-d66eca9054c9','高松','曾鞏','宋','宋诗','song-poetry','','[]','高松高干雲，衆木安可到。',108,'全唐诗/poet.song.26000.json','["高松高干雲，衆木安可到。", "湯湯鳴寒溪，偃偃倚翠纛。", "側聽心神醒，仰視目睛眊。", "風雨天地動，一葉不欹倒。", "豈同澗中萍，上下逐流潦。", "豈同牆根槐，卷卷秋可掃。", "鳳凰引衆禽，此木陰可燾。", "君求百常柱，星日此可造。", "般匠世有無，方鍾野人好。"]'),
('a5b4d0e3-6373-4f99-89cc-b31f172f7804','青青間青青','曾鞏','宋','宋诗','song-poetry','','[]','青青間青青，盡望密如罅。',84,'全唐诗/poet.song.26000.json','["青青間青青，盡望密如罅。", "風柔聲自和，草縟陰可藉。", "遊蜂不暫去，啼鳥時獨下。", "繚牆隔深園，高枝出虛榭。", "貴人無餘事，歡言持玉斝。", "茅簷亦自好，吾廬四如畫。", "故人儻可遲，倒屣不辭迓。"]'),
('be82a414-dbce-461c-bb94-c57621c2b2b5','洪州','曾鞏','宋','宋诗','song-poetry','','[]','洪州城中荒且遠，每到弱馬常驅馳。',64,'全唐诗/poet.song.26000.json','["洪州城中荒且遠，每到弱馬常驅馳。", "交朋顧我亦已厚，謝詞有禮寧當違。", "人生有累乃汲汲，萬事敦迫如銜羈。", "山中無塵水清白，安得去吟梁甫辭。"]'),
('5472cef6-e2e2-41f4-a580-6f8bddd83850','咏史二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','仲尼一旅人，吳楚據南面。',24,'全唐诗/poet.song.26000.json','["仲尼一旅人，吳楚據南面。", "不知千載下，究竟誰貴賤。"]'),
('af48fc24-ba7f-4375-a452-2188dd7e56c1','咏史二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','賜也相國尊，子思終不慕。',24,'全唐诗/poet.song.26000.json','["賜也相國尊，子思終不慕。", "乃知古今士，輕重復內顧。"]'),
('5d78f1d3-093e-4212-9f26-b18b8d2dfec6','泝河','曾鞏','宋','宋诗','song-poetry','','[]','客舟泝河西北行，日夜似與河流爭。',144,'全唐诗/poet.song.26000.json','["客舟泝河西北行，日夜似與河流爭。", "不知洶洶竟何爲，怒意彼此何時平。", "但疑天地送秋至，惡雨疾風相觸聲。", "我病入寒饒睡思，歸夢正美還遭驚。", "東南水鄉我所住，楊花散時春水生。", "湖江渺邈不見岸，汩汩自流無可憎。", "石泉百丈落山嘴，此縱有聲清可聽。", "莫如此水極凶驁，土木暫觸還轟轟。", "吁嗟造化何厚薄，惡物受稟無由更。"]'),
('01e31769-461c-4e8d-bba1-1fba8d219799','尹師魯','曾鞏','宋','宋诗','song-poetry','','[]','衆人生死如塵泥，一賢廢死千載悲。',144,'全唐诗/poet.song.26000.json','["衆人生死如塵泥，一賢廢死千載悲。", "漢初董生不大用，厥政自此慚隆姬。", "至今董生沒雖久，語者爲漢常嗟欷。", "尹公素志任天下，衆亦共望齊皋伊。", "文章氣節蓋當世，尚在功德如豪氂。", "安知蔓草蔽原野，雪霰先折青松枝。", "百身可贖世豈惜，訃告四至人猶疑。", "悲公尚至千載後，況復悲者同其時。", "非公生平舊相識，跽向北極陳斯詩。"]'),
('74b3308c-3d81-4074-a588-3a1ffd0c38b6','發松門寄介甫','曾鞏','宋','宋诗','song-poetry','','[]','南風夜發吹孤舟，起視北極星辰稠。',192,'全唐诗/poet.song.26000.json','["南風夜發吹孤舟，起視北極星辰稠。", "曉開征帆破長浪，挾以兩櫓當中流。", "松門東面見廬阜，其上少日烟氣浮。", "舟人指我極四望，黑處無底蛟龍湫。", "櫧溪左蠡信浩蕩，兩涘若粒分岡丘。", "落星囷囷孰可狀，清漢夜獨垂牽牛。", "故人曾期此同載，捨櫂直抵雲山遊。", "念今五載負斯語，心獨動蕩風中斿。", "况聞肥遯須山在，早時事力胡能謀。", "所嗟親老食未足，安得一畝操鋤耰。", "此言此笑吾此取，非子世孰吾相投。", "今諧與子脫然去，亦有文字歌唐周。"]'),
('14b9e96d-3f82-4571-afca-8fb27c09b3fe','北風','曾鞏','宋','宋诗','song-poetry','','[]','北風動地江翻天，我坐極浦維空船。',80,'全唐诗/poet.song.26000.json','["北風動地江翻天，我坐極浦維空船。", "浮雲冥冥下無日，老樹自擺相樛纏。", "薰琴空聞不可見，應已久絕朱絲弦。", "遂令陰飆自回斡，安得歲物無疵愆。", "江頭酒賤且就醉，勿復著口問陶甄。"]'),
('8ed508b6-ad2f-4c7d-802f-7c326aa6b9a5','過彭澤','曾鞏','宋','宋诗','song-poetry','','[]','淵明昔抱道，爲貧仕茲邑。',72,'全唐诗/poet.song.26000.json','["淵明昔抱道，爲貧仕茲邑。", "幡然復謝去，肯受一官縶。", "予觀長者憂，慷慨在遺集。", "豈同孤蒙人，剪剪慕原隰。", "遭時乃肥遯，茲理固可執。", "獨有田廬歸，嗟我未能及。"]'),
('fd0b3f1e-d760-45f9-9b07-af6dcb7891c5','江上懷介甫','曾鞏','宋','宋诗','song-poetry','','[]','江上信清華，月風亦蕭灑。',48,'全唐诗/poet.song.26000.json','["江上信清華，月風亦蕭灑。", "故人在千里，樽酒難獨把。", "由來懶拙甚，豈免交遊寡。", "朱弦任塵埃，誰是知音者。"]'),
('a1c7f0e5-292f-4b14-865f-a92fd1eb1b91','讀五代史','曾鞏','宋','宋诗','song-poetry','','[]','唐衰非一日，遠自開元中。',72,'全唐诗/poet.song.26000.json','["唐衰非一日，遠自開元中。", "尚傳十四帝，始告曆數窮。", "由來根本强，暴戾豈易攻。", "嗟哉梁周間，卒莫相始終。", "興無累世德，滅若燭向風。", "當時積薪上，曾寧廢歌鐘。"]'),
('2a2697a6-85ee-474e-8cbf-94575584931d','庭木','曾鞏','宋','宋诗','song-poetry','','[]','庭中有佳樹，清影四面垂。',288,'全唐诗/poet.song.26000.json','["庭中有佳樹，清影四面垂。", "往往風雨夜，蛟龍此投依。", "留之待鸞鳳，未許燕雀窺。", "誰謂烏鳥惡，安巢最高枝。", "不顧白日照，直傍陰虹飛。", "自恃棲託穩，豈憂彈射危。", "三春獨翱翔，百鳥斂羽儀。", "鳳凰不能爭，況乃鳬雁微。", "既務志意得，都爲世可欺。", "白晝攫鼎肉，從容擇牷犧。", "近人不肯避，一怒終夜啼。", "遭其瞰牆屋，禍患豈可移。", "聽之欲占赦，婦女固已癡。", "忿害乃其所，何肯報福釐。", "行路指之嘆，童稚爭駡譏。", "鸚鵡獻至尊，言語固可奇。", "翡翠輸太府，器服所取資。", "雉鷄美文章，贄贈理亦宜。", "鷹鸇逐惡鳥，天威得施爲。", "關雎於周室，耿潔配后妃。", "莫如此鳥頑，飽食無所裨。", "一善不能有，醜聲日交馳。", "但知擇嘉處，巍然治其棲。", "衆怒未易忽，徼幸亦有斯。"]'),
('4f5a49a3-38e0-459d-b380-417f3d5bb9cb','發彭澤','曾鞏','宋','宋诗','song-poetry','','[]','卧聞櫓聲知雨來，起見江流與天合。',64,'全唐诗/poet.song.26000.json','["卧聞櫓聲知雨來，起見江流與天合。", "山回風吹霧不盡，帆健船衝浪相沓。", "歸雲難乘望空斷，落日乍掩凉可納。", "去家今夜一千里，誰見愁來坐方榻。"]'),
('9968ee6c-cd22-4b4b-9218-5865066374cb','菊花','曾鞏','宋','宋诗','song-poetry','','[]','東籬菊花今已開，萬物各自相驅催。',96,'全唐诗/poet.song.26000.json','["東籬菊花今已開，萬物各自相驅催。", "却尋桃杏那復有，舊樹慘慘空牆隈。", "年光日日已非昔，人世可能無盛衰。", "朱顔白髮相去幾，勢利聲名相抑排。", "三公未能逃餓死，九鼎竟亦爲塵埃。", "乃知萬事皆自枉，有便只宜持酒杯。"]'),
('382d706f-d9a9-4c12-855b-0862b2223175','落葉','曾鞏','宋','宋诗','song-poetry','','[]','秋雨與風相噴薄，樹木可能無葉落。',128,'全唐诗/poet.song.26000.json','["秋雨與風相噴薄，樹木可能無葉落。", "琅玕散漫不可收，野步滿船誰掃掠。", "垂楊千樹舊所惜，顔色易衰由力弱。", "空條尚舞不自休，物意豈能知索寞。", "菊花雖開能幾許，新酒縱酸猶可酌。", "朱顔久已拚銷減，豈有功名堪寫貌。", "衣冠塵土欲更洗，其奈滿堤河水濁。", "花開葉落須强醉，壯士豈憂常落魄。"]'),
('c6629de9-db90-4ce3-9c3c-acbead228076','舞鶴','曾鞏','宋','宋诗','song-poetry','','[]','蓬瀛歸未得，偃翼清溪陰。',36,'全唐诗/poet.song.26000.json','["蓬瀛歸未得，偃翼清溪陰。", "忽聞瑶琴奏，遂舞玉山岑。", "舞罷復嘹唳，誰知天外心。"]'),
('642c0c5b-99d3-4a17-9cb1-8c53cb066e03','降龍','曾鞏','宋','宋诗','song-poetry','','[]','降龍左右施襟裾，兩廊夾廟深渠渠。',128,'全唐诗/poet.song.26000.json','["降龍左右施襟裾，兩廊夾廟深渠渠。", "禮下天子一等爾，衣服居處何其殊。", "文旛列戟照私第，青紫若若官其孥。", "先後熒煌首珠翠，侍者百十顔溫瑜。", "凝寒墮指熱侵骨，一宴百盞傾金壺。", "窮民疾首望雨露，太上欲倚攀姚虞。", "君胡爲乎目時病，橐針襆艾恬以愉。", "生前赫赫浪自重，身後沒沒寧非愚。"]'),
('7f363957-3011-4968-8df4-72c0a4ae541e','湘寇','曾鞏','宋','宋诗','song-poetry','','[]','衡湘有寇未誅剪，殺氣凜凜圍江潯。',240,'全唐诗/poet.song.26000.json','["衡湘有寇未誅剪，殺氣凜凜圍江潯。", "北兵居南匪便習，若以大舶乘高岑。", "傖人操兵快如鶻，千百其旅巢深林。", "超突溪崖出又伏，勢變不易施戈鐔。", "能者張弓入城郭，連邑累鎮遭驅侵。", "群黨爭誇殺吏士，白骨棄野誰棺衾。", "貔貅數萬直何用，月費空已逾千金。", "楚爲貧鄉乃其素，應此調發寧能禁。", "捷如馬援不得志，强曳兩足登嶔崟。", "烏蟻睢盱倚岩險，此虜難勝端非今。", "較然大體著方冊，唯用守長懷其心。", "祝良張僑乃真選，李瑑道古徒爲擒。", "嗚呼廟堂不慎擇，彼士齪齪何能任。", "大中咸通乃商鑒，養以歲月其憂深。", "願書此語致太史，獻之以補丹扆箴。"]'),
('b3c03668-7982-4e70-9fad-2751b99eb0c3','地動','曾鞏','宋','宋诗','song-poetry','','[]','吾聞元氣判爲二，升降相輔非相傷。',224,'全唐诗/poet.song.26000.json','["吾聞元氣判爲二，升降相輔非相傷。", "今者無端越疆畔，陰氣焰焰侵於陽。", "陽收剛明避其勢，陰負捷勝尤倡佯。", "地乘是氣亢於下，震蕩裂拆乖其常。", "齊秦晉代及荆楚，千百其堵崩連牆。", "隆丘桀屋不自定，翩若猛吹摇旌幢。", "生民洶洶避無所，如寄厥命於湖江。", "有聲四出嘻可怕，誰擊萬鼓何雷硠。", "陰爲氣靜乃如此，天意昧密寧能詳。", "或云蠻夷尚侵軼，已事豈必垂災祥。", "意者邪臣有專恣，氣象翕翕難爲當。", "據經若此非臆决，皎如秋日浮清霜。", "祖宗威靈陛下聖，安得直語聞明堂。", "朝廷肅穆法度治，豈用懔懔憂胡羌。"]'),
('ddb73251-7351-4a2c-8376-5d4b3887d79b','邊將','曾鞏','宋','宋诗','song-poetry','','[]','太祖太宗能得人，長壘橫邊遮虜塵。',300,'全唐诗/poet.song.26000.json','["太祖太宗能得人，長壘橫邊遮虜塵。", "太傅李漢超，侍中何繼筠。", "二子追接吳與孫，鎮齊撫棣功業均。", "卓哉祖宗信英特，明如秋泉斷如石。", "一朝出節合二子，口付心隨斷纖惑。", "磨笄之旁郡城下，酒利商租若山積。", "二子開庫啗戰士，以屋量金乘量帛。", "洪濤入坐行酒杯，牛胾羊蒸委若灰。", "歲費巨萬不計籍，戰士歡酣氣皆百。", "二子按轡行邊隅，牙纛宛轉翻以舒。", "汛掃沙磧無纖埃，塞門千里常夜開。", "壯耕老餔安且愉，桑麻蔽野華芬敷。", "濟南遠清書樂石，百井夜出摧穹廬。", "神哉祖宗知大體，趙任李牧真如是。", "漢文齷齪豈足稱，郎吏致激面污騂。", "當今羌夷久猖獗，兵如疽癰理須决。", "堂堂諸公把旄鉞，碩策神韜困羈紲。", "祖宗憲度存諸書，㸌若白日明天衢。", "國容軍政不可亂，薦此以爲陛下娛。"]'),
('e18e5e46-0a01-4394-948f-7ee21de36a96','多雨','曾鞏','宋','宋诗','song-poetry','','[]','嗟江之濱地多雨，冬雷不收開蟄戶。',128,'全唐诗/poet.song.26000.json','["嗟江之濱地多雨，冬雷不收開蟄戶。", "陰氣濁晦化爲霧，或雲於山水於礎。", "雜花萬株紅與紫，臘風吹開不可數。", "入春十日寒始至，春氣欲歸寒格住。", "群山巉空雪相亙，摧折草木何可禦。", "霖傾潦洶那復止，穹林大丘滅無渚。", "及今孟夏理宜熱，重裘無溫坐當午。", "四時云然了安謂，吁吾有愁誰可語。"]'),
('2460ba33-ea7a-432c-a218-a3f5fe115292','秋日','曾鞏','宋','宋诗','song-poetry','','[]','陰氣先贏縱秋熱，時節有幾相與奪。',128,'全唐诗/poet.song.26000.json','["陰氣先贏縱秋熱，時節有幾相與奪。", "情知赫日不可久，須聽西風生木末。", "浮雲滿天明復暗，天意自然如慘怛。", "園林秀色已漸失，次第豈能無葉脫。", "南山獨佳不可挫，氣象更清連日月。", "燕飛度海向何處，今去昔來真可劣。", "繡簾錦幕不算重，從此朱門戒霜雪。", "誰憐丱角歌者哀，歲歲苦貧思短褐。"]'),
('98f43c10-bc40-4afc-9802-eee798ae5e4f','山水屏','曾鞏','宋','宋诗','song-poetry','','[]','吳縑落寒機，舒卷光亂目。',288,'全唐诗/poet.song.26000.json','["吳縑落寒機，舒卷光亂目。", "秋刀剪新屏，尺寸隨折曲。", "搜羅得珍匠，徙倚思先屬。", "經營頃刻內，千里在一幅。", "定視乃漸通，紀數難迫促。", "山亂若無窮，負抱頗重複。", "高棱最當中，桀大勢尤獨。", "回環衆峰接，趨向若奔伏。", "矜雄跨九州，爭險掛星宿。", "深疑雪霜積，暗覺烟霧觸。", "泉源出青冥，漲潦兩崖束。", "歷遠始紆徐，派別輸衆谷。", "輕舟漾其間，沿泝無緩速。", "微尋得修逕，側起破蒼麓。", "遠到無限極，窮升犯雲族。", "遊子定何之，顧眄停馬足。", "盤石長自閑，空原偶誰築。", "塵氛見荒林，物色存古俗。", "粲粲弄幽花，蒼蒼蔭嘉木。", "遺牛上岩顛，驚麏出槎腹。", "鮮明極萬狀，指似才一粟。", "雖從人力爲，頗類陰怪續。", "深堂得欹眠，高枕生遠矚。", "餘光耀衾幬，清意凝幔褥。"]'),
('1764984a-fe8d-410b-b683-a3f276731d3b','八月二十九日小飲','曾鞏','宋','宋诗','song-poetry','','[]','陰陽在天地，鼓吹猶橐籥。',264,'全唐诗/poet.song.26000.json','["陰陽在天地，鼓吹猶橐籥。", "煩蒸翕已盡，灝氣乃浮薄。", "群山翠相抱，塵靄如洗濯。", "川源亦虛徹，派別歸衆壑。", "囂音滅蛙蚓，勁意動鵰鶚。", "蠅蚊自不容，雖有類鉗縛。", "驅之舊苦衆，忽去寧匪樂。", "俯仰自醒然，意適忘體瘼。", "天運雖已晏，生物固未剝。", "薑芋圃可掘，禾黍田始穫。", "脫苞紫栗迸，透葉紅梨渥。", "幽花媚清景，鮮叢耀新萼。", "西風動孤格，露曉愈修擢。", "能終犯寒沍，詎可忽纖弱。", "况當九日近，家釀成已昨。", "溫顔几杖適，弱質衣冠恪。", "閨門自可會，非必千里約。", "箏匏出人指，邐迤奮宮角。", "初嚴小人獻，終拜長者酢。", "清言喜自洽，細故憂可略。", "幸無職事顧，况荷租賦薄。", "讀書有休暇，得醉且吟噱。"]'),
('f3ecfae0-ec5d-4a51-bbb9-fcf679119eba','食梨','曾鞏','宋','宋诗','song-poetry','','[]','今歲天旱甚，百穀病已久。',216,'全唐诗/poet.song.26000.json','["今歲天旱甚，百穀病已久。", "山梨最大樹，屬此亦乾朽。", "當春花盛時，雪滿山前後。", "常期摘秋實，穰穰落吾手。", "忽驚冰玉敗，不與膏澤偶。", "清朝起周覽，映葉才八九。", "閑居問時物，此說得溪叟。", "貧齋分寂絕，塵抱徒噎嘔。", "寧知蕭條內，把握忽先有。", "食新恐非稱，分少覺已厚。", "開苞日星動，落刃冰雪剖。", "烟潯擇新汲，遠負盈素缶。", "英華兩相發，光彩生戶牖。", "初嘗蜜經齒，久嚼泉垂口。", "蠲煩慰諸親，愈渴忻衆友。", "肯視故畦瓜，寧論濁泥藕。", "歲晚迫風霜，人饑乏藜糗。", "真味雖暫御，未許置樽酒。"]'),
('ed52bf22-855e-4e12-a16d-233baaab7320','追租','曾鞏','宋','宋诗','song-poetry','','[]','耕耨筋力苦，收刈田野樂。',288,'全唐诗/poet.song.26000.json','["耕耨筋力苦，收刈田野樂。", "鄉鄰約來往，樽酒追酬酢。", "生涯給俯仰，公斂忘厚薄。", "胡爲此歲暮，老少顔色惡。", "國用有緩急，時議廢量度。", "內外奔氣勢，上下窮割剝。", "今歲九夏旱，赤日萬里灼。", "陂湖蹙埃𡏖，禾黍死磽确。", "衆期必見省，理在非可略。", "謂須倒廩賑，詎止追租閣。", "吾人已迫切，此望亦迂邈。", "奈何呻吟訴，卒受鞭棰却。", "寧論救憔悴，反與爭合龠。", "問胡應驅迫，久已罹匱涸。", "計須賣强壯，勢不存尪弱。", "去歲已如此，愁呼遍郊郭。", "饑羸乞分寸，斯須死笞縛。", "法令尚修明，此理可驚愕。", "公卿飽天祿，耳目知民瘼。", "忍令瘡痍內，每肆誅求虐。", "但憂值空虛，寧無挺犁钁。", "暴吏理宜除，浮費義可削。", "吾卧避囂喧，茲言偶斟酌。", "試起望遺村，霾風振墟落。"]'),
('a185882c-09c6-4dac-8ecb-e33efbdc5d09','桐樹','曾鞏','宋','宋诗','song-poetry','','[]','棄地瓦礫間，茲桐偶誰樹。',120,'全唐诗/poet.song.26000.json','["棄地瓦礫間，茲桐偶誰樹。", "憶見擁西牆，俄成劃烟霧。", "得時花葉鮮，照影清泉助。", "當軒蔽赤日，對卧醒百慮。", "惜哉稟受弱，妄使鸞凰顧。", "商聲動猶微，秀色觸已沮。", "低摧亂繁條，逼迫畏清露。", "暄晴幸未闋，飄落儻可拒。", "噫號衝飆回，激射陰霰聚。", "此勢復可言，瞪視空薄暮。"]'),
('2e2c7396-8534-48ef-b8f2-7741b4c73f65','九月九日','曾鞏','宋','宋诗','song-poetry','','[]','凄凄風露滋，靡靡塵靄屏。',168,'全唐诗/poet.song.26000.json','["凄凄風露滋，靡靡塵靄屏。", "已忻廬舍清，未苦裘褐冷。", "眠食味尤嘉，起坐日尚永。", "虛天照積水，精鑑出幽礦。", "石瑩見山稜，林疏覺窗冏。", "黄花宿蕊破，艷艷晨妝靚。", "頻尋遠逕香，每愛蒼池影。", "爲誰佳色鮮，慰我貧齋靜。", "寒醅出家法，異果得他境。", "甘腴饌新兔，醜怪薦修蠯。", "幽閑重時節，老大珍物景。", "獻酬興未薄，比諷思猶騁。", "况同親戚歡，詎匪田野幸。", "俱醉任棲鴉，燭炬尚可秉。"]'),
('e2dd3de3-b158-4aa8-8ac3-9f3ba3ce9c81','路中對月','曾鞏','宋','宋诗','song-poetry','','[]','山川困遊人，而不斷歸夢。',204,'全唐诗/poet.song.26000.json','["山川困遊人，而不斷歸夢。", "其餘惟日月，朝夕南北共。", "日光驅人身，擾擾逐群動。", "鄉思須暫忘，世事那止重。", "豈如月可喜，露坐息倥傯。", "清明入襟懷，萬里絕纖霿。", "愛之不能飧，但以目睛送。", "想知吾在廬，皎皎上修棟。", "慈親坐高堂，切切兒女衆。", "憐其到吾前，不使降帷幪。", "豈不映時節，荏苒更季仲。", "而我去方急，其能計歸鞚。", "我非土木爲，耳目異聾瞢。", "念之曷由安，腸胃百憂中。", "何言月可喜，喜意亦有用。", "爲其同此時，水木光可弄。", "猶勝夢中事，記之聊一誦。"]'),
('2715473c-7f15-4c35-be4e-f41659cbf8c7','聽鵲寄家人','曾鞏','宋','宋诗','song-poetry','','[]','鵲聲喳喳寧有知，家人聽鵲占歸期。',176,'全唐诗/poet.song.26000.json','["鵲聲喳喳寧有知，家人聽鵲占歸期。", "物情固不等人事，爾意自驚思別離。", "秋花粲粲正可愛，黄菊芙蓉開滿枝。", "春楓千樹變顔色，遠水靜照紅霞衣。", "梧桐楊柳豈知數，沙步露冷銀床欹。", "新黄暗綠各自媚，爛漫未減春風時。", "誰言秋物不可賞，人意自移隨盛衰。", "山田正冷酒味美，禾黍半收鷄雁肥。", "霜梨野栗處處有，雪蜜薦口清香隨。", "鄉園物物可想見，我意祇隨魂夢飛。", "家人未用占鵲語，應到歸時春亦歸。"]'),
('e690ec2f-b954-4b8c-a068-3045d9ffb52c','讀書','曾鞏','宋','宋诗','song-poetry','','[]','吾性雖嗜學，年少不自强。',288,'全唐诗/poet.song.26000.json','["吾性雖嗜學，年少不自强。", "所至未及門，安能望其堂。", "荏苒歲云幾，家事已獨當。", "經營食衆口，四方走遑遑。", "一身如飛雲，遇風任飄揚。", "山川浩無涯，險怪靡不嘗。", "落日號虎豹，吾未停車箱。", "波濤動蛟龍，吾方進舟航。", "所勤半天下，所濟一毫芒。", "最自憶往歲，病軀久羸尪。", "呻吟千里外，蒼黄值親喪。", "母弟各在遠，訃歸恐驚惶。", "凶禍甘獨任，危形載孤艎。", "崎嶇護旅櫬，緬邈投故鄉。", "至今驚未定，生還乃非常。", "憂慮心膽耗，馳驅筋力傷。", "況已近衰境，而常犯風霜。", "驅之久如此，負疴固宜長。", "朝晡暫一飽，百回步空廊。", "未免廢坐卧，其能視縑緗。", "新知固云少，舊學亦已忘。", "百家異旨趣，六經富文章。", "其言既卓闊，其義固荒茫。", "古人至白首，搜窮敗肝腸。"]'),
('1a2f01ae-e688-46ba-ab8d-3ab9d19171e7','雜詩五首  其一','曾鞏','宋','宋诗','song-poetry','','[]','三季已千載，古道久荒榛。',72,'全唐诗/poet.song.26000.json','["三季已千載，古道久荒榛。", "紛紛東漢士，飛鳴不當辰。", "經營救氛沴，此志卒埃塵。", "士生有進退，何必棄其身。", "其道雖褊迫，其行絕緇磷。", "公心不吾誑，復求無此人。"]'),
('83af209e-02cd-4f93-9890-594c3a565acb','雜詩五首  其二','曾鞏','宋','宋诗','song-poetry','','[]','貧仕任固小，會計未可失。',96,'全唐诗/poet.song.26000.json','["貧仕任固小，會計未可失。", "方今備千品，內外有卑秩。", "孰當責在己，施設能自必。", "拘文已難騁，避世固多屈。", "細云且可略，於大復何實。", "所就正如斯，與古豈同術。", "雖非萬鍾富，苟冒歸一律。", "焉能示朋友，學仕空自咄。"]'),
('f159cbf4-683c-46c5-a372-c3b03f99dc4b','雜詩五首  其三','曾鞏','宋','宋诗','song-poetry','','[]','韓公綴文辭，筆力乃天授。',168,'全唐诗/poet.song.26000.json','["韓公綴文辭，筆力乃天授。", "並驅六經中，獨立千載後。", "謂爲學可及，不覺驚縮手。", "如天有日月，厥耀無與偶。", "當之萬象瑩，所照百怪走。", "此其自然光，萬物安得有。", "其人雖已歿，其氣著星斗。", "窮天破大惑，更覺功業久。", "其餘施諸小，未負風義厚。", "當身止自善，所遇時則不。", "致官九列齊，此理嗟亦苟。", "去就惟用舍，士固無常守。", "孔孟非其稱，斗祿應未取。", "惜哉天下才，甘受外物誘。"]'),
('dfbfa53b-e8c9-48a9-a36e-7cfc67eb9de6','雜詩五首  其四','曾鞏','宋','宋诗','song-poetry','','[]','少年百事銳，豈謂身力孱。',84,'全唐诗/poet.song.26000.json','["少年百事銳，豈謂身力孱。", "心笑古時士，樹立勢苦難。", "差池歲月邁，自照失朱顔。", "初心不復道，齟齬常未安。", "紛紛憂與勞，幾不傷肺肝。", "人生省己分，靜默固其端。", "詩書可自喜，施設諒漫漫。"]'),
('a0e1f34d-a01e-4b09-91d6-5a9086575ace','雜詩五首  其五','曾鞏','宋','宋诗','song-poetry','','[]','相去幾年今與古，睢陽幾人朱與紫。',96,'全唐诗/poet.song.26000.json','["相去幾年今與古，睢陽幾人朱與紫。", "嗟哉二子獨有名，義烈乃能長不死。", "當時美人歡未足，一日蒼皇行萬里。", "豈無公卿尊且寵，急反與胡爲眼耳。", "丈夫感激世莫測，二子引身蒿下起。", "忠驅義激鬼神動，漠漠胡沙來此止。"]'),
('b430e72f-3868-4304-99c6-7ef40b554c22','與舍弟別舟岸間相望感嘆成咏','曾鞏','宋','宋诗','song-poetry','','[]','涕淚昨辭親，酸心今別子。',24,'全唐诗/poet.song.26000.json','["涕淚昨辭親，酸心今別子。", "舟陸空相望，摻袂即千里。"]'),
('ec34435b-7612-44a6-90ae-43ba60a09278','戲呈休文屯田','曾鞏','宋','宋诗','song-poetry','','[]','陳侯雋拔人所羨，歲晚江湖初識面。',192,'全唐诗/poet.song.26000.json','["陳侯雋拔人所羨，歲晚江湖初識面。", "已聞清論至更僕，更讀新詩欲焚硯。", "天子無由熟姓名，諸公固合思論薦。", "烏靴况已踏臺省，黑綬未得辭州縣。", "落落逢人愈難合，欣欣顧我能忘倦。", "跬步粗官別經歲，角巾廣坐今相見。", "繞郭青山疊寒玉，縈堤遠水鋪文練。", "明紅靚白花千樹，隔葉跳枝鶑百囀。", "佳時苦雨已蕭索，落蕊隨風還面旋。", "縱無供帳出郊野，尚有清樽就閑燕。", "脫遺拘檢任真率，放恣嘲諧較豪健。", "東廊解榻不共語，明日離亭空眷眷。"]'),
('27a81551-c268-44e8-8679-b311049794fa','送宣州杜都官','曾鞏','宋','宋诗','song-poetry','','[]','夜聞陵陽峰上雨，曉見宛溪春水平。',160,'全唐诗/poet.song.26000.json','["夜聞陵陽峰上雨，曉見宛溪春水平。", "畫船不待雙櫓挾，歸客喜成千里行。", "牧之文采宜未泯，夫子風流今有聲。", "篇什高吟鳳凰下，翰墨醉灑烟雲生。", "撥置簿書有餘力，放意樽罍無俗情。", "忠義非徒勸風俗，愷悌固可交神明。", "餘休比戶得涵泳，嚚訟累歲皆澄清。", "薦章交論付丞相，士行如此宜名卿。", "江湖一見十年舊，談笑相逢肝膽傾。", "鷦鷯一枝亦自得，去矣黄鵠高飛鳴。"]'),
('edd1fdf7-5e96-42d2-9299-6926c2e2db80','麻姑山送南城尉羅君','曾鞏','宋','宋诗','song-poetry','','[]','麻姑之路摩青天，蒼苔白石松風寒。',348,'全唐诗/poet.song.26000.json','["麻姑之路摩青天，蒼苔白石松風寒。", "峭壁直上無攀援，懸磴十步九屈盤。", "上有錦繡百頃之平田，山中遺人耕紫烟。", "又有白玉萬仞之飛泉，噴崖直瀉蛟龍淵。", "豐堂廣殿何言言，階脚插入斗牛間。", "樛枝古木不記年，空槎枵然卧道邊。", "幽花自嬋娟，林深爲誰妍。", "但見塵消境靜翔白鶴，吟清猿，雛禽乳鹿往往嗥荒顛。", "却視來徑如緣絙，千重萬疊窮岩巒。", "下有荆吳粟粒之群山，又有甌閩一髮之平川。", "弈棋縱衡遠近布城郭，魚鱗參差高下分岡原。", "千奇萬異可意得，墨筆盡禿誰能傳。", "丈夫舒卷要宏達，世路俯仰多拘牽。", "偶來到此醒心目，便欲洗耳辭囂喧。", "羅夫子，一日遠補東南官。", "愛此層崖峻壑之秀發，開軒把酒可縱觀。", "喜此披霄插漢之敻起，出門舉足得往還。", "羅夫子，一尉龍蛇方屈蟠。", "此邦人人衣食足，闔境年年枹鼓閑。", "几案剸裁得休暇，山水登躡遺紛煩。", "我行送之思故園，引領南望心長懸。"]'),
('de1e7cc1-6a74-4af9-9656-c9e17d026a6e','東軒小飲呈坐中','曾鞏','宋','宋诗','song-poetry','','[]','二年委質繫官次，一日偷眼看青山。',160,'全唐诗/poet.song.26000.json','["二年委質繫官次，一日偷眼看青山。", "念隨薄祿困垂首，似見故人羞滿顔。", "及門幸得二三友，把酒能共頃刻閒。", "海魚腥鹹聊復進，野果酸澀誰能刪。", "談劇清風生麈柄，氣酣落日解带鐶。", "瑰材壯志皆可喜，自笑我拙何由攀。", "高情坐使鄙吝去，病體頓覺神明還。", "簡書皇皇奔走地，管庫碌碌塵埃間。", "功名難合若捕影，日月遽易如循環。", "不如飲酒不知厭，欲罷更起相牽扳。"]'),
('7caa07d0-6fe6-4848-9a8c-e4c346f14b5b','明妃曲二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','明妃未出漢宮時，秀色傾人人不知。',144,'全唐诗/poet.song.26000.json','["明妃未出漢宮時，秀色傾人人不知。", "何况一身辭漢地，驅令萬里嫁胡兒。", "喧喧雜虜方滿眼，皎皎丹心欲語誰。", "延壽爾能私好惡，令人不自保妍媸。", "丹青有迹尚如此，何况無形論是非。", "窮通豈不各有命，南北由來非爾爲。", "黄雲塞路鄉國遠，鴻雁在天音信稀。", "度成新曲無人聽，彈向東風空淚垂。", "若道人情無感慨，何故衛女苦思歸。"]'),
('e3b81e3d-4787-4479-88ae-e135f50cd850','明妃曲二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','蛾眉絕世不可尋，能使花羞在上林。',128,'全唐诗/poet.song.26000.json','["蛾眉絕世不可尋，能使花羞在上林。", "自信無由污白玉，向人不肯用黄金。", "一辭椒屋風塵遠，去託氈廬沙磧深。", "漢姬尚自有妒色，胡女豈能無忌心。", "直欲論情通漢地，獨能將恨寄胡琴。", "但取當時能託意，不論何代有知音。", "長安美人誇富貴，未央宮殿競光陰。", "豈知泯泯沈烟霧，獨有明妃傳至今。"]'),
('e76cfcb3-4b67-46d3-b6b2-bfa3a196f530','喜二弟侍親將至','曾鞏','宋','宋诗','song-poetry','','[]','嗟予懷抱徒蠢蠢，二弟胸中何落落。',192,'全唐诗/poet.song.26000.json','["嗟予懷抱徒蠢蠢，二弟胸中何落落。", "政如魯衛各馳騁，文似機雲飽磨琢。", "坐曹風義動江淮，爲縣聲名到京洛。", "鴻雁峨峨並羽儀，棠棣韡韡聯跗鄂。", "我於兩處抱饑渴，恨寄一官如束縛。", "周南留滯勿復論，平陸可來無厭數。", "慈親况不倦行役，官長幸復寬期約。", "似聞笑語已仿佛，想見追隨先踴躍。", "共眠布被取溫暖，同舉菜羹甘淡薄。", "山花得折隨好醜，村酒可醉無清濁。", "屈伸有命更勿疑，細故偶然皆可略。", "春風爲子送帆檣，速放船頭來此泊。"]'),
('04685fe2-0452-44c9-972b-62b7c04776ab','七月一日休假作','曾鞏','宋','宋诗','song-poetry','','[]','初秋尚苦暑，歸沐乃君恩。',96,'全唐诗/poet.song.26000.json','["初秋尚苦暑，歸沐乃君恩。", "地閑少來客，日晏猶閉門。", "家乏念藜藿，開顔無一樽。", "况復辭貌拙，敢隨車馬奔。", "盥濯何所事，讀書坐前軒。", "豈堪當世用，空味古人言。", "頗喜市朝內，獨無塵土喧。", "終年但如此，真竊大官餐。"]'),
('ab5a7d3e-054c-404e-b1cf-af3f4f09afa1','秋夜','曾鞏','宋','宋诗','song-poetry','','[]','秋露隨節至，宵零在幽篁。',120,'全唐诗/poet.song.26000.json','["秋露隨節至，宵零在幽篁。", "灝氣入我牖，蕭然衾簟凉。", "念往不能寐，枕書嗟漏長。", "平生肺腑友，一訣餘空床。", "况有鵲巢德，顧方共糟糠。", "偕老遂不可，輔賢真淼茫。", "家事成濩落，嬌兒亦彷徨。", "晤言豈可接，虛貌在中堂。", "清淚昏我眼，沉憂回我腸。", "誠知百無益，恩義故難忘。"]'),
('cb5e6fc3-4ebf-41a2-a381-43fb5513b798','七月十四日韓持國直廬同觀山海經','曾鞏','宋','宋诗','song-poetry','','[]','高閣在清禁，長軒憑廣虛。',144,'全唐诗/poet.song.26000.json','["高閣在清禁，長軒憑廣虛。", "御幄閟圖象，依然臨幸餘。", "翠甓布天路，黄簾分直廬。", "一雨清景早，稍凉秋興初。", "解带就君坐，臨床闚素書。", "山海所錯出，飛潛類紛如。", "此語果虛實，遺編空卷舒。", "自笑正豕亥，更微注蟲魚。", "君材合遠用，就此固已疏。", "如我乃斯幸，地閑容誤居。", "竹影散良席，花香浮廣裾。", "俯仰自足適，歸時更當徐。"]'),
('52e70d0e-b999-4a2d-a273-eb5439b45754','李氏素風堂','曾鞏','宋','宋诗','song-poetry','','[]','丞相事唐室，獨馳三絕名。',120,'全唐诗/poet.song.26000.json','["丞相事唐室，獨馳三絕名。", "家世在圖史，詩書傳後生。", "郎位逮流澤，出令箴輩驚。", "歲暮營燕坐，高居遺世情。", "翠竹带書幌，青山臨酒觥。", "已使襟韵適，况聞吟誦聲。", "自可化鄉里，豈唯門戶榮。", "果有過庭子，穎然材思精。", "抱璞已三獻，驚人當一鳴。", "風義故常在，茲堂非偶成。"]'),
('f7f90901-a69e-45ca-8713-3bbb266cdd68','秋聲','曾鞏','宋','宋诗','song-poetry','','[]','喬柯與長谷，秀色故未浼。',120,'全唐诗/poet.song.26000.json','["喬柯與長谷，秀色故未浼。", "秋風來吹之，聲如振江海。", "怒號無晨夕，唱和若有待。", "翏翏遍坳漥，豈獨緣𡾋嵬。", "百川亦相投，取鬧不知悔。", "竹籬更謞然，呂律焉足采。", "蜩螿豈知微，切切如怨憝。", "惟人亦吟哦，沸若烹鼎鼐。", "八荒同一鳴，靜裏安得在。", "獨有虛室翁，恬然故無改。"]'),
('b33e1679-7f0f-401a-b9ec-3d86434b9e25','戲書','曾鞏','宋','宋诗','song-poetry','','[]','家貧故不用籌算，官冷又能無外憂。',67,'全唐诗/poet.song.26000.json','["家貧故不用籌算，官冷又能無外憂。", "交遊斷絕正當爾，眠飯安穩餘何求。", "君不見黄金滿籝要心計，大印如斗爲身讎。", "妻孥意氣賓客附，往往主人先白頭。"]'),
('035e8357-0d5c-4ff1-9c3e-80a6eba86666','李節推亭子','曾鞏','宋','宋诗','song-poetry','','[]','盱江郭東門，江水湛虛碧。',144,'全唐诗/poet.song.26000.json','["盱江郭東門，江水湛虛碧。", "東南望群峰，連延倚天壁。", "長林相蔽虧，蒼翠浮日夕。", "青冥窗戶寒，居者非咫尺。", "子初得從誰，有此烟霧宅。", "燕坐遠世喧，及門無塵客。", "築亭更求深，緩带聊自適。", "時花笑婀娜，山鳥吟格磔。", "家釀熟新樽，歡言命良席。", "故已輕華簪，寧論珍拱璧。", "我亦有菑田，相望在阡陌。", "安得巾柴車，過從佇三益。"]'),
('b23eab11-5c9c-40ea-8086-9da46f5fd7e4','秋夜露坐偶作','曾鞏','宋','宋诗','song-poetry','','[]','白雲飛尚低，清露泫猶早。',96,'全唐诗/poet.song.26000.json','["白雲飛尚低，清露泫猶早。", "風來亦依微，濁暑焉得掃。", "客堂虛四楹，灑水恨枯槁。", "喜茲宵漏初，露坐散襟抱。", "河明带飛觀，月白通馳道。", "顧眄塵慮銷，瓶泉謝頻倒。", "恨無同聲人，詩義與探討。", "踟躕拂方床，歸卧夢亦好。"]'),
('d7573000-dce6-421c-b0e8-21ee7765e25c','韓玉汝使歸','曾鞏','宋','宋诗','song-poetry','','[]','顧命逮殊鄰，輶軒遵此道。',120,'全唐诗/poet.song.26000.json','["顧命逮殊鄰，輶軒遵此道。", "公府戒行期，禁庭頒重寶。", "積雪正東流，度河盛前導。", "士勇踐胡塵，馬驕嘶塞草。", "玉節所鎮臨，氈廬先汛掃。", "赫爾示威靈，坦然布懷抱。", "國倚材實優，虜得聲名早。", "慷慨服天驕，從容問遺老。", "光華反原隰，沆碭看西顥。", "迎勞動都門，旌旗風亦好。"]'),
('311f7b3d-14fb-4571-89c3-c2c8898ecad9','苦熱','曾鞏','宋','宋诗','song-poetry','','[]','憶初中伏時，怫鬰炎氣升。',72,'全唐诗/poet.song.26000.json','["憶初中伏時，怫鬰炎氣升。", "赫日已照灼，赤雲助軒騰。", "積水殆將沸，清風豈能興。", "草木恐焚燎，窗扉似炊蒸。", "冰雪氣已奪，蚊蠅勢相矜。", "發狂憂不免，暑飲詎復勝。"]'),
('43d828df-588f-42f0-a30d-5487c9fe84a0','過介甫','曾鞏','宋','宋诗','song-poetry','','[]','日暮驅馬去，停鑣叩君門。',60,'全唐诗/poet.song.26000.json','["日暮驅馬去，停鑣叩君門。", "頗諳肺腑盡，不聞可否言。", "淡爾非外樂，恬然忘世喧。", "况值秋節應，清風蕩歊煩。", "徘徊望星漢，更復坐前軒。"]'),
('ad93e72e-6097-4f10-b84c-5b52fec220a5','過介甫歸偶成','曾鞏','宋','宋诗','song-poetry','','[]','結交謂無嫌，忠告期有補。',36,'全唐诗/poet.song.26000.json','["結交謂無嫌，忠告期有補。", "直道詎非難，盡言竟多迕。", "知者尚復然，悠悠誰可語。"]'),
('ec08e744-927f-4750-8b20-d925670710a3','合醤作','曾鞏','宋','宋诗','song-poetry','','[]','孺人捨我亡，稚子未堪役。',96,'全唐诗/poet.song.26000.json','["孺人捨我亡，稚子未堪役。", "家居拙經營，生理見侵迫。", "海鹽從私求，厨麵自官得。", "揀豆連數晨，汲泉候將夕。", "調撓遵古書，煎熬需日力。", "庶以具藜羹，故將供膾食。", "豈有寄徑憂，提瓶無所適。", "但慚著書非，覆瓿固其職。"]'),
('22c47361-a67c-40bc-a1df-43561f13b590','送章婺州','曾鞏','宋','宋诗','song-poetry','','[]','方擁使君節，駕言自東還。',120,'全唐诗/poet.song.26000.json','["方擁使君節，駕言自東還。", "又聞白丞相，懷紱出九關。", "遂縱大船去，欲追詎能攀。", "已喜所寄徑，幽尋足谿山。", "仍誇越西部，迥在雲林間。", "屋瓦遍高下，青蒼更回環。", "穿路竹裊裊，鳴沙水潺潺。", "會有樽酒適，每需庭訟閑。", "况席鼓琴舊，政行故非艱。", "歲暮當趨召，馳歸復玉班。"]'),
('45475f6c-3f97-40a9-9b15-385c6a2d0a27','瞿秘校新授官還南豐','曾鞏','宋','宋诗','song-poetry','','[]','柳色映馳道，水聲通御溝。',96,'全唐诗/poet.song.26000.json','["柳色映馳道，水聲通御溝。", "雖喜芳物盛，未同故人遊。", "叩門忽去我，躍馬振輕裘。", "佩印自茲始，過家當少留。", "中園何時到，薇蕨亦已柔。", "山翠入幽屐，渚香浮回舟。", "阡陌有還往，壺觴時獻酬。", "應笑天祿閣，寂寥誰見求。"]'),
('b2f82384-9182-4611-b863-abb8fe00ab75','送程公闢使江西','曾鞏','宋','宋诗','song-poetry','','[]','程侯昔使西山下，金印出懷光滿把。',320,'全唐诗/poet.song.26000.json','["程侯昔使西山下，金印出懷光滿把。", "坐馳雷電破奸伏，力送春陽煦鰥寡。", "袴襦優足遍里巷，禾黍豐穰罄郊野。", "訟庭終日自虛曠，德宇平生本瀟灑。", "龍淵决水漲清沼，鳥背誅林開廣厦。", "蒼顔擁檻四山出，翠色橫檐大江瀉。", "掌平百里露州郭，髪密千甍銜屋瓦。", "雲裘數曲秀蘭蕙，鳳蓋相摩擢梧榎。", "客來尚喜井投轄，主禮寧論燭飛灺。", "三吳月出照金戟，百越風來吹玉斝。", "羽釵絕艷舞回雪，寶劍諸儒談炙輠。", "一尊放意受天籟，萬累回頭真土苴。", "我思飛步綴登躡，又欲生綃乞圖寫。", "身縻東觀願雖阻，日注漳門心豈捨。", "過臨有幸破氛霧，奮厲方欣入陶冶。", "齋航又自日邊去，信節初從天上假。", "舊邦往靖寄揮麈，新穀來輸付流馬。", "遥知素譽在民口，已有歡聲騰里社。", "却尋泉石引幽士，想憶沙塵笑勞者。", "何當一解豫章榻，强賦土風令中雅。"]'),
('ef059ba8-8aba-49b4-94e3-009be03b8c19','遊金山寺作','曾鞏','宋','宋诗','song-poetry','','[]','候潮動鳴艫，出浦縱方舟。',144,'全唐诗/poet.song.26000.json','["候潮動鳴艫，出浦縱方舟。", "舉箔見茲山，巋然峙中流。", "朱堂出烟霧，縹緲若瀛洲。", "十年入夢想，一日恣尋遊。", "屐履上層閣，披襟當九秋。", "地勢已瀟灑，風飆更颼飀。", "遠挹蜀浪來，旁臨滄海浮。", "壺觴對京口，笑語落揚州。", "久聞神龍伏，況睹鷙鳥投。", "行緣石徑盡，却倚巖房幽。", "頗諧雲林思，頓豁塵土憂。", "昏鐘滿江路，歸榜尚夷猶。"]'),
('5f6af8ef-9769-4889-bfad-db17393d6b25','答葛藴','曾鞏','宋','宋诗','song-poetry','','[]','我初未識子，已知子能文。',252,'全唐诗/poet.song.26000.json','["我初未識子，已知子能文。", "春風吹我衣，暮召入九閽。", "衆中得子辭，默許非他人。", "方將引飛黄，使出萬馬群。", "差之在須臾，氣沮不復論。", "大明臨萬物，我亦傍車塵。", "相逢扶桑側，一揖意自親。", "屈子果由我，相示以無言。", "同行千步廊，攬轡金馬門。", "歸來客舍中，未及還往頻。", "東舟載子去，千里不逡巡。", "今者坐甌越，相望若參辰。", "忽有海上使，問我及牆藩。", "得子百篇作，讀之爲忻忻。", "大章已逸發，小章更清新。", "遠去筆墨畦，徒識斧鑿痕。", "想當經營初，落紙有如神。", "勉哉不自止，直可闚靈均。", "我老未厭此，持誇希代珍。", "朝吟忘日昃，暮吟忘日曛。", "發聲欲薦子，自笑不足云。"]'),
('f437e7d8-95cf-4549-8c15-1299f3687473','南湖行二首  其一','曾鞏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','二月南湖春雨多，春風蕩漾吹湖波。',144,'全唐诗/poet.song.26000.json','["二月南湖春雨多，春風蕩漾吹湖波。", "著紅少年里中出，百金市上裁輕羅。", "插花步步行看影，手中掉旅唱吳歌。", "放船縱櫂鼓聲促，蛟龍擘水爭馳逐。", "倏親忽遠誰可追，朝在西城暮南溪。", "奪標得雋唯恐遲，雷轟電激使人迷。", "紅簾彩舫觀者多，美人坐上揚雙蛾。", "斷瓶取酒飲如水，盤中白筍兼青螺。", "生長江湖樂卑濕，不信中州天氣和。"]'),
('d94db24e-a60a-4b87-8dc5-90df23a06e6c','南湖行二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','東南溪水來何長，若耶清明宜靚妝。',160,'全唐诗/poet.song.26000.json','["東南溪水來何長，若耶清明宜靚妝。", "南湖一吸三百里，古人已疑行鏡裏。", "春風來吹不生波，秀壁如奩四邊起。", "蒲芽荇蔓自相依，躑躅夭桃開滿枝。", "求群白鳥映沙去，接翼黄鸝穿樹飛。", "我坐荒城苦卑濕，春至花開曾未知。", "蕩槳如從武陵入，千花百草使人迷。", "山回水轉不知遠，手中紅螺豈須勸。", "輕舟短楫此溪人，相要水上亦湔裙。", "家住橫塘散時晚，分明笑語隔溪聞。"]'),
('43d3f9d4-07b4-4e10-b22e-8da54d62b1ff','種牡丹','曾鞏','宋','宋诗','song-poetry','','[]','經冬種牡丹，明年待看花。',60,'全唐诗/poet.song.26000.json','["經冬種牡丹，明年待看花。", "春條始秀出，蠹已病其芽。", "柯枯葉亦落，重尋但空槎。", "朱欄猶照耀，所待已泥沙。", "本不固其根，今朝謾咨嗟。"]'),
('48340a3f-b75f-4e88-bb63-50dea0de31d8','西湖二月二十日','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生拙人事，出走臨東藩。',96,'全唐诗/poet.song.26000.json','["平生拙人事，出走臨東藩。", "紛此獄訟地，欣乘刀筆閑。", "漾舟明湖上，清鏡照衰顔。", "春風隨我來，掃盡冰雪頑。", "花開滿北渚，水淥到南山。", "魚鳥自翔泳，白雲時往還。", "吾亦樂吾樂，放懷天地間。", "顧視彼誇者，錙銖何足言。"]'),
('8d1e1933-2825-45ee-8c56-43ad7a3fa264','北湖','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','常時泛西湖，已覺烟水永。',144,'全唐诗/poet.song.26000.json','["常時泛西湖，已覺烟水永。", "北堤復誰開，長涵一川靜。", "久幽繇地偏，跬步人迹屏。", "我初得之喜，指顧闢榛梗。", "種花延妙香，插柳待清影。", "飛梁通兩涯，結宇臨四境。", "包羅盡高卑，開拓極壬丙。", "灑然塵滓消，恍爾心目醒。", "興物振滯淹，如人出奇穎。", "日携二三子，杖屨屢觀省。", "念時方有爲，衆智各馳騁。", "獨此得逍遥，固知拙者幸。"]'),
('0d19e212-7354-46df-8d69-b9ce7b73dda2','百花堤','曾鞏','宋','宋诗','song-poetry','','[]','如玉水中沙，誰爲北湖路。',120,'全唐诗/poet.song.26000.json','["如玉水中沙，誰爲北湖路。", "久翳荒草根，未承青霞步。", "我爲發其枉，修營極幽趣。", "髮直而砥平，驊騮可馳騖。", "周以百花林，繁香泫清露。", "間以綠楊陰，芳風轉朝莫。", "飛梁憑太虛，嶢榭躡烟霧。", "直通高城顛，海岱歸指顧。", "爲州乏長材，幸歲足秔稌。", "與衆飽而嬉，陶然無外慕。"]'),
('a20dbae5-a89e-40f7-96db-a204323cdf3c','芙蓉臺','曾鞏','宋','宋诗','song-poetry','','[]','芙蓉花開秋水冷，水面無風見花影。',96,'全唐诗/poet.song.26000.json','["芙蓉花開秋水冷，水面無風見花影。", "飄香上下兩嬋娟，雲在巫山月在天。", "清瀾素礫爲庭戶，羽蓋霓裳不知數。", "臺上遊人下流水，柱脚亭亭插花裏。", "闌邊飲酒櫂女歌，臺北臺南花正多。", "莫笑來時常著屐，綠柳牆連使君宅。"]'),
('62eb66e6-8ea4-4960-a0d0-d74404dcf49d','秋懷二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','流水寒更澹，虛窗深自明。',72,'全唐诗/poet.song.26000.json','["流水寒更澹，虛窗深自明。", "褰帷遠鐘斷，擁褐晨香清。", "油然素心適，緬彼外物輕。", "因時固有應，在理復何營。", "隠几公事退，卷書坐南榮。", "以茲遠塵垢，何異山中情。"]'),
('a8c8cbf2-9a05-40ab-a60f-57554e02852f','秋懷二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','爲州詎非忝，即事亮何成。',73,'全唐诗/poet.song.26000.json','["爲州詎非忝，即事亮何成。", "幸茲桑麻熟，復爾倉箱盈。", "閭里凶黨戢，階除嚚拺訟清。", "日携二三子，飽食中園行。", "念非形勢迫，免有彈弋驚。", "幽閑固可樂，勿慕高遠名。"]'),
('39538ab5-b384-4217-b18a-002d22690655','送李撰赴舉','曾鞏','宋','宋诗','song-poetry','','[]','湖水碧，槐花黄，山川摇落窗戶凉。',112,'全唐诗/poet.song.26000.json','["湖水碧，槐花黄，山川摇落窗戶凉。", "宿雲星稀日東出，青冥風高雁南翔。", "華堂昨夜讀書客，匹馬今朝遊大梁。", "鋒鋩拂塵見飛影，把握驚人持夜光。", "康衢四闢通萬里，天駟得地方騰驤。", "我留東山意頗卓，屏棄外慮無毫芒。", "子能相從味沖漠，捉箠勿暫遲歸裝。"]'),
('b5494b0b-7be9-40de-aff4-d7083e1af4a7','送韓玉汝','曾鞏','宋','宋诗','song-poetry','','[]','野岸漲流水，名園紛雜英。',96,'全唐诗/poet.song.26000.json','["野岸漲流水，名園紛雜英。", "旭景冠蓋集，清談樽酒傾。", "重此臺省秀，駕言江海行。", "已喜懷抱粹，况推材實精。", "衆許極高遠，時方藉經營。", "詎止富中廩，固將澤東氓。", "還當本朝用，不待芳歲更。", "功名自茲始，勿嘆華髪生。"]'),
('7e59ea68-19d8-48d4-b64b-59530ff89295','招隠寺','曾鞏','宋','宋诗','song-poetry','','[]','一徑入松下，兩峰橫馬前。',84,'全唐诗/poet.song.26000.json','["一徑入松下，兩峰橫馬前。", "攀緣綠羅磴，飛步蒼崖巔。", "昔人此嘉遯，手弄朱絲弦。", "想當林間月，獨寫山中泉。", "此樂非外得，肯受世網牽。", "我亦本蕭散，至此更怡然。", "偏憐最幽處，流水鳴濺濺。"]'),
('2741a516-9a4c-4455-92ba-bde19aba29eb','延慶寺會景純正仲希道介夫明叟納凉同觀建鄴宮中畫像翰林墨迹延慶寺者劉裕故宅中有壽丘山','曾鞏','宋','宋诗','song-poetry','','[]','禪方壽丘山，平昔宋公宅。',144,'全唐诗/poet.song.26000.json','["禪方壽丘山，平昔宋公宅。", "好風吹雨來，暑氣一蕩滌。", "我與二三友，歡言同几席。", "神清軼埃𡏖，趣合盡肝膈。", "嶺竹翠尚新，水花紅可摘。", "以此侑樽酒，隤然岸巾幘。", "建鄴舊丹青，金鑾餘翰墨。", "綽約桃李顔，超遥龍虎迹。", "緬矣霸王業，信哉文章伯。", "感古已躊躇，慕奇復嘆息。", "泊無勢利心，自覺衿慮適。", "起坐相扳牽，遲留日將夕。"]'),
('8f706d6d-07c9-4e21-a022-f90fed6927cd','送豐稷','曾鞏','宋','宋诗','song-poetry','','[]','桃花染破南山青，漢江此時春水生。',192,'全唐诗/poet.song.26000.json','["桃花染破南山青，漢江此時春水生。", "客舟相語人夜起，勁櫓亂江群雁聲。", "之君飄泊動歸思，告我舉裝千里行。", "閎材壯思風雨發，綠鬢少年冰雪清。", "讀書一見若經誦，下筆千言能立成。", "精微自得有天質，操行秀出存鄉評。", "嗟從薄祿困流滯，能誘鄙俗銷紛爭。", "弦歌躬勸士强學，田里堵安人力耕。", "嗟予據桉但畫諾，遇事縮手方蒙成。", "雖知璞玉難强獻，欲挂塵榻空含情。", "歲寒不變乃知確，物理先否終當亨。", "維舟且盡今夕語，明日帆隨白鳥輕。"]'),
('f51327df-75aa-4fbe-b826-2a8edf6f4548','不飲酒','曾鞏','宋','宋诗','song-poetry','','[]','不飲酒，不善諧，少年醒眼看花開。',80,'全唐诗/poet.song.26000.json','["不飲酒，不善諧，少年醒眼看花開。", "况從多病久衰耗，自顧白髪垂毰毸。", "縱遇花時少情思，經春不曾銜酒杯。", "布穀但憂天雨少，提壺謾聞山鳥催。", "且坐蒲團紙窗暖，兩衙退後睡敦敦。"]'),
('8e0fe138-5ab3-4c67-b824-c082ad517e92','初發襄陽携家夜登峴山置酒','曾鞏','宋','宋诗','song-poetry','','[]','維舟沔南岸，置酒峴山堂。',96,'全唐诗/poet.song.26000.json','["維舟沔南岸，置酒峴山堂。", "入坐松雨濕，吹衣水風凉。", "烟嶺火明滅，秋湍聲激揚。", "乍釋塵垢累，况餘燈燭光。", "羊公昔宴客，爲樂未遽央。", "而我獨今夕，携家對壺觴。", "頗適麋鹿性，頓驚清興長。", "歸去任酩酊，詎期誇阿强。"]'),
('db6ed0a7-d3d6-484d-88fb-b679d8198f66','高陽池','曾鞏','宋','宋诗','song-poetry','','[]','山公昔在郡，日醉高陽池。',84,'全唐诗/poet.song.26000.json','["山公昔在郡，日醉高陽池。", "歸時誇酩酊，更問并州兒。", "我亦愛池上，眼明見清漪。", "二年始再往，一杯未嘗持。", "念豈公事衆，又非筋力衰。", "局束避世網，低回紲塵羈。", "獨慚曠達意，竊祿誠已卑。"]'),
('f23312e0-c94e-46d5-9e18-7666cf0cde4e','遊鹿門不果','曾鞏','宋','宋诗','song-poetry','','[]','方舟下秋瀨，已遠漢南城。',132,'全唐诗/poet.song.26000.json','["方舟下秋瀨，已遠漢南城。", "念昔在郡日，苦爲塵網嬰。", "低心就薄祿，實負山水情。", "鹿門最秀發，十里行松檉。", "宿幌白雲影，入窗流水聲。", "龐公昔抱道，遯世此躬耕。", "風雨塞天地，伺晨獨先鳴。", "故巖但聞說，已覺醒朝酲。", "及茲道途出，謂諧猿鶴迎。", "顧值深濘阻，獨憐幽思并。", "不踏蘇嶺石，虛作襄陽行。"]'),
('83ae8da1-7cbe-44e9-b1b6-72d83d1fe270','漢廣亭','曾鞏','宋','宋诗','song-poetry','','[]','悠悠漢水長，剡剡楚山密。',96,'全唐诗/poet.song.26000.json','["悠悠漢水長，剡剡楚山密。", "若與心目期，爭從窗戶出。", "太守朴鄙人，迂無適時術。", "治民務不煩，得以偷暇日。", "北城最頻登，局促諧曠逸。", "雲根辨毫芒，鳥背臨嵂崒。", "亦以樂賓遊，豈惟慰衰疾。", "欲寄別後情，嗟無少文筆。"]'),
('bb0d0a8a-0f68-43f7-93ed-a26623be5575','聞喜亭','曾鞏','宋','宋诗','song-poetry','','[]','聞喜名自昔，廣亭臨漢津。',84,'全唐诗/poet.song.26000.json','["聞喜名自昔，廣亭臨漢津。", "飛甍出萬屋，地絕無纖塵。", "盤道城堞古，遠林墟曲新。", "靜覺耕釣勝，幽宜鷗鷺馴。", "頼此荒僻郡，幸容樸愚人。", "閣鈴晝常寂，齋釀寒更醇。", "一樽且勤設，勿負頭上巾。"]'),
('c52c6fa5-7094-4cfe-9a5b-f32d4ca1d2e9','劉景升祠','曾鞏','宋','宋诗','song-poetry','','[]','景升得二蒯，坐論勝凶殘。',96,'全唐诗/poet.song.26000.json','["景升得二蒯，坐論勝凶殘。", "正當喪亂時，能使憔悴寬。", "繽紛多士至，肅穆萬里安。", "能收衆材助，圖大信不難。", "諸公龍鳳姿，有待久盤桓。", "得一固足興，致之豈無端。", "乃獨采樗櫟，不知取椅檀。", "蓋云器有極，在理良足嘆。"]'),
('5ebf72d8-e37a-43cb-b8dd-1ba26e896290','隆中','曾鞏','宋','宋诗','song-poetry','','[]','志士固有待，顯默非苟然。',84,'全唐诗/poet.song.26000.json','["志士固有待，顯默非苟然。", "孔明方微時，息駕隆中田。", "出身感三顧，魚水相後先。", "開迹在庸蜀，欲正九鼎遷。", "垂成中興業，復漢臨秦川。", "平生許與際，獨比管樂賢。", "人材品目異，自得豈虛傳。"]'),
('85c49774-ee7b-43da-9125-7d769e283c91','蔡州','曾鞏','宋','宋诗','song-poetry','','[]','蔡州昔人居，遺堵不可尋。',84,'全唐诗/poet.song.26000.json','["蔡州昔人居，遺堵不可尋。", "青石久埋沒，荒烟起空林。", "昔人依劉表，意氣傳至今。", "廣路競朱轂，深藏閟黄金。", "構難琦琮間，咎責積已深。", "終貽覆宗累，苟得非所欽。", "爲惡理當爾，足懲誇者心。"]'),
('ff38072a-7644-454a-ac1d-f3a96f845bb2','谷隠寺','曾鞏','宋','宋诗','song-poetry','','[]','峴南衆峰外，窅然空谷深。',72,'全唐诗/poet.song.26000.json','["峴南衆峰外，窅然空谷深。", "丹樓倚碧殿，敻出道安林。", "習池抱鄰曲，虛窗漱清音。", "竹靜幽鳥語，果熟孤猿吟。", "故多物外趣，足慰倦客心。", "但恨紲塵羈，無繇數追尋。"]'),
('c5ca1bf3-4b8c-4a40-852a-0a5a29529a9b','萬山','曾鞏','宋','宋诗','song-poetry','','[]','萬山臨漢皋，峰嶺頗秀發。',72,'全唐诗/poet.song.26000.json','["萬山臨漢皋，峰嶺頗秀發。", "王繁舊居處，荒草久埋沒。", "解佩蓋已迷，沉碑終自伐。", "最宜北城望，正值氛靄歇。", "縹緲出烟雲，清明動毛髮。", "留連至歸時，長見西林月。"]'),
('f1f2bea6-3423-4a0c-9ccc-48c844b84520','題張伯常漢上茅堂','曾鞏','宋','宋诗','song-poetry','','[]','遠出清漢上，隠然一堤長。',108,'全唐诗/poet.song.26000.json','["遠出清漢上，隠然一堤長。", "槐柳若雲布，連陰入虛堂。", "架險注鳴溜，分畦殖群芳。", "豈惟富桑柘，蓋亦餘囷倉。", "主人事幽屏，不願尚書郎。", "即此徇高志，風騷恣徜徉。", "强起迫義重，還歸直明光。", "清風凜然在，素壁盈文章。", "故棲勿回眄，黄鵠本高翔。"]'),
('c78375eb-4291-4afa-bf46-35dd042696f2','移守江西先寄潘延之節推','曾鞏','宋','宋诗','song-poetry','','[]','憶昔江西別子時，我初折腰五斗粟。',160,'全唐诗/poet.song.26000.json','["憶昔江西別子時，我初折腰五斗粟。", "南北相望十八年，俯仰飛光如轉燭。", "子遺萬事遂恬曠，我繫一官尚局促。", "早衰膽氣自然薄，多病顛毛那更綠。", "人情畦畛阻肝膈，世路風波悸心目。", "每嗟太守兩朱輪，寧及田家一黄犢。", "幸逢懷紱入斗牛，喜得披山收寶玉。", "薄材頑鈍待磨琢，舊學搶攘期反覆。", "雲鴻可近眼先明，野鹿尚縻顔自忸。", "長鬚幸未阻誨存，下榻應容拜臨辱。"]'),
('d64dd8e0-f44d-4cda-bb06-386bb6cd97f2','漢陽泊舟','曾鞏','宋','宋诗','song-poetry','','[]','暫泊漢陽岸，不登黄鶴樓。',72,'全唐诗/poet.song.26000.json','["暫泊漢陽岸，不登黄鶴樓。", "江含峨岷氣，萬里正東流。", "驚風孤雁起，蔽日寒雲浮。", "祗役雖遠道，放懷成薄遊。", "興隨滄洲發，事等漁樵幽。", "烟波一尊酒，盡室載扁舟。"]'),
('1e6100f0-d9d5-456d-91c0-6f2aee23872d','鄖口','曾鞏','宋','宋诗','song-poetry','','[]','我行去此二十年，鄖水不改流潺湲。',64,'全唐诗/poet.song.26000.json','["我行去此二十年，鄖水不改流潺湲。", "風光滿眼宛如昨，故人乘鸞獨騰騫。", "今人隨我不知昔，我記昔遊何處言。", "淚向幽襟落如瀉，况聞江漢斷腸猿。"]'),
('8641241f-7c86-4da1-90dd-44799743db95','促促爲物役','曾鞏','宋','宋诗','song-poetry','','[]','促促爲物役，區區迫世情。',48,'全唐诗/poet.song.26000.json','["促促爲物役，區區迫世情。", "但嗟束縛急，未覺章綬榮。", "奈此兩鬢白，顧無一廛耕。", "所求亦云幾，脫粟與藜羹。"]'),
('c60f8c2a-2bf1-4cff-879a-279e67576c0f','鴻雁','曾鞏','宋','宋诗','song-poetry','','[]','江南岸邊江水平，水荇青青渚蒲綠。',96,'全唐诗/poet.song.26000.json','["江南岸邊江水平，水荇青青渚蒲綠。", "鴻雁此時儔侶多，亂下沙汀恣棲宿。", "群依青荇唼且鳴，暖浴蒲根戲相逐。", "長無矰繳意自閑，不飽稻粱心亦足。", "性殊凡鳥自知時，飛不亂行聊漸陸。", "豈同白鷺空潔白，俯啄腥污期滿腹。"]'),
('7c25128d-a2ba-4c23-a948-4068ea527a67','喜晴','曾鞏','宋','宋诗','song-poetry','','[]','天晴萬里無纖風，江平水面磨青銅。',160,'全唐诗/poet.song.26000.json','["天晴萬里無纖風，江平水面磨青銅。", "光華逸發萬物上，精氣敻與扶桑通。", "我行江漢道苦惡，十步九折遺西東。", "况遭積雨駕高浪，沙翻石走相撞舂。", "操舟衆工立噤㾕，濕櫓鑽火磨星紅。", "荒蹊成潴尺寸礙，永日四望無人蹤。", "一時得意數蛙黽，鳴躍振踞泥塗中。", "陰消陽勝有先兆，宇宙丹翠含沖融。", "今晨霾曀一掃蕩，羲和徐行驅六龍。", "眼明意豁萬事快，預喜來年麰麥豐。"]'),
('9b991451-3273-474e-b44f-0e3ec998cbc3','酬王正仲登嶽麓寺閣見寄','曾鞏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','聞君東南使，攬轡雲松間。',96,'全唐诗/poet.song.26000.json','["聞君東南使，攬轡雲松間。", "皇華照楚甸，吉玉投衡山。", "幽尋得臨觀，意豁窮躋攀。", "顧我客斗牛，三年疏往還。", "低心念弱志，引領望衰顔。", "未共尊酒樂，良嗟人事艱。", "叱馭犯冰雪，迴鑣馳九關。", "何足慰離思，德音鏘珮環。"]'),
('4ea2367f-a57d-45cb-9a51-b72c924952b8','訪石仙巖杜法師','曾鞏','宋','宋诗','song-poetry','','[]','杜君袖銜丹砂書，一顧訶斥百怪除。',96,'全唐诗/poet.song.26000.json','["杜君袖銜丹砂書，一顧訶斥百怪除。", "聲如翻河落天衢，四方爭迎走高車。", "方瞳秀貌白鬚垂，買船東南尋舊居。", "石巖天開立精廬，四山波瀾勢爭趨。", "君琴一張酒一壺，笑談衮衮樂有餘。", "我今歸來尚踟躕，羨君决發真丈夫。"]'),
('f7e04fe4-b6cb-423e-bb5b-1474e538ccef','曉出','曾鞏','宋','宋诗','song-poetry','','[]','曉出城南羅卒乘，皂纛朱旗密相映。',64,'全唐诗/poet.song.26000.json','["曉出城南羅卒乘，皂纛朱旗密相映。", "貔貅距躍良家子，鵝鸛彌縫司馬令。", "奪標一一飛步疾，盤槊兩兩翻身勁。", "霸上今朝且兒戲，衛青異日須天幸。"]'),
('f2736d47-1504-475b-91dc-e8c78d5b21b9','和貢甫送元考元考不至','曾鞏','宋','宋诗','song-poetry','','[]','蓬山有行客，欲上北城舟。',120,'全唐诗/poet.song.26000.json','["蓬山有行客，欲上北城舟。", "學問本閎博，言談非謬悠。", "嘗陳帝王略，得試紫雲樓。", "一時驚豪捷，况復富春秋。", "朋遊所欣附，爭欲致綢繆。", "承明動鄉思，歲久道苦修。", "忽懷淄川組，夙昔願始酬。", "出餞集儔侶，清歡期少留。", "酒闌竟不至，睠睠久臨流。", "微我獨有咎，此詩聊可求。"]'),
('1f3612e0-3a31-480c-93a1-320cfd8b33f0','京師觀音院新堂','曾鞏','宋','宋诗','song-poetry','','[]','九衢言語亂人耳，三市塵沙瞇人目。',160,'全唐诗/poet.song.26000.json','["九衢言語亂人耳，三市塵沙瞇人目。", "猿狙未慣裹章綬，魚鳥寧忘慕谿谷。", "恨無棲宿在清曠，欲弄潺湲愈煩燠。", "道人誰氏斥佳境，决漢披霄敞華屋。", "駢羅嶷嶷三秀石，叢迸娟娟兩修竹。", "雲蒸雨泄被巖壑，海倒河垂動林麓。", "頓驚俯仰遠囂濁，豈直形骸擺羈束。", "解衣堅坐暝忘返，飲水清談心亦足。", "丈夫壯志須坦蕩，曲士陰機謾翻覆。", "青鞋赤舄偶然爾，安用區區巧追逐。"]'),
('b4e2a319-e289-4937-8a03-f11c6986bebb','郊祀慶成','曾鞏','宋','宋诗','song-poetry','','[]','即祚謳歌後，欽柴禮數新。',144,'全唐诗/poet.song.26000.json','["即祚謳歌後，欽柴禮數新。", "盛容超曠代，樂貢盡殊鄰。", "宿戒臨行殿，宵興絕衆臣。", "立須空便次，步進却柔裀。", "外物雖多品，天心在一純。", "高靈終享德，群望亦依仁。", "暗藹如無間，遲延若可親。", "欲知精意答，預睹太和臻。", "積曀沉遥甸，浮陽上綺闉。", "霱雲生斐亹，愛景駐逡巡。", "厚慶歸清廟，餘釐及兆人。", "還宮動前蹕，喜氣入韶鈞。"]'),
('224bba0f-caa2-439a-a417-8b4e5493f1ef','仁宗皇帝挽詞三首  其一','曾鞏','宋','宋诗','song-poetry','','[]','納諫終無牾，知人久更明。',48,'全唐诗/poet.song.26000.json','["納諫終無牾，知人久更明。", "恩波通四海，壽域載群生。", "異俗衣裳會，諸儒雅頌聲。", "威靈空想象，盛德詎能名。"]'),
('b84fa8f9-b94d-43ab-bcef-ac8ca18dcf09','仁宗皇帝挽詞三首  其二','曾鞏','宋','宋诗','song-poetry','','[]','日轉歸人外，天移入畫中。',48,'全唐诗/poet.song.26000.json','["日轉歸人外，天移入畫中。", "冕旒餘澤在，驚蹕舊儀空。", "卜宅三川繞，方喪萬里通。", "初寒石門路，松檜颯悲風。"]'),
('6c26904c-4ce0-4631-bee0-cc249e06662f','仁宗皇帝挽詞三首  其三','曾鞏','宋','宋诗','song-poetry','','[]','滄海難回日，青雲如送春。',48,'全唐诗/poet.song.26000.json','["滄海難回日，青雲如送春。", "服喪三月遍，遏樂四夷均。", "感格英靈在，褒揚大號新。", "依然社稷計，王業付真人。"]'),
('5af75c8c-edb6-40b7-b705-a44cf9f6d725','英宗皇帝挽詞二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','已應南陽氣，猶遲代邸來。',48,'全唐诗/poet.song.26000.json','["已應南陽氣，猶遲代邸來。", "範鎔歸獨化，綱理付群材。", "禹會方無外，虞巡遂不回。", "空驚柏城仗，簫鼓送餘哀。"]'),
('0ff470af-86d4-43be-8e6f-f3f42d9f23df','英宗皇帝挽詞二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','繼文猶旦暮，歸啟已謳吟。',48,'全唐诗/poet.song.26000.json','["繼文猶旦暮，歸啟已謳吟。", "畫手傳英氣，書筠見德音。", "鑄銅餘故鼎，啄草付春禽。", "試望橋山路，蕭蕭翠柏深。"]'),
('e917e5a6-fefd-4635-bc32-d9e86b47b885','慈聖光獻皇太后挽詞二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','祖烈鷹揚終食冀，家聲泉湧舊興譙。',64,'全唐诗/poet.song.26000.json','["祖烈鷹揚終食冀，家聲泉湧舊興譙。", "人倫風化歸三世，王室功勞屬兩朝。", "長信深嚴餘羽衛，閟宮崇大列宗祧。", "衣冠藉藉談遺事，不盡鴻名對永昭。"]'),
('52e61a86-0115-47ea-80ae-28f48c2f1265','慈聖光獻皇太后挽詞二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','山河德履孚潛顯，江漢仁風被邇遐。',64,'全唐诗/poet.song.26000.json','["山河德履孚潛顯，江漢仁風被邇遐。", "已輔乾坤成化育，終符日月繼光華。", "和熹未寤還威柄，明德猶疏抑外家。", "欲次徽音難仿佛，空餘流恨入哀笳。"]'),
('9aaa9fb7-357c-4728-ac4b-aebb13413a1b','送英州蘇秘丞','曾鞏','宋','宋诗','song-poetry','','[]','遠民歌舞戴升平，碧閣朱樓照眼明。',64,'全唐诗/poet.song.26000.json','["遠民歌舞戴升平，碧閣朱樓照眼明。", "鄉饌雨餘收白蕈，客樽秋後對紅英。", "瀧鳴湞水遥通海，路入南山不隔城。", "材術如君有餘暇，出遊應數擁雙旌。"]'),
('52790286-b85a-4c55-89bd-eae68e717edc','送陳郎中還京兼過九江新宅','曾鞏','宋','宋诗','song-poetry','','[]','鷁舟金碧照溪沙，帆上風吹五兩斜。',64,'全唐诗/poet.song.26000.json','["鷁舟金碧照溪沙，帆上風吹五兩斜。", "罷郡紫泥催向闕，過江紅旆引還家。", "因將舊社人携酒，應喜新林樹見花。", "莫作山齋久留意，中臺虛位有清華。"]'),
('cc65ae7c-2ed0-47c9-9400-dabb100d0303','遣興','曾鞏','宋','宋诗','song-poetry','','[]','青燈鬥鼠窺寒硯，落月啼烏送迥笳。',64,'全唐诗/poet.song.26000.json','["青燈鬥鼠窺寒硯，落月啼烏送迥笳。", "江漢置身貧作客，溪山合眼夢還家。", "百憂忽忽丹心破，萬事悠悠兩鬢華。", "誰與健帆先度鳥，更無留滯向天涯。"]'),
('1c9b459e-4566-43a6-8f72-0006eadc8a84','楚澤','曾鞏','宋','宋诗','song-poetry','','[]','楚澤荒凉白露根，盈虛無處問乾坤。',64,'全唐诗/poet.song.26000.json','["楚澤荒凉白露根，盈虛無處問乾坤。", "蟲蟲旱氣連年有，寂寂遺人幾戶存。", "盜賊恐多從此始，經綸空健與誰論。", "諸公日議雲臺上，忍使憂民獨至尊。"]'),
('0a30715d-268f-462d-8b5f-4e7814612a8b','西亭','曾鞏','宋','宋诗','song-poetry','','[]','團扇頻揮到此亭，他鄉愁坐思冥冥。',64,'全唐诗/poet.song.26000.json','["團扇頻揮到此亭，他鄉愁坐思冥冥。", "空羞避俗無高節，轉覺逢人惡獨醒。", "歲月淹留隨日老，乾坤狼狽幾時寧。", "欲知事事今何似，萬里波濤一點萍。"]'),
('e9a3eae7-56f0-414c-8078-93d39c0feaef','盆池','曾鞏','宋','宋诗','song-poetry','','[]','環環清泚旱猶深，炳炳芙蓉近可尋。',64,'全唐诗/poet.song.26000.json','["環環清泚旱猶深，炳炳芙蓉近可尋。", "蒼壁巧藏天影入，翠奩微带蘚痕侵。", "能供水石三秋興，不負江湖萬里心。", "照影獨憐身老去，日添華髪已盈簪。"]'),
('42133143-4f07-4708-ada6-dc2c9e9fdbdd','羈遊','曾鞏','宋','宋诗','song-poetry','','[]','粗飯寒齏且自如，欲將吾道付樵漁。',64,'全唐诗/poet.song.26000.json','["粗飯寒齏且自如，欲將吾道付樵漁。", "羈遊事事情懷惡，貧病年年故舊疏。", "自古幸容元亮醉，凡今誰喜子雲書。", "何由得洗塵埃盡，恣買滄洲結草廬。"]'),
('4ba5444e-3254-4028-a5df-4c395f5f2b06','南軒竹','曾鞏','宋','宋诗','song-poetry','','[]','密竹娟娟數十莖，旱天蕭灑有高情。',64,'全唐诗/poet.song.26000.json','["密竹娟娟數十莖，旱天蕭灑有高情。", "風吹已送煩心醒，雨洗還供遠眼清。", "新筍巧穿苔石去，碎陰微破粉牆生。", "應須萬物冰霜後，來看琅玕色轉明。"]'),
('c994ac11-29a5-4211-b2aa-583760d75e35','浮雲樓和趙嘏','曾鞏','宋','宋诗','song-poetry','','[]','萬里聊供遠眼開，檐前不盡水聲哀。',64,'全唐诗/poet.song.26000.json','["萬里聊供遠眼開，檐前不盡水聲哀。", "朝雲尚拂陽臺去，羽獵曾圍夢澤來。", "解带欲留長日坐，傾壺難飲故人杯。", "邅窮萬里飄萍內，到此登臨更幾回。"]'),
('8cb41aba-1d13-40a3-8b5d-b185aa024588','照影亭','曾鞏','宋','宋诗','song-poetry','','[]','河流縈檻色輝輝，無數幽禽入鏡飛。',64,'全唐诗/poet.song.26000.json','["河流縈檻色輝輝，無數幽禽入鏡飛。", "已映渚花紅四出，更涵沙柳翠相圍。", "不欺毫髪公雖有，太盡妍媸道恐非。", "自笑病容隨步見，未衰華髪滿緇衣。"]'),
('f29c8565-bd27-47d0-8287-a30baddb566a','晚望','曾鞏','宋','宋诗','song-poetry','','[]','蠻荆人事幾推移，舊國興亡欲問誰。',64,'全唐诗/poet.song.26000.json','["蠻荆人事幾推移，舊國興亡欲問誰。", "鄭袖風流今已盡，屈原辭賦世空悲。", "深山大澤成千古，暮雨朝雲又一時。", "落日西樓憑檻久，閑愁唯有此心知。"]'),
('10836e4f-ef56-4f3e-8801-ae24adf62e16','書閣','曾鞏','宋','宋诗','song-poetry','','[]','自憐野性生來拙，誰許交情晚最親。',64,'全唐诗/poet.song.26000.json','["自憐野性生來拙，誰許交情晚最親。", "世路因仍憂檻阱，他鄉衰暮傍風塵。", "惟將菽藿還求志，未有絲毫可爲人。", "一畝蕭然須暫得，欲偷閑日長精神。"]'),
('ff17b6a3-1599-4ee0-aa33-6fc9091aa965','贈彈琴者','曾鞏','宋','宋诗','song-poetry','','[]','至音淡薄誰曾賞，古意飄零自可憐。',32,'全唐诗/poet.song.26000.json','["至音淡薄誰曾賞，古意飄零自可憐。", "不似秦箏能合意，滿堂傾耳十三弦。"]'),
('746c8bba-8b2e-41ea-83ae-4da2b28d6ab5','寄孫正之','曾鞏','宋','宋诗','song-poetry','','[]','貌癯心苦氣飄飄，長餓空林不可招。',64,'全唐诗/poet.song.26000.json','["貌癯心苦氣飄飄，長餓空林不可招。", "能舉丘山惟筆力，可摩雲日是風標。", "詩篇綴緝應千首，學術窺尋豈一朝。", "耳冷高談經歲遠，江南春動雪還消。"]'),
('737629c1-396c-4fb9-8b6f-7643a36d88dd','秋日感事示介甫','曾鞏','宋','宋诗','song-poetry','','[]','秋日氣己盛，陰蟲朝暮聲。',48,'全唐诗/poet.song.26000.json','["秋日氣己盛，陰蟲朝暮聲。", "烟雲斷溪樹，風雨入山城。", "沙磧有遺虜，旌旗多遠行。", "生民苦未息，吾黨耻論兵。"]'),
('b19e20af-a25e-4e38-a037-e6980f95084e','簡翁都官','曾鞏','宋','宋诗','song-poetry','','[]','倦遊公府曳長裾，笑上扁舟指舊廬。',64,'全唐诗/poet.song.26000.json','["倦遊公府曳長裾，笑上扁舟指舊廬。", "自有文章真杞梓，不須雕琢是璠璵。", "浮蛆滿甕嘗春酒，垂露臨窗理素書。", "况得君賓同壯節，一鄉清問更誰知。"]'),
('3ab6ab4a-8dc8-456d-8a96-791452f4216b','陳祁秀才園亭','曾鞏','宋','宋诗','song-poetry','','[]','眼無塵土境殊清，一繞芳蹊病體輕。',64,'全唐诗/poet.song.26000.json','["眼無塵土境殊清，一繞芳蹊病體輕。", "烟樹疑從古畫見，水軒真在碧天行。", "君能極巧安山勢，我欲忘歸聽竹聲。", "只恐主人難住此，弟兄嘉行滿鄉評。"]'),
('837507d9-3399-4370-a8ab-a78aa10e1dcf','上杜相公','曾鞏','宋','宋诗','song-poetry','','[]','水爲舟楫旱爲霖，社稷生民注意深。',64,'全唐诗/poet.song.26000.json','["水爲舟楫旱爲霖，社稷生民注意深。", "豈謂便辭黄閣議，翻然求就紫芝吟。", "始終好古儒林士，進退憂時國老心。", "只有聲名隨日遠，不令功被管弦音。"]'),
('87ddf908-661a-48ae-bbdb-32d4e6f23437','胡太傅挽詞二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','讜言留簡冊，恭德載閨門。',48,'全唐诗/poet.song.26000.json','["讜言留簡冊，恭德載閨門。", "福履三朝盛，官儀一品尊。", "九原無復起，萬事付誰論。", "不必諸儒記，清名久自存。"]'),
('25f0a4df-2e8b-41e1-aa2c-1b135bc5107f','胡太傅挽詞二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','遠略參基命，雄文入典章。',48,'全唐诗/poet.song.26000.json','["遠略參基命，雄文入典章。", "輤車俄就路，瑞節始還鄉。", "象物陳虛寢，哀歌寄奠觴。", "惟應九原上，松檜日蒼蒼。"]'),
('fcca7313-dc94-4980-9edb-3ced1bd777a0','酬材叔江西道中作','曾鞏','宋','宋诗','song-poetry','','[]','枉渚荒源百里間，草根經燒舊痕乾。',64,'全唐诗/poet.song.26000.json','["枉渚荒源百里間，草根經燒舊痕乾。", "入陂野水冬來淺，對樹諸峰雪後寒。", "塢笛最宜風外聽，嶺梅初得醉中看。", "行尋故友心無事，不覺西遊道路難。"]'),
('a06d2fb6-6783-4407-a6b8-e029786307e2','送雙漸之漢陽','曾鞏','宋','宋诗','song-poetry','','[]','楚國封疆最上流，夾江分命兩諸侯。',64,'全唐诗/poet.song.26000.json','["楚國封疆最上流，夾江分命兩諸侯。", "何年南狩牙檣出，六月西來雪浪浮。", "夏口樓臺供夕望，晴川風物待春遊。", "可能頻度漁陽曲，不負當年鸚鵡洲。"]'),
('8b7401e1-f1c2-46c7-bf46-d572a410a495','孔明','曾鞏','宋','宋诗','song-poetry','','[]','稱吳稱魏已紛紛，渭水西邊獨漢臣。',32,'全唐诗/poet.song.26000.json','["稱吳稱魏已紛紛，渭水西邊獨漢臣。", "平日將軍不三顧，尋常田里带經人。"]'),
('502f106c-040e-46d2-b4df-df6058a9450f','閑行','曾鞏','宋','宋诗','song-poetry','','[]','草軟沙勻野路晴，竹枝烏帽稱閑行。',64,'全唐诗/poet.song.26000.json','["草軟沙勻野路晴，竹枝烏帽稱閑行。", "鳥啼綠樹穿花影，風出青山送水聲。", "轉覺所憂非己事，儘從多難見人情。", "閑中我樂人應笑，忙處人爭我不爭。"]'),
('2f984f60-9d62-4da2-a156-b732f37f848f','贈安禪懃','曾鞏','宋','宋诗','song-poetry','','[]','詎知蕭灑吾廬舊，却有高明此寺鄰。',64,'全唐诗/poet.song.26000.json','["詎知蕭灑吾廬舊，却有高明此寺鄰。", "水竹迸生剛節老，秋山過抱翠嵐新。", "惟憐季子歸來困，自笑原思久更貧。", "深識幽人風義厚，掃軒開榻最相親。"]'),
('467c3a2b-2abf-4875-96a0-c14829b1252d','贈護仁監院','曾鞏','宋','宋诗','song-poetry','','[]','人貧舉世今爲甚，僧事新年始更多。',64,'全唐诗/poet.song.26000.json','["人貧舉世今爲甚，僧事新年始更多。", "食糲衣穿雖擾擾，構虛基險自峨峨。", "誅茅改築君初有，繫馬長吟我暫過。", "但覺滿山金碧澗，不知誰到爲烟蘿。"]'),
('57e81bfc-f36a-4106-bced-4961c94156e6','送覺祖院明上人','曾鞏','宋','宋诗','song-poetry','','[]','冠石新牆日月回，豐堂瓌殿起崔嵬。',64,'全唐诗/poet.song.26000.json','["冠石新牆日月回，豐堂瓌殿起崔嵬。", "鍾隨秋勢金聲壯，佛隠寒雲玉座開。", "流水遠奔雙澗去，平林高擁四山來。", "麒麟細草南東路，一望松門意自哀。"]'),
('7b1ca109-4b15-4c74-8b00-bb7fc0c1930e','謁李白墓','曾鞏','宋','宋诗','song-poetry','','[]','世間遺草三千首，林下荒墳二百年。',64,'全唐诗/poet.song.26000.json','["世間遺草三千首，林下荒墳二百年。", "信矣輝光爭日月，依然精爽動山川。", "曾無近屬持門戶，空有鄉人拂几筵。", "顧我自慚才力薄，欲將何物弔前賢。"]'),
('e4e0934f-b087-4c0b-983f-adc1dd330d69','送撫州錢郎中','曾鞏','宋','宋诗','song-poetry','','[]','名郎元是足風流，得郡東南地更優。',64,'全唐诗/poet.song.26000.json','["名郎元是足風流，得郡東南地更優。", "翠幕管弦三市晚，畫堂烟雨五峰秋。", "黄柑巧綴星垂檻，香稻勻翻雪滿甌。", "應與謝公資健筆，邦人才薄詎能酬。"]'),
('943c29bc-8ff5-43cd-9c07-d52125f8332c','送韓玉汝使兩浙','曾鞏','宋','宋诗','song-poetry','','[]','使傳東馳下九天，此邦曾屈試鳴弦。',64,'全唐诗/poet.song.26000.json','["使傳東馳下九天，此邦曾屈試鳴弦。", "仁聲又向新年入，惠澤猶爲故老傳。", "翠巘煙雲生席上，滄溟風雨到樽前。", "經營智略多餘暇，賞燕誰酬白雪篇。"]'),
('38234885-21fb-466e-9cbb-80806beaeb04','丁元珍挽詞二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','翰墨金聲遠，神情玉氣溫。',48,'全唐诗/poet.song.26000.json','["翰墨金聲遠，神情玉氣溫。", "節廉貧愈見，風義老彌惇。", "舊學資詳正，新儀屬討論。", "誰憐一麾出，終不反修門。"]'),
('485da971-5ff7-4e27-9f76-92018380bc64','丁元珍挽詞二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','從軍王粲筆，記禮后蒼篇。',48,'全唐诗/poet.song.26000.json','["從軍王粲筆，記禮后蒼篇。", "謾有殘書在，能令好事傳。", "鵩來悲四月，鶴去遂千年。", "試想長橋路，昏昏隴隧烟。"]'),
('3da9d09f-4c30-49b6-84c4-69685011e7af','簡景山侍御','曾鞏','宋','宋诗','song-poetry','','[]','長年心事最相親，一笑相疏忽數旬。',64,'全唐诗/poet.song.26000.json','["長年心事最相親，一笑相疏忽數旬。", "柏府地嚴方許國，芸臺官冷但容身。", "饑腸漫竊公厨膳，病髮難堪客舍塵。", "還有鹿門棲宿興，想君他日肯爲鄰。"]'),
('0cbe0b01-a730-4a31-873f-aeb4ac5ee2dc','送李莘太博','曾鞏','宋','宋诗','song-poetry','','[]','郪道鳴弦去，容臺抱蕝初。',48,'全唐诗/poet.song.26000.json','["郪道鳴弦去，容臺抱蕝初。", "塵沙開祖帳，冰雪映征車。", "久待連城價，誰騰一鶚書。", "君王覽豪俊，應復召嚴徐。"]'),
('919527b3-0d9c-47f3-91a0-354a4b0e2660','遊天章寺','曾鞏','宋','宋诗','song-poetry','','[]','籃輿朝出踏輕塵，拂面毿毿柳色新。',64,'全唐诗/poet.song.26000.json','["籃輿朝出踏輕塵，拂面毿毿柳色新。", "曲水豈能留往事，南湖空解照行人。", "最宜靈運登山屐，不負淵明漉酒巾。", "老去飄零心未折，暫須同醉海邊春。"]'),
('0c180efe-19b9-47f8-927d-7c3221b131e4','送關彥遠','曾鞏','宋','宋诗','song-poetry','','[]','莫辭爲我百分飲，從此送君千里行。',64,'全唐诗/poet.song.26000.json','["莫辭爲我百分飲，從此送君千里行。", "物情簪屨尚須念，人道交親那可輕。", "渚梅江柳弄佳色，林鳥野蜂吟好聲。", "對之但醉餘可置，明日此杯誰共傾。"]'),
('daa9d918-70b9-47f5-8832-b6dd1f795c59','送關彥遠赴江西','曾鞏','宋','宋诗','song-poetry','','[]','食飲冰廉士操，敝衣穿履古人風。',63,'全唐诗/poet.song.26000.json','["食飲冰廉士操，敝衣穿履古人風。", "溪堂興足登臨後，滕閣今歸嘯傲中。", "一榻高懸賓閣峻，二龍俱化縣池空。", "因過勝境須行樂，驛召方當急詔東。"]'),
('58546938-b31a-422a-80de-54af64967622','西園席上','曾鞏','宋','宋诗','song-poetry','','[]','省閣名郎國羽儀，瀛洲仙客衆蓍龜。',64,'全唐诗/poet.song.26000.json','["省閣名郎國羽儀，瀛洲仙客衆蓍龜。", "山蹊向日花開早，海聚經寒酒熟遲。", "下榻笑談紅旆偃，引觴醉醒玉釵隨。", "唯慚別乘疏頑甚，滿面塵埃更有詩。"]'),
('742609a3-1cb0-422a-b846-32310a1b3136','送孫穎賢','曾鞏','宋','宋诗','song-poetry','','[]','穰穰秦州鐵馬群，青衫吾子仕猶屯。',64,'全唐诗/poet.song.26000.json','["穰穰秦州鐵馬群，青衫吾子仕猶屯。", "高談消長才驚世，藐視公侯行出人。", "古氣欲遵奔日月，畏塗曾觸滯荆榛。", "明夷夬决應斟酌，自向窮通有屈伸。"]'),
('5a192aaa-c932-4765-8215-e49d5bf0afee','送鄭州邵資政','曾鞏','宋','宋诗','song-poetry','','[]','江夏無雙譽，菑川第一才。',240,'全唐诗/poet.song.26000.json','["江夏無雙譽，菑川第一才。", "笑談成黼藻，咳唾落瓊瑰。", "紫氣鋒鋩露，青冥羽翼開。", "雋遊追幕府，高步集蓬萊。", "探討篇章洽，研磨術業該。", "九霄新漢邸，萬目注梁臺。", "選擇真儒用，招延急詔催。", "衣冠驚角綺，賓友重鄒枚。", "每右橫經席，寧虛置醴杯。", "八荒披日月，萬里散雲雷。", "始去東山榜，俄參北斗魁。", "廟堂奇計得，羌虜鷙心摧。", "帝念人求舊，朝須汝作梅。", "避榮言屢切，請外志難回。", "際海歸封略，連吳入剸裁。", "夕冰承命出，晝錦過鄉來。", "許國風猷壯，容民宇量恢。", "節旄恩換鎮，京室地稱陪。", "賜覲親中扆，通班接上台。", "壺漿空度洧，公位在三槐。"]'),
('d151bf64-1323-4862-ae84-86253fbf2289','看花','曾鞏','宋','宋诗','song-poetry','','[]','春來日日探花開，紫陌看花始此回。',64,'全唐诗/poet.song.26000.json','["春來日日探花開，紫陌看花始此回。", "欲賦妍華無健筆，擬酬芳景怕深盃。", "但知抖擻紅塵去，莫問鬅鬙白髮催。", "更老風情轉應少，且邀佳客試徘徊。"]'),
('0272d976-e413-4a40-b605-643a199dab4b','會稽絕句三首  其一','曾鞏','宋','宋诗','song-poetry','','[]','花開日日去看花，遲日猶嫌影易斜。',32,'全唐诗/poet.song.26000.json','["花開日日去看花，遲日猶嫌影易斜。", "莫問會稽山外事，但將歌管醉流霞。"]'),
('52a6adbf-a5d8-4bdf-9a4f-b5c0825e003f','會稽絕句三首  其二','曾鞏','宋','宋诗','song-poetry','','[]','花開日日插花歸，酒盞歌喉處處隨。',32,'全唐诗/poet.song.26000.json','["花開日日插花歸，酒盞歌喉處處隨。", "不是心閑無此樂，莫教門外俗人知。"]'),
('4c92980f-5e3c-44c7-8e7f-c24d761dae5a','會稽絕句三首  其三','曾鞏','宋','宋诗','song-poetry','','[]','年年穀雨愁春晚，况是江湖兩鬢華。',32,'全唐诗/poet.song.26000.json','["年年穀雨愁春晚，况是江湖兩鬢華。", "欲載一樽乘興去，不知何處有殘花。"]'),
('b58358ab-96c9-4de4-bbcd-e424592d67f8','送任逵度支監嵩山崇福宮','曾鞏','宋','宋诗','song-poetry','','[]','漢陽門下士，車騎幕中賓。',240,'全唐诗/poet.song.26000.json','["漢陽門下士，車騎幕中賓。", "志節初皆壯，風流久更新。", "樞庭承遠派，郎位襲清塵。", "雅淡琴聲古，溫純玉性真。", "詩書來射策，慈惠起臨人。", "淮海褰帷久，褒斜叱馭頻。", "政平無橫吏，刑省絕冤民。", "汴路揚旌出，吳門擁節巡。", "持權心似水，待物氣如春。", "懋德垂承詔，遺榮遽乞身。", "行高寧繫俗，道勝不憂貧。", "北絕分琳館，西歸近紫宸。", "鴻飛開羽翼，驥逸露精神。", "却理烟霞宅，重尋水石鄰。", "青嵩銷鶴怨，碧洛見鷗馴。", "故友欣聯璧，諸儒慕墊巾。", "學兼鴻寶異，興與赤松親。", "激勸留方冊，驚傳動縉紳。", "浮雲雖抗意，仄席正逢辰。", "祇恐尊廉退，丁寧致軟輪。"]'),
('71b220fc-c00f-4dfd-985e-49ddd54217fd','送趙資政','曾鞏','宋','宋诗','song-poetry','','[]','好問逢真主，能言邁古風。',288,'全唐诗/poet.song.26000.json','["好問逢真主，能言邁古風。", "犯顔天意沃，造膝衆情通。", "彈治心忘勢，澄清誼匪躬。", "朝廷推指佞，都邑避乘驄。", "白簡威方厲，青規遇更隆。", "析符霄漢上，開幕斗牛中。", "里聚追胥息，階庭訟缿空。", "紀綱官特峻，帷幄地彌崇。", "吏治連城肅，倉儲絕塞充。", "錦官清鎮俗，玉壘靜臨戎。", "膏澤涵荒阻，春陽煦滯窮。", "鈞衡求雋望，龜筮協淵衷。", "間出千齡合，平居一德同。", "股肱康事力，舟楫濟川功。", "遠大經綸略，精微獻替忠。", "夕冰分外閫，晝錦過江東。", "比戶仁聲入，提封喜氣融。", "信深銷衆僞，明盛破群蒙。", "正洽謳歌美，俄更節制雄。", "保民追呂尚，分土繼逢公。", "淄水移幢碧，牛山駐旆紅。", "魚鹽方舸集，綺繡萬箱叢。", "少憩驅千騎，行歸冠百工。", "衮衣天下咏，豈獨是倥侗。"]'),
('da91707c-b4f9-450a-acc7-eb8fb31d2252','過高士坊','曾鞏','宋','宋诗','song-poetry','','[]','一畝蕭然絕世喧，抗懷那肯就籠樊。',64,'全唐诗/poet.song.26000.json','["一畝蕭然絕世喧，抗懷那肯就籠樊。", "功名晚更爲餘事，災異初嘗出至言。", "郡閣已空徐孺榻，里人猶識鄭公門。", "斯文未喪如繇我，後代當知李仲元。"]'),
('cd06579c-ec31-4723-9d23-5d22aae0e0d1','餘杭久旱趙悅道入境之夕四郊雨足二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','連章天上乞身閑，笑入吳船擁節還。',32,'全唐诗/poet.song.26000.json','["連章天上乞身閑，笑入吳船擁節還。", "一夜風雷驅旱魃，始知霖雨出人間。"]'),
('3fa0c582-8775-4ecc-8225-f1570ad2959f','餘杭久旱趙悅道入境之夕四郊雨足二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','旌旗東下路塵開，六月風雲席上回。',32,'全唐诗/poet.song.26000.json','["旌旗東下路塵開，六月風雲席上回。", "正恐一方人暍死，直將霖雨過江來。"]'),
('d39d47b4-ff57-4494-8b1b-dae249992bd1','錢塘上元夜祥符寺陪咨臣郎中丈燕席','曾鞏','宋','宋诗','song-poetry','','[]','月明如晝露葉濃，錦帳名郎笑語同。',64,'全唐诗/poet.song.26000.json','["月明如晝露葉濃，錦帳名郎笑語同。", "金地夜寒消美酒，玉人春困倚東風。", "紅雲燈火浮滄海，碧水樓臺浸遠空。", "白髮蹉跎歡意少，强顔猶入少年叢。"]'),
('1a627314-f292-4d14-a01e-aa52b4748eee','送沈諫議','曾鞏','宋','宋诗','song-poetry','','[]','東南經濟得時英，方底除書下漢庭。',64,'全唐诗/poet.song.26000.json','["東南經濟得時英，方底除書下漢庭。", "將幕鼓旗驚白晝，諫垣冠劍動青冥。", "指撝甌越歸談笑，鎮壓江吳出醉醒。", "金鼎鹽梅須大用，九霄應已夢儀刑。"]'),
('0a92cc24-031c-400e-835b-57a219655da3','酬王微之汴中見贈','曾鞏','宋','宋诗','song-poetry','','[]','黄流渾渾來沙際，佳氣葱葱近日邊。',64,'全唐诗/poet.song.26000.json','["黄流渾渾來沙際，佳氣葱葱近日邊。", "河漢槎雖通遠客，蓬萊風未縱歸船。", "山城劇飲銷紅燭，水驛高吟襞彩箋。", "老去相逢情自密，不關清賞合留連。"]'),
('638cc795-fee2-413e-9ce7-2f3cc25d4fd1','寄鄆州邵資政','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鉛筆讎書客，朱轓守土臣。',240,'全唐诗/poet.song.26000.json','["鉛筆讎書客，朱轓守土臣。", "素餐方側席，黄髮已侵巾。", "喜有山圍郭，仍憐水滿津。", "清華閑耳目，瀟灑長精神。", "秀色秋來重，寒聲雨後新。", "宿雲當戶牖，流月過松筠。", "北圃分殊境，西湖斷俗塵。", "渚花紅四出，沙鳥翠相親。", "芡老含珠實，魚驚躍錦鱗。", "飛梁凌窅渺，虛榭壓奫淪。", "嶺對橫修竹，洲分抱白蘋。", "靜宜人事拙，閑覺道腴真。", "器小難周物，官微幸庇身。", "簿書偷暇日，杖屨想幽人。", "泝險飛遊艇，探奇漾釣緡。", "形縻甘鶴怨，心泰得鷗馴。", "督府恩容久，芳箋訊問頻。", "門庭嚴衛戟，尊俎從華紳。", "却起烟霞興，還思水石鄰。", "自嗤田父樂，那可薦鴻鈞。"]'),
('ac8d7da9-905a-4645-941f-0f6bfced97e5','和邵資政','曾鞏','宋','宋诗','song-poetry','','[]','拂衣久欲求三徑，竊食聊須把一麾。',64,'全唐诗/poet.song.26000.json','["拂衣久欲求三徑，竊食聊須把一麾。", "世路賤貧從所好，老年胸臆固無奇。", "樊籠偶得滄洲趣，蕪纇難酬白雪辭。", "督府繇來恩禮厚，每容商也與言詩。"]'),
('8fdeac5d-7eb5-47ee-bf00-f9c4ca5b04d9','和孔教授','曾鞏','宋','宋诗','song-poetry','','[]','治煩方喜衆材同，坐嘯南陽郡閣中。',64,'全唐诗/poet.song.26000.json','["治煩方喜衆材同，坐嘯南陽郡閣中。", "几案有塵書檄簡，里閭無事稻粱豐。", "衣冠濟濟歸儒學，俎豆詵詵得古風。", "幸屈異能來助我，敢將顔色在蜚鴻。"]'),
('ebf55fab-a89c-4021-857a-2899652680c3','喜雪二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','欲休還舞任風吹，斷續繁雲作陣隨。',64,'全唐诗/poet.song.26000.json','["欲休還舞任風吹，斷續繁雲作陣隨。", "已塞茅蹊人起晚，更迷沙渚鳥飛遲。", "混同天地歸無迹，潤色山川入有爲。", "太守不辭留客醉，豐年佳兆可前知。"]'),
('c9ce0c8b-6da8-42be-ad4c-54f91f370ad0','喜雪二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','雜雨零初急，因風灑更狂。',120,'全唐诗/poet.song.26000.json','["雜雨零初急，因風灑更狂。", "英華傾月窟，光氣瀉天潢。", "宛轉花飛密，紆餘舞態長。", "化材隨大小，成器任圓方。", "秀已滋山國，清尤助水鄉。", "色嚴齊上下，明盛析毫芒。", "潤屋情誇誕，埋輪興激昂。", "收功歸澤物，全德在包荒。", "預喜倉箱富，潛知海嶽康。", "蕭晨迎賀客，歌吹趣傳觴。"]'),
('6017c0e6-5d89-4d7f-94fa-5faf98d5a941','雪後同徐秘丞皇甫節推孔教授北園晚步','曾鞏','宋','宋诗','song-poetry','','[]','沙草正黄瀕海意，江梅還白故園情。',64,'全唐诗/poet.song.26000.json','["沙草正黄瀕海意，江梅還白故園情。", "循除遠水春前急，繞郭空山雪後明。", "林影易斜寒日短，角聲吹去暮雲平。", "最慚佳客忘形契，肯伴衰翁著屐行。"]'),
('9a940276-8e09-4323-bd6a-97e51118bb67','郡齋即事二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','畫戟森門寵誤蒙，從來田舍一衰翁。',64,'全唐诗/poet.song.26000.json','["畫戟森門寵誤蒙，從來田舍一衰翁。", "囷倉穰穰逢康歲，閭里恂恂有古風。", "瞷氏宿奸投海外，伏生新學始山東。", "依然自昔興王地，長在南陽佳氣中。"]'),
('da70042b-e579-46af-afa2-e841925ddb41','郡齋即事二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','滿軒山色長浮黛，繞舍泉聲不受塵。',64,'全唐诗/poet.song.26000.json','["滿軒山色長浮黛，繞舍泉聲不受塵。", "四境带牛無事日，兩衙封印自繇身。", "白羊酒熟初看雪，黄杏花開欲探春。", "總是濟南爲郡樂，更將詩興屬何人。"]'),
('cf62b41f-04b6-471a-ac3b-6a4c279370c7','憶越中梅','曾鞏','宋','宋诗','song-poetry','','[]','浣沙亭北小山梅，蘭渚移來手自栽。',32,'全唐诗/poet.song.26000.json','["浣沙亭北小山梅，蘭渚移來手自栽。", "今日舊林冰雪地，泠香幽艷向誰開。"]'),
('b5511b00-20f6-412e-a448-aa3435bd6810','再賦喜雪','曾鞏','宋','宋诗','song-poetry','','[]','六花飛舞勢蹁躚，點綴寒林態更妍。',64,'全唐诗/poet.song.26000.json','["六花飛舞勢蹁躚，點綴寒林態更妍。", "山險龍蛇盤鳥道，野平江海變畬田。", "人狂奔月非關夜，馬健乘雲別有天。", "况值白羊新酒熟，可能相就慶豐年。"]'),
('d522d2e2-12b1-4cb9-9662-033a9fdb06e9','寄致仕歐陽少師','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四海文章伯，三朝社稷臣。',240,'全唐诗/poet.song.26000.json','["四海文章伯，三朝社稷臣。", "功名垂竹帛，風義動簪紳。", "此道推先覺，諸儒出後塵。", "忘機心皎皎，樂善意循循。", "大略才超古，昌言勇絕人。", "抗懷輕紱冕，瀝懇謝陶鈞。", "耕稼歸莘野，畋漁返渭濱。", "五年清興屬，一日壯圖伸。", "北闕恩知舊，東宮命數新。", "鸞凰開羽翼，驥騄放精神。", "曠達林中趣，高閑物外身。", "揮金延故老，置驛候嘉賓。", "主當西湖月，勾留潁水春。", "露寒消鶴怨，沙靜見鷗馴。", "酒熟誇浮蟻，書成感獲麟。", "激昂疏受晚，沖淡赤松親。", "龍卧傾時望，鴻冥聳士倫。", "少休均逸豫，獨往異沉淪。", "策畫咨詢急，儀刑矚想頻。", "應須協龜筮，更起爲生民。"]'),
('661951e6-c4a6-481b-bf30-8e9eb3cc2a49','冬夜即事','曾鞏','宋','宋诗','song-poetry','','[]','印奩封罷閣鈴閑，喜有秋毫免素餐。',64,'全唐诗/poet.song.26000.json','["印奩封罷閣鈴閑，喜有秋毫免素餐。", "市粟易求倉廩實，邑尨無警里閭安。", "香清一榻氍毹暖，月淡千門霿凇寒。", "聞說豐年從此始，更回籠燭卷簾看。"]'),
('7eb84ee5-2449-469e-994e-0b9f026b8b4d','酬介甫還自舅家書所感','曾鞏','宋','宋诗','song-poetry','','[]','旱氣滿原野，子行歸舊廬。',48,'全唐诗/poet.song.26000.json','["旱氣滿原野，子行歸舊廬。", "籲天高未動，望歲了何如。", "荒土欲生火，涸溪容過車。", "民期得霖雨，吾豈灌園蔬。"]'),
('9082f32b-e129-4f38-b013-4e01fbff4894','西湖二首  其一','曾鞏','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u897f\u6e56"]','左符千里走東方，喜有西湖六月凉。',64,'全唐诗/poet.song.26000.json','["左符千里走東方，喜有西湖六月凉。", "塞上馬歸終反覆，泰山鴟飽正飛揚。", "懶宜魚鳥心常靜，老覺詩書味更長。", "行到平橋初見日，滿川風露紫荷香。"]'),
('5f79460f-359c-473a-a24d-03c22b07e35f','西湖二首  其二','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖面平隨葦岸長，碧天垂影入清光。',64,'全唐诗/poet.song.26000.json','["湖面平隨葦岸長，碧天垂影入清光。", "一川風露荷花曉，六月蓬瀛燕坐凉。", "滄海桴浮成曠蕩，明河槎上更微茫。", "何須辛苦求人外，自有仙鄉在水鄉。"]'),
('449c87ec-ddbb-45a3-b5fb-89e813fda260','早起赴行香','曾鞏','宋','宋诗','song-poetry','','[]','枕前聽盡小梅花，起見中庭月未斜。',64,'全唐诗/poet.song.26000.json','["枕前聽盡小梅花，起見中庭月未斜。", "微破宿雲猶度雁，欲深烟柳已藏鴉。", "井轤聲急推寒玉，籠燭光繁秉絳紗。", "行到市橋人語密，馬頭依約對朝霞。"]'),
('86e22fce-8c0f-489c-80b6-1d9025e087f3','席上','曾鞏','宋','宋诗','song-poetry','','[]','市井蕭條烟火微，兩衙散後雪深時。',32,'全唐诗/poet.song.26000.json','["市井蕭條烟火微，兩衙散後雪深時。", "若無一曲傳金盞，爭奈衰翁兩鬢絲。"]'),
('612db25f-b4f4-4141-ab94-a583e739fe49','和陳郎中','曾鞏','宋','宋诗','song-poetry','','[]','材薄安時甘寂寞，身閑乘興喜登臨。',64,'全唐诗/poet.song.26000.json','["材薄安時甘寂寞，身閑乘興喜登臨。", "每尋香草牽狂思，曾向幽蘭費苦吟。", "明月幾人非按劍，高山從古少知音。", "數篇清絕賡歌意，默見馮唐異俗心。"]'),
('f025cfaf-9c50-4563-bf24-13f9e0bdc742','雪後','曾鞏','宋','宋诗','song-poetry','','[]','雪景鮮妍猶弄色，柳條葱蒨已抽萌。',64,'全唐诗/poet.song.26000.json','["雪景鮮妍猶弄色，柳條葱蒨已抽萌。", "風光苒苒流雙轂，人事悠悠寄一枰。", "射羿未應今獨有，嘲雄何必史能評。", "且將畫諾供談笑，更選名園載酒行。"]'),
('0252aa4d-bd4a-44d0-8773-44e3c1399efc','舜泉','曾鞏','宋','宋诗','song-poetry','','[]','山麓舊耕迷故壟，井幹餘汲見飛泉。',64,'全唐诗/poet.song.26000.json','["山麓舊耕迷故壟，井幹餘汲見飛泉。", "清涵廣陌能成雨，冷浸平湖別有天。", "南狩一時成往事，重華千古似當年。", "更應此水無休歇，餘澤人間世世傳。"]'),
('dcbb6591-4257-45af-82c9-00a0aa291c44','閱武堂','曾鞏','宋','宋诗','song-poetry','','[]','五朝壞冶歸皇極，萬里車書共太平。',64,'全唐诗/poet.song.26000.json','["五朝壞冶歸皇極，萬里車書共太平。", "胡馬不闚光祿塞，漢家常肄羽林兵。", "柳間自詫投壺樂，桑下方安佩犢行。", "高枕四封無一事，腐儒何幸偶專城。"]'),
('9bef35bb-140c-4eb0-a9d0-a74b48afb15b','環波亭','曾鞏','宋','宋诗','song-poetry','','[]','水心還有拂雲堆，日日應須把酒杯。',64,'全唐诗/poet.song.26000.json','["水心還有拂雲堆，日日應須把酒杯。", "楊柳巧含烟景合，芙蓉爭带露華開。", "城頭山色相圍出，檐底波聲四面來。", "誰信瀛洲未歸去，兩州俱得小蓬萊。"]'),
('640ffaad-1023-4b03-be7d-3af8247755b6','鵲山亭','曾鞏','宋','宋诗','song-poetry','','[]','大亭孤起壓城顛，屋角峨峨插紫煙。',64,'全唐诗/poet.song.26000.json','["大亭孤起壓城顛，屋角峨峨插紫煙。", "濼水飛綃來野岸，鵲山浮黛入晴天。", "少陵騷雅今誰和，東海風流世謾傳。", "太守自吟還自笑，歸來乘月尚留連。"]'),
('825dff1b-2bd3-450c-aca3-3cf7e1cd32f4','芍藥廳','曾鞏','宋','宋诗','song-poetry','','[]','小碧闌干四月天，露紅煙紫不勝妍。',64,'全唐诗/poet.song.26000.json','["小碧闌干四月天，露紅煙紫不勝妍。", "肯爲雲住陽臺女，恐逐風飛飾室仙。", "洧外送歸情放蕩，省中番直勢拘攣。", "何如蕭灑山城守，淺酌清吟濟水邊。"]'),
('5fe31470-b1da-49a1-a82e-d98e7a0c856b','水香亭','曾鞏','宋','宋诗','song-poetry','','[]','臨池飛構鬰岧嶢，櫺檻無風影自摇。',64,'全唐诗/poet.song.26000.json','["臨池飛構鬰岧嶢，櫺檻無風影自摇。", "群玉過林抽翠竹，雙虹垂岸跨平橋。", "煩依美藻魚爭餌，清見寒沙水滿橈。", "莫問荷花開幾曲，但知行處異香飄。"]'),
('0d7be627-cdac-4e0c-99c5-11b1eec56517','靜化堂','曾鞏','宋','宋诗','song-poetry','','[]','修檐䡾䡾背成陰，行盡松篁一徑深。',64,'全唐诗/poet.song.26000.json','["修檐䡾䡾背成陰，行盡松篁一徑深。", "好鳥自飛還自下，白雲無事亦無心。", "客來但飲平陽酒，衙退常携靖節琴。", "世路人情方擾擾，一遊須抵萬黄金。"]'),
('549026da-f043-4f49-b946-5356020ede5f','仁風廳','曾鞏','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','凜凜風生寄此堂，塵埃消盡興何長。',64,'全唐诗/poet.song.26000.json','["凜凜風生寄此堂，塵埃消盡興何長。", "朱絲鼓舞逢千載，白羽吹揚慰一方。", "已散浮雲滄海上，更飛霖雨泰山傍。", "誰知萬物心焦日，獨對松筠四座凉。"]'),
('94eb43bb-76e9-4c44-97ed-c38149685f91','閱武堂下新渠','曾鞏','宋','宋诗','song-poetry','','[]','方渠新鑿北林開，流水遥經畫閣來。',64,'全唐诗/poet.song.26000.json','["方渠新鑿北林開，流水遥經畫閣來。", "洗耳厭聞誇勢利，濯纓羞去傍塵埃。", "不憂待月乾詩筆，已欲看華泛酒杯。", "却憶虎溪橋上過，夜凉臨砌尚徘徊。"]'),
('18ec35c8-306a-4d06-95e6-018ad76ce771','凝香齋','曾鞏','宋','宋诗','song-poetry','','[]','每覺西齋景最幽，不知官是古諸侯。',64,'全唐诗/poet.song.26000.json','["每覺西齋景最幽，不知官是古諸侯。", "一尊風月身無事，千里耕桑歲有秋。", "雲水醒心鳴好鳥，玉沙清耳漱寒流。", "沉烟細細臨黄卷，疑在香爐最上頭。"]'),
('5bb3f5a4-a978-40b2-8aa2-efaf0e272715','北渚亭','曾鞏','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','四楹虛徹地無鄰，斷送孤高與使君。',64,'全唐诗/poet.song.26000.json','["四楹虛徹地無鄰，斷送孤高與使君。", "午夜坐臨滄海日，半天吟看泰山雲。", "青徐氣接川原秀，常碣風連草木薰。", "莫笑一樽留戀久，下階塵土便紛紛。"]'),
('88059c1d-5198-4b72-8d91-b59fa3eef938','芙蓉橋','曾鞏','宋','宋诗','song-poetry','','[]','雁翅橫連杜若洲，碧闌干影在中流。',32,'全唐诗/poet.song.26000.json','["雁翅橫連杜若洲，碧闌干影在中流。", "蓬萊日日遊人到，誰道仙風解引舟。"]'),
('c5a77f3d-82ae-492a-b882-dbd20b4c3a3b','百花臺','曾鞏','宋','宋诗','song-poetry','','[]','烟波與客同樽酒，風月全家上采舟。',32,'全唐诗/poet.song.26000.json','["烟波與客同樽酒，風月全家上采舟。", "莫問臺前花遠近，試看何似武陵遊。"]'),
('ea406723-ff4a-401f-b5c8-86692d492183','次道子中書問歸期','曾鞏','宋','宋诗','song-poetry','','[]','竊食東州歲未期，蓬萊人問幾時歸。',64,'全唐诗/poet.song.26000.json','["竊食東州歲未期，蓬萊人問幾時歸。", "憑闌到處臨清泚，開閣終朝對翠微。", "兩印每閑軍市靜，雙旌多偃送迎稀。", "一枝數粒身安穩，不羨雲鵬九萬飛。"]'),
('78ed8f16-583f-4ada-affc-660eaff5e967','霿凇','曾鞏','宋','宋诗','song-poetry','','[]','園林初日靜無風，霿凇花開處處同。',32,'全唐诗/poet.song.26000.json','["園林初日靜無風，霿凇花開處處同。", "記得集英深殿裏，舞人齊插玉籠𩭤。"]'),
('f726c250-d6b1-4c32-b10f-10dea52e7fab','正月六日雪霽','曾鞏','宋','宋诗','song-poetry','','[]','雪消山水見精神，滿眼東風送早春。',32,'全唐诗/poet.song.26000.json','["雪消山水見精神，滿眼東風送早春。", "明日杏園應爛熳，便須期約看花人。"]'),
('118ebe23-1dff-403c-bf39-68ef18800b31','寄顧子敦','曾鞏','宋','宋诗','song-poetry','','[]','清曠亭邊雁欲回，南湖分浪入城來。',64,'全唐诗/poet.song.26000.json','["清曠亭邊雁欲回，南湖分浪入城來。", "空山過臘猶藏雪，野岸先春已放梅。", "三徑未歸聊自適，一尊尋勝每同開。", "如今試想長松下，玉麈高談豈易陪。"]'),
('2fe0eb48-30bb-4349-8ab9-de42b6ac678a','二月八日北城閑步','曾鞏','宋','宋诗','song-poetry','','[]','土膏初動麥苗青，飽食城頭信意行。',32,'全唐诗/poet.song.26000.json','["土膏初動麥苗青，飽食城頭信意行。", "便起高亭臨北渚，欲乘長日勸春耕。"]'),
('95d75f69-a301-4c8b-ad04-8935b5dfdaab','咏柳','曾鞏','宋','宋诗','song-poetry','','["\u6625\u5929", "\u548f\u7269", "\u67f3\u6811", "\u8bbd\u523a", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','亂條猶未變初黄，倚得東風勢便狂。',32,'全唐诗/poet.song.26000.json','["亂條猶未變初黄，倚得東風勢便狂。", "解把飛花蒙日月，不知天地有清霜。"]'),
('cefa36e9-dc89-4ea5-b2f9-a8e02a3fd3c5','北園會客不飲','曾鞏','宋','宋诗','song-poetry','','[]','畫橋南北水西東，高下花枝綠間紅。',32,'全唐诗/poet.song.26000.json','["畫橋南北水西東，高下花枝綠間紅。", "殢得春風人盡醉，獨醒誰似白頭翁。"]'),
('73ab8b6a-3e23-4775-bca5-f3985b55afed','西湖納凉','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','問吾何處避炎蒸，十頃西湖照眼明。',64,'全唐诗/poet.song.26000.json','["問吾何處避炎蒸，十頃西湖照眼明。", "魚戲一篙新浪滿，鳥啼千步綠陰成。", "虹腰隠隠松橋出，鷁首峨峨畫舫行。", "最喜晚凉風月好，紫荷香裏聽泉聲。"]'),
('e0cb313e-d971-453e-aec5-4f2097c04e8a','喜雨','曾鞏','宋','宋诗','song-poetry','','[]','偶徇一官偷祿計，便懷千里長人憂。',64,'全唐诗/poet.song.26000.json','["偶徇一官偷祿計，便懷千里長人憂。", "桑間舉箔蠶初繭，隴上揮鐮麥已秋。", "更喜風雷生北極，頓驅雲雨出靈湫。", "從今菽粟非虛禱，會見甌窶果滿篝。"]'),
('e6bc9baa-8685-4a3f-a7c8-9eba3f62b3d2','雨後環波亭次韵 次李秀才得魚字韵','曾鞏','宋','宋诗','song-poetry','','[]','候月已知星好雨，卜年方喜夢維魚。',32,'全唐诗/poet.song.26000.json','["候月已知星好雨，卜年方喜夢維魚。", "從今撥置庭中事，最喜西軒睡枕書。"]'),
('b123f10f-31f5-4ced-85c2-e31aecf61f32','雨後環波亭次韵 次綰得風字韵','曾鞏','宋','宋诗','song-poetry','','[]','荷芰東西魚映葉，樵舟朝暮客乘風。',32,'全唐诗/poet.song.26000.json','["荷芰東西魚映葉，樵舟朝暮客乘風。", "清泉雨後分毛髮，何必南湖是鏡中。"]'),
('24c73cfa-6adb-4b0f-b414-9cf35060f47e','雨後環波亭次韵 次維得禽字韵','曾鞏','宋','宋诗','song-poetry','','[]','黄蜀葵開收宿雨，紫桑椹熟囀新禽。',32,'全唐诗/poet.song.26000.json','["黄蜀葵開收宿雨，紫桑椹熟囀新禽。", "看花弄水非無事，猶勝紛紛別用心。"]'),
('14ac021f-9aa4-4301-aa15-1d3fc0b08479','雨後環波亭次韵 次綜得花字韵','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丹杏一番收美實，綠荷無數放新花。',32,'全唐诗/poet.song.26000.json','["丹杏一番收美實，綠荷無數放新花。", "西湖雨後清心目，坐到城頭泊暝鴉。"]'),
('24fe91c3-01c3-41bf-ae58-b554d910fef4','去年久旱六月十三日入境得雨今年復旱得雨亦六月十三日也','曾鞏','宋','宋诗','song-poetry','','[]','去年六月焦原雨，入得東州第一朝。',32,'全唐诗/poet.song.26000.json','["去年六月焦原雨，入得東州第一朝。", "今日看雲舊時節，又來農畔聽蕭蕭。"]'),
('2ce78483-7a9d-4c4f-beac-a2bd949686fd','到郡一年','曾鞏','宋','宋诗','song-poetry','','[]','薄材何幸擁朱軒，竊食東州已一年。',64,'全唐诗/poet.song.26000.json','["薄材何幸擁朱軒，竊食東州已一年。", "隴上雨餘看麥秀，桑間日永問蠶眠。", "官名雖冗身無累，心事長閑地自偏。", "祇恐再期官滿去，每來湖岸合留連。"]'),
('68b22390-78f3-4746-b036-9a07de4b97be','孔教授張法曹以曾論薦特示長箋','曾鞏','宋','宋诗','song-poetry','','[]','綠髮朱顔兩少年，出倫清譽每相先。',64,'全唐诗/poet.song.26000.json','["綠髮朱顔兩少年，出倫清譽每相先。", "壁中字爲時人考，圯上書從老父傳。", "泮水笑談邀法飲，高齋閑燕屬佳篇。", "衰翁厚幸懷雙璧，更起狂心慕薦賢。"]'),
('f4ef1f31-0bc6-4e4d-9405-acdc13e0b0ff','酬强幾聖','曾鞏','宋','宋诗','song-poetry','','[]','俯仰林泉繞舍清，經年閑卧濟南城。',64,'全唐诗/poet.song.26000.json','["俯仰林泉繞舍清，經年閑卧濟南城。", "山田雨足心無事，水榭華開眼更明。", "新霽煙雲飛觀出，晚凉歌吹畫橋橫。", "寄聲裴令樽前客，祇欠高談一座傾。"]'),
('43af6467-fb88-4f47-8c45-e170726823d5','人情','曾鞏','宋','宋诗','song-poetry','','[]','人情當面蔽山丘，誰可論心向白頭。',64,'全唐诗/poet.song.26000.json','["人情當面蔽山丘，誰可論心向白頭。", "天祿閣非真學士，玉麟符是假諸侯。", "詩書落落成孤論，耕釣依依憶舊遊。", "早晚抽簪江海去，笑將風月上扁舟。"]'),
('433b53b2-1835-4c2c-ab18-3067daf27b8c','寄王樂道','曾鞏','宋','宋诗','song-poetry','','[]','荆州南走困塵埃，應喜文章意自開。',64,'全唐诗/poet.song.26000.json','["荆州南走困塵埃，應喜文章意自開。", "明世正逢多事日，要塗須用出倫材。", "不回霜雪天應惜，未得風雲衆忍摧。", "若向沙頭弔杜甫，近詩懸望自書來。"]'),
('c7c1b86b-f0f6-4195-8d40-7e60e60cd441','戲書','曾鞏','宋','宋诗','song-poetry','','[]','集賢自笑文章少，爲郡誰言樂事多。',64,'全唐诗/poet.song.26000.json','["集賢自笑文章少，爲郡誰言樂事多。", "報答書題親筆硯，逢迎使客聽笙歌。", "一心了了無人語，兩鬢蕭蕭奈老何。", "還有不隨流俗處，秋毫無累損天和。"]'),
('6189967b-5097-4320-ae09-87fd582aaaa6','贈張濟','曾鞏','宋','宋诗','song-poetry','','[]','憶初蘭渚訪沉淪，一畝蕭然里舍貧。',64,'全唐诗/poet.song.26000.json','["憶初蘭渚訪沉淪，一畝蕭然里舍貧。", "節行久窮彌好古，文章垂老更驚人。", "詩書就我論新意，冠劍投誰拂舊塵。", "山驛荒凉煩枉道，一觴相屬莫嫌頻。"]'),
('31fa6aea-a02f-4842-82df-bf0bc13f34a4','北渚亭雨中','曾鞏','宋','宋诗','song-poetry','','[]','振衣已出塵土外，卷箔更當風雨間。',64,'全唐诗/poet.song.26000.json','["振衣已出塵土外，卷箔更當風雨間。", "泉聲漸落石溝澗，雲氣迥壓金輿山。", "寒沙漠漠鳥飛去，野路悠悠人自還。", "耕桑千里正無事，况有樽酒聊開顔。"]'),
('98e9f193-71cd-48cd-ae97-702436b6a6cb','送趙資政','曾鞏','宋','宋诗','song-poetry','','[]','鎮撫西南衆望傾，玉書天上輟持衡。',64,'全唐诗/poet.song.26000.json','["鎮撫西南衆望傾，玉書天上輟持衡。", "春風不覺岷山遠，和氣還從錦水生。", "學舍却尋餘教在，棠郊應喜舊陰成。", "歸來促召調爐冶，莫爲兒童竹馬迎。"]'),
('8511320c-9e25-4c63-89a0-c211f5724d04','趵突泉','曾鞏','宋','宋诗','song-poetry','','[]','一派遥從玉水分，暗來都灑歷山塵。',64,'全唐诗/poet.song.26000.json','["一派遥從玉水分，暗來都灑歷山塵。", "滋榮冬茹溫常早，潤澤春茶味更真。", "已覺路傍行似鑑，最憐沙際涌如輪。", "曾成齊魯封疆會，况託娥英詫世人。"]'),
('51d3bf20-1f25-4f48-993c-d6fcf73a7a44','金線泉','曾鞏','宋','宋诗','song-poetry','','[]','玉甃常浮灝氣鮮，金絲不定路南泉。',64,'全唐诗/poet.song.26000.json','["玉甃常浮灝氣鮮，金絲不定路南泉。", "雲依美藻爭成縷，月照寒漪巧上弦。", "已繞渚花紅灼灼，更縈沙竹翠娟娟。", "無風到底塵埃盡，界破冰綃一片天。"]'),
('03495e9c-595c-4e7a-9317-4b0254c1774e','北池小會','曾鞏','宋','宋诗','song-poetry','','[]','笑語從容酒慢巡，笙歌隨賞北池春。',64,'全唐诗/poet.song.26000.json','["笑語從容酒慢巡，笙歌隨賞北池春。", "波間鏤檻花迷眼，沙際朱橋柳拂人。", "金縷暗移泉溜急，銀簧相合鳥聲新。", "幸時無事須行樂，物外乾坤一點塵。"]'),
('d5eaadd6-4cca-4f10-b7ba-0cdfebe50de9','送韓廷評','曾鞏','宋','宋诗','song-poetry','','[]','謝庭冠蓋舊追尋，僻郡相從喜更深。',64,'全唐诗/poet.song.26000.json','["謝庭冠蓋舊追尋，僻郡相從喜更深。", "進道由來輕拱璧，傳經知不羨籝金。", "騏騮要試風沙遠，竹柏須忘霰雪侵。", "別後壯懷應努力，白頭傾耳聽徽音。"]'),
('8ac30468-c257-4a45-a5ad-8a5a16179b44','寄孫莘老湖州墨妙亭','曾鞏','宋','宋诗','song-poetry','','[]','隆名盛位知難久，壯字豐碑亦易亡。',64,'全唐诗/poet.song.26000.json','["隆名盛位知難久，壯字豐碑亦易亡。", "棗木已非真篆刻，色絲空喜好文章。", "峴山漢水成虛擲，大厦深檐且秘藏。", "好事今推霅溪守，故開新館集琳琅。"]'),
('35e2a88c-add3-4ed4-adf1-52d8063568f8','鵲山','曾鞏','宋','宋诗','song-poetry','','[]','一峰孤起勢崔嵬，秀色挼藍入酒杯。',64,'全唐诗/poet.song.26000.json','["一峰孤起勢崔嵬，秀色挼藍入酒杯。", "靈藥已從清露得，平湖長泛宿雲回。", "翰林明月舟中過，司馬虛亭竹外開。", "我亦退公思蠟屐，會看歸路送人來。"]'),
('39aa0559-9cee-4b83-9e12-5cbd8555905b','華不注山','曾鞏','宋','宋诗','song-poetry','','[]','虎牙千仞立巉巉，峻拔遥臨濟水南。',64,'全唐诗/poet.song.26000.json','["虎牙千仞立巉巉，峻拔遥臨濟水南。", "翠嶺嫩嵐晴可掇，金輿陳迹久誰探。", "高標特起青雲近，壯士三周戰氣酣。", "丑父遺忠無處問，空餘一掬野泉甘。"]'),
('96864b05-58c9-4296-9393-9cf353842f5a','靈巖寺兼簡重元長老二劉居士','曾鞏','宋','宋诗','song-poetry','','[]','法定禪房臨峭谷，辟支靈塔冠層巒。',64,'全唐诗/poet.song.26000.json','["法定禪房臨峭谷，辟支靈塔冠層巒。", "軒窗勢聳雲林合，鐘磬聲高鳥道盤。", "白鶴已飛泉自湧，青龍無迹洞常寒。", "更聞雷遠相從樂，世道囂塵豈可干。"]'),
('7e722f13-336d-4b28-8a92-a267ed0ddd1c','和孔平仲','曾鞏','宋','宋诗','song-poetry','','[]','園池方喜共追尋，正是槐榆夾路陰。',64,'全唐诗/poet.song.26000.json','["園池方喜共追尋，正是槐榆夾路陰。", "雙燭縱談樽酒綠，一枰銷日紙窗深。", "波濤萬字驚人筆，塵土千鍾異俗心。", "佳句從來知寡和，愧將沙礫報黄金。"]'),
('7d61ede3-4c87-41cb-bc23-fbb943185b73','郡樓','曾鞏','宋','宋诗','song-poetry','','[]','滿眼青山更上樓，偶携閑客此閑遊。',64,'全唐诗/poet.song.26000.json','["滿眼青山更上樓，偶携閑客此閑遊。", "飛花不盡隨風起，野水無邊带雨流。", "懷舊有情惟社燕，忘機相得更沙鷗。", "黄金駟馬皆塵土，莫靳當歡酒百甌。"]'),
('d0424923-4667-47a2-9565-d7427c824870','鮑山','曾鞏','宋','宋诗','song-poetry','','[]','雲中一點鮑山青，東望能令兩眼明。',32,'全唐诗/poet.song.26000.json','["雲中一點鮑山青，東望能令兩眼明。", "若道人心是矛戟，山前那得叔牙城。"]'),
('031d27c7-cad5-4eba-8f02-ade6653c63fa','鄆州新堂','曾鞏','宋','宋诗','song-poetry','','[]','百尺豐堂汶水濱，魯侯清燕此逡巡。',64,'全唐诗/poet.song.26000.json','["百尺豐堂汶水濱，魯侯清燕此逡巡。", "溪寒素礫偏宜月，壁瑩黄金不受塵。", "引客笙歌行處是，賞心花木四時新。", "未應久作林泉主，天子今思舊學臣。"]'),
('1f061d1b-7112-4c4e-a2e3-372af6adb77e','垓下','曾鞏','宋','宋诗','song-poetry','','[]','三傑同歸漢道興，拔山餘力爾徒矜。',32,'全唐诗/poet.song.26000.json','["三傑同歸漢道興，拔山餘力爾徒矜。", "泫然垓下真兒女，不悟當從一范增。"]'),
('d01596d0-b431-4999-9bdb-2b53f12c19a7','離齊州後五首  其一','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲帆十幅順風行，卧聽隨船白浪聲。',32,'全唐诗/poet.song.26000.json','["雲帆十幅順風行，卧聽隨船白浪聲。", "好在西湖波上月，酒醒還到紙窗明。"]'),
('39776085-5aba-4e9a-8ba0-f10a2313eb06','離齊州後五首  其二','曾鞏','宋','宋诗','song-poetry','','[]','畫船終日扒沙行，已去齊州一月程。',32,'全唐诗/poet.song.26000.json','["畫船終日扒沙行，已去齊州一月程。", "千里相隨是明月，水西亭上一般明。"]'),
('224e6e7a-7387-4d6b-859e-979a705da38d','離齊州後五首  其三','曾鞏','宋','宋诗','song-poetry','','[]','文犀剡剡穿林筍，翠靨田田出水荷。',32,'全唐诗/poet.song.26000.json','["文犀剡剡穿林筍，翠靨田田出水荷。", "正是西亭銷暑日，却將離恨寄煙波。"]'),
('86a944be-9e19-4f52-ad5d-85d0dc1f1655','離齊州後五首  其四','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','將家須向習池遊，難放西湖十頃秋。',32,'全唐诗/poet.song.26000.json','["將家須向習池遊，難放西湖十頃秋。", "從此七橋風與月，夢魂長到木蘭舟。"]'),
('3b69f628-8f8a-4612-b26f-48f3b48f1e12','離齊州後五首  其五','曾鞏','宋','宋诗','song-poetry','','[]','荷氣夜凉生枕席，水聲秋醉入簾幃。',32,'全唐诗/poet.song.26000.json','["荷氣夜凉生枕席，水聲秋醉入簾幃。", "一帆千里空回首，寂寞船窗祇自知。"]'),
('0f9c51de-a62f-4f94-aa7e-8e432e70f21d','寄齊州同官','曾鞏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖一曲舞霓裳，勸客花前白玉觴。',32,'全唐诗/poet.song.26000.json','["西湖一曲舞霓裳，勸客花前白玉觴。", "誰對七橋今夜月，有情千里不相忘。"]'),
('cde7ec79-c2ee-46c7-979d-15cb43fd11d1','庭檜呈蔣穎叔','曾鞏','宋','宋诗','song-poetry','','[]','樛枝高下秀森森，曾寄名卿異俗心。',64,'全唐诗/poet.song.26000.json','["樛枝高下秀森森，曾寄名卿異俗心。", "草舍一時成往事，松身千尺見新陰。", "聲清不受笙竽雜，氣勁能遺霰雪侵。", "漢節從來縱真賞，謝庭蘭玉載芳音。"]'),
('05f901ea-6b00-49a8-bcd3-a37f1ea05e0b','甘露寺多景樓','曾鞏','宋','宋诗','song-poetry','','[]','欲收嘉景此樓中，徙倚闌干四望通。',64,'全唐诗/poet.song.26000.json','["欲收嘉景此樓中，徙倚闌干四望通。", "雲亂水光浮紫翠，天含山氣入青紅。", "一川鐘唄淮南月，萬里帆檣海外風。", "老去衣衿塵土在，祇將心目羨冥鴻。"]'),
('f814f46f-5196-4521-865c-fcc85c24b313','孫少述示近詩兼仰高致','曾鞏','宋','宋诗','song-poetry','','[]','大句閎篇久擅場，一函初得勝琳琅。',64,'全唐诗/poet.song.26000.json','["大句閎篇久擅場，一函初得勝琳琅。", "少陵雅健材孤出，彭澤清閑興最長。", "世外麒麟誰可繫，雲中鴻雁本高翔。", "白頭多病襄陽守，展卷臨風欲自强。"]'),
('48e14e1b-ad85-4590-9876-c9112e7c99dd','金山寺','曾鞏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','塵外岧嶢鷲嶺宮，架虛排險出青紅。',64,'全唐诗/poet.song.26000.json','["塵外岧嶢鷲嶺宮，架虛排險出青紅。", "林光巧轉滄波上，海色遥涵白日東。", "夜靜神龍聽呪食，秋深蒼鶻起摶風。", "連荆控蜀長江水，盡在回廊顧盼中。"]'),
('b0758da3-0972-435c-af40-b346003d27f6','水西亭書事','曾鞏','宋','宋诗','song-poetry','','[]','一番雨熟林間杏，四面風開水上花。',64,'全唐诗/poet.song.26000.json','["一番雨熟林間杏，四面風開水上花。", "岸盡龍鱗盤翠篠，溪深鰲背露晴沙。", "隴頭刈麥催行饁，桑下繰絲急轉車。", "總是白頭官長事，莫嫌粗俗向人誇。"]'),
('612c6fb1-de70-4074-bb61-a64b5b90f736','高郵逢人約襄陽之遊','曾鞏','宋','宋诗','song-poetry','','[]','一川風月高郵夜，玉麈清談畫鷁舟。',32,'全唐诗/poet.song.26000.json','["一川風月高郵夜，玉麈清談畫鷁舟。", "未把迂疏笑山簡，更須同上習池遊。"]'),
('44972eb0-9eba-4589-b7bb-c72bc04649b5','彭城道中','曾鞏','宋','宋诗','song-poetry','','[]','百步洪聲潦退初，白沙新岸湊舟車。',64,'全唐诗/poet.song.26000.json','["百步洪聲潦退初，白沙新岸湊舟車。", "一時屠釣英雄盡，千載河山戰伐餘。", "楚漢舊歌流俚耳，韓彭遺壁冠荒墟。", "可憐馬上縱橫略，只在邳橋一卷書。"]'),
('9dc92564-8515-4c56-a5ce-e1977e086263','送程殿丞還朝','曾鞏','宋','宋诗','song-poetry','','[]','如雲青髮擁朝簪，佳譽喧喧動士林。',64,'全唐诗/poet.song.26000.json','["如雲青髮擁朝簪，佳譽喧喧動士林。", "自重肯悲三獻玉，不欺常慎四知金。", "芝蘭秀出清門盛，鴻鷺翻飛紫殿深。", "別後齋中掛塵榻，更將梁甫向誰吟。"]'),
('b56473f0-3c70-417b-8a97-c7e8d31c8041','送高秘丞','曾鞏','宋','宋诗','song-poetry','','[]','簿書壅處精神健，風俗澆時質性淳。',64,'全唐诗/poet.song.26000.json','["簿書壅處精神健，風俗澆時質性淳。", "公退種花常滿縣，政成馴雉不驚人。", "指麾細柳通河外，歌咏甘棠付漢濱。", "惆悵不能留自助，謾將樽酒駐車輪。"]'),
('713e2d25-d9f1-4d07-9e47-26a50d8581d5','康定軍使高秘丞自襄陽司農寺勾業寺丞自光化相繼遷拜簽判程殿丞受代還朝預有惜別之意輒書長句奉呈','曾鞏','宋','宋诗','song-poetry','','[]','千里分符漢上城，爲僚方喜得時英。',64,'全唐诗/poet.song.26000.json','["千里分符漢上城，爲僚方喜得時英。", "已無楚澤行吟意，便有南陽坐嘯名。", "驥力用來精爽緊，鵷行歸去羽翰輕。", "須知別後狂山簡，夢寐清談鄙吝生。"]'),
('82a3a80d-f9b9-48b7-810a-039a2a6501eb','雨中王駕部席上','曾鞏','宋','宋诗','song-poetry','','[]','鳩呼連日始成陰，薄雨聊寬望歲心。',64,'全唐诗/poet.song.26000.json','["鳩呼連日始成陰，薄雨聊寬望歲心。", "浴雁野塘新浪細，藏鴉宮柳嫩條深。", "春寒巧放花遲發，人老嗟辭酒滿斟。", "英雋並遊知最幸，名園偷暇更追尋。"]'),
('de48a580-1aee-4802-ba1e-7d6f21a115fc','贈張伯常之郢見過因話荆楚故事仍貺佳什','曾鞏','宋','宋诗','song-poetry','','[]','一見心親十載前，相望南北久茫然。',64,'全唐诗/poet.song.26000.json','["一見心親十載前，相望南北久茫然。", "喜傾白髮論文酒，重訪清江下瀨船。", "志大肯同悲抱璞，識高寧許笑求田。", "已闚品藻傳荆楚，更味陽春白雪篇。"]'),
('5189f36a-0794-4fe4-811a-2e0ca9204a3b','伯常少留別業寄詩索酒因以奉報','曾鞏','宋','宋诗','song-poetry','','[]','未擁雙騶謁漢庭，暫留車馬憩林坰。',64,'全唐诗/poet.song.26000.json','["未擁雙騶謁漢庭，暫留車馬憩林坰。", "多情置驛邀佳客，好事磨鉛勘舊經。", "芳草連門三徑遠，朝雲臨幌數峰青。", "春醪有禁無繇寄，誰爲江潭訪獨醒。"]'),
('5812996c-5087-4a78-b7de-38fb3f532a45','贈黄降自宜城赴官許昌','曾鞏','宋','宋诗','song-poetry','','[]','所學從誰得最完，豫章新出已難攀。',64,'全唐诗/poet.song.26000.json','["所學從誰得最完，豫章新出已難攀。", "不摇聲利心能定，欲正哇淫手自刪。", "潁水珠璣來席上，鄢城桃李在人間。", "高齋掛榻驪歌後，坐守塵編少往還。"]'),
('a5a4b8ef-93a8-405f-95f4-269f3aa4b59c','招澤甫竹亭閑話','曾鞏','宋','宋诗','song-poetry','','[]','偶歸塞馬應何定，粒食鷦鷯頗自安。',64,'全唐诗/poet.song.26000.json','["偶歸塞馬應何定，粒食鷦鷯頗自安。", "雲壓楚山春後雪，風吹襄水坐來寒。", "詩豪已分材難强，酒聖還諳量未寬。", "頼有佳賓堪下榻，且將清話對檀欒。"]'),
('36d97f15-8ffb-4a0f-bdb8-38f7baec5a9b','和鄭微之','曾鞏','宋','宋诗','song-poetry','','[]','故人容下榻，清宴得傳杯。',48,'全唐诗/poet.song.26000.json','["故人容下榻，清宴得傳杯。", "地秀偏宜竹，天寒未見梅。", "雲林千嶂出，烟艇一帆開。", "且醉休言別，歸期信召催。"]'),
('16222322-362d-4d04-9c32-52662caf9720','送陳世脩','曾鞏','宋','宋诗','song-poetry','','[]','沙渚鴻飛入楚雲，遠林樵爨宿烟昏。',64,'全唐诗/poet.song.26000.json','["沙渚鴻飛入楚雲，遠林樵爨宿烟昏。", "娟娟野菊經秋淡，漠漠滄江带雨渾。", "歸路賞心應駐節，客亭離思暫開樽。", "莫嗟問俗淹翔久，從此頻繁不次恩。"]'),
('67b2479a-dee8-41c3-9538-f5268089b68a','和張伯常自郢中將及敝境先寄長句','曾鞏','宋','宋诗','song-poetry','','[]','拔薤威名高外服，握蘭風力冠中臺。',64,'全唐诗/poet.song.26000.json','["拔薤威名高外服，握蘭風力冠中臺。", "好音忽有雙魚至，喜氣遥知五馬來。", "梨顆玉腴含雨重，菊房金粉傍寒開。", "池邊且欲留同醉，思拙難酬白雪才。"]'),
('66bc001f-fa04-4683-8a52-d53b16a5602f','和張伯常峴山亭晚起元韵','曾鞏','宋','宋诗','song-poetry','','[]','揮手紅塵意浩然，夙興招客與扳聯。',64,'全唐诗/poet.song.26000.json','["揮手紅塵意浩然，夙興招客與扳聯。", "烟雲秀發春前地，草木清含雪後天。", "已卜耕桑臨富水，暫拋魚鳥去伊川。", "更追羊杜經行樂，况有風騷是謫仙。"]'),
('3e2efd2a-598b-46f7-bd8b-52b3a769ce12','峴山亭置酒','曾鞏','宋','宋诗','song-poetry','','[]','石磴縈回入杳冥，筠松高下簇虛亭。',64,'全唐诗/poet.song.26000.json','["石磴縈回入杳冥，筠松高下簇虛亭。", "春歸野路梅爭白，雪盡沙田麥正青。", "馬窟飛雲臨畫棟，鳳林斜日照疏櫺。", "長年酒量殊山簡，却上籃輿恨獨醒。"]'),
('ba0ddf56-29fb-4e5f-989a-33d484898913','韓魏公挽歌詞二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','堂堂風骨氣如春，衮服貂冠社稷臣。',64,'全唐诗/poet.song.26000.json','["堂堂風骨氣如春，衮服貂冠社稷臣。", "天上立談迎白日，握中隨物轉洪鈞。", "忽騎箕尾精靈遠，長誓山河寵數新。", "萬里耕桑無一事，三朝功德在生民。"]'),
('36b38d62-1c98-481e-8010-d3d1af8a87ec','韓魏公挽歌詞二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','錙銖赤舄無驕志，咳唾黄金有古風。',64,'全唐诗/poet.song.26000.json','["錙銖赤舄無驕志，咳唾黄金有古風。", "覆冒荒遐知大度，委蛇艱急見孤忠。", "謀謨邴魏丹青力，擁立昭宣柱石功。", "御筆新詩在新隴，哀榮誰得似初終。"]'),
('be3c9d8d-5d62-419d-8ce8-3a40948460d8','酬吳仲庶龍圖暮春感懷','曾鞏','宋','宋诗','song-poetry','','[]','瑣闈延閣腹心臣，籍甚聲華動縉紳。',64,'全唐诗/poet.song.26000.json','["瑣闈延閣腹心臣，籍甚聲華動縉紳。", "藥石言行天下雨，袴襦恩達國中春。", "召南去後餘思在，綸氏歸來壯志新。", "莫爲流年嗟白髮，濟時須仗老成人。"]'),
('5bcfe7ae-fa55-46d0-b37d-db76de8be788','陳君式恭軒','曾鞏','宋','宋诗','song-poetry','','[]','不要牆頭俗眼看，故開蒼蘚種檀欒。',64,'全唐诗/poet.song.26000.json','["不要牆頭俗眼看，故開蒼蘚種檀欒。", "虛心得處從天性，勁節知來在歲寒。", "葉養風煙誇酒美，枝留冰雪送歌殘。", "名郎感慕同桑梓，手植依然一畝寬。"]'),
('91bdb7cc-be80-4c36-bc13-5818b2f64c1d','僧正倚大師庵居','曾鞏','宋','宋诗','song-poetry','','[]','蘭裓方袍振錫回，結茅蕭寺遠塵埃。',64,'全唐诗/poet.song.26000.json','["蘭裓方袍振錫回，結茅蕭寺遠塵埃。", "五峰日破朝雲出，三谷花浮澗水來。", "風散異香禪榻靜，鳥窺清唄法筵開。", "因過舊國枌榆地，松麈高談喜暫陪。"]'),
('dec952aa-50a1-4d00-a4cf-ac703e6311e1','以白山茶寄吳仲庶見貺佳篇依韵和酬','曾鞏','宋','宋诗','song-poetry','','[]','山茶純白是天真，筠籠封題摘尚新。',64,'全唐诗/poet.song.26000.json','["山茶純白是天真，筠籠封題摘尚新。", "秀色未饒三谷雪，清香先得五峰春。", "瓊花散漫情終蕩，玉蕊蕭條迹更塵。", "遠寄一枝隨驛使，欲分芳種恨無因。"]'),
('5eb66f1a-fe0a-4b72-9be9-acf9d3911a0a','酬江西運使蔣穎叔','曾鞏','宋','宋诗','song-poetry','','[]','收科同日曳華裾，砉劃驚聞刃有餘。',64,'全唐诗/poet.song.26000.json','["收科同日曳華裾，砉劃驚聞刃有餘。", "驄馬已騰雙闕路，木牛還實太倉儲。", "多歧易感千名別，置袖空榮一紙書。", "欲佩左符甌越去，更從南斗望單車。"]'),
('0d0d8744-24f2-4563-87a1-4d88cf5bb1ac','刁景純挽歌詞二章  其一','曾鞏','宋','宋诗','song-poetry','','[]','史觀郎闈得謝歸，桓桓筋力未全衰。',64,'全唐诗/poet.song.26000.json','["史觀郎闈得謝歸，桓桓筋力未全衰。", "園林笑傲笙歌擁，山水追尋几杖隨。", "尺牘百封虛有意，文章十帙更傳誰。", "餘花自出藏春塢，一點青燈照繐帷。"]'),
('6ea0e88d-152f-4b11-a7d6-1aacb4da740f','刁景純挽歌詞二章  其二','曾鞏','宋','宋诗','song-poetry','','[]','八十登高步更輕，殷勤愛客是平生。',64,'全唐诗/poet.song.26000.json','["八十登高步更輕，殷勤愛客是平生。", "能臨緩急敦風誼，不向炎凉逐世情。", "北岳雲烟思抗志，東門冠蓋羨遺榮。", "可憐昨日壺觴地，嗚咽唯聞薤露聲。"]'),
('09218f56-8a11-49b1-b998-22e5a2dc60f1','寄留交代元子發','曾鞏','宋','宋诗','song-poetry','','[]','青雲寶構雖同直，白髮魚符各未歸。',64,'全唐诗/poet.song.26000.json','["青雲寶構雖同直，白髮魚符各未歸。", "倚玉詎應公論許，續貂還恐邑人非。", "莫辭海畔留連久，須惜天涯故舊稀。", "預想明年雙節召，九霄鵬翼看橫飛。"]'),
('3b5a8854-c54b-4f39-a398-98d9bc3a8143','遊東山示客','曾鞏','宋','宋诗','song-poetry','','[]','虞寄庵餘蘚徑通，滿山臺殿出青紅。',64,'全唐诗/poet.song.26000.json','["虞寄庵餘蘚徑通，滿山臺殿出青紅。", "難逢堆案文書少，偶見憑欄笑語同。", "梅粉巧含溪上雪，柳黄微破日邊風。", "從今準擬頻行樂，日伴樽前白髮翁。"]'),
('34178346-589b-4ce5-b2dd-cff8906721b0','大乘寺','曾鞏','宋','宋诗','song-poetry','','[]','行春門外是東山，籃轝寧辭數往還。',64,'全唐诗/poet.song.26000.json','["行春門外是東山，籃轝寧辭數往還。", "溪上鹿隨人去遠，洞中花照水長閑。", "樓臺勢出塵埃外，鐘磬聲來縹緲間。", "自笑粗官偷暇日，暫携妻子一開顔。"]'),
('cc32ba38-1ab2-4258-99d9-ca7940af9f54','聖泉寺','曾鞏','宋','宋诗','song-poetry','','[]','笑問并兒一舉鞭，亦逢佳景暫留連。',64,'全唐诗/poet.song.26000.json','["笑問并兒一舉鞭，亦逢佳景暫留連。", "青冥日抱山腰閣，碧野雲含石眼泉。", "躡屐路通林北寺，落帆門繫海東船。", "閩王舊事今何在，惟有村村供佛田。"]'),
('baf405ad-c1c5-48a4-b256-6e6877f3bd3c','昇山靈巖寺','曾鞏','宋','宋诗','song-poetry','','[]','修竹長松十里陰，任敦燒藥洞門深。',64,'全唐诗/poet.song.26000.json','["修竹長松十里陰，任敦燒藥洞門深。", "獨闚金版驚人語，能到青霞出世心。", "鷄犬亦隨雲外去，蓬瀛何必海中尋。", "丹樓碧閣唐朝寺，鐘唄香花滿舊林。"]'),
('a86d81aa-b76c-4a07-9dff-d3e3f88f0a8e','鳳池寺','曾鞏','宋','宋诗','song-poetry','','[]','經年聞說鳳池山，蠟屐方偷半日閑。',64,'全唐诗/poet.song.26000.json','["經年聞說鳳池山，蠟屐方偷半日閑。", "笑語客隨朱閣上，醉醒身在白雲間。", "溪橋野水清猶急，海岸輕寒去却還。", "爲郡天涯亦瀟灑，莫嗟流落鬢毛斑。"]'),
('07011fe9-8cea-47f6-abc3-4aaa91b78149','上元','曾鞏','宋','宋诗','song-poetry','','[]','金鞍馳騁屬兒曹，夜半喧闐意氣豪。',64,'全唐诗/poet.song.26000.json','["金鞍馳騁屬兒曹，夜半喧闐意氣豪。", "明月滿街流水遠，華燈入望衆星高。", "風吹玉漏穿花急，人近朱闌送目勞。", "自笑低心逐年少，祇尋前事撚霜毛。"]'),
('869be1e2-7cb4-4c35-896b-b25888686900','元沙院','曾鞏','宋','宋诗','song-poetry','','[]','昇山南下一峰高，上盡層軒未厭勞。',64,'全唐诗/poet.song.26000.json','["昇山南下一峰高，上盡層軒未厭勞。", "際海煙雲常慘淡，大寒松竹更蕭騷。", "經臺日永銷香篆，談席風生落麈毛。", "我亦有心從自得，琉璃瓶水照秋毫。"]'),
('028c73d5-f3ca-4cb6-8234-cc79f2a153cf','酬柳國博','曾鞏','宋','宋诗','song-poetry','','[]','行止恂恂衆所褒，東南佳譽映時髦。',64,'全唐诗/poet.song.26000.json','["行止恂恂衆所褒，東南佳譽映時髦。", "洞無畦畛心常坦，凜若冰霜節最高。", "朱紱少留居客左，白頭難敵是詩豪。", "須知別後山城守，悵望歸艎送目勞。"]'),
('a952113b-003a-4086-884a-699abd950fff','閏正月十一日呂殿丞寄新茶','曾鞏','宋','宋诗','song-poetry','','[]','偏得朝陽借力催，千金一胯過溪來。',32,'全唐诗/poet.song.26000.json','["偏得朝陽借力催，千金一胯過溪來。", "曾坑貢後春猶早，海上先嘗第一杯。"]'),
('ddb709da-2c7f-4643-ab3a-53938103498f','旬休日過仁王寺','曾鞏','宋','宋诗','song-poetry','','[]','雜花飛盡綠陰成，處處黄鸝百囀聲。',32,'全唐诗/poet.song.26000.json','["雜花飛盡綠陰成，處處黄鸝百囀聲。", "隨分笙歌與樽酒，且偷閑日試閑行。"]'),
('fd7be45a-7445-40c6-9dec-014165154a46','亂山','曾鞏','宋','宋诗','song-poetry','','[]','亂山深處轉山多，此地栖身奈遠何。',32,'全唐诗/poet.song.26000.json','["亂山深處轉山多，此地栖身奈遠何。", "莫問吾親在何處，舉頭東岸是新羅。"]'),
('0b92cbdf-90f2-44e8-b175-e75b907ad300','親舊書報京師盛聞治聲','曾鞏','宋','宋诗','song-poetry','','[]','自知孤宦無材術，誰道京師有政聲。',32,'全唐诗/poet.song.26000.json','["自知孤宦無材術，誰道京師有政聲。", "默坐海邊何計是，白頭親在鳳凰城。"]'),
('d6508ad9-79f0-4a14-9dee-66c448f14f06','寄獻新茶','曾鞏','宋','宋诗','song-poetry','','[]','種處地靈偏得日，摘時春早未聞雷。',32,'全唐诗/poet.song.26000.json','["種處地靈偏得日，摘時春早未聞雷。", "京師萬里爭先到，應得慈親手自開。"]'),
('7c7d97e8-9558-423f-9c06-8e5a1c96a4ce','方推官寄新茶','曾鞏','宋','宋诗','song-poetry','','[]','採摘東溪最上春，壑源諸葉品尤新。',32,'全唐诗/poet.song.26000.json','["採摘東溪最上春，壑源諸葉品尤新。", "龍團貢罷爭先得，肯寄天涯主諾人。"]'),
('be2e0fc0-2821-4884-9d03-e47a29d635a9','嘗新茶','曾鞏','宋','宋诗','song-poetry','','[]','麥粒收來品絕倫，葵花製出樣爭新。',32,'全唐诗/poet.song.26000.json','["麥粒收來品絕倫，葵花製出樣爭新。", "一杯永日醒雙眼，草木英華信有神。"]'),
('ff39e399-8ce2-4ee1-b7ee-fbaf9aa4d8bb','厚卿子中使高麗','曾鞏','宋','宋诗','song-poetry','','[]','並使時推出衆材，異方迎拜六城開。',64,'全唐诗/poet.song.26000.json','["並使時推出衆材，異方迎拜六城開。", "宣風直到東西部，仗節遥臨大小梅。", "滄海路從三島去，玉山人到二星回。", "黄金白㲲饒君用，銅器應餘寄我來。"]'),
('afe91850-f1e0-455f-9b68-6bb92d0a9011','出郊','曾鞏','宋','宋诗','song-poetry','','[]','葛葉催耕二月時，斜橋曲岸馬行遲。',32,'全唐诗/poet.song.26000.json','["葛葉催耕二月時，斜橋曲岸馬行遲。", "家家賣酒清明近，紅白花開一兩枝。"]'),
('0f9eb4c3-a7a2-4884-9b3d-a95a22ff4ae3','蹇磻翁寄新茶二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','龍焙嘗茶第一人，最憐溪岸兩旗新。',32,'全唐诗/poet.song.26000.json','["龍焙嘗茶第一人，最憐溪岸兩旗新。", "肯分方胯醒衰思，應恐慵眠過一春。"]'),
('ac5330bf-8595-4040-a74c-4cde228c9d3e','蹇磻翁寄新茶二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','貢時天上雙龍去，鬥處人間一水爭。',32,'全唐诗/poet.song.26000.json','["貢時天上雙龍去，鬥處人間一水爭。", "分得餘甘慰憔悴，碾嘗終夜骨毛清。"]'),
('bf7a37de-379a-4f5f-8f4a-26739250be0f','城南二首  其一','曾鞏','宋','宋诗','song-poetry','','["\u5199\u8349", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u5b8b\u8bd7", "\u82b1", "\u5199\u82b1"]','雨過橫塘水滿堤，亂山高下路東西。',32,'全唐诗/poet.song.26000.json','["雨過橫塘水滿堤，亂山高下路東西。", "一番桃李花開盡，惟有青青草色齊。"]'),
('81c74dfc-c204-4f45-8b09-b100200c38cc','城南二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','水滿橫塘雨過時，一番紅影雜花飛。',32,'全唐诗/poet.song.26000.json','["水滿橫塘雨過時，一番紅影雜花飛。", "送春無限情惆悵，身在天涯未得歸。"]'),
('785fbd91-a299-48c6-a4ca-7acc4d093e34','寒食','曾鞏','宋','宋诗','song-poetry','','[]','一麾飄泊在天涯，寒食園林不見花。',32,'全唐诗/poet.song.26000.json','["一麾飄泊在天涯，寒食園林不見花。", "唯有市亭酤酒客，俚歌聲到日西斜。"]'),
('0da6524c-3fae-46f6-b56f-dab2605abb23','夜出過利涉門','曾鞏','宋','宋诗','song-poetry','','[]','紅紗籠燭照斜橋，複觀翬飛入斗杓。',32,'全唐诗/poet.song.26000.json','["紅紗籠燭照斜橋，複觀翬飛入斗杓。", "人在畫船猶未睡，滿堤明月一溪潮。"]'),
('9d36bbe0-a7cd-4a76-9de8-22cab9c28a5e','夜出城南禱雨','曾鞏','宋','宋诗','song-poetry','','[]','海天重疊四山雲，半出星辰亦半昏。',32,'全唐诗/poet.song.26000.json','["海天重疊四山雲，半出星辰亦半昏。", "上得籃轝是中夜，兩街燈照九重門。"]'),
('3a4974ab-769a-4554-b9d1-9f5fadcb4142','西樓','曾鞏','宋','宋诗','song-poetry','','[]','海浪如雲去却回，北風吹起數聲雷。',32,'全唐诗/poet.song.26000.json','["海浪如雲去却回，北風吹起數聲雷。", "朱樓四面鈎疏箔，卧看千山急雨來。"]'),
('83d3d341-9cbd-4eca-8d70-b220fe535fd6','荔枝四首  其一','曾鞏','宋','宋诗','song-poetry','','[]','剖見隋珠醉眼開，丹砂緣手落塵埃。',32,'全唐诗/poet.song.26000.json','["剖見隋珠醉眼開，丹砂緣手落塵埃。", "誰能有力如黄犢，摘盡繁星始下來。"]'),
('81b721f8-fb76-43e5-bb0a-015d543831c5','荔枝四首  其二','曾鞏','宋','宋诗','song-poetry','','[]','玉潤冰清不受塵，仙衣裁剪絳紗新。',32,'全唐诗/poet.song.26000.json','["玉潤冰清不受塵，仙衣裁剪絳紗新。", "千門萬戶誰曾得，只有昭陽第一人。"]'),
('d82e25de-b2be-4483-9e67-aec2523d4061','荔枝四首  其三','曾鞏','宋','宋诗','song-poetry','','[]','絳縠囊收白露團，未曾封植向長安。',32,'全唐诗/poet.song.26000.json','["絳縠囊收白露團，未曾封植向長安。", "昭陽殿裏才聞得，已道佳人不奈寒。"]'),
('0826184a-340b-4f86-b9ab-07c2fef38570','荔枝四首  其四','曾鞏','宋','宋诗','song-poetry','','[]','金釵雙捧玉纖纖，星宿光芒動寶奩。',32,'全唐诗/poet.song.26000.json','["金釵雙捧玉纖纖，星宿光芒動寶奩。", "解笑詩人誇博物，祇知紅顆味酸甜。"]'),
('998ce5ae-2c53-42eb-b8b1-bdba51228883','王虞部惠佳篇敘述昔與湘潭亡弟遊從仍以亡弟舊詩見示','曾鞏','宋','宋诗','song-poetry','','[]','薄宦紅塵常拂面，早衰黄髮已盈顛。',64,'全唐诗/poet.song.26000.json','["薄宦紅塵常拂面，早衰黄髮已盈顛。", "棣華零落曾誰語，鴻羽蕭條祇自憐。", "已矣空聞懷舊賦，泫然猶獲濟江篇。", "殷勤慰我如君少，更悟之他友最賢。"]'),
('01fa3feb-b2c2-4b0f-8bed-60e4e77be0d8','北歸三首  其一','曾鞏','宋','宋诗','song-poetry','','[]','終日思歸今日歸，著鞭鞭馬尚嫌遲。',32,'全唐诗/poet.song.26000.json','["終日思歸今日歸，著鞭鞭馬尚嫌遲。", "曲臺殿裏官雖冷，須勝天涯海角時。"]'),
('d0c42bac-22f0-4c16-b391-b8f6841603b1','北歸三首  其二','曾鞏','宋','宋诗','song-poetry','','[]','拜捧恩書喜滿顔，馬蹄遥望斗杓還。',32,'全唐诗/poet.song.26000.json','["拜捧恩書喜滿顔，馬蹄遥望斗杓還。", "從今步步行平地，出得千山與萬山。"]'),
('02f0365b-6dcc-4923-bbda-ba07f20c9d82','北歸三首  其三','曾鞏','宋','宋诗','song-poetry','','[]','江海多年似轉蓬，白頭歸拜未央宮。',32,'全唐诗/poet.song.26000.json','["江海多年似轉蓬，白頭歸拜未央宮。", "堵牆學士驚相問，何處塵埃瘦老翁。"]'),
('0596d2bc-2c27-407c-a717-44efe36b9cea','和酬孫少述','曾鞏','宋','宋诗','song-poetry','','[]','自信簞瓢樂，寧羞猿鶴驚。',48,'全唐诗/poet.song.26000.json','["自信簞瓢樂，寧羞猿鶴驚。", "論高知峻節，交淡見純誠。", "自昔心無間，相逢眼更明。", "何當薦有道，坐想軟輪迎。"]'),
('8ebe065f-202d-4610-ac83-d7b62d57a1fa','和孫少述侯職方同燕席','曾鞏','宋','宋诗','song-poetry','','[]','兩翁頭白喜追陪，好事鈴齋燕席開。',64,'全唐诗/poet.song.26000.json','["兩翁頭白喜追陪，好事鈴齋燕席開。", "臘在未消盈尺雪，春歸先放一枝梅。", "况無庭下書投缿，更盡筵中酒滿杯。", "周召二南皆絕唱，抑揚賡和愧非材。"]'),
('2226cc6c-ee7c-4770-bb1c-50ee23b5c8d4','寄趙宮保','曾鞏','宋','宋诗','song-poetry','','[]','銅扉得謝從今日，玉鉉辭榮已十年。',64,'全唐诗/poet.song.26000.json','["銅扉得謝從今日，玉鉉辭榮已十年。", "素節讜言留簡冊，高情清興入林泉。", "海邊愛日疲人戀，劍外仁風故老傳。", "門外最應瀟灑客，喜公平地作神仙。"]'),
('57b9b9be-e0a7-4833-94e2-bbe924ee47ef','和酬趙宮保致政言懷二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','讜論危言望素隆，獨於聲利性偏慵。',64,'全唐诗/poet.song.26000.json','["讜論危言望素隆，獨於聲利性偏慵。", "龍樓調護官雖寵，鳩杖躋攀興已濃。", "不變松篁心轉勁，無邊江海量兼容。", "磻溪縱老寧閒得，會爲蒼生起更重。"]'),
('a91d6f4f-676e-4d7c-8b37-28f16bf0c187','和酬趙宮保致政言懷二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','愛國憂民有古風，米鹽親省尚嫌慵。',64,'全唐诗/poet.song.26000.json','["愛國憂民有古風，米鹽親省尚嫌慵。", "衮衣天上歸何晚，霖雨人間望正濃。", "三少官儀雖赫赫，五湖心事肯容容。", "角巾藜杖經行處，知在雲山第幾重。"]'),
('43975a04-84f9-4b51-a61e-1eb1f2da3cf3','和趙宮保別杭州','曾鞏','宋','宋诗','song-poetry','','[]','紞鼓留公豈是催，湖山得意且徘徊。',32,'全唐诗/poet.song.26000.json','["紞鼓留公豈是催，湖山得意且徘徊。", "更應準擬須乘興，范蠡扁舟去却來。"]'),
('9b686ded-0001-44be-a680-e381002f7675','過零壁張氏園三首  其一','曾鞏','宋','宋诗','song-poetry','','[]','梨棗纍纍正熟時，粟田鶉兔亦爭肥。',32,'全唐诗/poet.song.26000.json','["梨棗纍纍正熟時，粟田鶉兔亦爭肥。", "園亭盡日追尋遍，只欠厭厭醉始歸。"]'),
('1bb1abb7-26c8-4327-b5f7-1d5a2d8c287d','過零壁張氏園三首  其二','曾鞏','宋','宋诗','song-poetry','','[]','汴水溶溶带雨流，黄花艷艷亦迎秋。',32,'全唐诗/poet.song.26000.json','["汴水溶溶带雨流，黄花艷艷亦迎秋。", "看花引水園林主，應笑行人易白頭。"]'),
('bc8f5a9e-bb93-4d8a-84ba-9c32311b96b2','過零壁張氏園三首  其三','曾鞏','宋','宋诗','song-poetry','','[]','秫地成來多釀酒，杏林熟後亦留錢。',32,'全唐诗/poet.song.26000.json','["秫地成來多釀酒，杏林熟後亦留錢。", "不須置驛迎賓客，直到門前繫畫船。"]'),
('05541757-0798-400b-9b71-014f1ef4dbda','雪亳州','曾鞏','宋','宋诗','song-poetry','','[]','欲下蒼凉日，全低黯霮天。',144,'全唐诗/poet.song.26000.json','["欲下蒼凉日，全低黯霮天。", "飄颻投夜急，瑣碎得風儇。", "穢壤彌縫遍，枯荄點綴妍。", "繁英飛面旋，艷舞起翩躚。", "已壓穿林竹，還冰落澗泉。", "抵巇輕自肆，乘隙巧爭先。", "壅隔書郵斷，侵凌客履穿。", "恐傾貧巷屋，覺重溯溪船。", "唶有顔空姣，洵無質可鎸。", "包藏兼海岳，蒙蔽匝坤乾。", "枚叟招何晚，袁安卧正堅。", "會須逢見睍，萬里豁晴川。"]'),
('847a6bac-1c99-4006-b020-9ee97fee491c','送元厚之資政致仕歸蘇州','曾鞏','宋','宋诗','song-poetry','','[]','笑指家園是五湖，畫船東下載圖書。',64,'全唐诗/poet.song.26000.json','["笑指家園是五湖，畫船東下載圖書。", "收功玉鉉丹青後，得老銅樓羽翼初。", "醒醉放懷從野服，登臨乘興屬安車。", "都門飲餞光華盛，不獨當年有二疏。"]'),
('1f42f695-18c9-4ee8-a0f1-d18e57c31d05','壽聖院昌山主靜軒','曾鞏','宋','宋诗','song-poetry','','[]','一峰瀟灑背成陰，碧瓦新堂地布金。',64,'全唐诗/poet.song.26000.json','["一峰瀟灑背成陰，碧瓦新堂地布金。", "花落禪衣松砌冷，日臨經帙紙窗深。", "幽棲鳥得林中樂，燕坐人存世外心。", "應似白蓮香火社，不妨籃轝客追尋。"]'),
('d3b3c894-2e1e-416b-a8f5-e62f41c9ad08','鶴林寺','曾鞏','宋','宋诗','song-poetry','','[]','昔人春盡强登山，只肯逢僧半日閑。',32,'全唐诗/poet.song.26000.json','["昔人春盡强登山，只肯逢僧半日閑。", "何似一尊乘興去，醉中騎馬月中還。"]'),
('4de9f6d4-3ad3-4852-a047-a203e97ea7d4','送關彥遠赴河北','曾鞏','宋','宋诗','song-poetry','','[]','子明高誼衆人知，苗裔清材世所推。',64,'全唐诗/poet.song.26000.json','["子明高誼衆人知，苗裔清材世所推。", "詩作士林誇刻燭，賦成天路喜同時。", "豈當白首淹風力，自合青雲縱羽儀。", "北部經營應不久，玉階朝夕是歸期。"]'),
('a7462b7a-169e-4c00-b3ec-ea9bd03d6501','正月十一日迎駕呈諸同舍','曾鞏','宋','宋诗','song-poetry','','[]','錦袍周衛一番新，警蹕朝嚴下紫宸。',64,'全唐诗/poet.song.26000.json','["錦袍周衛一番新，警蹕朝嚴下紫宸。", "俗眼望來猶眩日，天顔回處自生春。", "行齊鵷鷺常隨仗，步穩驊騮不起塵。", "歸路青雲喧鼓吹，樂遊從此屬都人。"]'),
('2a93343a-fd7a-4e10-bd63-63d58d2988de','和御製上元觀燈','曾鞏','宋','宋诗','song-poetry','','[]','翠幰霓旌夾露臺，夜凉宮扇月中開。',64,'全唐诗/poet.song.26000.json','["翠幰霓旌夾露臺，夜凉宮扇月中開。", "龍銜燭抱金門出，鰲負山趨玉座來。", "碭極戲添夷客喜，柏梁篇較從臣材。", "共知天意同民樂，願奏君王萬壽杯。"]'),
('3d6414f2-7c01-4ba3-a7fa-8c312fda8714','和史館相公上元觀燈','曾鞏','宋','宋诗','song-poetry','','[]','九衢仙仗豫遊歸，寶燭星繁換夕暉。',64,'全唐诗/poet.song.26000.json','["九衢仙仗豫遊歸，寶燭星繁換夕暉。", "傳醆未斜清禁月，散花還拂侍臣衣。", "天香暗度金虬暖，宮扇雙開彩鳳飛。", "法曲世人聽未足，却迎朱輦下端闈。"]'),
('6c2bb844-ecb2-4019-8cb5-21086c2a491c','集賢殿春燕呈諸同舍','曾鞏','宋','宋诗','song-poetry','','[]','御爐風細麝烟浮，法樂聲和酒味柔。',64,'全唐诗/poet.song.26000.json','["御爐風細麝烟浮，法樂聲和酒味柔。", "冠劍九重霄漢路，鶑花三月帝王州。", "垂廊四合盤龍幕，當殿雙高彩鳳樓。", "歸去人人誇雨露，總含歡意躍驊騮。"]'),
('0555021a-a501-4973-b319-5b31be59a28b','上巳日瑞聖園錫燕呈諸同舍','曾鞏','宋','宋诗','song-poetry','','[]','北上郊原一據鞭，華林清集綴儒冠。',64,'全唐诗/poet.song.26000.json','["北上郊原一據鞭，華林清集綴儒冠。", "方塘渰渰春先淥，密竹娟娟午更寒。", "流渚酒浮金鑿落，照庭花並玉闌干。", "君恩倍覺丘山重，長日從容笑語歡。"]'),
('7175b9a9-5295-406b-b03a-00b57b7ac298','池上即席送况之赴宣城','曾鞏','宋','宋诗','song-poetry','','[]','池上紅深綠淺時，春風蕩漾水逶迤。',64,'全唐诗/poet.song.26000.json','["池上紅深綠淺時，春風蕩漾水逶迤。", "南州鼓舞歸慈惠，東觀壺觴惜別離。", "遠岫烟雲供醉眼，雙溪魚鳥付新詩。", "陵陽豈是遲留地，趣駕追鋒自有期。"]'),
('bdeee945-b64d-414a-96ac-05f870b37619','寄題饒君茂才葆光庵','曾鞏','宋','宋诗','song-poetry','','[]','適意藜羹與布裘，結廬人境地還幽。',64,'全唐诗/poet.song.26000.json','["適意藜羹與布裘，結廬人境地還幽。", "清談汝水孤猿夜，爽氣麻源一葉秋。", "應有風騷歸健筆，可無尊酒付扁舟。", "因君更起家園興，夢寐思從几杖遊。"]'),
('c6a9e3a2-6499-4fc6-a81d-f7cda654497c','朝退即事呈大尹正仲龍圖','曾鞏','宋','宋诗','song-poetry','','[]','六街塵斷早凉生，細葛含風體更清。',64,'全唐诗/poet.song.26000.json','["六街塵斷早凉生，細葛含風體更清。", "官府吏閑時樂易，市廛人喜政和平。", "揮金蔌蔌宮槐蕊，鳴玉淙淙御水聲。", "觀闕漸迎初日上，馬頭還傍綠陰行。"]'),
('a091b7bd-7786-4fd2-9b1b-69f00556bb6b','喜晴赴田中','曾鞏','宋','宋诗','song-poetry','','[]','自愁雨破西嶺出，只看水緣南澗生。',64,'全唐诗/poet.song.26000.json','["自愁雨破西嶺出，只看水緣南澗生。", "青天忽從樹杪見，白日漸向谷中明。", "豳公滌場不可失，陶令負禾須自行。", "歸時小榼搊亦滿，固有阿連相伴傾。"]'),
('eb9d2581-01fc-4e43-8607-ad6a56e233bb','少年','曾鞏','宋','宋诗','song-poetry','','[]','不復論心與少年，世間情僞久茫然。',32,'全唐诗/poet.song.26000.json','["不復論心與少年，世間情僞久茫然。", "朱門如市方招客，獨守殘經自可憐。"]'),
('ee70d4b2-4078-407e-b797-098f6de75b31','上杜相三首  其一','曾鞏','宋','宋诗','song-poetry','','[]','天扶昌代得忠良，坐以材謀鎮廟堂。',64,'全唐诗/poet.song.26000.json','["天扶昌代得忠良，坐以材謀鎮廟堂。", "萬里聲名開學校，四方根本勸農桑。", "從容賢路通江海，慷慨公心貫雪霜。", "謙讓黑轅歸太早，空令終古愛餘芳。"]'),
('20851c5c-bd0d-4532-853e-e795ce8dc067','上杜相三首  其二','曾鞏','宋','宋诗','song-poetry','','[]','翊戴唐虞旦暮中，忽將符節撫山東。',64,'全唐诗/poet.song.26000.json','["翊戴唐虞旦暮中，忽將符節撫山東。", "憶歸慷慨無私計，抗疏頻煩有古風。", "世路一人知進退，士林當日計窮通。", "壽觴須祝年年喜，舊德華夷望更隆。"]'),
('38dccb12-a60d-4979-861e-9ecdba306fee','上杜相三首  其三','曾鞏','宋','宋诗','song-poetry','','[]','轉覺憂餘好尚孤，較量唯合老葭蒲。',64,'全唐诗/poet.song.26000.json','["轉覺憂餘好尚孤，較量唯合老葭蒲。", "聖賢可是隨時拙，正直由來濟世迂。", "生事有親甘釣築，客情無力買山湖。", "天邊愁絕傷離苦，台象空看照宋都。"]'),
('13184903-7aba-4c28-8da7-8abc1d7599e1','寄王荆公介甫','曾鞏','宋','宋诗','song-poetry','','[]','數病門稀出，常貧客少過。',48,'全唐诗/poet.song.26000.json','["數病門稀出，常貧客少過。", "經綸知齟齬，耕釣亦蹉跎。", "兩事艱難極，孤心感慨多。", "素交千里遠，誰聽此時歌。"]'),
('a6fd1e75-2f94-4675-bd64-658ae012c721','送王補之歸南城','曾鞏','宋','宋诗','song-poetry','','[]','瘦馬君將去，清樽我謾開。',48,'全唐诗/poet.song.26000.json','["瘦馬君將去，清樽我謾開。", "眼看新雨露，身带舊塵埃。", "但喜丹心在，休驚白髮催。", "窮通莫須問，功業有時來。"]'),
('54b20e42-c097-45fa-b731-b67ab43044d9','和酬王平甫道中見寄','曾鞏','宋','宋诗','song-poetry','','[]','安危魁柄倚誰操，斂笏千官拱赭袍。',64,'全唐诗/poet.song.26000.json','["安危魁柄倚誰操，斂笏千官拱赭袍。", "能有本根持國論，豈須毫髮間戎韜。", "征求藉藉人多困，羈旅皇皇我亦勞。", "棲宿與君何計得，半生飄蕩似風毛。"]'),
('7c372b27-2172-4cb3-9a69-a3cd3f6f1ff8','讀孟子','曾鞏','宋','宋诗','song-poetry','','[]','千載士推無比擬，一編吾喜竊窺觀。',64,'全唐诗/poet.song.26000.json','["千載士推無比擬，一編吾喜竊窺觀。", "苟非此道知音少，安有茲人得志難。", "機巧滿朝論勢利，瘡痍連室嘆饑寒。", "先生自是齊梁客，誰作商巖渭水看。"]'),
('4fd83460-9af3-432b-b553-2a83d9037c81','聖賢','曾鞏','宋','宋诗','song-poetry','','[]','聖賢性分良難並，好惡情懷豈得同。',64,'全唐诗/poet.song.26000.json','["聖賢性分良難並，好惡情懷豈得同。", "荀子書猶非孟子，召公心未悅周公。", "况令樹立追高遠，而使裁量屬闇蒙。", "舉世不知何足怪，力行無顧是豪雄。"]'),
('b9eb8571-e103-4106-b7f8-b123f22c6c3a','寄晉州孫學士','曾鞏','宋','宋诗','song-poetry','','[]','風標閑淡易爲安，晉陝應忘道路難。',64,'全唐诗/poet.song.26000.json','["風標閑淡易爲安，晉陝應忘道路難。", "學似海收天下水，性如桂奈月中寒。", "素心已向新書見，大法常留後世看。", "自送西舟江上別，孤懷經歲未能寬。"]'),
('fbc1233f-41d3-448b-bfd8-79a0a173de4d','送戚郎中','曾鞏','宋','宋诗','song-poetry','','[]','一心清淡本如秋，何必錙銖較兩州。',64,'全唐诗/poet.song.26000.json','["一心清淡本如秋，何必錙銖較兩州。", "身向宦名雖黽勉，性於人事豈雕鎪。", "但思簿領忙時俗，便覺溪山靜處優。", "荔子滿盤寧易得，與誰頻宴嶺邊樓。"]'),
('83e22281-2429-4909-a344-806d391863c6','李供奉','曾鞏','宋','宋诗','song-poetry','','[]','一身得祿從孤客，千里還喪獲舊林。',64,'全唐诗/poet.song.26000.json','["一身得祿從孤客，千里還喪獲舊林。", "清節蕭條妻子計，白頭敦篤弟兄心。", "能拋印綬高應少，自築丘墳達更深。", "我與往來無力薦，褒傳唯有北窗吟。"]'),
('5fc635ef-cbfb-4f83-bf34-3f9915a56599','寄孫正之二首  其一','曾鞏','宋','宋诗','song-poetry','','[]','兩人懷抱喜相投，初得青山一日遊。',64,'全唐诗/poet.song.26000.json','["兩人懷抱喜相投，初得青山一日遊。", "已聽高文吟太古，更開昏眼洗清流。", "共尋素壁題皆遍，欲去紅橋釣始休。", "回首至今嘉興在，夢魂猶擬奉觥籌。"]'),
('e2e24dfe-7842-46ea-88c5-eecb8e191a88','寄孫正之二首  其二','曾鞏','宋','宋诗','song-poetry','','[]','隠似龍蛇應有待，清□冰雪更無雙。',64,'全唐诗/poet.song.26000.json','["隠似龍蛇應有待，清□冰雪更無雙。", "志留世外雖遺俗，文落人間或過江。", "峻節但期終老學，健詩猶愧一時降。", "風騷近亦思强伴，恨未高吟共北窗。"]'),
('a63126b7-3d08-43c0-ade1-e851eae53111','依韵和酬提刑都官寒食阻風見寄','曾鞏','宋','宋诗','song-poetry','','[]','畫舡齊泊倚青山，正值春風阻往還。',64,'全唐诗/poet.song.26000.json','["畫舡齊泊倚青山，正值春風阻往還。", "江作鼓鼙聲浩渺，樹爲城障綠回環。", "幽花婀娜偏當眼，啼鳥交加亦解顔。", "使者文章工不淺，盡將模寫寄柴關。"]'),
('1743f4b7-01ca-49c5-ae3d-c6541ab6c164','杜鵑','曾鞏','宋','宋诗','song-poetry','','[]','杜鵑花上杜鵑啼，自有歸心似見機。',32,'全唐诗/poet.song.26000.json','["杜鵑花上杜鵑啼，自有歸心似見機。", "人各有求難意合，何須勤苦勸人歸。"]'),
('0dcb449c-2809-42fc-8c19-15a0ba8e7e27','雨中','曾鞏','宋','宋诗','song-poetry','','[]','愁煙苦雨今朝是，小屋深扉野性憐。',64,'全唐诗/poet.song.26000.json','["愁煙苦雨今朝是，小屋深扉野性憐。", "偶似魯連能肆志，肯如劉備耻求田。", "貧諳親友難過飲，病笑詩書可枕眠。", "欲會此心何自適，平生消長任陶甄。"]'),
('6a4c15ec-7ff7-49ad-a462-ecd36baad9aa','題祝道士房','曾鞏','宋','宋诗','song-poetry','','[]','悠悠行處是風波，萬事萬驚久琢磨。',64,'全唐诗/poet.song.26000.json','["悠悠行處是風波，萬事萬驚久琢磨。", "心逐世情知齟齬，身求閑伴恐蹉跎。", "功名自古時應少，山水輸君樂最多。", "爭得有田收迹去，比中文酒數經過。"]'),
('2fe972c8-7104-42bd-961c-a8acf900ecd3','題寶月大師法喜堂','曾鞏','宋','宋诗','song-poetry','','[]','誰能懷抱信分明，擾擾相欺是世情。',63,'全唐诗/poet.song.26000.json','["誰能懷抱信分明，擾擾相欺是世情。", "只有陋儒夸勢利，幾曾高位功名。", "欲將志義期千載，只合溪山過一生。", "君向此堂應笑我，病身南北正營營。"]'),
('9c6f0e32-91aa-4efc-bfa5-077c2c3be836','題關都官宅','曾鞏','宋','宋诗','song-poetry','','[]','麻衣少壯干時去，朱紱康强得老歸。',64,'全唐诗/poet.song.26000.json','["麻衣少壯干時去，朱紱康强得老歸。", "身世自如天下少，利名難退古來稀。", "更無俗事侵方寸，只與閑人話翠微。", "科第諸郎同日顯，高門當代有光輝。"]'),
('ecc7dac4-f503-4997-a2eb-23c5016aec88','題修廣房','曾鞏','宋','宋诗','song-poetry','','[]','世情衮衮利名間，子有高情獨閉關。',64,'全唐诗/poet.song.26000.json','["世情衮衮利名間，子有高情獨閉關。", "萬事長年拋似夢，一堂終日靜於山。", "幽花得地無妍醜，好鳥窺人自往還。", "藥籙棋枰俱我好，幾時能共此中閑。"]'),
('385dcd37-6b34-4ddf-9092-b8783d33de09','田中作','曾鞏','宋','宋诗','song-poetry','','[]','傍人應總笑爲生，病體朝朝踏雨行。',64,'全唐诗/poet.song.26000.json','["傍人應總笑爲生，病體朝朝踏雨行。", "紅飯白菹妻具餉，青秧綠水自催耕。", "止知索寞簞瓢計，豈論喧嘩內素名。", "勝事山風吹木石，暫如韶夏管弦聲。"]'),
('44cbc10a-d2d7-4bf8-b499-578856872f3c','寄人','曾鞏','宋','宋诗','song-poetry','','[]','懶聽詩書散滿床，鬢鬚垂白坐茅堂。',64,'全唐诗/poet.song.26000.json','["懶聽詩書散滿床，鬢鬚垂白坐茅堂。", "溪山入手何時見，塵土勞心繼日忙。", "氣味向人卑可耻，風波隨處險難當。", "羨君出處由胸臆，安穩將家水石傍。"]'),
('d63e90fb-77d7-403a-bea1-fb94b4026759','首夏','曾鞏','宋','宋诗','song-poetry','','[]','亂崖蒸潤滴嵯峨，苒苒生雲雨意多。',64,'全唐诗/poet.song.26000.json','["亂崖蒸潤滴嵯峨，苒苒生雲雨意多。", "已愛破山泉漱玉，更憐垂壠麥翻波。", "妖紅落後新篁出，老綠濃時野鳥過。", "還與北窗添睡思，盡拋塵上養天和。"]'),
('2640a911-2a29-4ffd-94f2-a7b33b4dc169','雹','曾鞏','宋','宋诗','song-poetry','','[]','窮谷結時雷已動，荒臺看處雪猶埋。',64,'全唐诗/poet.song.26000.json','["窮谷結時雷已動，荒臺看處雪猶埋。", "崩騰沙靂乘風下，宛轉珠璣壓雨來。", "已激山聲如駭浪，更回天色似寒灰。", "何繇得見晴輝上，愁放昏昏睡眼開。"]'),
('31dfd565-3407-43a3-8248-f696b9082d20','初冬道中','曾鞏','宋','宋诗','song-poetry','','[]','潦退蛟螭不可逃，溪潭清澈見秋毫。',64,'全唐诗/poet.song.26000.json','["潦退蛟螭不可逃，溪潭清澈見秋毫。", "欲霜日射西山赤，漸冷天騰北極高。", "秀色更濃唯竹柏，孤根先動是蓬蒿。", "感時一撫青萍嘆，馬踏西風氣自豪。"]'),
('ec37a217-5951-47a0-83aa-0f93fda02e1e','留山中諸君子見訪','曾鞏','宋','宋诗','song-poetry','','[]','茅舍開扉勝事稠，況携佳客此中遊。',64,'全唐诗/poet.song.26000.json','["茅舍開扉勝事稠，況携佳客此中遊。", "妖紅落後堅松在，南澗清時野潦收。", "林带寒煙如水合，山含晴日似塵浮。", "不嫌淡薄幽人趣，欲進藜羹更少留。"]'),
('b953ba2a-2925-423e-bb06-9d4fe5b61b97','豐年有高廩','曾鞏','宋','宋诗','song-poetry','','[]','盛德臨昭旦，多祥獲有年。',72,'全唐诗/poet.song.26000.json','["盛德臨昭旦，多祥獲有年。", "嘉禾登羨溢，高廩積連延。", "田入豐維億，倉收富且千。", "夢魚諧素兆，如櫛比前篇。", "瑞貺神之與，休明頌所傳。", "粢盛繇此備，清廟薦恭虔。"]'),
('c0f9e9d6-b627-4d70-acf4-5ccbb40f9fb9','將行陪貳車觀燈','曾鞏','宋','宋诗','song-poetry','','[]','行歌紅粉滿城歡，猶作常時五馬看。',32,'全唐诗/poet.song.26000.json','["行歌紅粉滿城歡，猶作常時五馬看。", "忽憶使君身是客，一時揮淚逐金鞍。"]'),
('66ed9c20-ae28-4381-91dc-ea1fe8921457','赴齊州','曾鞏','宋','宋诗','song-poetry','','[]','淮南蒙召鬢毛斑，乞得東秦慰病顔。',32,'全唐诗/poet.song.26000.json','["淮南蒙召鬢毛斑，乞得東秦慰病顔。", "曉整輕鞍汶陽北，却衝微雨看青山。"]'),
('c164e3e7-2828-47d3-bc34-b8a6cf8d308e','恩藏主送古梅求詩','曾鞏','宋','宋诗','song-poetry','','[]','折得前村雪裏枝，殷勤來聘老夫詩。',32,'全唐诗/poet.song.26000.json','["折得前村雪裏枝，殷勤來聘老夫詩。", "請公靜看橫斜影，便是當年一字師。"]'),
('9057a9a4-ea72-47e2-8f02-00517471374a','餞神','曾鞏','宋','宋诗','song-poetry','','[]','擊牲釃酒薦明蠲，飣果裝香婢僕專。',64,'全唐诗/poet.song.26000.json','["擊牲釃酒薦明蠲，飣果裝香婢僕專。", "揀米作糜分糝椀，折篿爲箸插芳筵。", "兒驚庖下添熏肉，神笑人間用紙錢。", "巫祝謂知來歲事，珓杯猶有暫時權。"]'),
('b5d54fd3-9736-48a0-9494-90bef44cd8ad','千丈巖瀑布','曾鞏','宋','宋诗','song-poetry','','[]','玉虬垂處雪花翻，四季雷聲六月寒。',32,'全唐诗/poet.song.26000.json','["玉虬垂處雪花翻，四季雷聲六月寒。", "憑檻未窮千丈勢，請從巖下舉頭看。"]'),
('23a4a0a1-3ebf-4db9-8bb2-da90c051bc59','疏山','曾鞏','宋','宋诗','song-poetry','','[]','一見雲山病眼清，野僧勤動水邊迎。',32,'全唐诗/poet.song.26000.json','["一見雲山病眼清，野僧勤動水邊迎。", "蒼松翠竹東南道，亂石峰前踏月行。"]'),
('e5155465-cd45-4f71-ab36-11acef8591f4','石門','曾鞏','宋','宋诗','song-poetry','','[]','細草疏雲一徑凉，縱吟閒望興何長。',64,'全唐诗/poet.song.26000.json','["細草疏雲一徑凉，縱吟閒望興何長。", "僧關入竹行隨意，野茹持錢得滿筐。", "江腹遠吞千壑翠，峽門高控兩崖蒼。", "乘秋更欲西山雨，一洗郊原晚稻香。"]'),
('4c039144-62bc-4276-b721-f4a1f8fb0947','清風閣','曾鞏','宋','宋诗','song-poetry','','[]','百級危梯屈曲成，欄干朱碧半空橫。',64,'全唐诗/poet.song.26000.json','["百級危梯屈曲成，欄干朱碧半空橫。", "天垂遠水秋容靜，雪壓群山霽色明。", "海燕力窮飛不到，郊園陰合坐猶清。", "風前有客須留醉，莫放歸時月滿城。"]'),
('77664f22-0fb1-4660-91d4-2c0605e739b0','薛老亭晚歸','曾鞏','宋','宋诗','song-poetry','','[]','終日行山不出城，城中山勢與雲平。',64,'全唐诗/poet.song.26000.json','["終日行山不出城，城中山勢與雲平。", "萬家市井魚鹽合，千里川原彩錯明。", "座上潮風醒酒力，晚來巖霧蓋鐘聲。", "歸時休得燃官燭，在處林燈夾道迎。"]'),
('a9ce9cee-5005-4ba2-8b38-efc1b767ebf8','詩一首','曾鞏','宋','宋诗','song-poetry','','[]','食肉遺馬肝，未爲不知味。',48,'全唐诗/poet.song.26000.json','["食肉遺馬肝，未爲不知味。", "食魚必河豚，此理果何謂。", "非鱗亦非介，芒刺皮如蝟。", "見形固可憎，况復論腸胃。"]'),
('cf8dea01-2d38-41a5-85d0-84a941171b0f','句  其一','曾鞏','宋','宋诗','song-poetry','','[]','濯殘暑氣朝來雨，助作秋聲夜半風。',16,'全唐诗/poet.song.26000.json','["濯殘暑氣朝來雨，助作秋聲夜半風。"]'),
('4ff163d5-7026-4ffc-9b10-c34f6bd3cb1a','句  其二','曾鞏','宋','宋诗','song-poetry','','[]','荷花落日紅酣。',7,'全唐诗/poet.song.26000.json','["荷花落日紅酣。"]'),
('99c52185-6462-429a-87de-7a6265a839d9','句  其三','曾鞏','宋','宋诗','song-poetry','','[]','興亡兩丘土。',6,'全唐诗/poet.song.26000.json','["興亡兩丘土。"]'),
('c1809c3c-1f35-4111-b605-63338a8cc54d','句  其四','曾鞏','宋','宋诗','song-poetry','','[]','吟笑還孤永。',6,'全唐诗/poet.song.26000.json','["吟笑還孤永。"]'),
('9d09ddd3-32c1-4f74-b0d0-cee75507559c','句  其五','曾鞏','宋','宋诗','song-poetry','','[]','曠然青霞抱，永矣白雲適。',12,'全唐诗/poet.song.26000.json','["曠然青霞抱，永矣白雲適。"]'),
('a42fb712-830c-45cb-9753-dc803791ad15','句  其六','曾鞏','宋','宋诗','song-poetry','','[]','割蚌珠的皪。',6,'全唐诗/poet.song.26000.json','["割蚌珠的皪。"]'),
('aa91bc28-9da5-4468-8d84-70d377d2b131','句  其七','曾鞏','宋','宋诗','song-poetry','','[]','固知臭味非相類，其奈縈纏不自由。',16,'全唐诗/poet.song.26000.json','["固知臭味非相類，其奈縈纏不自由。"]'),
('aa811ac7-7e56-446b-b35a-35afadca2c64','存目','曾鞏','宋','宋诗','song-poetry','','[]','詩題：虞美人草首句：鴻門玉斗紛如雪。',18,'全唐诗/poet.song.26000.json','["詩題：虞美人草首句：鴻門玉斗紛如雪。"]'),
('6e2ce65e-1017-4b98-a00f-225cc4005820','逐伯强文','劉敞','宋','宋诗','song-poetry','','[]','皇皇上天兮，浩浩后土。',277,'全唐诗/poet.song.26000.json','["皇皇上天兮，浩浩后土。", "厥生孔繁兮，其施甚溥。", "陶陶仲夏兮，草木蕃廡。", "鳥獸孳息兮，我民樂胥。", "我民孔靈兮，上帝是仁。", "天子孔聖兮，百工日新。", "上無秕政兮，下無悖人。", "鄰里其集兮，樂哉欣欣。", "伯强何爲兮，孰畀以政。", "反世五福兮，持極以令。", "我民不怡兮，既喪其盛。", "白黑眩瞀兮，孰詧其正。", "謂壽反天兮，謂康反病。", "仁義無益兮，苟且爲幸。", "嗟爾子强兮，其獨何心。", "絕世和氣兮，俾民不任。", "上天孔神兮，大德曰生。", "天不可長罔兮，民不可久侵。", "天誅誠加兮靡所避，雷公驅兮風伯逝，嗟爾子强兮何所詣。", "南有蠻兮，爲寇爲逋。", "西羌戎兮，恃艱自虞。", "天子孔仁兮，靡焉畢屠。", "子强往兮，代天伐誅。", "嗟中國兮，不可久留。"]'),
('2f4af718-7873-4d3a-8e8c-6f5b1828df4f','屈原嘏辭','劉敞','宋','宋诗','song-poetry','','[]','維時仲夏，吉日維午。',242,'全唐诗/poet.song.26000.json','["維時仲夏，吉日維午。", "神歆既祠，錫辭以嘏。", "曰：朕之初生，皇揆予度。", "嘉朕以名，終身是守。", "抑豈不淑，不幸逢遇。", "離愍被憂，天不可訴。", "宗國爲墟，寧敢自賊。", "惟朕忍生，豈不永年。", "悁悁荆人，是拯是憐。", "赴水蹈波，歳不廢旃。", "既招朕魂，巫祝昔先。", "豈朕是私，将德是傳。", "淪胥及溺，初亦不悛。", "其後風靡，民益輕死。", "匪朕之心，是豈爲義。", "婦弔其夫，母傷其子。", "人訊其端，指予以詈。", "予亦念之，其本有自。", "昔朕婞直，不爲衆下。", "世予尚之，謂予好怒。", "昔朕不容，自投于江。", "世予尚之，謂予棄躬。", "既習而鬥，既遠益謬。", "被朕僞名，汙朕以咎。"]'),
('1cc6257d-5d03-48d7-be25-654b4ddbee8b','寄胡二因甫','劉敞','宋','宋诗','song-poetry','','[]','我思友人兮，在江之臯。',45,'全唐诗/poet.song.26000.json','["我思友人兮，在江之臯。", "去我無所兮，遠哉遙遙。", "世豈無美士兮，莫慰我勞。", "願爲白鶴兮，從之逍遙。"]'),
('7ca12cf0-5152-4a09-9eec-10aa25e8379e','河之水  其一','劉敞','宋','宋诗','song-poetry','','[]','河之水兮，一直而一曲。',19,'全唐诗/poet.song.26000.json','["河之水兮，一直而一曲。", "嗟湯湯兮安所屬。"]'),
('595af9c8-5e90-406a-885d-509a295bac50','河之水  其二','劉敞','宋','宋诗','song-poetry','','[]','河之水兮，一濁而一清。',19,'全唐诗/poet.song.26000.json','["河之水兮，一濁而一清。", "嗟湯湯兮何時平。"]'),
('9fdb631e-c277-4efb-bc82-3e5d983d8c84','彼山詩  其一','劉敞','宋','宋诗','song-poetry','','[]','彼山之阻兮，虎豹兟兟。',22,'全唐诗/poet.song.26000.json','["彼山之阻兮，虎豹兟兟。", "我旋而歸兮，虎來即人。"]'),
('90dea6a9-a730-4c42-9933-2f9038113253','彼山詩  其二','劉敞','宋','宋诗','song-poetry','','[]','彼山之澳兮，雄虺攸伏。',22,'全唐诗/poet.song.26000.json','["彼山之澳兮，雄虺攸伏。", "我息而作兮，虺将起陸。"]'),
('c34d4729-8e42-4d15-8e9b-ceb4bfc84961','彼山詩  其三','劉敞','宋','宋诗','song-poetry','','[]','深不可游兮，高不可飛。',21,'全唐诗/poet.song.26000.json','["深不可游兮，高不可飛。", "我後而悔兮，安庸歸。"]'),
('eeb45365-dedb-4f9f-9ae9-a660c7bfbfee','武溪深  其一','劉敞','宋','宋诗','song-poetry','','[]','武溪之水兮，日夜而東流。',23,'全唐诗/poet.song.26000.json','["武溪之水兮，日夜而東流。", "淺不可厲兮，深不可游。"]'),
('ea8243bd-fdb5-4067-a141-6b0cdfa69316','武溪深  其二','劉敞','宋','宋诗','song-poetry','','[]','武溪之山兮，高下而相乘。',23,'全唐诗/poet.song.26000.json','["武溪之山兮，高下而相乘。", "卑不可越兮，危不可憑。"]'),
('93836f7d-cbe9-412f-bba9-e908544c5135','武溪深  其三','劉敞','宋','宋诗','song-poetry','','[]','母水于憾兮，毋山于仇。',22,'全唐诗/poet.song.26000.json','["母水于憾兮，毋山于仇。", "庚庚武溪兮，曷云其尤。"]'),
('9746177a-edcf-4dad-a3ad-52027be361c1','懷歸詩  其一','劉敞','宋','宋诗','song-poetry','','[]','淮水悠悠兮，去我無舟。',22,'全唐诗/poet.song.26000.json','["淮水悠悠兮，去我無舟。", "匪我無舟兮，此焉優游。"]'),
('268b7a3f-fd98-43ae-bd90-d663b5c239ec','懷歸詩  其二','劉敞','宋','宋诗','song-poetry','','[]','淮水洋洋兮，去我無梁。',22,'全唐诗/poet.song.26000.json','["淮水洋洋兮，去我無梁。", "匪淮無梁兮，此焉翺翔。"]'),
('f4d209e7-ed0c-4a28-b598-d45319e0f35f','懷歸詩  其三','劉敞','宋','宋诗','song-poetry','','[]','淮水東注兮，惟禹之績。',26,'全唐诗/poet.song.26000.json','["淮水東注兮，惟禹之績。", "古人不可及兮，吾獨淹留其何得。"]'),
('b69f1272-3d4a-413b-8f37-6f51aab9a971','魏京詩  其一','劉敞','宋','宋诗','song-poetry','','[]','皇作大都，大都雄雄。',20,'全唐诗/poet.song.26000.json','["皇作大都，大都雄雄。", "奄定北國，四方來同。"]'),
('4762ccf0-d49e-4cce-b0ff-5f9f59b2db04','魏京詩  其二','劉敞','宋','宋诗','song-poetry','','[]','皇曰卿士，在昔聖考。',20,'全唐诗/poet.song.26000.json','["皇曰卿士，在昔聖考。", "祗遹文武，維慈幼老。"]'),
('6f07552d-c16e-44cd-835f-857330370ac2','魏京詩  其三','劉敞','宋','宋诗','song-poetry','','[]','天監在上，既有明德。',20,'全唐诗/poet.song.26000.json','["天監在上，既有明德。", "乃命于下，罔有不服。"]'),
('1a473794-c808-4416-b2bf-32eddac0cee7','魏京詩  其四','劉敞','宋','宋诗','song-poetry','','[]','匪允命之，亦章慶之。',20,'全唐诗/poet.song.26000.json','["匪允命之，亦章慶之。", "匪允服之，亦保育之。"]'),
('72f26796-5466-4160-bade-01110e28c28c','魏京詩  其五','劉敞','宋','宋诗','song-poetry','','[]','時維玁狁，侮予之疆。',20,'全唐诗/poet.song.26000.json','["時維玁狁，侮予之疆。", "靡度靡虞，跳呼以狂。"]'),
('992da159-5cb5-44c6-8a86-132606a46304','魏京詩  其六','劉敞','宋','宋诗','song-poetry','','[]','業業烝黎，載震載驚。',20,'全唐诗/poet.song.26000.json','["業業烝黎，載震載驚。", "侵魏及澶，羣心不寧。"]'),
('c8afce86-09f7-4b14-89cd-2cc1573037d5','魏京詩  其七','劉敞','宋','宋诗','song-poetry','','[]','帝奮厥武，百萬其士。',20,'全唐诗/poet.song.26000.json','["帝奮厥武，百萬其士。", "匪怒以棘，于三千里。"]'),
('c5af31e5-8ab6-43ed-a565-0d2891e868af','魏京詩  其八','劉敞','宋','宋诗','song-poetry','','[]','如虎如貔，如霆如雷。',20,'全唐诗/poet.song.26000.json','["如虎如貔，如霆如雷。", "靡有遠邇，天子其來。"]'),
('64c76b43-9298-4a48-be72-b05d63398814','魏京詩  其九','劉敞','宋','宋诗','song-poetry','','[]','天子來止，士增其喜。',20,'全唐诗/poet.song.26000.json','["天子來止，士增其喜。", "孰偷其生，以不奮興。"]'),
('12a36fb2-c66b-4784-99c9-bf8cd2138e58','魏京詩  其一○','劉敞','宋','宋诗','song-poetry','','[]','驅之渾渾，攘之賁賁。',20,'全唐诗/poet.song.26000.json','["驅之渾渾，攘之賁賁。", "靡有輈張，殱厥鯨鯤。"]'),
('21144bb6-66a1-4110-8763-96ba9abb0616','魏京詩  其一一','劉敞','宋','宋诗','song-poetry','','[]','或獻其寶，或請其命。',20,'全唐诗/poet.song.26000.json','["或獻其寶，或請其命。", "帝振于旅，惟時既定。"]'),
('fbfe222d-8f05-4cc1-a6ab-16e6c08e8cf7','魏京詩  其一二','劉敞','宋','宋诗','song-poetry','','[]','屹屹魏土，山河之固。',22,'全唐诗/poet.song.26000.json','["屹屹魏土，山河之固。", "匪山河則固，惟上帝伊祜。"]'),
('cb35d8d3-bf51-4d27-b4ad-4e5c5f44282e','魏京詩  其一三','劉敞','宋','宋诗','song-poetry','','[]','既閟爾弓，既櫜爾矛。',20,'全唐诗/poet.song.26000.json','["既閟爾弓，既櫜爾矛。", "玁狁臣止，四方是休。"]'),
('9585bdb1-ca14-49f7-987e-04c5dec8c7b9','魏京詩  其一四','劉敞','宋','宋诗','song-poetry','','[]','皇曰卿士，聖考之德。',20,'全唐诗/poet.song.26000.json','["皇曰卿士，聖考之德。", "允于孝思，孝思惟則。"]'),
('488fa2aa-e2a9-4ef3-ab13-06681c107527','魏京詩  其一五','劉敞','宋','宋诗','song-poetry','','[]','爾視京魏，以作我都。',20,'全唐诗/poet.song.26000.json','["爾視京魏，以作我都。", "以赫厥靈，俾後勿逾。"]'),
('9ec22111-0090-4355-8843-8b59963d1449','魏京詩  其一六','劉敞','宋','宋诗','song-poetry','','[]','皇曰卿士，惟帝時功。',20,'全唐诗/poet.song.26000.json','["皇曰卿士，惟帝時功。", "時亦惟人，惟寇萊公。"]'),
('c6d7d3c6-dbf9-4915-8cba-8b62f3fc84cd','魏京詩  其一七','劉敞','宋','宋诗','song-poetry','','[]','爾慎爾止，弼予于治。',20,'全唐诗/poet.song.26000.json','["爾慎爾止，弼予于治。", "期爾前人，用迪爾事。"]'),
('a930d8f1-038c-4c4e-ab32-1ea683c0dc3e','魏京詩  其一八','劉敞','宋','宋诗','song-poetry','','[]','皇曰卿士，惟帝作武。',20,'全唐诗/poet.song.26000.json','["皇曰卿士，惟帝作武。", "垂是萬年，莫敢予侮。"]'),
('85daf63c-2636-40ad-ae05-96f97e55fd23','魏京詩  其一九','劉敞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山之封，后土之禪。',20,'全唐诗/poet.song.26000.json','["泰山之封，后土之禪。", "予監若兹，惟天是眷。"]'),
('c8f7af22-37a4-4d1f-86df-9640df5a6d95','魏京詩  其二○','劉敞','宋','宋诗','song-poetry','','[]','翼翼之土，天子國之。',20,'全唐诗/poet.song.26000.json','["翼翼之土，天子國之。", "穆穆原廟，聖人則之。"]'),
('02df33ff-71e2-4e88-81ca-7894d7f616fd','魏京詩  其二一','劉敞','宋','宋诗','song-poetry','','[]','孰爲强暴，敢不來覲。',20,'全唐诗/poet.song.26000.json','["孰爲强暴，敢不來覲。", "俾怛于威，于忠是訓。"]'),
('7ea71ad8-6074-4207-87ec-6d175f787ca7','魏京詩  其二二','劉敞','宋','宋诗','song-poetry','','[]','顯顯天子，孝德自躬。',20,'全唐诗/poet.song.26000.json','["顯顯天子，孝德自躬。", "率是休烈，覃之北戎。"]'),
('2dafe343-c165-450d-b6c6-3fa4d5414000','魏京詩  其二三','劉敞','宋','宋诗','song-poetry','','[]','河水東注，昭哉禹績。',20,'全唐诗/poet.song.26000.json','["河水東注，昭哉禹績。", "時萬斯年，天子之德。"]'),
('829d4936-38c6-4929-be69-07023b8529d7','古怨詩  其一','劉敞','宋','宋诗','song-poetry','','[]','鴻鴈飛矣，邕邕其族。',20,'全唐诗/poet.song.26000.json','["鴻鴈飛矣，邕邕其族。", "孰是人斯，惸惸其獨。"]'),
('37b77c24-e06e-433f-ac79-9470cad45c6c','古怨詩  其二','劉敞','宋','宋诗','song-poetry','','[]','鴻鴈飛矣，或羣或伍。',20,'全唐诗/poet.song.26000.json','["鴻鴈飛矣，或羣或伍。", "孰是人斯，惸惸其處。"]'),
('8cc920db-5b1c-431e-a0c1-79ccc9893128','古怨詩  其三','劉敞','宋','宋诗','song-poetry','','[]','天兮地兮，戴且履兮。',20,'全唐诗/poet.song.26000.json','["天兮地兮，戴且履兮。", "孰是人斯，莫我視兮。"]'),
('d690a0ff-402a-496f-80bb-28aaadd70806','古怨詩  其四','劉敞','宋','宋诗','song-poetry','','[]','日兮月兮，出兮没兮。',20,'全唐诗/poet.song.26000.json','["日兮月兮，出兮没兮。", "孰是人斯，遠我忽兮。"]'),
('a7d809da-712f-40e7-9c91-3a6ec10ed544','雜詩效阮步兵','劉敞','宋','宋诗','song-poetry','','[]','浮雲泱鬱，迨天未雨。',140,'全唐诗/poet.song.26000.json','["浮雲泱鬱，迨天未雨。", "習習和風，長我稷黍。", "乾道變化，羣龍以序。", "元首永康，股肱是輔。", "其輔惟何，惟伊及呂。", "其康惟何，惟堯及禹。", "我食既豐，我衣惟楚。", "無有後艱，既歌且舞。", "我徂何往，于彼淮濱。", "俯玩其流，清波磷磷。", "扶搖起鷴，四海揚塵。", "孰能高蹈，獨潔其身。", "衆人惑惑，賢者葆真。", "獨寐寤歌，忘我賤貧。"]'),
('9ec9e778-8b46-4bad-99e8-c79c4f4e608c','四皓歌  其一','劉敞','宋','宋诗','song-poetry','','[]','與汝攜手，南山之阿。',20,'全唐诗/poet.song.26000.json','["與汝攜手，南山之阿。", "富貴多憂，孰知其他。"]'),
('207d6fe1-d8c4-4089-b25b-dd04c7bea35d','四皓歌  其二','劉敞','宋','宋诗','song-poetry','','[]','大風横厲，江海蕩波。',20,'全唐诗/poet.song.26000.json','["大風横厲，江海蕩波。", "嗟汝鱗介，傷如之何。"]'),
('ae870ddc-1cd5-4407-902f-e946ba239a2e','四皓歌  其三','劉敞','宋','宋诗','song-poetry','','[]','高巖有薇，深谷有芝。',20,'全唐诗/poet.song.26000.json','["高巖有薇，深谷有芝。", "人生實難，委曲何爲。"]'),
('45d2920d-639a-4e6b-866f-b1ef3fd027f3','閔雨詩  其一','劉敞','宋','宋诗','song-poetry','','[]','堪輿絪緼，一晦一明。',30,'全唐诗/poet.song.26000.json','["堪輿絪緼，一晦一明。", "或沈而晦，或亢而暘。", "自古已然，世習爲常。"]'),
('7237d7c8-ae5a-4d47-8c21-c920f8126a4d','閔雨詩  其二','劉敞','宋','宋诗','song-poetry','','[]','民生冥冥，靡究靡知。',30,'全唐诗/poet.song.26000.json','["民生冥冥，靡究靡知。", "其幸而吉，不幸而災。", "猖狂妄行，惟所遇之。"]'),
('88882766-ca50-444a-97a2-b20f732e00b0','閔雨詩  其三','劉敞','宋','宋诗','song-poetry','','[]','天命降監，在我元聖。',30,'全唐诗/poet.song.26000.json','["天命降監，在我元聖。", "兼覆廣裕，四方既定。", "惟民之恤，無所疵病。"]'),
('f604e9d9-75ca-4507-aa84-e52349ac0012','閔雨詩  其四','劉敞','宋','宋诗','song-poetry','','[]','伊年暮春，旱久不雨。',30,'全唐诗/poet.song.26000.json','["伊年暮春，旱久不雨。", "人曰時哉，曆有常數。", "禹湯之賢，莫能弗遇。"]'),
('fc6f84e9-bff3-444f-a9da-4fff05f9cf02','閔雨詩  其五','劉敞','宋','宋诗','song-poetry','','[]','帝獨喟息，是豈足言。',30,'全唐诗/poet.song.26000.json','["帝獨喟息，是豈足言。", "化育萬物，若鎔以埏。", "患在誠薄，不能動天。"]'),
('1cb37d17-8401-4216-9816-1bbd50180952','閔雨詩  其六','劉敞','宋','宋诗','song-poetry','','[]','退而齋心，淵默以居。',30,'全唐诗/poet.song.26000.json','["退而齋心，淵默以居。", "鐘鼓不設，宴游不娛。", "左右肅然，壹懷瞿瞿。"]'),
('f5944d9d-80f5-4e93-bb3b-597e56f6ce5c','閔雨詩  其七','劉敞','宋','宋诗','song-poetry','','[]','疏獄省刑，與物更始。',30,'全唐诗/poet.song.26000.json','["疏獄省刑，與物更始。", "內恕孔悲，引咎在己。", "爰及四海，愚智咸喜。"]'),
('24ecc5d7-1afd-4376-972a-b1b626c2817c','閔雨詩  其八','劉敞','宋','宋诗','song-poetry','','[]','追悟讜直，褒進淹滯。',30,'全唐诗/poet.song.26000.json','["追悟讜直，褒進淹滯。", "聲色無迕，式序在位。", "嬖習權近，懾威屏氣。"]'),
('558b7e5e-c7a9-4604-af70-dccb8b48b49d','閔雨詩  其九','劉敞','宋','宋诗','song-poetry','','[]','己巳乃雨，若有鬼神。',30,'全唐诗/poet.song.26000.json','["己巳乃雨，若有鬼神。", "凄凄其風，渰渰其雲。", "自東徂西，罄無不均。"]'),
('83ea2e33-fe00-4c20-9805-855f0fdf061e','閔雨詩  其一○','劉敞','宋','宋诗','song-poetry','','[]','匪震匪拔，匪溢匪洩。',30,'全唐诗/poet.song.26000.json','["匪震匪拔，匪溢匪洩。", "生我百穀，區萌畢達。", "以享以食，小大胥悅。"]'),
('20abff69-8ce8-4cf6-ac11-c84b4e0a561d','閔雨詩  其一一','劉敞','宋','宋诗','song-poetry','','[]','天子之德，視雨之施。',30,'全唐诗/poet.song.26000.json','["天子之德，視雨之施。", "肇自京師，達于四裔。", "無有蠻貊，孚我君惠。"]'),
('6377d93b-9788-46e5-8dbd-62c3ab30932f','閔雨詩  其一二','劉敞','宋','宋诗','song-poetry','','[]','天子之政，視雨之時。',30,'全唐诗/poet.song.26000.json','["天子之政，視雨之時。", "養老長幼，速哉熙熙。", "更化易俗，而民不知。"]'),
('970532f2-7f1f-46a0-af4d-dc9e5388066f','閔雨詩  其一三','劉敞','宋','宋诗','song-poetry','','[]','天子之慶，視雨之積。',30,'全唐诗/poet.song.26000.json','["天子之慶，視雨之積。", "自天降康，時萬時億。", "眉壽無疆，以靖四國。"]'),
('56689b28-ddc5-4800-a9b9-0acb4f72bd93','雜詩二十二首  其一','劉敞','宋','宋诗','song-poetry','','[]','五都貨財地，車馬趨市闤。',72,'全唐诗/poet.song.26000.json','["五都貨財地，車馬趨市闤。", "平明側肩入，薄暮掉臂旋。", "意氣何所期，盛衰俛仰間。", "乃知藝利合，厚薄未可原。", "張陳父子游，一旦復相殘。", "萬古稱凶終，此獨何足言。"]'),
('6f09e63c-b37e-4718-8e60-5439fe67b041','雜詩二十二首  其二','劉敞','宋','宋诗','song-poetry','','[]','大火序炎夏，盛陽劇炮燔。',72,'全唐诗/poet.song.26000.json','["大火序炎夏，盛陽劇炮燔。", "空桐疾風來，書景中變寒。", "皇天自平分，四氣尚相干。", "涼燠異朝夕，萬事誰獨堅。", "宛彼風中籜，衆芳自此殘。", "至理冥變化，履霜用爲歎。"]'),
('9adffcc7-9620-4237-a87b-ebfd21556412','雜詩二十二首  其三','劉敞','宋','宋诗','song-poetry','','[]','至人邁龍德，世豈識潛升。',72,'全唐诗/poet.song.26000.json','["至人邁龍德，世豈識潛升。", "昔在周道衰，伯陽起西征。", "胡爲委一世，畏此網與罾。", "川竭山亦摧，喟然吾何稱。", "豈不懷徘徊，民言憯無懲。", "亹亹强著書，後賢以爲經。"]'),
('ec62fd78-20d3-413d-9b16-bcf37154c3d4','雜詩二十二首  其四','劉敞','宋','宋诗','song-poetry','','[]','崑崙邈人境，日月相蔽虧。',96,'全唐诗/poet.song.26000.json','["崑崙邈人境，日月相蔽虧。", "上有仙聖居，帝閽俯崔嵬。", "王毋坐少廣，有娥閟瑤臺。", "弱水不可梁，大荒曠無厓。", "周穆昔好游，超絕僅能陪。", "方朔偷桃兒，沈濁何乃來。", "青鳥通其使，雄鳥爲之媒。", "靈化信難測，真契從此推。"]'),
('201c023a-b4ba-4f41-9f36-4ec8ae683854','雜詩二十二首  其五','劉敞','宋','宋诗','song-poetry','','[]','勿以隋侯珠，彈雀千仞峰。',48,'全唐诗/poet.song.26000.json','["勿以隋侯珠，彈雀千仞峰。", "勿以和氏璧，投人昏夜中。", "彈雀不可期，投人未必容。", "大賢惡皦皦，所以明若蒙。"]'),
('21b8c494-cc41-4574-b703-c48710dc83dd','雜詩二十二首  其六','劉敞','宋','宋诗','song-poetry','','[]','積薪莫自高，失馬莫自悲。',48,'全唐诗/poet.song.26000.json','["積薪莫自高，失馬莫自悲。", "薪積常先焚，馬失常復歸。", "人情習所近，物理豈易推。", "君看禍福間，紛糾如纆徽。"]'),
('c8dcff85-1978-44e6-9337-17941e39540b','雜詩二十二首  其七','劉敞','宋','宋诗','song-poetry','','[]','朱暉乘餘香，三月覺徂暑。',48,'全唐诗/poet.song.26000.json','["朱暉乘餘香，三月覺徂暑。", "流光不相待，時節猶逆旅。", "煌煌園中花，零落會見汝。", "啼鴂鳴空林，良辰竟何許。"]'),
('76ee36fc-ef39-4e2a-81ae-bdad044befde','雜詩二十二首  其八','劉敞','宋','宋诗','song-poetry','','[]','秋風吹賓鴻，千里飛一息。',96,'全唐诗/poet.song.26000.json','["秋風吹賓鴻，千里飛一息。", "水闊稻粱寡，天寒霜雪逼。", "豈不抱遠志，憔悴傷顔色。", "鷾鴯乘春暉，采采華羽翼。", "側身襲人間，慧巧誰怵愓。", "出入金玉堂，戶牖初不隔。", "上無飲啄患，下有居處益。", "胡爲事高遠，骯髒莫自適。"]'),
('a9e4d8da-02d9-4ac0-92b5-94751e9632ca','雜詩二十二首  其九','劉敞','宋','宋诗','song-poetry','','[]','駑駘不下廏，騏驥行萬里。',48,'全唐诗/poet.song.26000.json','["駑駘不下廏，騏驥行萬里。", "勞逸誰爲多，芻豢復誰美。", "天機信其宜，人事亦何恥。", "世無王樂徒，駿骨或空死。"]'),
('0c76897e-6275-4146-8c12-64c4317cf161','雜詩二十二首  其一○','劉敞','宋','宋诗','song-poetry','','[]','悠悠浮空雲，明暉何倐忽。',48,'全唐诗/poet.song.26000.json','["悠悠浮空雲，明暉何倐忽。", "造物固難恃，變化亦倉猝。", "響莫爲雷霆，明莫爲日月。", "日月易遮蔽，雷霆易奔絕。"]'),
('8f42706e-0ab4-4787-ad90-ac057dc48872','雜詩二十二首  其一一','劉敞','宋','宋诗','song-poetry','','[]','古風不可復，習俗已久敝。',84,'全唐诗/poet.song.26000.json','["古風不可復，習俗已久敝。", "咄嗟忠與信，流蕩爲詐術。", "詐忠惑其君，詐愚安其身。", "色厲內以荏，行違貎取仁。", "三年始横流，後來更日新。", "至公棄塗炭，正道敗荆榛。", "已矣千載後，誰能反其身。"]'),
('08299f97-d8f4-4f0c-aa4e-5a64462ebf94','雜詩二十二首  其一二','劉敞','宋','宋诗','song-poetry','','[]','毁巢鳯不至，竭澤龍不游。',84,'全唐诗/poet.song.26000.json','["毁巢鳯不至，竭澤龍不游。", "賢者有所歸，得非龍鳯儔。", "周公下白屋，聖德被九州。", "趙禹謝賓客，漢朝以爲優。", "澆淳不相襲，用舍何其繆。", "苟循一身利，不爲萬姓謀。", "哀彼杖杜詩，死生遺道周。"]'),
('5c748086-49ae-4290-9ee2-9da1cfd6d1b4','雜詩二十二首  其一三','劉敞','宋','宋诗','song-poetry','','[]','皇天不絕命，百姓何震愆。',72,'全唐诗/poet.song.26000.json','["皇天不絕命，百姓何震愆。", "歳暮霜雪至，悠悠事南遷。", "羈鳥哀去巢，游魚樂懷淵。", "如何道旁子，逝將不復還。", "西望周鄭郊，顧想河洛間。", "伯魚不可作，涕流爲淪漣。"]'),
('77fbe62d-5f89-4753-b9af-fa0e85dbbf64','雜詩二十二首  其一四','劉敞','宋','宋诗','song-poetry','','[]','爨桐深竈下，埋劍古獄間。',48,'全唐诗/poet.song.26000.json','["爨桐深竈下，埋劍古獄間。", "怨聲動旁人，憤氣凌彼天。", "當時頗見旌，後世稱爲賢。", "自古聞知音，此事或偶然。"]'),
('5acbb0fa-a1f4-4884-947b-3e9f64c3a45e','雜詩二十二首  其一五','劉敞','宋','宋诗','song-poetry','','[]','嶰山有奇竹，老棄陰崖巔。',72,'全唐诗/poet.song.26000.json','["嶰山有奇竹，老棄陰崖巔。", "太丘有神鼎，逃匿千丈淵。", "光景閟不見，音容杳無傳。", "豈能向時俗，干進心拳拳。", "世貴一人敵，又稱朱絲弦。", "吾欲評其風，願君詠此篇。"]'),
('64e6886a-b757-48cf-91c9-1d3f31ac2753','雜詩二十二首  其一六','劉敞','宋','宋诗','song-poetry','','[]','鑿井取泉飲，上山采薇食。',72,'全唐诗/poet.song.26000.json','["鑿井取泉飲，上山采薇食。", "豈不信憔悴，所願皆我力。", "泉也非難致，薇也亦易得。", "志士恥徒飽，衆人苟所獲。", "犧牲畏芻拳，樊籠害羽翼。", "悟理宜在早，無爲晚更惑。"]'),
('dafaddc2-4095-482e-9151-c7b23b9cf350','雜詩二十二首  其一七','劉敞','宋','宋诗','song-poetry','','[]','蛟龍蟠深泥，魚龜頗同調。',60,'全唐诗/poet.song.26000.json','["蛟龍蟠深泥，魚龜頗同調。", "變化且何有，蝘蜓亦可笑。", "煌煌千金珠，百仞閟其耀。", "風雷在所遇，隱顯始獨妙。", "屈身天地間，微物安得料。"]'),
('df8eb434-106e-4d01-bd3c-91d57e80e00d','雜詩二十二首  其一八','劉敞','宋','宋诗','song-poetry','','[]','伯夷逃西山，尼父居九夷。',84,'全唐诗/poet.song.26000.json','["伯夷逃西山，尼父居九夷。", "世苟不我用，我方從此辭。", "道悠豈忌遠，義豐不云饑。", "世非乏賢士，爲問從者誰。", "由也實好勇，叔齊固同時。", "捨此乃無人，籧篨而戚施。", "遠矣千歳後，愴焉我心悲。"]'),
('d8229c8e-d6b6-42f1-804f-07e57b0c9c24','雜詩二十二首  其一九','劉敞','宋','宋诗','song-poetry','','[]','道薄德亦散，功名爲時須。',72,'全唐诗/poet.song.26000.json','["道薄德亦散，功名爲時須。", "用力世所賢，守正衆云愚。", "智者競蒿目，小人復邇圖。", "悠悠三季後，此風益已渝。", "安知治未病，舐痔而多車。", "堯舜無能名，越哉巳矣夫。"]'),
('f2b2dfdc-ab03-4284-8036-7b537175bdda','雜詩二十二首  其二○','劉敞','宋','宋诗','song-poetry','','[]','雍門妙弦歌，哀響激人耳。',48,'全唐诗/poet.song.27000.json','["雍門妙弦歌，哀響激人耳。", "偉哉孟嘗君，慷慨淚如水。", "當生復念死，誰謂悲能已。", "絲桐信感人，世固乏之子。"]'),
('69707b46-3490-45ca-a811-8563aff25e1d','雜詩二十二首  其二一','劉敞','宋','宋诗','song-poetry','','[]','昔者有化人，來集周王庭。',108,'全唐诗/poet.song.27000.json','["昔者有化人，來集周王庭。", "咫尺逝萬里，頃刻超百齡。", "五音蕩心神，耳亂不可聽。", "衆采眩其目，不分丹與青。", "飄鷂惑真僞，怳忽迷窈冥。", "馳思八極表，詎知日與星。", "未嘗出戶牖，自疑涉天廷。", "左右莫覺悟，兀然殆遺形。", "祈招作悲歌，聖賢用爲經。"]'),
('1534b5fd-aa10-429e-81b6-6eef7421cbeb','雜詩二十二首  其二二','劉敞','宋','宋诗','song-poetry','','[]','翩翩丹穴鳥，志在萬里外。',48,'全唐诗/poet.song.27000.json','["翩翩丹穴鳥，志在萬里外。", "營營持罦叟，何事守蒿艾。", "聲音可得聞，羽翮不能害。", "嗟彼雉與兔，首身自此碎。"]'),
('babae25f-3e91-4939-a33f-ca27b4398b4c','詠古詩十二首  其一','劉敞','宋','宋诗','song-poetry','','[]','虹蜺明西方，五色相屬聫。',60,'全唐诗/poet.song.27000.json','["虹蜺明西方，五色相屬聫。", "浮雲萬里來，泱鬱天宇間。", "白日晦無象，盛陽變爲寒。", "洚水彌九土，陵谷相貿遷。", "盈虛叵前測，物理有固然。"]'),
('ee8c2af1-93c8-473e-bcef-a958c0a609b6','詠古詩十二首  其二','劉敞','宋','宋诗','song-poetry','','[]','長離乘風起，四顧求所棲。',60,'全唐诗/poet.song.27000.json','["長離乘風起，四顧求所棲。", "路窮臨蒼梧，復排層霄飛。", "豈不願安處，不知所可依。", "罾繳充逕隧，鴟梟正鳴悲。", "瞑夫抱同律，曠絕將何希。"]'),
('1a4ddbbb-8e6a-4470-a007-e751a29ec8d3','詠古詩十二首  其三','劉敞','宋','宋诗','song-poetry','','[]','趙國棄鳴犢，孔聖爲之回。',96,'全唐诗/poet.song.27000.json','["趙國棄鳴犢，孔聖爲之回。", "西伯善養老，伯夷以爲歸。", "馳驅西楚郊，徘徊太皥墟。", "周漢多封君，不祀既忽諸。", "三墳基皇德，八索總道樞。", "若人豈欺我，虞夏亦典謨。", "萬里如浮雲，古風訖無餘。", "往矣不可追，喟然爲躊躇。"]'),
('48282d19-d6cb-44ee-9835-543c4690933f','詠古詩十二首  其四','劉敞','宋','宋诗','song-poetry','','[]','游鱗泳泉下，黄鵠巢林端。',72,'全唐诗/poet.song.27000.json','["游鱗泳泉下，黄鵠巢林端。", "得失不相及，天理庸自全。", "有虞垂衣裳，西母獻厥環。", "周穆賓崑丘，車轍萬里間。", "宗廟頽爲墟，閶闔不可攀。", "祈招作悲詩，萬里用爲歎。"]'),
('a4824faf-3ece-4863-8e33-1d5624b6f42c','詠古詩十二首  其五','劉敞','宋','宋诗','song-poetry','','[]','靈山生神芝，一年再三秀。',72,'全唐诗/poet.song.27000.json','["靈山生神芝，一年再三秀。", "絢彩奪霞露，熒煌寄巖岫。", "真人勸我飡，可以躋萬壽。", "自古王子喬，秘此莫輕授。", "采之豈辭遠，時逝不可又。", "歳晏懷所思，終焉不盈袖。"]'),
('bf7c3f43-09ed-4776-b202-8bf91f7c4952','詠古詩十二首  其六','劉敞','宋','宋诗','song-poetry','','[]','元鈞運洪爐，晝夜不少停。',72,'全唐诗/poet.song.27000.json','["元鈞運洪爐，晝夜不少停。", "萬物更相禪，一氣紛異形。", "駒掇出竈下，久竹爲青寧。", "孰知范氏犧，晚就南畝耕。", "至人友造化，逝與一世冥。", "善惡故不屑，寵辱何足驚。"]'),
('384aca43-fcf1-4997-a097-277018aa15f1','詠古詩十二首  其七','劉敞','宋','宋诗','song-poetry','','[]','東遊滄海濱，回首面大荒。',72,'全唐诗/poet.song.27000.json','["東遊滄海濱，回首面大荒。", "豁達三齊風，連山鬱蒼蒼。", "在漢田横氏，不忍南面王。", "磊落五百賢，從死忽若亡。", "壯士不必成，令名固爲長。", "異體同一心，萬年尚耿光。"]'),
('332fe6fb-b38d-492d-804b-5b86977f4d97','詠古詩十二首  其八','劉敞','宋','宋诗','song-poetry','','[]','天道不可聞，自昔孔子徒。',72,'全唐诗/poet.song.27000.json','["天道不可聞，自昔孔子徒。", "籍籍秦漢間，將非愚且誣。", "大河決東郡，火德以爲符。", "哀哉冀州壤，兆民散爲魚。", "公孫雖前覺，執政疾魯儒。", "世無異物神，終竟遺泥塗。"]'),
('3d67fe1f-152b-4af5-8f95-ddcf1a201429','詠古詩十二首  其九','劉敞','宋','宋诗','song-poetry','','[]','萇弘謀周室，憤血死猶碧。',72,'全唐诗/poet.song.27000.json','["萇弘謀周室，憤血死猶碧。", "子胥殞吳門，江水爲之逆。", "精能動天地，忠不諭兩國。", "九鼎既西逝，姑蘇亦東側。", "偷容習爲俗，萬世未遽易。", "形勢敺使然，生民豈惡直。"]'),
('b7818a89-aa6f-4f89-a774-2240f3df61d8','詠古詩十二首  其一○','劉敞','宋','宋诗','song-poetry','','[]','麒麟不可羈，安得書春秋。',72,'全唐诗/poet.song.27000.json','["麒麟不可羈，安得書春秋。", "鳯凰云難致，孰使鳴岐周。", "無田于甫田，歳月忽已遒。", "如非行邁謀，自宜道路脩。", "安知吹鳴律，燕谷成良疇。", "不見託秋駕，崑墟亦能游。"]'),
('7ad1faf6-2fac-4c1f-8cc0-0a79d2bd6528','詠古詩十二首  其一一','劉敞','宋','宋诗','song-poetry','','[]','通都天下衢，名化交百廛。',72,'全唐诗/poet.song.27000.json','["通都天下衢，名化交百廛。", "鳴鷄側肩入，日暮掉臂還。", "有生寄無窮，過若空中煙。", "俯仰異去就，況乃多歷年。", "留侯獨悟此，解組從列仙。", "萬戶如脫屣，故爲絕世賢。"]'),
('01fdaabd-d17b-481b-be14-e97bd9aaa0e7','詠古詩十二首  其一二','劉敞','宋','宋诗','song-poetry','','[]','南山有樛木，葛虆蔓其封。',72,'全唐诗/poet.song.27000.json','["南山有樛木，葛虆蔓其封。", "上枝結紛菲，下枝散蒙蘢。", "下能使上好，上亦令下通。", "寧知力不足，歳暮摧烈風。", "苦成任兩國，德孰與棟隆。", "君苟以此始，又當以此終。"]'),
('3c5a467c-11d4-4d82-8ed8-e60828991188','讀峴山詩寄獻八舅龍圖','劉敞','宋','宋诗','song-poetry','','[]','道悠寄先覺，神契無近知。',96,'全唐诗/poet.song.27000.json','["道悠寄先覺，神契無近知。", "彼美羊公意，今在峴山詩。", "陵谷非一變，榮名獨至兹。", "當時偶然語，正與來者期。", "慷慨激悲歌，崔嵬構叢祠。", "懷哉千歳後，慰此江漢思。", "公亦蹈前人，方爲帝王師。", "奮筆成不朽，何啻中亭碑。"]'),
('1f6a7933-15bf-4170-af38-225369c69eaf','偶作二首  其一','劉敞','宋','宋诗','song-poetry','','[]','蓬蒿附高原，芙蕖植汙池。',48,'全唐诗/poet.song.27000.json','["蓬蒿附高原，芙蕖植汙池。", "物生自有性，不爲高下移。", "貴在世所用，未可以爲師。", "賤在衆不識，未可以爲嗤。"]'),
('6a6c0ecd-a7b0-46c5-a3a0-4fb086277d90','偶作二首  其二','劉敞','宋','宋诗','song-poetry','','[]','州來薄千乘，巢父輕九州。',108,'全唐诗/poet.song.27000.json','["州來薄千乘，巢父輕九州。", "齊景登牛山，涕泗獨交流。", "左右同來人，嗚咽不息收。", "共知富貴樂，變化不可留。", "四顧更悲嘆，萬類莽悠悠。", "歌舞未終曲，回首已可愁。", "或指白楊下，荒草古時丘。", "危辭才感拂，耿耿相應酬。", "豈識達觀士，笑爾若蜉蝣。"]'),
('bf2bd8ee-0977-4369-9ca6-2c4d731528d0','蒙示容齋詩輒爲五言仰續逸唱','劉敞','宋','宋诗','song-poetry','','[]','達人與道運，投迹繫所逢。',168,'全唐诗/poet.song.27000.json','["達人與道運，投迹繫所逢。", "在治信若鳯，處幽固猶龍。", "外物紛屢變，中扃豁兼容。", "乃知雲夢區，未足嬰其胸。", "明公蹈康濟，茲世已陶鎔。", "優游就偃息，暇豫奏時雍。", "高齋危舍字，數畝環崇墉。", "虛軒便炎夏，奥室宜隆冬。", "采真混出處，造適觀羲農。", "玩名肆獨樂，怙勢輕萬鍾。", "越人起丹穴，子房去赤松。", "材爲用見循，道以世難從。", "古事何昭昭，斯民積顒顒。", "獨應甘棠樹，方使來者封。"]'),
('7b335abe-7148-4b31-8b7a-e7532b78b840','得汝州舍弟新詩','劉敞','宋','宋诗','song-poetry','','[]','魯人貴韶濩，海鳥眩以憂。',276,'全唐诗/poet.song.27000.json','["魯人貴韶濩，海鳥眩以憂。", "豈不盛鐘鼓，性違理自愁。", "憶在田野時，終歳頗優游。", "食魚出有車，夏葛冬亦裘。", "弄翰不自量，著書望孔周。", "處身笑汲汲，視世良悠悠。", "誤及時君門，過緣名字求。", "軒冕非已好，簿書反自羞。", "因欲飾所短，强爲妻子謀。", "精神敝蹇淺，學殖誰勸修。", "歸卧常喟然，歳月屢以流。", "愧爾從軍詩，氣完語更遒。", "豈獨古人風，遠與王粲儔。", "實爲平生賞，若慰鍾儀囚。", "我年向四十，蒼髪已滿頭。", "篋中無寸書，磨滅悲蜉蝣。", "念此可以驚，如何復淹留。", "昔買吳下田，頗聞利鋤耰。", "汝宦何時歸，相與尋滄洲。", "處使有茅屋，出使有漁舟。", "知命贊易篇，沒身記春秋。", "但令文章顯，不愧時俗偷。", "世事非所了，咄哉無夷猶。"]'),
('1db11b65-88a1-4d88-8436-8ba361a4b603','續黄子温讀陶淵明詩十首  其一','劉敞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','四海方蕩潏，匡山得三隱。',36,'全唐诗/poet.song.27000.json','["四海方蕩潏，匡山得三隱。", "若人獨秀士，逸響露深藴。", "江漢東南流，滔滔未之盡。"]'),
('a8b0df92-5f57-4b40-9fea-01719d36bc0d','續黄子温讀陶淵明詩十首  其二','劉敞','宋','宋诗','song-poetry','','[]','羽輕鮮知福，地重毎貪禍。',36,'全唐诗/poet.song.27000.json','["羽輕鮮知福，地重毎貪禍。", "有以羲皇民，居然北窗卧。", "此意俗莫悟，將非首陽餓。"]'),
('cab99090-aa56-4480-825a-7b307be8705d','續黄子温讀陶淵明詩十首  其三','劉敞','宋','宋诗','song-poetry','','[]','長梧有高韻，千載不可及。',36,'全唐诗/poet.song.27000.json','["長梧有高韻，千載不可及。", "五柳遺世名，于今亦獨立。", "悲哉市朝士，夸競常汲汲。"]'),
('2b3fce30-4100-4b06-9d81-35fe56791100','續黄子温讀陶淵明詩十首  其四','劉敞','宋','宋诗','song-poetry','','[]','子綦委天樂，窮達兩已忘。',36,'全唐诗/poet.song.27000.json','["子綦委天樂，窮達兩已忘。", "九歅爾何知，梱也安得祥。", "一吟責子篇，千古如相望。"]'),
('8ffd8db7-a09d-498c-817e-6cf0eb5ee868','續黄子温讀陶淵明詩十首  其五','劉敞','宋','宋诗','song-poetry','','[]','追俗情易合，玩奇當企爾。',36,'全唐诗/poet.song.27000.json','["追俗情易合，玩奇當企爾。", "柴桑彼何者，高唱屢在此。", "縣令不俛眉，吾又悲揚子。"]'),
('1b4c6635-4d90-4401-a4f7-7ce1adea7949','續黄子温讀陶淵明詩十首  其六','劉敞','宋','宋诗','song-poetry','','[]','州縣徒勞人，著作非所務。',36,'全唐诗/poet.song.27000.json','["州縣徒勞人，著作非所務。", "道殊豈自强，氣直已多迕。", "屢招遂長往，歸歟彼何暮。"]'),
('82daeb1e-7b86-47d5-998c-d3a3b2a042d3','續黄子温讀陶淵明詩十首  其七','劉敞','宋','宋诗','song-poetry','','[]','昔在八州牧，功業濟衰晉。',36,'全唐诗/poet.song.27000.json','["昔在八州牧，功業濟衰晉。", "吾聞賢者後，鮮不祚休運。", "如何竟廖廓，天道蓋難問。"]'),
('9366dd1c-5f3f-4721-a065-70eadcdbe1a9','續黄子温讀陶淵明詩十首  其八','劉敞','宋','宋诗','song-poetry','','[]','孟嘗實超邁，舉世少其並。',36,'全唐诗/poet.song.27000.json','["孟嘗實超邁，舉世少其並。", "風流自有鍾，若士復孤迥。", "祖述酒中趣，乃知外家性。"]'),
('e0abc5d0-ea38-48ed-b1fd-b44d5ed17f26','續黄子温讀陶淵明詩十首  其九','劉敞','宋','宋诗','song-poetry','','[]','吾今乞食士，因詠乞食詩。',36,'全唐诗/poet.song.27000.json','["吾今乞食士，因詠乞食詩。", "諒無乞食怨，復想乞食時。", "貧賤自古然，豈愧世上兒。"]'),
('3a637bc1-cd49-4009-b3bd-67858b72765a','續黄子温讀陶淵明詩十首  其一○','劉敞','宋','宋诗','song-poetry','','[]','曩遊潯陽郭，懷古愴來暮。',36,'全唐诗/poet.song.27000.json','["曩遊潯陽郭，懷古愴來暮。", "不意陳蔡間，起予欣有遇。", "彼此共一時，悵然感佳句。"]'),
('023d5d7a-6e41-4ff9-80dd-5cdba5a32d2f','晝寢三首  其一','劉敞','宋','宋诗','song-poetry','','[]','日出百事集，人生亦多憂。',72,'全唐诗/poet.song.27000.json','["日出百事集，人生亦多憂。", "曲肱試少息，乃得逍遙游。", "圉圉爲潛魚，因之乘波流。", "翻翻爲飛鳥，爰以凌空遊。", "在己孰是非，于物任沈浮。", "觀化悟獨樂，真僞竟悠悠。"]'),
('e971def1-f2cb-4199-b2f9-bcda6f961203','晝寢三首  其二','劉敞','宋','宋诗','song-poetry','','[]','成敗勞耳目，是非喪神慮。',72,'全唐诗/poet.song.27000.json','["成敗勞耳目，是非喪神慮。", "我生天地間，安得棄之去。", "始疑昏逾明，漸覺夢勝寤。", "但可寐無聰，安知歳云暮。", "神交既倜儻，魄定奚憂懼。", "此以遣朝昏，因之保吾素。"]'),
('f548c200-8f87-4cae-a444-66ae9c0f9730','晝寢三首  其三','劉敞','宋','宋诗','song-poetry','','[]','久思謝時俗，奔走難自諧。',72,'全唐诗/poet.song.27000.json','["久思謝時俗，奔走難自諧。", "逍遙衡門下，雖陋得我懷。", "汲彼井底泉，掃兹風中埃。", "歊蒸爲之去，襟抱蕭然開。", "養心貴能適，造適不及排。", "胡爲車馬客，一往忘歸來。"]'),
('a5532cf8-62cd-41b4-bafc-1cec1ddb0526','晝寢上府公','劉敞','宋','宋诗','song-poetry','','[]','長日無所爲，高卧聊自如。',132,'全唐诗/poet.song.27000.json','["長日無所爲，高卧聊自如。", "清風拂庭樹，蕭蕭窗戶虚。", "曠逸追羲皇，粹和反華胥。", "暢然物外遊，謂若天下無。", "方今少陽交，田野東作初。", "壯者固不暇，老者日競趨。", "胡爲乃自便，徐徐以于于。", "從吏代力耕，飽食良自娛。", "事賢庇敏政，宿官特多餘。", "念兹寄幽閒，未覺勞簿書。", "但恨不可雕，正當砭其愚。"]'),
('e89ce64b-7248-4d3b-bd96-9db7b5ea227b','六月二十六日西閣晝寢','劉敞','宋','宋诗','song-poetry','','[]','馳騖聖不足，治安愚有餘。',120,'全唐诗/poet.song.27000.json','["馳騖聖不足，治安愚有餘。", "願言從物役，即事實燕居。", "清切掖垣峻，深沈雲閣虚。", "食有萬錢膳，架多四部書。", "低頭悟素飡，遊日慚古初。", "非吏復非隱，人言定何如。", "平生山林尚，自與功名疏。", "何爲出不反，視此歳月徂。", "秋風隕高林，蟋蟀鳴階除。", "行矣浮扁舟，季鷹不欺余。"]'),
('690ef54f-0b71-46f4-a425-14b60549530c','苦雨二首  其一','劉敞','宋','宋诗','song-poetry','','[]','洪河滔冀州，大陸日夜摧。',72,'全唐诗/poet.song.27000.json','["洪河滔冀州，大陸日夜摧。", "天時普陰沴，飛雨皆北來。", "崩騰亂雲霧，頃刻不暫開。", "通衢爲深淵，高堂生蒼苔。", "稼穡日以沒，民生一何哀。", "微禹既已矣，我其爲魚哉。"]'),
('ac6d0d9e-632b-488e-b19a-125ce4416437','苦雨二首  其二','劉敞','宋','宋诗','song-poetry','','[]','獨坐空堂上，漏濕無與娛。',60,'全唐诗/poet.song.27000.json','["獨坐空堂上，漏濕無與娛。", "晨炊煙不然，敗竈將生魚。", "被服蛙蠙衣，出入螺蚌居。", "里閭杳相絕，滔滔水漸車。", "安得雙羽翰，超然謝泥塗。"]'),
('bd4183dc-5699-490a-bc7a-984e05fdee11','久雨三首  其一','劉敞','宋','宋诗','song-poetry','','[]','繁陰過五日，積雨迷九天。',48,'全唐诗/poet.song.27000.json','["繁陰過五日，積雨迷九天。", "衣冠亦泥塗，陵陸成深淵。", "忘屨已乘橇，舍車始思船。", "曰余蹈滄海，良知時適然。"]'),
('39428d7b-a28e-4b65-a62f-cb134b65d1a6','久雨三首  其二','劉敞','宋','宋诗','song-poetry','','[]','清渠彼涓流，通逵此夷坦。',48,'全唐诗/poet.song.27000.json','["清渠彼涓流，通逵此夷坦。", "風雲瞬息間，江漢倏生眼。", "淵源詎能問，浩蕩頗可憚。", "白日蔽九霄，吾行幸當返。"]'),
('27ff6d5d-b35a-4409-8d8a-7bfd74f9fcb8','久雨三首  其三','劉敞','宋','宋诗','song-poetry','','[]','巖巖蓬萊巔，赫赫崑崙墟。',48,'全唐诗/poet.song.27000.json','["巖巖蓬萊巔，赫赫崑崙墟。", "上帝嚴紫垣，羣仙亦深居。", "高出雲電外，俯視風雨除。", "安知昏墊民，汩沒纔闔廬。"]'),
('4d063d91-4663-44f1-9cb0-b506e5db17a5','石林亭成宴府僚作五言','劉敞','宋','宋诗','song-poetry','','[]','吾愛謝宣城，適意安獨往。',132,'全唐诗/poet.song.27000.json','["吾愛謝宣城，適意安獨往。", "雖聮鳯池步，不廢山泉賞。", "吾慕應休璉，感事能屬書。", "頗嬰下流謗，獨占仁智居。", "寥寥二賢後，忽忽千載餘。", "若士不可追，此風或在予。", "延石象衆山，決泉瀉交渠。", "林壤使我欣，不知歳月徂。", "薜蘿分蔽虧，松竹相扶疏。", "時時四方客，顧此亦踟蹰。", "儻遇鍾子期，知子情所攄。"]'),
('b1896b1e-2e29-43f2-9051-75351dfda7ac','自京師泛舟還郡作三首  其一','劉敞','宋','宋诗','song-poetry','','[]','秋夜何迢迢，一夢八九覺。',108,'全唐诗/poet.song.27000.json','["秋夜何迢迢，一夢八九覺。", "孤舟寄風雨，短燭才自照。", "冥冥高雲過，寂寂山鬼嘯。", "展轉誰與歡，漂泊未可料。", "昔我自兹邁，春華巧相笑。", "今我復來此，落葉紛滿道。", "客行無遠近，勞苦略同調。", "一歳再羈旅，人生豈長少。", "良無二頃田，詎得守蓬藋。"]'),
('a0975b6d-7b71-44eb-bb8d-68e11a3afecb','自京師泛舟還郡作三首  其二','劉敞','宋','宋诗','song-poetry','','[]','昔在馬少游，抗志安故土。',72,'全唐诗/poet.song.27000.json','["昔在馬少游，抗志安故土。", "其後龐德公，迹不踐城府。", "出乘款段馬，身與麋鹿伍。", "鄉里稱善人，妻子同隴畝。", "人生資衣食，既足尚何取。", "致求多贏餘，筋力但自苦。"]'),
('757dfb30-eb1f-4384-9269-5a5097bda6fa','自京師泛舟還郡作三首  其三','劉敞','宋','宋诗','song-poetry','','[]','常陰貫秋序，洚水彌平陸。',72,'全唐诗/poet.song.27000.json','["常陰貫秋序，洚水彌平陸。", "居人逐飛鳥，往往巢樹木。", "四顧何茫茫，江海忽在目。", "古語乃信然，高陵或爲谷。", "乘桴義無憾，斷髪憂可辱。", "弁冕績禹功，誰其悲濡足。"]'),
('d51044b5-2bca-4d2f-bf7c-b0822594d1aa','西陽池新舟邀府公遊泛','劉敞','宋','宋诗','song-poetry','','[]','昔賢濟川意，固與斯人共。',96,'全唐诗/poet.song.27000.json','["昔賢濟川意，固與斯人共。", "曠代屬明德，至樂下及衆。", "池臺固舊賞，舟楫爲新用。", "忽疑江湖景，稍信風瀾縱。", "追參鳬雁泳，曆覽魚鼈動。", "頗已寓高興，矧今結輿誦。", "嘯歌一時適，顧盻萬全重。", "好勇知未能，乘桴自欣從。"]'),
('1af0cf5f-fd15-43c1-b058-6d687f8fabd0','贈馬惲供奉','劉敞','宋','宋诗','song-poetry','','[]','朝廷功名次，晉國在第一。',168,'全唐诗/poet.song.27000.json','["朝廷功名次，晉國在第一。", "受遺先皇帝，事與周召匹。", "丹青爛勳伐，終始最密勿。", "宗族宜甄庸，百世皆寵秋。", "公孫非遐胄，何乃尚淹屈。", "官名雖供奉，冗散真士卒。", "努力習文華，家貧傳清德。", "翰飛終不高，好事見心骨。", "人生繫逢遇，進退豈定律。", "古者如爾徒，萬戶自可必。", "今者如爾徒，富貴亦未失。", "主張有真宰，時態莽回聿。", "咄嗟元功世，頗復困蓬蓽。", "吁彼山野人，奚由自奮出。"]'),
('0ca4635d-5145-4855-b6bb-c0e5f75b481b','出城','劉敞','宋','宋诗','song-poetry','','[]','出城得自便，下馬事幽討。',120,'全唐诗/poet.song.27000.json','["出城得自便，下馬事幽討。", "曠野荒不耕，蒺藜牛滿道。", "往往逢饑人，羣輩掘野草。", "不惟黄頭兒，亦有白髪老。", "問之指積水，此去殊浩浩。", "室廬久漂蕩，樹木多立槁。", "食此且賖死，堯年亦久澇。", "不能去墳墓，更欲依蒲藻。", "昨來計蓮芡，頗不減粳稻。", "明年當大種，妻子或相保。"]'),
('57250ff6-d557-411e-bddb-bea326ff13c1','夢中','劉敞','宋','宋诗','song-poetry','','[]','誰謂夏夜短，一夕夢九逝。',60,'全唐诗/poet.song.27000.json','["誰謂夏夜短，一夕夢九逝。", "夢中如平生，歡笑隨母氏。", "覺來拊形軀，獨在人間世。", "上呼聲連天，灑泣血滿地。", "何忍留我生，哀哀抱微志。"]'),
('059a1d75-0a94-4d1e-9064-a9b8882d3628','癭木樽','劉敞','宋','宋诗','song-poetry','','[]','先民任天真，吾得見其器。',192,'全唐诗/poet.song.27000.json','["先民任天真，吾得見其器。", "其器云如何，蓋若刳木類。", "不戕生以戚，不傷材以蔽。", "不以遠見遺，不以枯見棄。", "因其無用姿，授以有用意。", "取彼自然象，廓此閎然制。", "豈無彫磨工，不欲敗淳粹。", "豈無青黄文，不欲增巧僞。", "其高豈無蓋，不設簋簠制。", "其下豈無舟，不著雞鳥麗。", "任真肆穫落，肯慕金玉貴。", "兒童誚敦朴，婦女驚醜異。", "豈若輕薄子，形容混兹世。", "矜愚以相高，飾貎以自喜。", "淳風陷衰薄，古道喪簡易。", "自非窊樽民，慎勿同一醉。"]'),
('121e3f2e-dba8-42a9-8c24-2a874e72fa28','泛舟','劉敞','宋','宋诗','song-poetry','','[]','長嘯望江漢，緬懷滄浪行。',84,'全唐诗/poet.song.27000.json','["長嘯望江漢，緬懷滄浪行。", "因浮扁舟去，共盡幽人情。", "春日天氣佳，近郊潁水清。", "雜花亂繽紛，好鳥相嚶鳴。", "解纜相沿泝，凌風恣縱横。", "適心故真樂，徇物皆虚名。", "興盡相與歸，夕陽半東城。"]'),
('6c5a911e-93c0-43aa-8068-38a39ae2af65','過士建中屯田居此君年六十請致仕所居蔽風雨而已','劉敞','宋','宋诗','song-poetry','','[]','市朝隱非一，躁靜理不同。',72,'全唐诗/poet.song.27000.json','["市朝隱非一，躁靜理不同。", "多君金閨彦，遠有山林風。", "千鍾卧名利，三徑入蒿蓬。", "似是於陵子，又云張長公。", "相望千年外，獨得環堵中。", "自古用先進，誰當駐飛鴻。"]'),
('e1a68e16-ff52-4086-b17b-0a1298d04e08','出城','劉敞','宋','宋诗','song-poetry','','[]','簡服謝車馬，逍遙理輕策。',96,'全唐诗/poet.song.27000.json','["簡服謝車馬，逍遙理輕策。", "平原草樹美，百里見秋色。", "稍知人境殊，似與囂塵隔。", "悠悠出岫雲，杳杳歸林翮。", "煩腸寛鬱紆，遠相俱幽寂。", "孤煙起晴縹，去水照心白。", "所期尚臯壤，生事視耕植。", "適野非昔賢，于焉如有獲。"]'),
('4525d826-0c44-4318-a215-a35413736998','泛舟三首  其一','劉敞','宋','宋诗','song-poetry','','[]','冰泮池水綠，春意亦已歸。',96,'全唐诗/poet.song.27000.json','["冰泮池水綠，春意亦已歸。", "長楊特多思，浩蕩隨風飛。", "弄舟不用楫，漾漾陶春暉。", "回還無終極，孰謂江湖非。", "舉觴屬坐人，行樂常苦稀。", "一醉捐百慮，念子勿相違。", "乘日復來游，北林稍芳菲。", "當令魚與鳥，識我心無機。"]'),
('ac7f30f6-5262-4f2a-a61a-43f45d146c37','泛舟三首  其二','劉敞','宋','宋诗','song-poetry','','[]','雪消泉似漲，冰解舟可通。',48,'全唐诗/poet.song.27000.json','["雪消泉似漲，冰解舟可通。", "操篙不憚冷，環渚故無窮。", "歌詠淹短日，醉酣輕朔風。", "何須萬乘相，始辨鴟夷翁。"]'),
('f7a20e1a-bf66-4c34-9d94-5011aa29f66d','泛舟三首  其三','劉敞','宋','宋诗','song-poetry','','[]','方池亦通舟，水色涵碧霄。',72,'全唐诗/poet.song.27000.json','["方池亦通舟，水色涵碧霄。", "解舟不用楫，漾漾隨風飄。", "中河乍縱横，顧眄幽興饒。", "白鳥逃人飛，赤鯉時復跳。", "稍與外物遠，解襟歌且謡。", "安知抱憂思，謂我士也驕。"]'),
('d962f976-513d-4f3c-b31f-4c8b032392ed','初到毗陵','劉敞','宋','宋诗','song-poetry','','[]','獻歳涉重江，仲春安我居。',120,'全唐诗/poet.song.27000.json','["獻歳涉重江，仲春安我居。", "衆物已熙熙，新花生遶廬。", "解裝慰羈旅，置此琴與書。", "稍稍道吾真，幽襟得軒虚。", "頗聞蘭陵俗，尚有荀卿餘。", "文章幸仰止，夙好今欲攄。", "膏雨復應候，带經得耕鋤。", "歌成擬焱氏，賦就期相如。", "出處方自爾，名聲亦從渠。", "無煩畏礨民，屑屑俎豆予。"]'),
('58001d7e-cfda-47fb-bc16-08ad2cb8356d','雨後城下','劉敞','宋','宋诗','song-poetry','','[]','雨餘百川漲，遠水浮林梢。',48,'全唐诗/poet.song.27000.json','["雨餘百川漲，遠水浮林梢。", "忽怪有帆席，何爲出鳥巢。", "登臨非吾土，虚爽慰南交。", "稍見暝烟起，陰蟲啼草茅。"]'),
('05c70238-9fb6-4429-af69-2787ac33bdd5','下汴','劉敞','宋','宋诗','song-poetry','','[]','畏途心多驚，强寢終不安。',48,'全唐诗/poet.song.27000.json','["畏途心多驚，强寢終不安。", "雖是仗忠信，猶有行路難。", "古今惡隨波，今乃知所患。", "胡爲出溷濁，幽興悠然寛。"]'),
('cc078d5b-c57f-48c0-a505-cdb0de5d90a8','望九華山','劉敞','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','九華非人境，聞譽不相識。',168,'全唐诗/poet.song.27000.json','["九華非人境，聞譽不相識。", "南浮大江波，始見蒼翠色。", "是時雨初霽，積靄尚融液。", "九峰若驚龍，並躍雲外碧。", "森然聳牙角，未謂真是石。", "問名審其實，歡喜愜所適。", "恢奇一何甚，遠想始開闢。", "造化競淫巧，斧斤恣彫刻。", "不然何其功，不與嵩華敵。", "我行宇宙間，若此曾未覿。", "中國名山川，幾何亢斯迹。", "徘徊不能去，塵土愧行役。", "平生樂間曠，時俗況迫阨。", "誰爲隱君子，攜手宅巖隙。"]'),
('3de9babd-5c2c-4819-9e55-608671d9f8f7','鷄冠花','劉敞','宋','宋诗','song-poetry','','[]','秋至天地間，百芳變枯草。',84,'全唐诗/poet.song.27000.json','["秋至天地間，百芳變枯草。", "愛爾得雄名，宛然出陳寶。", "未甘階墀陋，肯與時節老。", "赤玉刻縝栗，丹芝謝凋槁。", "鮮鮮雲葉卷，粲粲鳬翁好。", "由來名實副，何必榮華早。", "君看先春花，浮浪難自保。"]'),
('86d54f9e-6edc-4998-9b55-57b3dd086d2e','陳郎中竹園','劉敞','宋','宋诗','song-poetry','','[]','蒼竿十餘畝，歳晚色更好。',48,'全唐诗/poet.song.27000.json','["蒼竿十餘畝，歳晚色更好。", "詰曲逗遠村，深沈象晴島。", "鳴禽自相應，風葉不待掃。", "何事主人心，白頭三署老。"]'),
('9226e93c-9a19-4e57-9144-9bc23d425b43','浮雲','劉敞','宋','宋诗','song-poetry','','[]','高雲乘飇風，泱漭縱所適。',48,'全唐诗/poet.song.27000.json','["高雲乘飇風，泱漭縱所適。", "大哉九霄闊，俾爾萬里客。", "豈無一掬潤，浩蕩洗南國。", "應龍潛冀州，回首空眇默。"]'),
('b99bd917-0112-4cc7-b707-96a8f4445052','題度支廳事許道寧畫松石呈彦猷鄰幾直孺','劉敞','宋','宋诗','song-poetry','','[]','長松森無依，蒼石儼相對。',120,'全唐诗/poet.song.27000.json','["長松森無依，蒼石儼相對。", "自然山林氣，若出天壤外。", "許生筆妙絕，今世殊少輩。", "發揮得意表，瀟灑與神會。", "炎熱五月交，塵土九衢內。", "微風度窗來，左右含天籟。", "下有漁樵翁，生事尤可愛。", "茅茨乍隱見，畎畝更向背。", "吾廬若辦此，軒冕本不賴。", "願從二三子，相與駕言邁。"]'),
('39f4637e-abf1-4391-a6c4-cca8c0fe32d6','擬阮步兵一夕復一晨','劉敞','宋','宋诗','song-poetry','','[]','一昏復一晨，一晨復一夕。',96,'全唐诗/poet.song.27000.json','["一昏復一晨，一晨復一夕。", "擾擾若有爲，悠悠定何役。", "譬如風中葉，不自知所適。", "譬如池中魚，强自營所得。", "朝乘日車出，暮與羈鳥息。", "昔我髪純漆，今我髪半白。", "誰能邀神靈，傳我雲表翼。", "我與從之遊，覽觀元化極。"]'),
('13f7d82e-ea5e-4a93-a44a-318c60996b5e','紀危','劉敞','宋','宋诗','song-poetry','','[]','四月河水湍，怒風復相乘。',132,'全唐诗/poet.song.27000.json','["四月河水湍，怒風復相乘。", "維絕柁亦摧，舟人廢其能。", "中流急迴環，頃刻不可勝。", "性命委自然，豈知所依憑。", "堤旁多聚觀，失色氣崩騰。", "孰不願引手，而乏鉤與繩。", "嗟我亦天幸，既危乃復興。", "追思方厄時，汗出如洗冰。", "側聞前此者，覆溺已屢曾。", "此事通爲邦，長民可以懲。", "因書作長詩，俾不忘戰兢。"]'),
('5642fe94-c488-4262-b60f-b09c4a61916c','十二月十一日雷電有作','劉敞','宋','宋诗','song-poetry','','[]','今兹方隆冬，陽春尚宜少。',72,'全唐诗/poet.song.27000.json','["今兹方隆冬，陽春尚宜少。", "何忽雷早聞，因之電争曜。", "砰轟非常怒，䃸磹通夕照。", "號令無乃乖，災祥諒誰召。", "吾聞玉女戯，獨得天公笑。", "此理正應爾，君毋强譏誚。"]'),
('d6a9efa7-ac2f-4faa-a47f-5b336171f9c4','種紫蘇','劉敞','宋','宋诗','song-poetry','','[]','赤日厚地裂，百草殆立枯。',96,'全唐诗/poet.song.27000.json','["赤日厚地裂，百草殆立枯。", "朝雨應所至，雖微念勝無。", "力難興禾黍，可以成嘉蔬。", "歲暮有此望，帯經且親鋤。", "今兹五月交，盛陽消已徂。", "汲汲愧老圃，仲尼云不如。", "養生寄空瓢，雖乏未可虚。", "正以營一飲，形骸如此劬。"]'),
('dfef13af-9f9c-451a-8237-f3a6e66d79f4','遣懷三首  其一','劉敞','宋','宋诗','song-poetry','','[]','天道與性命，聖人罕其言。',60,'全唐诗/poet.song.27000.json','["天道與性命，聖人罕其言。", "七十豈常士，游夏終不聞。", "鞠躬慕仁義，或不免饑寒。", "奸雄何爲者，往往爲世賢。", "倘復有真宰，無用預其間。"]'),
('d2dad07e-80ab-4b39-bb7c-8b3e0b376a2c','遣懷三首  其二','劉敞','宋','宋诗','song-poetry','','[]','有形毎共生，達士獨無惑。',60,'全唐诗/poet.song.27000.json','["有形毎共生，達士獨無惑。", "昔有蒙袂子，恥從嗟來食。", "物生會當盡，壽非金與石。", "但恨居世俗，不能盡胸臆。", "壯士志溝壑，斯言著前識。"]'),
('f4dd1f56-108d-4c6f-bde5-cc6eca2a0255','遣懷三首  其三','劉敞','宋','宋诗','song-poetry','','[]','初歲志慮淺，所慕在輕肥。',60,'全唐诗/poet.song.27000.json','["初歲志慮淺，所慕在輕肥。", "自恨聞道晚，不虞失性非。", "迷途將未遠，回駕有庶幾。", "古賢多事業，出處何不知。", "寧受芻豢辱，倘爲鴻鵠飛。"]'),
('1f73dae4-ffa1-455b-8f64-4e016a45c5f4','歸牧相訪示所作詩賦篇予與其兄子緯還往頗熟','劉敞','宋','宋诗','song-poetry','','[]','曰予謝賓客，久與時世疏。',96,'全唐诗/poet.song.27000.json','["曰予謝賓客，久與時世疏。", "何忽衡門下，見枉使君車。", "彤旆映落日，腰間有懸魚。", "抵掌若平生，論文及空虚。", "昔與君猶子，結交幸通書。", "往還苦不早，相見情有餘。", "置我二阮間，遠慚德不如。", "强來束帯起，投謁尋君廬。"]'),
('899707ac-c177-4f58-b19b-b06e352148c5','大雨中入局寄彦猷時以疾臥家','劉敞','宋','宋诗','song-poetry','','[]','歊蒸變繁陰，快雨如破谷。',60,'全唐诗/poet.song.27000.json','["歊蒸變繁陰，快雨如破谷。", "明趨閶闔路，深水入馬腹。", "此地常結轍，江海忽在目。", "冥行畏坎井，躡迹戒顛覆。", "慚問高眠翁，不知泥塗辱。"]'),
('d3ec5375-ba58-4a8b-a06c-80bdb3ccb041','賀范龍圖兼知延安','劉敞','宋','宋诗','song-poetry','','[]','大兵昔摧傷，兩将折旗鼓。',192,'全唐诗/poet.song.27000.json','["大兵昔摧傷，兩将折旗鼓。", "哀哉中國士，化作城下土。", "冤魂不得返，殺氣凌彼蒼。", "天亦爲之悲，白晝日無光。", "人言此城下，往往鬼神哭。", "此事天子憂，此心大夫辱。", "昔公守東越，人怨公不用。", "今日公在西，知公德持重。", "築城不必堅，解甲不可攻。", "何况保金城，弛張皆繫公。", "汲黯輔炎漢，淮南內竦懼。", "郅都守窮邊，匈奴爲之去。", "此事昔所聞，今日見所親。", "折衝樽俎間，震動旃裘民。", "國恥行且刷，寇讎不可保。", "斯人嘆微管，願及太平老。"]'),
('dbf4962b-8a59-42b0-aa82-e2167e636fa9','奉和宋次道遊嵩十五韻','劉敞','宋','宋诗','song-poetry','','[]','嵩峰三十六，皆在青雲端。',180,'全唐诗/poet.song.27000.json','["嵩峰三十六，皆在青雲端。", "宿昔望見之，恨不生羽翰。", "卷臠塵土中，日月如波瀾。", "邇來老将至，更覺行路難。", "聞君謝車徒，選勝羣峰巒。", "幽深每獨往，神異多所觀。", "若有真仙子，羽衣白玉顔。", "吹笙煙霧中，舉手留盤桓。", "信非人間境，邈與時俗懸。", "顧懷平生舊，慰以逍遙篇。", "三復想在目，令人愧衣冠。", "處世闊且疏，幼輿亦有言。", "一丘與一壑，自謂無間然。", "安得從君游，解纓弄雲泉。", "昏昏歲復晏，相望空長歎。"]'),
('a0fa8c71-857e-4c8b-8e53-4f59c78c57ac','和聖俞逢羊','劉敞','宋','宋诗','song-poetry','','[]','道旁逢羣羊，問羊将何之。',60,'全唐诗/poet.song.27000.json','["道旁逢羣羊，問羊将何之。", "朝供大官膳，躑躅未自知。", "觳觫此何罪，無乃芻豢爲。", "肥軀一報德，鼎爼安可辭。", "寧辱泥塗中，故人所以悲。"]'),
('bb21964b-cb93-4c85-9103-16ec7e076017','懷歸','劉敞','宋','宋诗','song-poetry','','[]','圖養始干祿，執官復辭親。',72,'全唐诗/poet.song.27000.json','["圖養始干祿，執官復辭親。", "外物與我違，幽懷安得仲。", "低徊畏簡書，苟且謀賤貧。", "碌碌已無期，規規徒自珍。", "秋風卷層雲，鴻雁知所賓。", "我獨無羽翰，不能絕飇塵。"]'),
('759323ce-c031-4918-99dc-ec3153839072','送呂光祿','劉敞','宋','宋诗','song-poetry','','[]','氾濫誠易挹，俊賢噬肯留。',72,'全唐诗/poet.song.27000.json','["氾濫誠易挹，俊賢噬肯留。", "愧君殊邂逅，卒歲能優游。", "會心到稽呂，訪古窮嬴劉。", "誰令春風來，翩翩動歸舟。", "千里在明發，一樽成獻酬。", "江湖望魏闕，離思空悠悠。"]'),
('5eee5910-075e-487c-b1a9-e31a9830bf80','題改芷亭作水鑒亭','劉敞','宋','宋诗','song-poetry','','[]','昔人種白芷，既以名此亭。',96,'全唐诗/poet.song.27000.json','["昔人種白芷，既以名此亭。", "今我開蠪淵，復以水鑑名。", "吾豈異昔人，而徒易其稱。", "所樂於水乎，內明而外清。", "內明可比心，外清可照形。", "照形不吾欺，比心不吾傾。", "虚静吾自居，逍遙以無營。", "會有水鑒賢，吾能與同登。"]'),
('7cf74bd9-f75b-48b3-9e1b-acebd6ce711d','閉門二首  其一','劉敞','宋','宋诗','song-poetry','','[]','閉門無所事，歲月忽已極。',96,'全唐诗/poet.song.27000.json','["閉門無所事，歲月忽已極。", "豈敢空絕交，出門諒安適。", "是非歛外慮，文字堆四壁。", "堯舜參在前，孔孟凛居側。", "崑崙默泛覽，萬里在瞬息。", "夐古時幽尋，千年僅頃刻。", "悠悠富貴士，此趣猶未得。", "胡爲逐車馬，辛苦牽事役。"]'),
('16ca5caf-ee4e-464c-8fa7-c8048589ba1a','閉門二首  其二','劉敞','宋','宋诗','song-poetry','','[]','傅巖由帝賚，圯橋自神授。',48,'全唐诗/poet.song.27000.json','["傅巖由帝賚，圯橋自神授。", "商道粲復興，漢基翕然構。", "窮通苟有命，貧賤豈足疚。", "斯道誰得聞，人方薄圭竇。"]'),
('d357baf2-f1db-454a-bf42-01c3d2e52921','小孤山','劉敞','宋','宋诗','song-poetry','','[]','驚波觸南崖，反怒射北壁。',156,'全唐诗/poet.song.27000.json','["驚波觸南崖，反怒射北壁。", "蒼山相與排，所謂小孤石。", "蟠根萬仞淵，聳角百丈碧。", "祠堂豁精嚴，行旅進粉澤。", "或云婦女神，肸蠁頗有迹。", "吾知定名意，似欲旌介特。", "流俗失其真，傳聞莫開釋。", "居人私其利，禍福妄損益。", "競爲媢妒說，以誣聪明德。", "先王秩山川，禮典有廟食。", "奈何媚於竈，屈己忘正直。", "吾欲爲小孤，作書解行客。", "復恐不見從，嗟哉世多惑。"]'),
('a00fc8ce-8b0f-48fe-ae5a-1f1169df7adc','新種雜花樹','劉敞','宋','宋诗','song-poetry','','[]','天地大逆旅，浮生遠行客。',180,'全唐诗/poet.song.27000.json','["天地大逆旅，浮生遠行客。", "大無萬里異，遠不百年役。", "乘流惟其遇，得性從所適。", "何必思舊鄉，而復名一宅。", "此邦非吾土，此廬非我迹。", "彼我苟巳齊，賓主不足擇。", "終樹宿所好，及閒易爲力。", "芳草十餘品，往往手自植。", "春風二月交，重疊庭下碧。", "欣欣生意好，一一見顔色。", "對之默終日，澹若無情極。", "四時背人馳，壮士每歎息。", "憂來忽無方，外物不可釋。", "中和一相伐，頭髪先爲白。", "萱乎爾能忘，於我獨有德。"]'),
('05570478-b514-4502-ae47-9ad4ffaa2582','滕司諫知涇州','劉敞','宋','宋诗','song-poetry','','[]','天狼東南鳴，雨矢西北集。',96,'全唐诗/poet.song.27000.json','["天狼東南鳴，雨矢西北集。", "覆載豈不容，縳虎宜在急。", "詩書擢将帥，高枕付城邑。", "權變非武臣，恩威在呼吸。", "壮夫氣已激，義士感成泣。", "籍籍名四喧，蕭蕭髪競立。", "行旂亂鷹集，已有邊風入。", "遙知謁明光，介胄但長揖。"]'),
('7ada0cfb-6056-497f-89ab-4d917e7afc25','城下','劉敞','宋','宋诗','song-poetry','','[]','秋成雨更綠，高下共萋萋。',48,'全唐诗/poet.song.27000.json','["秋成雨更綠，高下共萋萋。", "浮烟晚自起，歸鳥暝爭棲。", "山谷入幽想，茅茨多舊蹊。", "日涉遂成趣，身將麋鹿齊。"]'),
('32175e41-b345-45c3-b518-5af707f09d14','庶幾堂','劉敞','宋','宋诗','song-poetry','','[]','徂暑亦已煩，清旦尚餘爽。',60,'全唐诗/poet.song.27000.json','["徂暑亦已煩，清旦尚餘爽。", "薰風應候至，芳物與春往。", "庭樹交浮陰，山禽轉清響。", "空堂更幽寂，初日正蒼莽。", "時節無所感，忘言以爲賞。"]'),
('c68bfbdb-905a-4376-810e-20ba6a52fbcf','涼夜','劉敞','宋','宋诗','song-poetry','','[]','疏雨洗明月，清風生晚涼。',48,'全唐诗/poet.song.27000.json','["疏雨洗明月，清風生晚涼。", "動搖星辰影，泛澹河漢光。", "螢變覺草腐，蟲吟知境荒。", "端憂易遠感，不眠疑夜長。"]'),
('c21716a0-b499-452a-b62c-fbe9812f0699','狄梁公李太尉廟','劉敞','宋','宋诗','song-poetry','','[]','就列貴陳力，立功尚成名。',72,'全唐诗/poet.song.27000.json','["就列貴陳力，立功尚成名。", "兩君雖異時，令望相提衡。", "治獄多陰德，不戰屈人兵。", "去思獨至今，奉祀見遺氓。", "文武百世師，将相一時榮。", "念我誰與歸，愴然悲九京。"]'),
('61771d07-9c7f-4e1c-b5a2-c9ab13af2e0f','畢吏部冢','劉敞','宋','宋诗','song-poetry','','[]','蓬蒿道旁冡，云是晋時賢。',48,'全唐诗/poet.song.27000.json','["蓬蒿道旁冡，云是晋時賢。", "名聲與陵谷，共盡一千年。", "惟昔縱達觀，死生同蜕蟬。", "安知泉下魄，非復甕間眠。"]'),
('55519ced-a47d-4dbd-9ecc-e49aa1eaf9f4','和張洞春雪','劉敞','宋','宋诗','song-poetry','','[]','水國雖暑濕，亦惡春令早。',132,'全唐诗/poet.song.27000.json','["水國雖暑濕，亦惡春令早。", "雨暘恒不時，過燠未爲好。", "凌威集驕陽，瘴疹一以埽。", "宿麥根復濡，豐年不煩禱。", "堪輿氣清真，生物同壽考。", "大哉造化力，排斡正穹昊。", "能令四時順，少失安足道。", "君胡乃嗟嘆，哀彼花與草。", "方今王正始，節物自未老。", "繁華雖云遲，秀實終自保。", "可以寛君愛，毋爲色枯槁。"]'),
('a15939cf-c84c-4d06-adf0-8a9123746ae3','雪意','劉敞','宋','宋诗','song-poetry','','[]','淒風起幽朔，白日晦光色。',48,'全唐诗/poet.song.27000.json','["淒風起幽朔，白日晦光色。", "仰視浮雲高，蒼茫天容碧。", "林林愯羣木，栗栗抱寒魄。", "今朝識天意，欲見松與柏。"]'),
('64dccb3d-de4d-47ba-ba58-e201aa97a6d2','雪後','劉敞','宋','宋诗','song-poetry','','[]','日出桑柘巔，鶴鳴風景和。',48,'全唐诗/poet.song.27000.json','["日出桑柘巔，鶴鳴風景和。", "縱心適田野，顧覺春意多。", "欣欣林間叟，負薪行且歌。", "此中有真樂，富貴如余何。"]'),
('1829a1fa-954f-4417-89c4-2d058166b75c','壽寧觀殘雪','劉敞','宋','宋诗','song-poetry','','[]','春陽漏潛筦，凛氣留深殿。',48,'全唐诗/poet.song.27000.json','["春陽漏潛筦，凛氣留深殿。", "金莖向飛露，碧瓦仍鋪練。", "寒光寂寞迴，暖色依微變。", "壺中異風景，會待花如霰。"]'),
('70832ac9-60e2-4f06-a28d-1c2b26108e4e','初雪','劉敞','宋','宋诗','song-poetry','','[]','荒居人迹絕，但覺歲月頹。',72,'全唐诗/poet.song.27000.json','["荒居人迹絕，但覺歲月頹。", "北風不我欺，吹雪天上來。", "入戶時繽紛，當軒肆徘徊。", "有情知相親，高臥未足哀。", "他日門晝關，今旦門早開。", "開門將誰爲，南山玉崔嵬。"]'),
('9c0de798-b7ea-4dcc-b49a-dce4d0ee99c2','雪中寄貢弟','劉敞','宋','宋诗','song-poetry','','[]','天寒雲長浮，雪急風更厲。',72,'全唐诗/poet.song.27000.json','["天寒雲長浮，雪急風更厲。", "行子歸何時，遠遊感人思。", "脊令顧儔下，鴻雁順時逝。", "原隰無安居，稻梁無深志。", "誰令歲月晚，坐使羽毛瘁。", "江湖可遣憂，引領正相遲。"]'),
('6b33708f-9ca1-4aaa-873f-d94c7305dae0','月夜期江梅兩君不至聞在李二審言家飲','劉敞','宋','宋诗','song-poetry','','[]','日入更灑埽，翛然庭檻空。',48,'全唐诗/poet.song.27000.json','["日入更灑埽，翛然庭檻空。", "酒杯落明月，白羽來清風。", "佳興自不淺，幽人無與同。", "徘徊卧林下，重露霑蘭叢。"]'),
('b1bd2ee9-1ff4-4e6e-a70c-5ce16a0a3c28','和閻都官九月十三日夜對月是夕某與子華聖俞如晦會飲君謨所','劉敞','宋','宋诗','song-poetry','','[]','秋霖恣淫溢，后土無時乾。',216,'全唐诗/poet.song.27000.json','["秋霖恣淫溢，后土無時乾。", "忽驚浮雲盡，更覺天宇寛。", "涼月如白璧，飛來青冥端。", "衆星稍滅没，驚鵲自盤桓。", "興發思遠遊，惜無凌風翰。", "聊尋故人家，呼酒澆肺肝。", "適與二三子，四座俱解鞍。", "意合心同賞，百觴不辭難。", "玩古騐漢魏，舞姝試邯鄲。", "詼諧雜謡語，大笑傾衣冠。", "足爲一時樂，未悟清夜闌。", "毎至絕倒處，恨君不獲觀。", "明發得新詩，照人瑩琅玕。", "又知共兹翫，正若相從歡。", "君本青雲人，淹留尚郎官。", "曠懷不自屑，遇景宴且般。", "古來悲秋士，局促宋與潘。", "相望如轅駒，豈足爲君歎。"]'),
('c1251ef1-13b7-4eaf-bb70-04fc933cc66f','夜月','劉敞','宋','宋诗','song-poetry','','[]','執熱不可濯，昏昏倦衣巾。',72,'全唐诗/poet.song.27000.json','["執熱不可濯，昏昏倦衣巾。", "涼月如有情，萬里來慰人。", "浮雲卷層虚，六合隨清新。", "河漢涵光輝，城郭息埃塵。", "兹時一可畏，與子聊相親。", "逍遙夜未央，更益情性真。"]'),
('6281bd82-44ed-4d3f-9b5c-0b1aa744141e','夜起呼徐監簿同看月','劉敞','宋','宋诗','song-poetry','','[]','夜長愁無端，歲晚易多感。',72,'全唐诗/poet.song.27000.json','["夜長愁無端，歲晚易多感。", "徘徊中庭步，相與肆遐覽。", "繁霜冷次骨，皎月清照膽。", "幽意暫欲飛，秀色若可攬。", "明夕雖復來，素華已應減。", "念兹徑使醉，無使我心慘。"]'),
('44583727-358c-4cb3-9be7-29d25e71901c','南伐詩','劉敞','宋','宋诗','song-poetry','','[]','兵行何怱忽，百里不一息。',192,'全唐诗/poet.song.27000.json','["兵行何怱忽，百里不一息。", "南征有期會，相觀各努力。", "三年戍西荒，蟣虱生金革。", "歸來席未煖，羽檄何奔迫。", "行行當逾嶺，五月逼炎赫。", "尚有筋骨存，所虞生死隔。", "山林如惔焚，溪水沸湍激。", "自古皆有言，一夫萬人敵。", "蝮蛇長相逐，虎豹不可格。", "主将貪功名，謀臣貴恩澤。", "奈何輕人命，棄置曾不惜。", "探湯入其中，未半死已積。", "蒼生亦齊民，不必皆盗賊。", "賢主尚扇暍，仲春猶掩骼。", "一身不自愛，所懼失爲國。", "堯舜有舊書，廟堂爲法則。"]'),
('405019af-01bb-4921-a13a-5efff15b3683','城樓送别','劉敞','宋','宋诗','song-poetry','','[]','驚風走枯蓬，百里不暫息。',84,'全唐诗/poet.song.27000.json','["驚風走枯蓬，百里不暫息。", "密雲乘飛雨，前山坐成隔。", "蓬老初無根，豈辭遠爲客。", "山高雖可望，路遠當不識。", "去留類如此，覽物意寧極。", "鞍馬未動間，會合彌可惜。", "緩歌送清觴，更醉日将夕。"]'),
('42a094e6-1708-4135-abdb-754b54dc0a34','李綿州訪别','劉敞','宋','宋诗','song-poetry','','[]','天寒起常晏，日出扉未啟。',132,'全唐诗/poet.song.27000.json','["天寒起常晏，日出扉未啟。", "深巷聞傳呼，兒童怪旌棨。", "知是漢中守，訪舊來至此。", "適我平生懷，趨迎願少止。", "結交許忘年，並坐每抗禮。", "語罷當遠行，眷然色不喜。", "君惟二千石，我徒一男子。", "貧賤宜輕肥，反如不能已。", "善化遲期月，壮心隘萬里。", "側聞報政速，永觀凌風起。", "寧復悲東山，滔滔歷年祀。"]'),
('7c9806b5-ccd9-4516-b274-d5be1bd2443f','食橘','劉敞','宋','宋诗','song-poetry','','[]','吾聞江陵橘，乃比千戶侯。',144,'全唐诗/poet.song.27000.json','["吾聞江陵橘，乃比千戶侯。", "歲獻天子旁，取爲廟堂羞。", "問其何能爾，無脛而遠遊。", "橘也不自言，請君以臆酬。", "憑生覆載中，頗亦萬木儔。", "通爲騷人頌，謬得禹貢收。", "託身聖賢間，自覺名譽浮。", "苞苴賴攜挈，富貴常見求。", "明珠無先容，按劍或暗投。", "而我適衆口，鑠金不予憂。", "物生有通塞，不必在中州。", "何用懷苦辛，但爲時所仇。"]'),
('534eead2-2c23-4b28-b739-ebeea6690a4b','留鄰幾君章奕棋便宿小齋','劉敞','宋','宋诗','song-poetry','','[]','簿書易短景，燈火宜清夜。',108,'全唐诗/poet.song.27000.json','["簿書易短景，燈火宜清夜。", "過從喜吾子，尊酒迨我暇。", "歡來中扃豁，興盡外物借。", "錯落盤上棋，白黑互陵跨。", "決機競神速，取勝頗雄覇。", "惜我壮士氣，局此萬里駕。", "時乎無由試，寓目亦悲咜。", "天地一枰土，古今萬物化。", "願無辨其間，痛飲但來舍。"]'),
('99f58eb3-f68c-4702-8031-1fd360ba4db6','與鄰幾對棋戯作','劉敞','宋','宋诗','song-poetry','','[]','碌碌無用智，玩此方罫間。',72,'全唐诗/poet.song.27000.json','["碌碌無用智，玩此方罫間。", "君乘百戰餘，勝氣不可攀。", "拙速亦天幸，出奇犯險艱。", "數俘効軍實，斥境除邊關。", "捧觴跪進養，座客歡解顔。", "安得百壺酒，使君酩酊還。"]'),
('2b3a23b5-d72d-4197-a31a-0d1daeafde1f','今古路','劉敞','宋','宋诗','song-poetry','','[]','出門道路多，縱横不可測。',216,'全唐诗/poet.song.27000.json','["出門道路多，縱横不可測。", "我今欲遠行，須問曾行客。", "徐徐逢路人，借問青松側。", "客曰今何往，答之遊京國。", "客乃指要路，而言行有益。", "古路雖大道，不如今路直。", "但行今人路，猶如假羽翼。", "彼客别我去，獨自躊躇立。", "爲見今古路，信乃無差忒。", "今路足輪蹄，古路多荆棘。", "欲行今人路，恐背古人迹。", "欲行古人路，今人笑迂僻。", "又擬不出門，奈何饑寒逼。", "哀哀此時路，悠悠蒼天色。", "不避今人嫌，路須行古陌。", "古陌雖然遠，且保無蹶失。", "勉哉自勉哉，前去難云適。", "不獲見楊朱，萬古凝愁魄。"]'),
('f344f2ce-21e9-4f99-b7c0-0620b3dee773','曉至池上','劉敞','宋','宋诗','song-poetry','','[]','宿雨墜高葉，薄雲麗朝陽。',60,'全唐诗/poet.song.27000.json','["宿雨墜高葉，薄雲麗朝陽。", "園林澹澹秋，庭戶蕭蕭凉。", "水淺魚怫鬱，荷深鷺低昂。", "幽懷欣自得，佳賞契所望。", "忽恐羣動作，深林沸蜩螗。"]'),
('2c4c7651-fb3a-4274-9931-b7a81c084d2b','晚凉','劉敞','宋','宋诗','song-poetry','','[]','落日蔽崑崙，微風起閶闔。',48,'全唐诗/poet.song.27000.json','["落日蔽崑崙，微風起閶闔。", "蟲聲語悽惻，樹影翻離合。", "蚤露結明珠，圓蟾瑩塵匣。", "浩歌始自放，喟此區中狹。"]'),
('b307e2eb-e2b6-4ef7-8e5c-9df62a864bdc','金山東崖北望海門','劉敞','宋','宋诗','song-poetry','','[]','憑高仍一望，北固何崔嵬。',48,'全唐诗/poet.song.27000.json','["憑高仍一望，北固何崔嵬。", "地形東吳越，江險通卭崍。", "英雄既已矣，壮觀空在哉。", "寂寥寒潮上，孤帆當檻來。"]'),
('b85be817-2ebc-47af-8d64-aa9cbc3787b7','屏上兩賢二首  其一','劉敞','宋','宋诗','song-poetry','','[]','謝公樂山水，不以官爵間。',60,'全唐诗/poet.song.27000.json','["謝公樂山水，不以官爵間。", "天機有所賦，世俗從爾訕。", "上躡巉巖峰，下弄清冷澗。", "吾生慕如此，敢避刺疏慢。", "寧爲途中龜，勿作蒿下鷃。"]'),
('bcc13f02-1458-47af-8560-78ccef905c15','屏上兩賢二首  其二','劉敞','宋','宋诗','song-poetry','','[]','人生誰不如，妄爲世所束。',60,'全唐诗/poet.song.27000.json','["人生誰不如，妄爲世所束。", "興來當自往，興盡斯自復。", "大雪暗溪路，新晴月微燭。", "去非之子慕，返豈斯人辱。", "優游便所適，偃蹇媚幽獨。"]'),
('5e747cea-a6ce-40ed-8e80-a1bd291f7053','贈梅聖俞','劉敞','宋','宋诗','song-poetry','','[]','耳聞梅聖俞，及此将十載。',108,'全唐诗/poet.song.27000.json','["耳聞梅聖俞，及此将十載。", "洛下聚英豪，文華富如海。", "聲名動冠劍，久合參朝寀。", "何意幕中客，新違江上宰。", "材高雖用晚，大器終有在。", "三公識者多，薦拔可立待。", "棲棲九衢裏，塵土增厭殆。", "相逢恨知晚，乍似去貧餒。", "鄰居幸見過，沃此胸礧磈。"]'),
('1a586fe9-c2c0-4b5a-bb65-9787b8f37339','登禪智寺上方贈同遊諸公','劉敞','宋','宋诗','song-poetry','','[]','重岡抱城起，清川带野回。',96,'全唐诗/poet.song.27000.json','["重岡抱城起，清川带野回。", "舊都遷陵谷，遺寺空池臺。", "脩竹入晻靄，荒溪轉崔嵬。", "鳴禽畏人起，故老驚客來。", "置酒感興廢，浩歌寄歡哀。", "伊昔游此人，于今安在哉。", "谷深春先覺，地爽景後頽。", "造適假一笑，願君盡餘杯。"]'),
('5044f87d-c76a-4a3e-bd8a-815473a3ffb8','楊白花','劉敞','宋','宋诗','song-poetry','','[]','飛飛楊白花，随風渡江水。',48,'全唐诗/poet.song.27000.json','["飛飛楊白花，随風渡江水。", "江水來不極，楊花去無已。", "鴉啼淺深樹，雪落千萬里。", "春風傷人心，綿綿復如此。"]'),
('a62e7d00-4b4f-4a21-9121-12a186ee6198','涵虚閣玩玄猿孔雀','劉敞','宋','宋诗','song-poetry','','[]','清池明夕景，高樹含凉風。',60,'全唐诗/poet.song.27000.json','["清池明夕景，高樹含凉風。", "巴猿戯前檻，越鳥安深籠。", "悲吟激清漲，文繡揮蒙茸。", "弱喪不自非，全生或爲容。", "曠然感真樂，達哉濠梁翁。"]'),
('4decdfc0-3a2a-4524-b745-6c8e04aaceae','雨霽同聖民登西北樓','劉敞','宋','宋诗','song-poetry','','[]','雨餘暑氣滅，日出浮雲開。',72,'全唐诗/poet.song.27000.json','["雨餘暑氣滅，日出浮雲開。", "高樓極遠目，百里無纖埃。", "山形西北騖，江勢東南來。", "舊都尚能記，壯觀多可哀。", "微風激清嘯，浩霧侵寒杯。", "亦知非吾土，聊復樂徘徊。"]'),
('da14706b-05fc-4db5-a8d4-6daca17f5028','秋興三首  其一','劉敞','宋','宋诗','song-poetry','','[]','微風起閶闔，秋意日已滋。',48,'全唐诗/poet.song.27000.json','["微風起閶闔，秋意日已滋。", "陰蟲羣悲鳴，草木同變衰。", "天道雖茫昧，平分爲四時。", "功名自當去，搖落獨何悲。"]'),
('b259aa48-475d-40f5-933f-f65419c62f33','秋興三首  其二','劉敞','宋','宋诗','song-poetry','','[]','魏牟貴公子，沉没功名間。',48,'全唐诗/poet.song.27000.json','["魏牟貴公子，沉没功名間。", "一浮江湖水，惨戚頽朱顔。", "魯連揖萬乘，蹈海如忘還。", "棄世脱敝屣，風流安可攀。"]'),
('38343166-44f5-47e0-b07f-5de304d14e4c','秋興三首  其三','劉敞','宋','宋诗','song-poetry','','[]','耿耿河漢輝，中夜西南流。',48,'全唐诗/poet.song.27000.json','["耿耿河漢輝，中夜西南流。", "牛女永相望，婉孌悲素秋。", "安知乘槎翁，徑出海外遊。", "天路或幽險，神仙非所求。"]'),
('86f04f42-9a28-40de-8536-ccb7f4c617b8','留城子房廟','劉敞','宋','宋诗','song-poetry','','[]','大風起豊沛，海水羣飛揚。',120,'全唐诗/poet.song.27000.json','["大風起豊沛，海水羣飛揚。", "逐鹿未有歸，飛熊猶道旁。", "一見契千載，立談開八荒。", "蛟龍不可羈，鴻鵠得新翔。", "昔爲黄石師，智策無與雙。", "晚蹈赤松賞，功名忽如忘。", "由來神仙流，理與天地長。", "陵谷自有遷，若人豈復亡。", "我行覧遺蹟，城邑空蒼蒼。", "感古追遠遊，白雲杳無鄉。"]'),
('8a1084f1-902a-4621-bae0-d59c8ffc2f5c','同介甫和聖俞贈狄梁公裔孫','劉敞','宋','宋诗','song-poetry','','[]','陳平智有餘，周勃勇無敵。',144,'全唐诗/poet.song.27000.json','["陳平智有餘，周勃勇無敵。", "兩人相提衡，終復漢社稷。", "梁公柱石姿，獨立謝羣力。", "匡居多直言，薦士有深畫。", "既扶将頽運，復起未然策。", "事業兼二子，浩然雪霜白。", "偏材戒獨往，特達見令德。", "誰謂十世遠，風義猶不隔。", "末孫何支離，畎畝有餓色。", "明詔問樂鄉，布衣列士籍。", "名垂天壤間，氣使懦夫激。", "聞君商聲歌，更若出金石。"]'),
('de754bc1-81a2-44f8-8169-bd35032e4c94','贈聖從待制','劉敞','宋','宋诗','song-poetry','','[]','君居御街西，我居御街東。',96,'全唐诗/poet.song.27000.json','["君居御街西，我居御街東。", "如何百步間，十日不相從。", "君非園中植，落落千丈松。", "我亦湖海人，庶幾孤飛鴻。", "俱遊人世間，俛仰豈不同。", "蕭蕭髪向白，哀哀嗟轉蓬。", "仕固不期達，貧亦不諱窮。", "行當一麾去，幸識攖寧翁。"]'),
('962fa7cf-603a-4bec-b2cc-031fabb4251e','早至凉榭觀芙蕖','劉敞','宋','宋诗','song-poetry','','[]','林深池亦淺，日出光晚及。',60,'全唐诗/poet.song.27000.json','["林深池亦淺，日出光晚及。", "粲粲花尚含，漙漙露猶浥。", "良魚潛復躍，幽鳥翔又集。", "物情怳如慕，心賞浩難戢。", "誰能贈遠人，采采空佇立。"]'),
('7acd64a7-ed0e-4071-98f8-b1a35b7008bf','同客飲涪州薛使君佚老亭','劉敞','宋','宋诗','song-poetry','','[]','百尺井底泉，激輪乍飛流。',144,'全唐诗/poet.song.27000.json','["百尺井底泉，激輪乍飛流。", "潺湲入庭戶，宛轉如奔虬。", "主人三署郎，持節西南州。", "棄之臥故里，富貴安足留。", "郤埽長閉門，贏餘非所求。", "客來坐林下，樽酒相獻酬。", "未嘗語朝市，餘事良悠悠。", "乃知獨往意，不必山林幽。", "衣冠多雋才，繼踵公與侯。", "誰能懸其車，五十未白頭。", "嗟嗟賢大夫，此風可鎮浮。", "爲問三輔間，何如馬少遊。"]'),
('5b063504-c749-4e1b-ad3e-763d3bb85053','曲水臺竹間默坐','劉敞','宋','宋诗','song-poetry','','[]','杖履不能遠，逍遙池上林。',72,'全唐诗/poet.song.27000.json','["杖履不能遠，逍遙池上林。", "微風起衆響，炎日隔繁陰。", "斐亹激流泉，間關語鳴禽。", "放懷在離人，寄賞欣會心。", "既謝朝市喧，亦忘山谷深。", "雖知非吾室，猶以開煩襟。"]'),
('998426ed-ff3f-4f0e-9ee4-632c5206ca62','永興軍作','劉敞','宋','宋诗','song-poetry','','[]','凉風響高樹，清露墜明河。',48,'全唐诗/poet.song.27000.json','["凉風響高樹，清露墜明河。", "誰謂夏夜短，已覺秋氣多。", "豔膚麗華燭，皓齒揚清歌。", "臨觴不作意，奈此粲者何。"]'),
('b7ce92a2-5b63-4e3f-8359-6191708ae7fd','北軒手種竹兩竿近輒有甘露降其上作五言示諸同舍','劉敞','宋','宋诗','song-poetry','','[]','秋來手種竹，憔悴不成林。',72,'全唐诗/poet.song.27000.json','["秋來手種竹，憔悴不成林。", "復此雪霜晚，空驚孤直心。", "如何沾瑞露，似欲慰窮陰。", "珠華粲将墜，玉色潤還深。", "含春乍荏苒，戴日尚蕭森。", "玄澤非人力，樵蘇無見侵。"]'),
('feaadc22-7e13-4aa3-af7c-8e57cb40fa0d','舅氏見索新詩','劉敞','宋','宋诗','song-poetry','','[]','賤子本不學，大賢宜見疏。',120,'全唐诗/poet.song.27000.json','["賤子本不學，大賢宜見疏。", "奈何手賜教，反謂詩起予。", "高義終炯然，內慚良闕如。", "得非魯仲尼，不廢狂接輿。", "羈旅習荆楚，荒唐存簡書。", "敢驚和者稀，長恐歳已徂。", "雲漢回天章，圖書秘石渠。", "瓊瑤落咳唾，寒暑随吹嘘。", "百年渭陽悲，萬古秦風餘。", "嗟我送舅氏，終焉非路車。"]'),
('60a14b17-a3af-4eb8-b9dd-a9b48b272550','贈蘇頌','劉敞','宋','宋诗','song-poetry','','[]','犬豕蒙虎革，氣能懾羣雌。',144,'全唐诗/poet.song.27000.json','["犬豕蒙虎革，氣能懾羣雌。", "衆人見之美，蘇生見之嗤。", "褐客懷寶玉，精神暗塵緇。", "他人望而唾，蘇生望而知。", "知之竟何補，位下容貌卑。", "雷同世方尚，獨異誠難施。", "嗟子豈不謬，拳拳心不移。", "拜我呼我兄，問我謂我師。", "奔蜂負藿蠋，誰道當其宜。", "憫子空慕古，且爲世人非。", "古人亦如此，如此名已垂。", "但當勵行習，慰我千里思。"]'),
('739a7d16-6fd5-4a4b-8b23-7eb05a318fb0','雪後城上作','劉敞','宋','宋诗','song-poetry','','[]','雪後原野曠，春生風氣和。',48,'全唐诗/poet.song.27000.json','["雪後原野曠，春生風氣和。", "藹藹林表色，輝輝池上波。", "形閒境逾静，望遠意更多。", "年華適可玩，不醉将謂何。"]'),
('ccd7cf84-8d1f-41c4-8c2a-bf59781a555f','寄因甫','劉敞','宋','宋诗','song-poetry','','[]','君雖委計吏，官似宣尼公。',48,'全唐诗/poet.song.27000.json','["君雖委計吏，官似宣尼公。", "貧賤更何恨，優游聊與同。", "忘懷鴟夷酒，乘興松江風。", "此亦隱柱下，何用臥隆中。"]'),
('8b800e86-583a-434a-ae9e-c4bda793b86c','寄聖俞','劉敞','宋','宋诗','song-poetry','','[]','徘徊帝城裏，獨詠有所思。',48,'全唐诗/poet.song.27000.json','["徘徊帝城裏，獨詠有所思。", "故人昔别此，秋風今若兹。", "流水去不已，新鴈來有期。", "寄聲可相及，一見慰天涯。"]'),
('2cdab308-5eb6-4d76-ac57-d6b94ec55047','秋雨','劉敞','宋','宋诗','song-poetry','','[]','天道去人遠，好惡常若違。',48,'全唐诗/poet.song.27000.json','["天道去人遠，好惡常若違。", "始耕苦炎旱，既穫雨過時。", "憔悴兩無補，饑寒方自兹。", "素飽猶可恃，眷言采其薇。"]'),
('6a49f118-1526-4300-a3dc-cb08a1084619','寄密令楊彦文再舉學官皆中正','劉敞','宋','宋诗','song-poetry','','[]','三年不相見，相見當何時。',96,'全唐诗/poet.song.27000.json','["三年不相見，相見當何時。", "曩别不謂久，後期庸可知。", "周南滯留地，宿昔太史悲。", "春草愁山中，王孫髪垂絲。", "懷寶常若迷，獻玉常若疑。", "聞君已屢薦，終歳獨差池。", "得鹿在詭遇，亡羊實多岐。", "著書成自樂，回首空相思。"]'),
('61abdb72-eced-4c87-b2ac-478c1ca0a45c','贈黄子温别','劉敞','宋','宋诗','song-poetry','','[]','雙鴻俱異鄉，來集清川流。',96,'全唐诗/poet.song.27000.json','["雙鴻俱異鄉，來集清川流。", "鳴聲偶邂逅，形影共沉浮。", "一以風波去，一以罦網留。", "去留雖殊趣，失侣自懷愁。", "五里一斂翼，十里一回頭。", "有情同覆載，誰免顧朋儔。", "南國江海闊，豐年稻梁優。", "力弱霜霰繁，無因攜汝遊。"]'),
('81b784fe-823c-4a23-a151-030415dec759','同謝十三賦盆池','劉敞','宋','宋诗','song-poetry','','[]','碧沼含白水，動搖明鏡光。',48,'全唐诗/poet.song.27000.json','["碧沼含白水，動搖明鏡光。", "浮沉見魚樂，舒卷聞荷香。", "賞翫兹有適，紛囂因以忘。", "多君江湖意，不復疑坳堂。"]'),
('f764dc51-8fd0-4609-bde8-6ee0199fccae','詠庭前箭竹','劉敞','宋','宋诗','song-poetry','','[]','冉冉東南美，託根郡在兹。',48,'全唐诗/poet.song.27000.json','["冉冉東南美，託根郡在兹。", "鳯凰不可待，歳月方屢移。", "非復山林意，空餘霜霰姿。", "清風有時至，獨與幽人期。"]'),
('85a83bb2-d42b-430b-a69b-c590a41f461f','新置盆池種蓮荷菖蒲養小魚數十頭終日玩之甚可愛偶作五言詩','劉敞','宋','宋诗','song-poetry','','[]','采芳未盈手，積潤不滿尋。',72,'全唐诗/poet.song.27000.json','["采芳未盈手，積潤不滿尋。", "游魚亦何樂，幽客同此心。", "安排在所寓，相與忘浮沉。", "濟理趣自足，孰知慕高深。", "鵬翻蕩滄海，龍起焚山林。", "體妨反多累，豈若終蹄涔。"]'),
('f21b075d-5696-494f-b896-d78e80503666','送鬱林楊守','劉敞','宋','宋诗','song-poetry','','[]','鴻鵠懷遠心，不畏霜露寒。',120,'全唐诗/poet.song.27000.json','["鴻鵠懷遠心，不畏霜露寒。", "鷄鶩守樊籠，朝遊暮來還。", "人生感意氣，朋友死一言。", "况分社稷憂，復在君臣間。", "楊侯一麾守，萬里蒼梧山。", "瘴海不可游，衆人昔云難。", "升車獨慷慨，即路無險艱。", "乃知抱忠信，可以居夷蠻。", "昔賢尚功名，天子憂南蕃。", "報國恩汲汲，勿令歳月遷。"]'),
('37a8166e-5459-4ce0-859d-15cf440902a7','送春','劉敞','宋','宋诗','song-poetry','','[]','莫埽林下花，花存春尚在。',48,'全唐诗/poet.song.27000.json','["莫埽林下花，花存春尚在。", "一随南風散，飄忽不可待。", "四時相乘凌，萬物随變改。", "不如玩三秀，忘年蹈雲海。"]'),
('a8d5474c-6507-4371-a02e-2b2f863b4a08','答舅氏時詔不就學官者郡勿舉故見督赴期','劉敞','宋','宋诗','song-poetry','','[]','飛鳥知深林，潛魚樂淵濬。',96,'全唐诗/poet.song.27000.json','["飛鳥知深林，潛魚樂淵濬。", "升沉久相笑，出處各自殉。", "漆雕不願仕，孟子恥獨進。", "軒冕世所榮，吾斯未能信。", "辟雍焕文章，王國聚英俊。", "及門足自喜，內省愧多吝。", "且将事畎畝，亦以樂堯舜。", "悠悠謝知音，當識斯言訒。"]'),
('16a9434e-4155-433c-a9e3-88a002e8c3e6','送張宗道崇班自潁徙秦不樂于行','劉敞','宋','宋诗','song-poetry','','[]','宛馬來東道，燕鴻起南飛。',72,'全唐诗/poet.song.27000.json','["宛馬來東道，燕鴻起南飛。", "適時必有遇，去遠不獨迷。", "左攬繁弱絃，右拂青萍輝。", "笑作千里别，出門亦依依。", "人生何新故，行道情有違。", "勉率歌清風，以慰君永懷。"]'),
('57708008-cf01-44fb-a3f8-6a6c8c98d6b1','陳元龍','劉敞','宋','宋诗','song-poetry','','[]','元龍湖海士，固有湖海氣。',96,'全唐诗/poet.song.27000.json','["元龍湖海士，固有湖海氣。", "自臥百尺樓，羣兒仆諸地。", "大賢資遠到，高節邁一世。", "四野爲戶庭，九河乃衣带。", "靈機有時屈，英識豈獨閉。", "蛟龍随波游，恥與魚鼈計。", "撃劍歌商聲，捐書謝俗議。", "功名留當年，異代見君意。"]'),
('d7536003-f0e5-4aca-97e5-d9b14cc98eed','一月贈深甫','劉敞','宋','宋诗','song-poetry','','[]','一月三過公，此非兒女情。',108,'全唐诗/poet.song.27000.json','["一月三過公，此非兒女情。", "詩人感伐木，相鳥猶嚶鳴。", "尚友百世近，結交千里輕。", "矧惟生並時，况復居同城。", "攜手未宜少，興發從公行。", "開口露肝膽，觧衿頓塵纓。", "心親愛自至，外物都忘形。", "赤日留中天，火雲正崢嶸。", "頗復哀老子，安眠枕羣經。"]'),
('b9c42d3f-e578-4123-8802-988a22f8ac58','懷歸','劉敞','宋','宋诗','song-poetry','','[]','往昔佩觽日，童蒙幸相求。',96,'全唐诗/poet.song.27000.json','["往昔佩觽日，童蒙幸相求。", "中間萬里别，倐忽二十秋。", "人事固契闊，歳華易如流。", "聞君尚黄綬，失意成白頭。", "奄速不可期，升沉亦難謀。", "寧知及門晚，忽辱從政優。", "感舊勞心腸，相從恨淹留。", "寄聲不盡意，何以紓離憂。"]'),
('a3b4d41e-7b94-4d7f-af27-22588e92b633','同寄題康州陳生連理木','劉敞','宋','宋诗','song-poetry','','[]','幽人吉素履，佳瑞應精誠。',96,'全唐诗/poet.song.27000.json','["幽人吉素履，佳瑞應精誠。", "蕭蕭衡門下，珍木爲之榮。", "連理出高幹，交陰庇前庭。", "顧恐俗未知，天方表其閎。", "太邱往千歳，慈孝復騰聲。", "誰言報施遠，有若晝夜明。", "世悲上留田，吾慕董生行。", "作詩寄南州，且以慰父兄。"]'),
('f9056ac8-3ee4-4c2c-9e66-113745f18cee','雪後','劉敞','宋','宋诗','song-poetry','','[]','雪銷吐膏潤，日出春意歸。',60,'全唐诗/poet.song.27000.json','["雪銷吐膏潤，日出春意歸。", "藹藹多時趣，融融含夕暉。", "徘徊終林下，彷彿田野期。", "天歡頗不減，吏隱亦庶幾。", "歳宴竟何事，濁酒但當揮。"]'),
('cbfd7eb4-e9d6-49cd-921f-c6ef09da0d29','和彦文秋興','劉敞','宋','宋诗','song-poetry','','[]','商飊零枯林，疏雨堕中夕。',96,'全唐诗/poet.song.27000.json','["商飊零枯林，疏雨堕中夕。", "覧物愴已驚，懷人渺難得。", "明發聆逸唱，願言慰幽寂。", "胡爲抱紆鬱，更使動悽惻。", "蜚鴻識來賓，鷹隼知所撃。", "物微有逢辰，子北獨失職。", "高天終難間，淺俗每忌直。", "浮沈豈非智，器遠固難識。"]'),
('5a135ddb-099b-471f-a827-bbee760f4fdb','贈周生','劉敞','宋','宋诗','song-poetry','','[]','騏驥能千里，不能走鼠穴。',144,'全唐诗/poet.song.27000.json','["騏驥能千里，不能走鼠穴。", "猛虎拘穽中，不如狗善齧。", "周生學干祿，强進屢顛蹶。", "時不用周生，周生亦不屑。", "行年過五十，頗就知命說。", "未嘗畜妻子，名利敢貪竊。", "所憂道未能，欲辨孔與桀。", "人知如此鮮，况不厭藜蕨。", "與我始相見，便覺抱高節。", "人皆用其巧，子獨趨所拙。", "春秋舉逸民，蔽善尚貶絕。", "誰期大夫賢，薦使在班列。"]'),
('2297f0c9-4a7f-41f2-9101-58daff77401f','嘯亭納凉','劉敞','宋','宋诗','song-poetry','','[]','翻翻竹梢葉，習習蘋末風。',48,'全唐诗/poet.song.27000.json','["翻翻竹梢葉，習習蘋末風。", "水氣稍澄澈，雲陰反蒙籠。", "解襟面虛曠，幽興欲飛冲。", "得意恥獨善，慨然環堵中。"]'),
('08a9dabb-cde9-4076-bed2-302ea1cca887','過澶州陽橋有感','劉敞','宋','宋诗','song-poetry','','[]','河水東赴海，還從天上回。',48,'全唐诗/poet.song.27000.json','["河水東赴海，還從天上回。", "寧知今日波，還復前時來。", "岸柳亦已荑，原田正莓莓。", "念我平生歡，悵然使心哀。"]'),
('c7edee9c-e107-43e7-bc23-6325051981f0','春晚小園','劉敞','宋','宋诗','song-poetry','','[]','歳華一何速，春物俱已老。',72,'全唐诗/poet.song.27000.json','["歳華一何速，春物俱已老。", "綠柳低映墻，臯蘭生滿道。", "郊居止幽曠，野色慰懷抱。", "入鳥不亂羣，閉門但郤埽。", "平生佯狂性，更覺高臥好。", "不及古之人，吾誰玩芳草。"]'),
('27b22928-20ea-4b20-abfa-86acdffc0914','停雲詩','劉敞','宋','宋诗','song-poetry','','[]','停停何山雲，靄靄在我廬。',84,'全唐诗/poet.song.27000.json','["停停何山雲，靄靄在我廬。", "濃光賁草木，潤氣下琴書。", "望望若可親，久之翳寒虛。", "坐恐猋風來，東西隨所如。", "我道與世異，里閭相見疏。", "嗟雲亦何事，低徊能慕予。", "諒以無心故，形影暫相於。"]'),
('387ae17a-f2c7-4f3f-a559-c0df5f60fde2','華山隱者圖','劉敞','宋','宋诗','song-poetry','','[]','神仙不可學，淺俗如醯雞。',156,'全唐诗/poet.song.27000.json','["神仙不可學，淺俗如醯雞。", "逍遙二三叟，乃獨秦遺黎。", "避地思遠適，名山得幽棲。", "深巖紫芝秀，歸路桃花迷。", "稍遠人世隔，遂忘陵谷移。", "至今山中人，往往猶見之。", "吾聞秦皇帝，甚慕真人爲。", "駕石窺蓬萊，載車象雲蜺。", "沙丘往不返，四海忽若遺。", "安知全真子，近在西山垂。", "一千二百年，修身未嘗衰。", "古稱山澤臞，非復萬乘期。", "觀君此圖意，有以和天倪。"]'),
('f4036eee-7c13-4065-b2d1-14e7824407f9','送上元張孟侯著作','劉敞','宋','宋诗','song-poetry','','[]','避世金馬門，歇直承明廬。',120,'全唐诗/poet.song.27000.json','["避世金馬門，歇直承明廬。", "月贏一囊粟，調笑騶侏儒。", "忽憶東南行，秋風熟鱸魚。", "聞君已先我，扁舟向江湖。", "銅章垂腰問，賜履雙飛鳧。", "千室豈不憂，弦歌自爲娛。", "古稱有人民，無事專讀書。", "自顧都城游，刺促轅間駒。", "六朝若流川，覽古半有無。", "山中折瑤華，千里懷離居。"]'),
('159eab95-0c21-420a-a201-9bbe1db2681e','小隱吟','劉敞','宋','宋诗','song-poetry','','[]','世道喪純粹，徼名掠其美。',72,'全唐诗/poet.song.27000.json','["世道喪純粹，徼名掠其美。", "悲哉山林客，過半朝市死。", "夸誕一相習，澆浮益紛起。", "古風日飄泊，末路空頽靡。", "堯舜安得逢，巢由亦已矣。", "我歌竟誰和，惆悵同心子。"]'),
('70d574d6-a2eb-4628-8a47-205bfc420600','招隱','劉敞','宋','宋诗','song-poetry','','[]','鱣鱘不容池，鴻鵠常畏網。',60,'全唐诗/poet.song.27000.json','["鱣鱘不容池，鴻鵠常畏網。", "全真貴遠到，先覺每獨往。", "綺皓遺泰憂，季鷹樂吴壤。", "知幾効來世，前識妙難賞。", "勿謂鳥獸羣，高山適予仰。"]'),
('727bd0a0-ccd0-400f-8a2f-facc12940cfb','反招隱','劉敞','宋','宋诗','song-poetry','','[]','伊尹樂堯舜，伯夷傲姬周。',144,'全唐诗/poet.song.27000.json','["伊尹樂堯舜，伯夷傲姬周。", "顔生一簞瓢，陋巷亦自休。", "豈不困寂寞，時俗非所謀。", "脱身灑泥滓，緬與前人游。", "嗟哉波上鳧，徒爲信沈浮。", "鴻鵠假長風，不能占渠溝。", "晞羽扶桑阿，刷翼滄海流。", "世途既超邈，矰繳何足愁。", "所以狂接輿，肆歌悟東丘。", "觸時懷慷慨，視世悲蜉蝣。", "哲人有先覺，達者無近憂。", "綺皓吾所師，緒言起長謳。"]'),
('bb237628-de17-456e-8f52-b5a9fa5bbb9c','郡齋燕居寄海陵道粹儀真景休高郵不疑三太守學士','劉敞','宋','宋诗','song-poetry','','[]','尚容恥玩世，畏景希就陰。',120,'全唐诗/poet.song.27000.json','["尚容恥玩世，畏景希就陰。", "一麾諧微願，千里非遐心。", "平生志江海，寤寐在山林。", "及此吏如隱，始知古猶今。", "鷾鴯避落實，蜎蠉安蹄涔。", "但恐得已多，尚非力可任。", "諸公蓬萊秀，夙昔交契深。", "擊柝聲相聞，照鄰光四臨。", "清濁涇以渭，離合商與參。", "願言三秋思，毋閟金玉音。"]'),
('22dadeda-8a4d-4618-b2ea-5197128d20b6','新作涼軒會張拱辰至','劉敞','宋','宋诗','song-poetry','','[]','張翁垂白鬚，扶病過我廬。',60,'全唐诗/poet.song.27000.json','["張翁垂白鬚，扶病過我廬。", "向無俗客至，適慰幽人居。", "酌此瓢中泉，振兹架上書。", "雖無德與汝，會有歌起予。", "欲識消長情，願君講盈虚。"]'),
('2aad3e6f-8033-47b1-8007-cca7f6d6cf89','發桑乾河','劉敞','宋','宋诗','song-poetry','','[]','四牡懷靡及，侵旦肅征騑。',72,'全唐诗/poet.song.27000.json','["四牡懷靡及，侵旦肅征騑。", "凝霜被野草，四顧人迹稀。", "水流日邊去，鴈向江南飛。", "我行亦已久，羸馬聲正悲。", "覽物歲華逝，撫事壯心違。", "豈伊越鄉感，乃復淚沾衣。"]'),
('729377c1-e8ee-4f63-926c-0a59fa07990f','寄呂侍郎','劉敞','宋','宋诗','song-poetry','','[]','荒山逢故轍，自上重岡立。',48,'全唐诗/poet.song.27000.json','["荒山逢故轍，自上重岡立。", "君車不可望，君手何由執。", "旅思隨日遠，徂年背人急。", "舞劍中夜興，應知憂感集。"]'),
('df9c70f3-59e9-4568-b825-e9d45834c47a','蔣生','劉敞','宋','宋诗','song-poetry','','[]','仙翁棄妻子，往爲壺中客。',48,'全唐诗/poet.song.27000.json','["仙翁棄妻子，往爲壺中客。", "玉棺竟未掩，人世已成昔。", "白雲無回期，三徑滅餘迹。", "猶傳有青鳥，往往寄消息。"]'),
('9e6bc1e8-8bcb-4e34-8ae6-64601c478a3f','新年','劉敞','宋','宋诗','song-poetry','','[]','流光無停期，二十忽復五。',144,'全唐诗/poet.song.27000.json','["流光無停期，二十忽復五。", "古昔如我人，功烈難遽數。", "上天終無私，日月不少駐。", "三皇與五帝，回首焉得顧。", "新年獨何爲，擾擾趁俗務。", "壯羞兒女態，浩歎覺已屢。", "巍巍九重闕，象魏懸法度。", "木鐸非仲尼，布衣欲何預。", "滄溟百萬里，乘桴意決去。", "顧世聊徘徊，非爲取材誤。", "東風發幽滯，花彩映草樹。", "爛醉苟自娱，終焉背時譽。"]'),
('0045dffe-f641-4a3b-8467-7a1fb781165a','築室種樹','劉敞','宋','宋诗','song-poetry','','[]','誅茅作吾廬，種樹滿百株。',72,'全唐诗/poet.song.27000.json','["誅茅作吾廬，種樹滿百株。", "偃仰可卒歲，優游問誰如。", "墨翟不暖席，仲尼無安居。", "良知聖賢貴，逝與功名疏。", "清泉可深鑿，惡草須早除。", "適意田野間，誰能歎歸歟。"]'),
('2f4d03fa-c3e3-4591-b1c4-5c20e6580db0','題所種金鳯花自淮北攜子種之云','劉敞','宋','宋诗','song-poetry','','[]','愛此名字佳，攜之不憚遠。',96,'全唐诗/poet.song.27000.json','["愛此名字佳，攜之不憚遠。", "豈惟江淮闊，兼恐歲月晚。", "手植中庭地，分破紫蘭畹。", "綠葉紛映階，紅芳爛盈眼。", "輝輝丹穴禽，矯矯翅翎展。", "卑飛何在此，寂寞難自顯。", "按圖感形似，覽物意繾綣。", "三復接輿歌，悲風動湘沔。"]'),
('a15015d4-21e5-4993-8904-d75692d4cd81','得隱直書并聞將之洛陽','劉敞','宋','宋诗','song-poetry','','[]','三月一得書，始知去君遠。',120,'全唐诗/poet.song.27000.json','["三月一得書，始知去君遠。", "開緘見無恙，豁達百慮展。", "秋風催時節，搖落歲向晚。", "遲遲行旅外，色瘁足更趼。", "邊封鳴狐狸，牙爪貴鷹犬。", "儒者非所須，棄置自未免。", "上書報聞罷，試吏何繾綣。", "雖無小官羞，頗貴有道卷。", "洛陽雄王都，主簿亦極選。", "折腰得免否，局促時態淺。"]'),
('3760aa77-4ca9-4f0c-8847-f97cfc39e285','閲武堂','劉敞','宋','宋诗','song-poetry','','[]','涼風郤炎暑，飛雨除氛埃。',96,'全唐诗/poet.song.27000.json','["涼風郤炎暑，飛雨除氛埃。", "旅行得興會，珍館爲我開。", "主人平生舊，上客自遠來。", "何異東序賢，共此中山杯。", "留連恨落日，披寫仍高臺。", "山川愴興廢，歌舞寄歡哀。", "徐方多賢牧，天祿繼英才。", "遊子悲故鄉，爲君更徘徊。"]'),
('4165cbb2-b124-4465-a9aa-66dbdb13c626','寄張十二時在城北讀書簡云幾至絕糧','劉敞','宋','宋诗','song-poetry','','[]','新秋意無聊，多病時畏晚。',72,'全唐诗/poet.song.27000.json','["新秋意無聊，多病時畏晚。", "出門塵埃隔，扶杖行步蹇。", "雖聞一城居，邈有千里遠。", "風雨思雞鳴，幽懷固繾綣。", "食貧非余病，學道與時反。", "悲歌空相望，不復能裹飯。"]'),
('5303a4e0-3e22-461d-b671-41562308b6ce','因甫移宰晋陵','劉敞','宋','宋诗','song-poetry','','[]','自我游毗陵，五年今于兹。',204,'全唐诗/poet.song.27000.json','["自我游毗陵，五年今于兹。", "未嘗不閔雨，未嘗不苦饑。", "成湯周宣世，豈復能過斯。", "上無桑林禱，下無雲漢詩。", "赤子餓溝渠，良田生蒺藜。", "聽于閭里間，愁毒不可爲。", "思得一賢人，救其渇與饑。", "上天似悔禍，子乃今來尸。", "愛民在恭儉，自可爲吏師。", "但恐百里小，膏澤難盡施。", "子本湘鄉君，湘人望子來。", "下難兄弟别，上顧墳墓違。", "將母以諗君，上書再三辭。", "朝廷欣然許，多士咸謂宜。", "爲政推此心，可令孝者慈。", "吾聞屠牛刀，不貴于割雞。", "思君苦道遠，莞爾寄此詞。"]'),
('d3a007b0-b634-418d-90f8-6bf06141c6de','同彦文送敦儒宰晋陵','劉敞','宋','宋诗','song-poetry','','[]','朝廷貴儒術，子以文學顯。',72,'全唐诗/poet.song.27000.json','["朝廷貴儒術，子以文學顯。", "郡國重民社，子由政事選。", "榮名信難兼，衆望固不淺。", "古人定何如，壯志獨能勉。", "由來跬步益，必有千里遠。", "去去聆絃歌，吾當謝言偃。"]'),
('f082dac6-b06e-4bef-9212-0b1fccd56ca6','九日','劉敞','宋','宋诗','song-poetry','','[]','霜薄氣早寒，木落景已變。',48,'全唐诗/poet.song.27000.json','["霜薄氣早寒，木落景已變。", "佳晨事厭勝，習俗推往彦。", "憂來初無方，興盡復自遣。", "所遇無故物，登臨殊非願。"]'),
('ade092bc-13c0-4b51-bc3a-3cc75460dec6','寓言','劉敞','宋','宋诗','song-poetry','','[]','感豫常出異，禦宼哀壺丘。',60,'全唐诗/poet.song.27000.json','["感豫常出異，禦宼哀壺丘。", "好大固累已，巢父笑許由。", "東海有意怠，飛飛何所求。", "縱軀天地間，細故紛悠悠。", "願言不死鄉，可與賢達游。"]'),
('fd64d4fe-8014-4389-ba2b-85246505300a','晚景','劉敞','宋','宋诗','song-poetry','','[]','結廬玩蓬藿，反畏人足聞。',60,'全唐诗/poet.song.27000.json','["結廬玩蓬藿，反畏人足聞。", "杖藜有時去，入獸不亂羣。", "疏雨洗徂暑，夕陽澹微曛。", "俛仰多物態，逍遙遣塵紛。", "興適將何述，寄心孤飛雲。"]'),
('ac342819-bff4-463e-8141-84f4dc4bf6b1','野人致枸杞青蒿','劉敞','宋','宋诗','song-poetry','','[]','味薄時共笑，野人猶相高。',120,'全唐诗/poet.song.27000.json','["味薄時共笑，野人猶相高。", "春田有餘暇，饋我杞與蒿。", "酌酒謝其意，採之亦誠勞。", "城中多好事，過半稱賢豪。", "杯肴具五鼎，珠玉輕一毫。", "將之獻門下，皆有千金褒。", "何故背此計，而反從吾曹。", "淡泊徒自樂，膏薌未能叨。", "信知老農美，頗欲耕東臯。", "因閒有餘力，從爾觀芟薅。"]'),
('502007c6-6419-4b96-98c8-0d5fa81b643e','春暮到小園','劉敞','宋','宋诗','song-poetry','','[]','春餘百芳歇，喬木有輕陰。',84,'全唐诗/poet.song.27000.json','["春餘百芳歇，喬木有輕陰。", "客子成春服，商絃應鳴琴。", "獨行迕世俗，長往期山林。", "庭竹風正駛，池波雨已深。", "臨流窺躍魚，倚杖聆遷禽。", "順時寄俯仰，適興契飛沈。", "試謝及門客，未慚招隱吟。"]'),
('78f87da3-883c-427b-b9bd-5b8c8c1e4ddf','送雅禪師若神','劉敞','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖三萬頃，澄澈浮寒穹。',72,'全唐诗/poet.song.27000.json','["太湖三萬頃，澄澈浮寒穹。", "明月不可取，孤帆安所窮。", "俯弔滄浪人，緬懷鴟夷翁。", "古今共灰滅，得失如夢中。", "詩興觸物遠，禪心隨念空。", "猶多碧雲句，寄信東南風。"]');
